B.a8h=new A.f("q1","economic_law","\uacf5\uc815\uac70\ub798\ubc95",null,"\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.QE,3,'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c5\uc870\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ub0a8\uc6a9\ud589\uc704\ub97c \u2460 \uac00\uaca9\uc758 \ubd80\ub2f9\ud55c \uacb0\uc815\xb7\uc720\uc9c0\xb7\ubcc0\uacbd, \u2461 \ucd9c\uace0\uc870\uc808, \u2462 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \u2463 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574, \u2464 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \ub610\ub294 \uc18c\ube44\uc790\uc774\uc775 \uc800\ud574 \uc6b0\ub824 \ud589\uc704\ub85c \uc720\ud615\ud654\ud558\uace0 \uc788\ub2e4. \ubc18\uba74 \u2463 "\ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc870\uac74 \uc81c\uc2dc"\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1\uc801\uc73c\ub85c \ud589\ud558\ub294 \uc815\uc0c1\uc801\uc778 \uc601\uc5c5\ud65c\ub3d9\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c, \uadf8 \uc790\uccb4\ub85c\ub294 \ubd80\ub2f9\uc131\uc774 \uc778\uc815\ub418\uc9c0 \uc54a\uc544 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4. \ub530\ub77c\uc11c \ub2e4\ub978 \uc120\ud0dd\uc9c0\ub4e4\uc774 \ubaa8\ub450 \ubc95\uc5d0 \uba85\uc2dc\ub41c \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc778 \uac83\uacfc \ub2ec\ub9ac, \uc774 \uc120\ud0dd\uc9c0\ub9cc \ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.Nl,B.S7,"2024")
