B.aav=new A.f("q2","civil_law","\ubbfc\ubc95\ucd1d\uce59",null,"\ubbfc\ubc95\uc0c1 \ubc95\ub960\ud589\uc704\uc758 \ubb34\ud6a8\uc640 \ucde8\uc18c\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.KZ,3,'\ubb34\ud6a8(\u7121\u6548)\ub294 \ubc95\ub960\ud589\uc704\uac00 \uc131\ub9bd \ub2f9\uc2dc\ubd80\ud130 \ub2f9\uc5f0\ud788 \ud6a8\ub825\uc774 \uc5c6\ub294 \uac83\uc744 \ub9d0\ud558\uace0, \ucde8\uc18c(\u53d6\u6d88)\ub294 \uc77c\ub2e8 \uc720\ud6a8\ud558\uac8c \uc131\ub9bd\ud55c \ubc95\ub960\ud589\uc704\ub97c \ucde8\uc18c\uad8c\uc790\uc758 \uc758\uc0ac\ud45c\uc2dc\ub85c \uc18c\uae09\ud558\uc5ec \ubb34\ud6a8\ub85c \ub9cc\ub4dc\ub294 \uac83\uc744 \ub9d0\ud55c\ub2e4. \uc989 \ubb34\ud6a8\ub294 \ubcc4\ub3c4\uc758 \uc758\uc0ac\ud45c\uc2dc \uc5c6\uc774\ub3c4 \ucc98\uc74c\ubd80\ud130 \ud6a8\ub825\uc774 \uc5c6\uc9c0\ub9cc, \ucde8\uc18c\ub294 \ucde8\uc18c\uad8c\uc790\uac00 \ucde8\uc18c\uad8c\uc744 \ud589\uc0ac\ud558\uae30 \uc804\uae4c\uc9c0\ub294 \uc720\ud6a8\ud55c \ubc95\ub960\ud589\uc704\ub85c \ucde8\uae09\ub41c\ub2e4. \uc774\ucc98\ub7fc \ub450 \uc81c\ub3c4\ub294 \ubc1c\uc0dd \uc6d0\uc778\uacfc \ud6a8\uacfc \ubc1c\uc0dd \uc2dc\uc810\uc774 \uc804\ud600 \ub2e4\ub978 \ubcc4\uac1c\uc758 \uc81c\ub3c4\uc774\ubbc0\ub85c, "\ud56d\uc0c1 \ud568\uaed8 \ubc1c\uc0dd\ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ub2e4\ub9cc \uc608\uc678\uc801\uc73c\ub85c \ubb34\ud6a8\ud589\uc704\uc640 \ucde8\uc18c\ud560 \uc218 \uc788\ub294 \ud589\uc704\uac00 \ub3d9\uc2dc\uc5d0 \uc131\ub9bd\ud558\ub294 \uacbd\uc6b0(\uc774\uc911\ud6a8)\uac00 \uc788\uc744 \uc218\ub294 \uc788\uc73c\ub098, \uc774\ub294 \ud56d\uc0c1 \uadf8\ub7f0 \uac83\uc774 \uc544\ub2c8\ub77c \ud2b9\uc815 \uc694\uac74\uc774 \uacb9\uce60 \ub54c\uc5d0 \ud55c\ud55c\ub2e4.',B.VY,B.KB,"2023")
