B.abi=new A.f("gen_al_1","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.H_,4,'\uc57d\uad00\ubc95 \uc81c3\uc870\uc5d0 \ub530\ub974\uba74 \uc0ac\uc5c5\uc790\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uace0\uac1d\uc774 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc5ec\uc57c \ud558\uc9c0\ub9cc, "\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0"\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \uc774 \uc124\uba85\uc758\ubb34\uac00 \uba74\uc81c\ub41c\ub2e4(\uc81c3\uc870 \uc81c3\ud56d \ub2e8\uc11c). \ub530\ub77c\uc11c "\uc124\uba85\uc758\ubb34\ub294 \uba74\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4"\uace0 \ub2e8\uc815\ud55c \uc120\ud0dd\uc9c0\uac00 \uc633\uc9c0 \uc54a\uc740 \uc124\uba85\uc774\ub2e4. \ud55c\ud3b8 \uc5ec\uac1d\uc6b4\uc1a1\uc5c5, \uc804\uae30\xb7\uac00\uc2a4\xb7\uc218\ub3c4\uc0ac\uc5c5, \uc6b0\ud3b8\uc5c5 \ub4f1\uc740 \uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c2\ud56d \ub2e8\uc11c\uc5d0 \ub530\ub77c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub9cc \uba74\uc81c\ub420 \ubfd0, \uc124\uba85\uc758\ubb34\uae4c\uc9c0 \uc790\ub3d9\uc73c\ub85c \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\ub294 \uc810(\uc120\ud0dd\uc9c0 \u2462)\uc740 \uc2e4\uc81c\ub85c \uc633\uc740 \uc124\uba85\uc774\ubbc0\ub85c \ud63c\ub3d9\ud558\uc9c0 \uc54a\ub3c4\ub85d \uc8fc\uc758\ud574\uc57c \ud55c\ub2e4. \uc989 "\uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34 \uba74\uc81c \uc5c5\uc885"\uacfc "\uc124\uba85\uc758\ubb34 \uba74\uc81c \uc0ac\uc720"\ub294 \uc11c\ub85c \ub2e4\ub978 \uc870\ud56d\uc5d0 \uadfc\uac70\ud55c \ubcc4\uac1c\uc758 \uc608\uc678\ub77c\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub2e4.',B.Qh,B.S_,null)
B.Zx=s(["\uace0\uac1d\uc774 \uc694\uccad\ud558\uc9c0 \uc54a\uc73c\uba74 \uc5b4\ub5a0\ud55c \ubc29\ubc95\uc73c\ub85c\ub3c4 \uba85\uc2dc\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uace0\uac1d\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uc57d\uad00\uc744 \uac8c\uc2dc\ud558\uac70\ub098 \uadf8 \ub0b4\uc6a9\uc744 \uc54c\ub9ac\uba74 \ub41c\ub2e4","\ubc18\ub4dc\uc2dc \uace0\uac1d\uacfc \ub300\uba74\ud558\uc5ec \uad6c\ub450\ub85c \uc57d\uad00 \uc804\uccb4\ub97c \ub0ad\ub3c5\ud574\uc57c \ud55c\ub2e4","\uc57d\uad00\uc744 \ud648\ud398\uc774\uc9c0\uc5d0 \uac8c\uc2dc\ud558\ub294 \uac83\uc740 \uba85\uc2dc\uc758\ubb34\uc758 \uc774\ud589 \ubc29\ubc95\uc73c\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4","\uba85\uc2dc\uc758\ubb34\ub294 \uacc4\uc57d \uccb4\uacb0 \uc774\ud6c4 \uc5b8\uc81c\ub4e0 \uc774\ud589\ud558\uba74 \ucda9\ubd84\ud558\ub2e4"],t.s)
B.Zc=s(["\uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uace0\uac1d\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uac8c\uc2dc\ud558\uac70\ub098 \uace0\uac1d\uc5d0\uac8c \uc54c\ub824\uc57c"],t.s)
B.XZ=s(["\uba85\uc2dc\uc758\ubb34 \uc774\ud589\ubc29\ubc95"],t.s)
B.abT=new A.f("gen_al_expl_2","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc57d\uad00\uc758 "\uba85\uc2dc\uc758\ubb34"\uc758 \uc774\ud589 \ubc29\ubc95\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.Zx,1,'\uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c2\ud56d\uc740 \uc0ac\uc5c5\uc790\uac00 \uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uace0\uac1d\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uac8c\uc2dc\ud558\uac70\ub098 \uace0\uac1d\uc5d0\uac8c \uc54c\ub824\uc57c \ud55c\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \ubc18\ub4dc\uc2dc \uad6c\ub450 \ub0ad\ub3c5\uc774 \ud544\uc694\ud55c \uac83\uc740 \uc544\ub2c8\uba70, \uc5c5\uc885\uc758 \ud2b9\uc131\uc5d0 \ub9de\ub294 \ud569\ub9ac\uc801\uc778 \ubc29\ubc95(\ub9e4\uc7a5 \uac8c\uc2dc, \ud648\ud398\uc774\uc9c0 \uac8c\uc2dc, \uacc4\uc57d\uc11c \ucca8\ubd80 \ub4f1)\uc774\uba74 \ucda9\ubd84\ud558\ub2e4. \ub2e4\ub9cc \uacc4\uc57d \uccb4\uacb0 "\uc774\uc804"\uc5d0 \uc774\ud589\ub418\uc5b4\uc57c \ud558\ubbc0\ub85c \uccb4\uacb0 \uc774\ud6c4 \uc784\uc758\uc758 \uc2dc\uc810\uc5d0 \uc774\ud589\ud574\ub3c4 \ub41c\ub2e4\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.Zc,B.XZ,null)
B.N3=s(["\uc0ac\uc5c5\uc790\ub294 \uacc4\uc57d \uccb4\uacb0 \uc2dc \uace0\uac1d\uc758 \uc694\uccad\uc774 \uc5c6\uc5b4\ub3c4 \ud56d\uc0c1 \uc57d\uad00 \uc0ac\ubcf8\uc744 \uad50\ubd80\ud558\uc5ec\uc57c \ud55c\ub2e4","\uace0\uac1d\uc774 \uc57d\uad00\uc758 \uc0ac\ubcf8 \uad50\ubd80\ub97c \uc694\uccad\ud558\uba74 \uc0ac\uc5c5\uc790\ub294 \uc774\uc5d0 \uc751\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc5ec\uac1d\uc6b4\uc1a1\uc5c5 \ub4f1 \uc77c\ubd80 \uc5c5\uc885\uc740 \uad50\ubd80\uc758\ubb34\uac00 \uba74\uc81c\ub420 \uc218 \uc788\ub2e4","\uc804\uc790\ubb38\uc11c\ub85c \uc57d\uad00\uc744 \uc81c\uacf5\ud558\ub294 \uac83\ub3c4 \uad50\ubd80\uc758 \ud55c \ubc29\ubc95\uc73c\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4","\uad50\ubd80\uc758\ubb34\ub294 \uba85\uc2dc\uc758\ubb34\uc640 \ubcc4\uac1c\ub85c \uaddc\uc815\ub418\uc5b4 \uc788\ub2e4"],t.s)
B.a1Q=s(['\uace0\uac1d\uc774 "\uc694\uccad"\ud558\uba74 \uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uc758 \uc0ac\ubcf8\uc744 \uad50\ubd80\ud558\ub3c4\ub85d \uaddc\uc815'],t.s)
