B.abq=new A.f("gen_al_expl_4","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\uac00 \uba74\uc81c\ub418\ub294 \uc5c5\uc885\uc73c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Qm,4,"\uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c2\ud56d \ub2e8\uc11c\ub294 \uc5ec\uac1d\uc6b4\uc1a1\uc5c5, \uc804\uae30\xb7\uac00\uc2a4 \ubc0f \uc218\ub3c4\uc0ac\uc5c5, \uc6b0\ud3b8\uc5c5, \uacf5\uc911\uc804\ud654 \uc11c\ube44\uc2a4 \uc81c\uacf5 \ud1b5\uc2e0\uc5c5 \ub4f1 \uacc4\uc57d\uc758 \uc2e0\uc18d\xb7\uc815\ud615\uc131\uc774 \uc694\uad6c\ub418\ub294 \uc77c\ubd80 \uc5c5\uc885\uc5d0 \ud55c\ud558\uc5ec \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub97c \uba74\uc81c\ud558\uace0 \uc788\ub2e4. \ud1b5\uc2e0\ud310\ub9e4\uc5c5\uc740 \uc774\ub7ec\ud55c \uba74\uc81c \uc5c5\uc885\uc73c\ub85c \uc5f4\uac70\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc73c\ubbc0\ub85c, \ud1b5\uc2e0\ud310\ub9e4\uc5c5\uc790\ub3c4 \uc6d0\uce59\ub300\ub85c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub97c \uc774\ud589\ud574\uc57c \ud55c\ub2e4.",B.Wg,B.a_c,null)
B.Gu=s(["\uace0\uac1d\uc758 \uad8c\ub9ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc5d0\uac8c \uc0c8\ub85c\uc6b4 \uc758\ubb34\ub97c \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d","\uacc4\uc57d\uc758 \ud574\uc9c0\xb7\ud574\uc81c \uc0ac\uc720\uc5d0 \uad00\ud55c \uc870\ud56d","\ubc95\ub839\uc5d0 \uc774\ubbf8 \uc815\ud574\uc9c4 \ub0b4\uc6a9\uc744 \uadf8\ub300\ub85c \ud655\uc778\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc774 \ubd80\ub2f4\ud558\ub294 \ube44\uc6a9\uc5d0 \uad00\ud55c \uc870\ud56d"],t.s)
