B.a_T=s(["\uac70\ub798\uacc4\uc5d0\uc11c \uc77c\ubc18\uc801\uc774\uace0 \uacf5\ud1b5\ub41c \uac83\uc774\uc5b4\uc11c \uace0\uac1d\uc774 \ubcc4\ub3c4 \uc124\uba85 \uc5c6\uc774\ub3c4 \ucda9\ubd84\ud788 \uc608\uc0c1\ud560 \uc218 \uc788\uc5c8\ub358 \uc0ac\ud56d"],t.s)
