B.ac5=new A.f("gen_al_expl_12","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.W1,1,"\ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\ub294 \ubd88\uacf5\uc815\ud55c \uc57d\uad00 \uc0ac\uc6a9\uc744 \uc608\ubc29\ud558\uae30 \uc704\ud55c \uac83\uc77c \ubfd0, \ud45c\uc900\uc57d\uad00\uc744 \uc0ac\uc6a9\ud55c\ub2e4\uace0 \ud558\uc5ec \uc0ac\uc5c5\uc790\uac00 \uac1c\ubcc4 \uace0\uac1d\uc5d0 \ub300\ud55c \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \uba74\uc81c\ubc1b\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. \ud45c\uc900\uc57d\uad00\uc744 \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\ub3c4 \uc77c\ubc18 \uc0ac\uc5c5\uc790\uc640 \ub9c8\ucc2c\uac00\uc9c0\ub85c \uacc4\uc57d \uccb4\uacb0 \uc2dc \uc57d\uad00\uc744 \uba85\uc2dc\ud558\uace0 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uc124\uba85\ud574\uc57c \ud55c\ub2e4.",B.T1,B.Tf,null)
B.Y6=s(["\ucd5c\ucd08 \uacc4\uc57d \uc2dc \uc124\uba85\ud558\uc600\ub2e4\uba74 \uc774\ud6c4 \uc57d\uad00\uc774 \ubcc0\uacbd\ub418\uc5b4\ub3c4 \ub2e4\uc2dc \uc124\uba85\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4",u.m4,"\uc57d\uad00 \ubcc0\uacbd\uc740 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc758 \uc77c\ubc29\uc801 \uad8c\ud55c\uc774\ubbc0\ub85c \uace0\uac1d\uc5d0\uac8c \uc54c\ub9b4 \ud544\uc694\uac00 \uc5c6\ub2e4","\uc57d\uad00\uc774 \ubcc0\uacbd\ub418\uba74 \uc885\uc804 \uacc4\uc57d\uc740 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\ubcc0\uacbd\ub41c \uc57d\uad00\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc0ac\uc804 \uc2b9\uc778\uc744 \ubc1b\uc73c\uba74 \uc124\uba85 \uc5c6\uc774 \ubc14\ub85c \uc801\uc6a9\ub41c\ub2e4"],t.s)
