B.a8y=new A.f("gen_al_expl_13","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00 \ub0b4\uc6a9\uc774 \ubcc0\uacbd\ub41c \uacbd\uc6b0 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Y6,1,"\uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc774 \ubcc0\uacbd\ub418\uc5b4 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \uc601\ud5a5\uc744 \ubbf8\uce60 \uc218 \uc788\ub294 \uacbd\uc6b0, \uc0ac\uc5c5\uc790\ub294 \ubcc0\uacbd\ub41c \ub0b4\uc6a9\uc5d0 \ub300\ud574\uc11c\ub3c4 \uc6d0\uce59\uc801\uc73c\ub85c \ub2e4\uc2dc \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub97c \uc774\ud589\ud558\uc5ec\uc57c \ud55c\ub2e4. \ucd5c\ucd08 \uacc4\uc57d \uc2dc \uc124\uba85\uc744 \uc774\ud589\ud558\uc600\ub2e4\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uc774\ud6c4\uc758 \ubd88\ub9ac\ud55c \ubcc0\uacbd \uc0ac\ud56d\uae4c\uc9c0 \ub2f9\uc5f0\ud788 \uace0\uac1d\uc5d0\uac8c \ud6a8\ub825\uc774 \ubbf8\uce5c\ub2e4\uace0 \ubcfc \uc218\ub294 \uc5c6\ub2e4.",B.Gt,B.W7,null)
B.Tx=s(["\uc124\uba85\uc758\ubb34\ub97c \uc704\ubc18\ud55c \uc870\ud56d\uc740 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c \ud3b8\uc785\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubb38\uc81c\ub41c \uc870\ud56d\ub9cc \uacc4\uc57d \ub0b4\uc6a9\uc5d0\uc11c \ubc30\uc81c\ub418\uace0 \ub098\uba38\uc9c0 \uc870\ud56d\uc740 \uc720\ud6a8\ud560 \uc218 \uc788\ub2e4","\uc124\uba85\uc758\ubb34\ub97c \uc704\ubc18\ud55c \uc870\ud56d\uc774 \ubc30\uc81c\ub41c \uacb0\uacfc \uacc4\uc57d\uc758 \ubaa9\uc801\uc744 \ub2ec\uc131\ud560 \uc218 \uc5c6\uac8c \ub418\uba74 \uacc4\uc57d \uc804\uccb4\uac00 \ubb34\ud6a8\ub85c \ub420 \uc218 \uc788\ub2e4","\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc740 \ud615\uc0ac\ucc98\ubc8c\uc758 \ub300\uc0c1\uc774 \ub418\ub294 \ubc94\uc8c4\ud589\uc704\uc774\ub2e4","\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc774 \uc788\uc5b4\ub3c4 \uace0\uac1d\uc774 \uadf8 \ub0b4\uc6a9\uc744 \uc2e4\uc81c\ub85c \uc54c\uace0 \uacc4\uc57d\uc744 \uccb4\uacb0\ud588\ub2e4\uba74 \uacb0\ub860\uc774 \ub2ec\ub77c\uc9c8 \uc218 \uc788\ub2e4"],t.s)
B.HS=s(["\uc124\uba85\uc758\ubb34 \uc704\ubc18\uc740 \ud615\uc0ac\ucc98\ubc8c\uc758 \ub300\uc0c1\uc774 \ub418\ub294 \ubc94\uc8c4\ud589\uc704\uc774\ub2e4"],t.s)
