B.ab6=new A.f("gen_ai_def_1","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00\uc758 \uc815\uc758\xb7\uc801\uc6a9\ub300\uc0c1(\uc81c2\uc870)",'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc57d\uad00"\uc758 \uc815\uc758\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a1J,0,'\uc57d\uad00\ubc95\uc0c1 "\uc57d\uad00"\uc740 \uadf8 \uba85\uce6d\uc774\ub098 \ud615\ud0dc, \ubc94\uc704\uc640 \uad00\uacc4\uc5c6\uc774 \uacc4\uc57d\uc758 \ud55c\ucabd \ub2f9\uc0ac\uc790\uac00 \ub2e4\uc218\uc758 \uc0c1\ub300\ubc29\uacfc \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\uae30 \uc704\ud574 \uc77c\uc815\ud55c \ud615\uc2dd\uc73c\ub85c \ubbf8\ub9ac \ub9c8\ub828\ud55c \uacc4\uc57d\ub0b4\uc6a9\uc744 \uc758\ubbf8\ud55c\ub2e4. \uc11c\uba74 \uc5ec\ubd80, \uc0ac\uc5c5\uc790 \uac04 \uacc4\uc57d\uc778\uc9c0 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \uc774\ub7ec\ud55c \uc815\ud615\uc131\xb7\uc0ac\uc804 \ub9c8\ub828\uc131\uc744 \uac16\ucd94\uba74 \uc57d\uad00\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4.',B.ZZ,B.TC,null)
B.LE=s([u.G,"\uac1c\ubcc4\uad50\uc12d \uc5ec\ubd80\uc640 \uad00\uacc4\uc5c6\uc774 \uacc4\uc57d\uc11c\uc5d0 \ud3ec\ud568\ub418\uba74 \ubaa8\ub450 \uc57d\uad00\uc774 \ub41c\ub2e4","\uac1c\ubcc4\uad50\uc12d\ub41c \uc870\ud56d\ub3c4 \ubc18\ub4dc\uc2dc \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \ub300\uc0c1\uc774 \ub41c\ub2e4","\uac1c\ubcc4\uad50\uc12d\ub41c \uc870\ud56d\uc740 \ud56d\uc0c1 \ubb34\ud6a8\ub85c \ucde8\uae09\ub41c\ub2e4","\uac1c\ubcc4\uad50\uc12d \uc5ec\ubd80\ub294 \uc57d\uad00 \ud574\ub2f9\uc131 \ud310\ub2e8\uacfc \ubb34\uad00\ud558\ub2e4"],t.s)
