B.Iq=s([u.kr,"\uc804\uc790\uc801\uc73c\ub85c \ud45c\uc2dc\ub41c \uc57d\uad00\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc57d\uad00\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uc628\ub77c\uc778 \uc774\uc6a9\uc57d\uad00\uc740 \uc0ac\uc5c5\uc790\uac00 \uc6d0\ud558\ub294 \uacbd\uc6b0\uc5d0\ub9cc \uc57d\uad00\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4","\uc628\ub77c\uc778 \uc774\uc6a9\uc57d\uad00\uc740 \ubc18\ub4dc\uc2dc \ubcc4\ub3c4 \ubc95\ub960\ub85c\ub9cc \uaddc\uc728\ub418\uace0 \uc57d\uad00\ubc95\uacfc\ub294 \ubb34\uad00\ud558\ub2e4","\uc774\uc6a9\uc57d\uad00\uc740 \uace0\uac1d\uc774 \ud074\ub9ad\ud558\uc9c0 \uc54a\uc73c\uba74 \uc874\uc7ac \uc790\uccb4\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
