B.J6=s(["\ubc18\ub4dc\uc2dc \uad00\ud560 \ud589\uc815\uccad\uc758 \uc0ac\uc804 \uc778\uac00\ub97c \ubc1b\uc544\uc57c \ud55c\ub2e4","\ub2e4\uc218\uc758 \uc0c1\ub300\ubc29\uc744 \ub300\uc0c1\uc73c\ub85c \ud560 \uac83\uc744 \uc608\uc815\ud558\uace0 \uc788\uc744 \uac83","\uacc4\uc57d\uccb4\uacb0 \uc804\uc5d0 \ubbf8\ub9ac \ub9c8\ub828\ub418\uc5b4 \uc788\uc744 \uac83","\uc77c\uc815\ud55c \ud615\uc2dd\uc73c\ub85c \uc815\ud615\ud654\ub418\uc5b4 \uc788\uc744 \uac83","\ud55c\ucabd \ub2f9\uc0ac\uc790\uac00 \uc774\ub97c \uacc4\uc57d\ub0b4\uc6a9\uc73c\ub85c \uc81c\uc2dc\ud560 \uac83"],t.s)
