B.KI=s([u.ao,"\uc57d\uad00\uc740 \uac1c\ubcc4\uc57d\uc815\ubcf4\ub2e4 \ud56d\uc0c1 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uc740 \ubc18\ub4dc\uc2dc \uc11c\uba74\uc73c\ub85c\ub9cc \uc778\uc815\ub41c\ub2e4","\uac1c\ubcc4\uc57d\uc815\uacfc \uc57d\uad00\uc774 \ub2e4\ub974\uba74 \ud56d\uc0c1 \uc57d\uad00 \ub0b4\uc6a9\ub300\ub85c \uacc4\uc57d\uc774 \uc131\ub9bd\ud55c\ub2e4","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uc740 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc720\ub9ac\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4"],t.s)
