B.a8o=new A.f("gen_ai_special_6","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59(\uc81c4\uc870)","\uac1c\ubcc4\uc57d\uc815 \uc6b0\uc120\uc758 \uc6d0\uce59\uacfc \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Qd,0,"\uc57d\uad00\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\ub294 \uc0ac\uc5c5\uc790\uac00 \uc77c\ubc29\uc801\uc73c\ub85c \ub9c8\ub828\ud55c \uc815\ud615\uc801 \uc57d\uad00\uc870\ud56d\uc744 \uace0\uac1d\uc774 \uc778\uc9c0\ud558\uc9c0 \ubabb\ud55c \ucc44 \uacc4\uc57d\ub0b4\uc6a9\uc774 \ub418\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc778 \ubc18\uba74, \uac1c\ubcc4\uc57d\uc815\uc740 \ub2f9\uc0ac\uc790 \uac04 \uc2e4\uc9c8\uc801 \uad50\uc12d\uc744 \uac70\uccd0 \uc131\ub9bd\ud558\ub294 \uac83\uc774\ubbc0\ub85c \ud1b5\uc0c1\uc801\uc778 \uc57d\uad00\uc5d0 \ub300\ud55c \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34 \ubc95\ub9ac\uac00 \uadf8\ub300\ub85c \uc801\uc6a9\ub418\ub294 \uc870\ud56d\uacfc\ub294 \uc131\uaca9\uc744 \ub2ec\ub9ac\ud55c\ub2e4\uace0 \uc774\ud574\ub41c\ub2e4.",B.ZO,B.Ls,null)
B.a1h=s([u.l7,"\uc57d\uad00\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c\ub9cc \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc57d\uad00\uc740 \uac01 \uace0\uac1d\uc758 \uac1c\ubcc4 \uc0ac\uc815\uc5d0 \ub530\ub77c \uc11c\ub85c \ub2e4\ub974\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc57d\uad00 \ud574\uc11d\uc740 \ubc95\uc6d0\uc758 \uc7ac\ub7c9\uacfc \uc804\ud600 \ubb34\uad00\ud558\uac8c \uc0ac\uc5c5\uc790\uac00 \uc815\ud55c \ub300\ub85c\ub9cc \uc774\ub8e8\uc5b4\uc9c4\ub2e4","\uc57d\uad00\uc740 \ud574\uc11d\uc758 \uc5ec\uc9c0 \uc5c6\uc774 \ubb38\uc5b8 \uadf8\ub300\ub85c\ub9cc \uae30\uacc4\uc801\uc73c\ub85c \uc801\uc6a9\ub41c\ub2e4"],t.s)
