B.acv=new A.f("gen_ai_good_1","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c5\uc870 \uc81c1\ud56d\uc774 \uc815\ud558\ub294 \uc57d\uad00 \ud574\uc11d\uc758 \uc6d0\uce59\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a1h,0,"\uc57d\uad00\ubc95 \uc81c5\uc870 \uc81c1\ud56d\uc740 \uc57d\uad00\uc740 \uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc5d0 \ub530\ub77c \uacf5\uc815\ud558\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud558\uba70, \uace0\uac1d\uc5d0 \ub530\ub77c \ub2e4\ub974\uac8c \ud574\uc11d\ub418\uc5b4\uc11c\ub294 \uc548 \ub41c\ub2e4\ub294 \uc6d0\uce59\uc744 \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \ub2e4\uc218\uc758 \uace0\uac1d\uc5d0\uac8c \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub418\ub294 \uc57d\uad00\uc758 \ud2b9\uc131\uc0c1 \ud1b5\uc77c\uc801\uc774\uace0 \uac1d\uad00\uc801\uc778 \ud574\uc11d\uc774 \uc774\ub8e8\uc5b4\uc838\uc57c \ud55c\ub2e4\ub294 \ucde8\uc9c0\uc774\ub2e4.",B.a0x,B.N4,null)
B.HO=s([u.nn,"\ud1b5\uc77c\uc801 \ud574\uc11d\uc740 \uc0ac\uc5c5\uc790\uc758 \ud3b8\uc758\ub9cc\uc744 \uc704\ud55c \uac83\uc774\ub2e4","\ud1b5\uc77c\uc801 \ud574\uc11d\uc740 \uc624\uc9c1 \ubc95\uc6d0\uc758 \uc5c5\ubb34 \ubd80\ub2f4\uc744 \uc904\uc774\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\ud1b5\uc77c\uc801 \ud574\uc11d\uc740 \uc57d\uad00\ubc95\uacfc \ubb34\uad00\ud55c \uc808\ucc28\ubc95\uc0c1 \uc6d0\uce59\uc774\ub2e4","\ud1b5\uc77c\uc801 \ud574\uc11d\uc740 \uace0\uac1d\uc758 \uac1c\ubcc4 \uc0ac\uc815\uc744 \ucd5c\uc6b0\uc120\uc73c\ub85c \ubc18\uc601\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4"],t.s)
