B.Vq=s(["\ud1b5\uc77c\uc801 \ud574\uc11d\uc758 \ud544\uc694\uc131"],t.s)
B.abN=new A.f("gen_ai_good_2","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)",'\uc57d\uad00\uc758 "\ud1b5\uc77c\uc801 \ud574\uc11d"\uc774 \uc694\uad6c\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.HO,0,"\uc57d\uad00\uc740 \ub2e4\uc218\uc758 \uace0\uac1d\uc5d0\uac8c \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub418\ub294 \uac83\uc744 \uc804\uc81c\ub85c \ud558\ubbc0\ub85c, \ub3d9\uc77c\ud55c \uc870\ud56d\uc774 \uace0\uac1d\ub9c8\ub2e4 \ub2e4\ub974\uac8c \ud574\uc11d\ub41c\ub2e4\uba74 \ubc95\uc801 \uc548\uc815\uc131\uacfc \uace0\uac1d \uac04 \ud615\ud3c9\uc131\uc774 \ud06c\uac8c \uc800\ud574\ub420 \uc218 \uc788\ub2e4. \uc774 \ub54c\ubb38\uc5d0 \uc57d\uad00\ubc95\uc740 \uac1c\ubcc4 \uace0\uac1d\uc758 \uc8fc\uad00\uc801 \uc0ac\uc815\uc5d0 \uc88c\uc6b0\ub418\uc9c0 \uc54a\ub294 \uac1d\uad00\uc801\xb7\ud1b5\uc77c\uc801 \ud574\uc11d\uc744 \uc694\uad6c\ud55c\ub2e4.",B.ZF,B.Vq,null)
B.XK=s([u.dj,"\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uc758\ubb34\uc774\ub2e4","\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc740 \uc57d\uad00 \ud574\uc11d\uacfc \ubb34\uad00\ud55c \ud615\ubc95\uc0c1 \uac1c\ub150\uc774\ub2e4","\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc740 \uace0\uac1d\uc758 \uc8fc\uc7a5\uc744 \ud56d\uc0c1 \uadf8\ub300\ub85c \uc778\uc815\ud574\uc57c \ud55c\ub2e4\ub294 \uc758\ubbf8\uc774\ub2e4","\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc740 \uacc4\uc57d\uc11c\uc5d0 \uba85\uc2dc\ub418\uc5b4\uc57c\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.K6=s([u.dj],t.s)
B.Uc=s(["\uc2e0\uc758\uc131\uc2e4 \uc6d0\uce59\uc758 \uc758\ubbf8"],t.s)
B.a93=new A.f("gen_ai_good_3","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)",'\uc57d\uad00 \ud574\uc11d \uc2dc "\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59"\uc774 \uc758\ubbf8\ud558\ub294 \ubc14\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.XK,0,"\uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc740 \uacc4\uc57d \ub2f9\uc0ac\uc790\uac00 \uc0c1\ub300\ubc29\uc758 \uc815\ub2f9\ud55c \uc774\uc775\uc744 \uace0\ub824\ud558\uc5ec \ud615\ud3c9\uc5d0 \ub9de\uac8c \ud589\ub3d9\ud574\uc57c \ud55c\ub2e4\ub294 \ubbfc\ubc95\uc758 \uc77c\ubc18\uc6d0\uce59\uc73c\ub85c, \uc57d\uad00 \ud574\uc11d\uc5d0\uc11c\ub3c4 \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc5b4\ub290 \uc77c\ubc29\uc758 \uc774\uc775\uc5d0 \uce58\uc6b0\uce58\uc9c0 \uc54a\uace0 \uc30d\ubc29\uc758 \uc774\uc775\uc744 \uacf5\uc815\ud558\uac8c \ud615\ub7c9\ud558\uc5ec \ud574\uc11d\ud574\uc57c \ud55c\ub2e4\ub294 \uc758\ubbf8\ub85c \uc801\uc6a9\ub41c\ub2e4.",B.K6,B.Uc,null)
B.UD=s([u.aT,"\ud574\uc11d\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \uc8fc\uad00\uc801 \uc758\ub3c4\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud55c\ub2e4","\ud574\uc11d\uc740 \uc624\uc9c1 \uac00\uc7a5 \uc9c0\uc2dd\uc774 \ub9ce\uc740 \uc804\ubb38\uac00 \uace0\uac1d\uc758 \uad00\uc810\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud55c\ub2e4","\ud574\uc11d\uc740 \ub9e4\ubc88 \uac1c\ubcc4 \uace0\uac1d\uc758 \uc774\ud574\uc218\uc900\uc5d0 \ub9de\ucd94\uc5b4 \ub2ec\ub77c\uc9c4\ub2e4","\ubd88\uba85\ud655\ud55c \uc870\ud56d\uc740 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub41c\ub2e4"],t.s)
