B.a_w=s(["\ud3c9\uade0\uc801 \uace0\uac1d \uae30\uc900 \ud574\uc11d"],t.s)
B.ac3=new A.f("gen_ai_good_4","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)","\uc57d\uad00 \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \ubd88\uba85\ud655\ud55c \uacbd\uc6b0 \ud574\uc11d \ubc29\ubc95\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.UD,0,"\uc57d\uad00 \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \ubd88\uba85\ud655\ud55c \uacbd\uc6b0\uc5d0\ub294 \ud2b9\uc815 \uac1c\uc778\uc774 \uc544\ub2c8\ub77c \ud3c9\uade0\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 \uace0\uac1d\uc774 \uadf8 \uc870\ud56d\uc744 \uc5b4\ub5bb\uac8c \uc774\ud574\ud560 \uac83\uc778\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \uac1d\uad00\uc801\uc774\uace0 \ud1b5\uc77c\uc801\uc73c\ub85c \ud574\uc11d\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774\ub294 \ub2e4\uc218\uc758 \uace0\uac1d\uc5d0\uac8c \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub418\ub294 \uc57d\uad00\uc758 \uc131\uaca9\uc5d0 \ubd80\ud569\ud558\ub294 \ud574\uc11d\ubc29\ubc95\uc774\ub2e4.",B.Pq,B.a_w,null)
B.Jf=s([u.ml,"\uc774\ub7ec\ud55c \uac00\ub2a5\uc131\uc740 \ud1b5\uc77c\uc801 \ud574\uc11d \uc6d0\uce59\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ubc95\uc6d0\uc740 \ub3d9\uc77c \uc870\ud56d\uc5d0 \ub300\ud574 \ud56d\uc0c1 \uae30\uacc4\uc801\uc73c\ub85c \ub3d9\uc77c\ud55c \uacb0\ub860\ub9cc \ub0b4\ub824\uc57c \ud558\uba70 \uc0ac\uc2e4\uad00\uacc4\ub294 \uc804\ud600 \uace0\ub824\ud558\uc9c0 \uc54a\ub294\ub2e4","\ud1b5\uc77c\uc801 \ud574\uc11d \uc6d0\uce59\uc774 \uc788\uc73c\ubbc0\ub85c \ubc95\uc6d0\uc758 \ud310\ub2e8\uc740 \uc808\ub300\ub85c \ub2ec\ub77c\uc9c8 \uc218 \uc5c6\ub2e4","\uc774 \ubb38\uc81c\ub294 \uc57d\uad00\ubc95\uacfc \ubb34\uad00\ud55c \uc18c\uc1a1\ubc95\uc0c1 \ubb38\uc81c\uc77c \ubfd0\uc774\ub2e4"],t.s)
B.a2t=s([u.ml],t.s)
B.Ti=s(["\ud1b5\uc77c\uc801 \ud574\uc11d\uacfc \uac1c\ubcc4 \uc0ac\uc548\uc758 \uad00\uacc4"],t.s)
B.acH=new A.f("gen_ai_good_5","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)","\ub3d9\uc77c\ud55c \uc57d\uad00 \uc870\ud56d\uc5d0 \ub300\ud574 \uc11c\ub85c \ub2e4\ub978 \uc18c\uc1a1\uc5d0\uc11c \ubc95\uc6d0\uc774 \ub2e4\ub974\uac8c \ud310\ub2e8\ud560 \uac00\ub2a5\uc131\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Jf,0,'\ud1b5\uc77c\uc801 \ud574\uc11d\uc758 \uc6d0\uce59\uc740 \ub3d9\uc77c\ud55c \uc57d\uad00 \uc870\ud56d\uc758 "\uc758\ubbf8" \uc790\uccb4\ub97c \uace0\uac1d\uc5d0 \ub530\ub77c \uc790\uc758\uc801\uc73c\ub85c \ub2ec\ub9ac \ud574\uc11d\ud574\uc11c\ub294 \uc548 \ub41c\ub2e4\ub294 \uac83\uc774\uc9c0, \uad6c\uccb4\uc801 \uc0ac\uac74\ub9c8\ub2e4 \ub2e4\ub978 \uc0ac\uc2e4\uad00\uacc4(\uacc4\uc57d\uacbd\uc704, \ud2b9\uc57d \uc874\ubd80 \ub4f1)\uae4c\uc9c0 \uc644\uc804\ud788 \ubb34\uc2dc\ud558\uace0 \ud56d\uc0c1 \ub3d9\uc77c\ud55c \uacb0\ub860\uc744 \ub0b4\ub824\uc57c \ud55c\ub2e4\ub294 \uc758\ubbf8\ub294 \uc544\ub2c8\ub2e4. \ub2e4\ub9cc \uc870\ud56d\uc758 \ud574\uc11d \uc790\uccb4\uac00 \uc0ac\uc548\ub9c8\ub2e4 \ub2ec\ub77c\uc9c0\ub294 \uac83\uc740 \ud1b5\uc77c\uc801 \ud574\uc11d\uc758 \ucde8\uc9c0\uc5d0 \ube44\ucd94\uc5b4 \ubc14\ub78c\uc9c1\ud558\uc9c0 \uc54a\ub2e4.',B.a2t,B.Ti,null)
B.HY=s([u.gO,"\uc81c5\uc870\uc640 \uc81c6\uc870~\uc81c14\uc870\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \uc911\ubcf5 \uaddc\uc815\ud55c \uac83\uc774\ub2e4","\uc81c5\uc870\uac00 \uc801\uc6a9\ub418\uba74 \uc81c6\uc870~\uc81c14\uc870\ub294 \uc801\uc6a9\ub420 \uc5ec\uc9c0\uac00 \uc5c6\ub2e4","\uc81c6\uc870~\uc81c14\uc870\uac00 \uc801\uc6a9\ub418\uba74 \uc81c5\uc870\ub294 \uc804\ufffd\ud5a5 \ubd88\ud544\uc694\ud558\ub2e4","\ub450 \uaddc\uc815\uc740 \uc11c\ub85c \uc804\ud600 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \ubc95\ub960\uc5d0 \uc18d\ud55c\ub2e4"],t.s)
B.Ly=s([u.gO],t.s)
B.V6=s(["\ud574\uc11d\uaddc\uc815\uacfc \ubb34\ud6a8\uaddc\uc815\uc758 \uad00\uacc4"],t.s)
B.a94=new A.f("gen_ai_good_6","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc2e0\uc758\uc131\uc2e4 \ud574\uc11d\xb7\ud1b5\uc77c\uc801 \ud574\uc11d(\uc81c5\uc870 \uc81c1\ud56d)","\uc57d\uad00 \ud574\uc11d\uc5d0 \uad00\ud55c \uc81c5\uc870 \uc81c1\ud56d\uacfc \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720(\uc81c6\uc870~\uc81c14\uc870)\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.HY,0,'\uc81c5\uc870\ub294 \uc57d\uad00 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \uc5b4\ub5bb\uac8c "\ud574\uc11d"\ud560 \uac83\uc778\uc9c0\uc5d0 \uad00\ud55c \ubc29\ubc95\ub860\uc744 \uaddc\uc815\ud558\ub294 \ubc18\uba74, \uc81c6\uc870\ubd80\ud130 \uc81c14\uc870\uae4c\uc9c0\ub294 \ud574\uc11d\uc744 \uac70\uccd0 \ud655\uc815\ub41c \uc57d\uad00 \uc870\ud56d\uc758 "\ub0b4\uc6a9" \uc790\uccb4\uac00 \ubd88\uacf5\uc815\ud558\uc5ec \ubb34\ud6a8\uc778\uc9c0\ub97c \ud310\ub2e8\ud558\ub294 \uaddc\uc815\uc774\ub2e4. \uc2e4\ubb34\uc0c1 \uba3c\uc800 \ud574\uc11d\uc744 \ud1b5\ud574 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \ud655\uc815\ud55c \ub4a4, \uadf8 \ub0b4\uc6a9\uc774 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0\ub97c \uac80\ud1a0\ud558\ub294 \uc21c\uc11c\ub85c \ub450 \uaddc\uc815\uc774 \ud568\uaed8 \uc791\ub3d9\ud55c\ub2e4.',B.Ly,B.V6,null)
B.Tc=s(["\uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0\uc5d0\ub294 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc54a\uc73c\uba74 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub41c\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \uc801\uc6a9\ub41c\ub2e4","\uc774 \uc6d0\uce59\uc740 \uace0\uac1d\uc774 \uc0ac\uc5c5\uc790\uc778 \uacbd\uc6b0\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc0ac\uc5c5\uc790\uac00 \uc791\uc131\ud55c \ubaa8\ub4e0 \ubb38\uc11c\uc5d0 \uc608\uc678 \uc5c6\uc774 \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.a0o=s(["\uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0\uc5d0\ub294 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4"],t.s)
B.HI=s(["\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59"],t.s)
B.a7H=new A.f("gen_ai_contra_1","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)",'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c5\uc870 \uc81c2\ud56d\uc774 \uc815\ud558\ub294 "\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.Tc,0,'\uc57d\uad00\ubc95 \uc81c5\uc870 \uc81c2\ud56d\uc740 \uc57d\uad00\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc54a\uc740 \uacbd\uc6b0\uc5d0\ub294 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ub418\uc5b4\uc57c \ud55c\ub2e4\ub294 \uc774\ub978\ubc14 "\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59"(contra proferentem)\uc744 \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uc57d\uad00\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uc791\uc131\ud55c \uc0ac\uc5c5\uc790\uac00 \uadf8 \ubd88\uba85\ud655\uc131\uc5d0 \ub530\ub978 \uc704\ud5d8\uc744 \ubd80\ub2f4\ud558\ub3c4\ub85d \ud558\ub824\ub294 \ucde8\uc9c0\uc774\uba70, \uc57d\uad00\uc758 \uc758\ubbf8\uac00 \uba85\ubc31\ud55c \uacbd\uc6b0\uc5d0\ub294 \ubcc4\ub3c4\ub85c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.a0o,B.HI,null)
B.Hv=s([u.ii,"\uc870\ud56d\uc758 \uc758\ubbf8\uac00 \uba85\ubc31\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \uc6b0\uc120 \uc801\uc6a9\ub41c\ub2e4","\uace0\uac1d\uc774 \uc0ac\uc5c5\uc790\ubcf4\ub2e4 \uc6b0\uc6d4\ud55c \uc9c0\uc704\uc5d0 \uc788\ub294 \uacbd\uc6b0\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uacc4\uc57d\uae08\uc561\uc774 \uc77c\uc815 \uaddc\ubaa8 \uc774\uc0c1\uc778 \uacbd\uc6b0\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 \ubcc4\ub3c4\uc758 \uc804\uc81c \uc5c6\uc774 \ubaa8\ub4e0 \uc57d\uad00 \ubd84\uc7c1\uc5d0 \uc790\ub3d9 \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.MK=s([u.ii],t.s)
B.Te=s(["\uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uc801\uc6a9\uc804\uc81c"],t.s)
B.a6L=new A.f("gen_ai_contra_2","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\uae30 \uc704\ud55c \uc804\uc81c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Hv,0,'\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 \uc5b4\ub514\uae4c\uc9c0\ub098 "\ubcf4\ucda9\uc801" \ud574\uc11d\uc6d0\uce59\uc73c\ub85c, \ubb38\uc5b8\xb7\ubaa9\uc801\xb7\uccb4\uacc4 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud55c \ud1b5\uc0c1\uc801\uc778 \ud574\uc11d\ubc29\ubc95\uc744 \ub2e4 \ub3d9\uc6d0\ud574\ub3c4 \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \uba85\ubc31\ud788 \ud655\uc815\ub418\uc9c0 \uc54a\ub294 \uacbd\uc6b0\uc5d0 \ube44\ub85c\uc18c \uc801\uc6a9\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \ud1b5\uc0c1\uc758 \ud574\uc11d\ubc29\ubc95\uc73c\ub85c \uba85\ubc31\ud788 \ud655\uc815\ub41c\ub2e4\uba74 \uc774 \uc6d0\uce59\uc774 \uac1c\uc785\ud560 \uc5ec\uc9c0\ub294 \uc5c6\ub2e4.',B.MK,B.Te,null)
B.LP=s([u.iP,"\uace0\uac1d\uc774 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\ubcf4\ub2e4 \ubc95\ub960\uc9c0\uc2dd\uc774 \ubd80\uc871\ud558\uae30 \ub54c\ubb38\uc5d0 \ubb34\uc870\uac74 \uace0\uac1d\uc774 \uc774\uae34\ub2e4\ub294 \ucde8\uc9c0\uc774\ub2e4","\uc774 \uc6d0\uce59\uc740 \uc0ac\uc5c5\uc790\uc758 \uc774\uc775\uc744 \uc6b0\uc120 \ubcf4\ud638\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc774 \uc6d0\uce59\uc740 \ubc95\uc6d0\uc758 \uc5c5\ubb34 \ubd80\ub2f4\uc744 \uc904\uc774\uae30 \uc704\ud55c \uc784\uc758\uc801 \uad00\ud589\uc5d0 \ubd88\uacfc\ud558\ub2e4","\uc774 \uc6d0\uce59\uc740 \uad6d\uc81c\uc870\uc57d\uc5d0 \ub530\ub77c \uac15\uc81c\ub41c \uac83\uc77c \ubfd0 \uc815\ucc45\uc801 \uadfc\uac70\uac00 \uc5c6\ub2e4"],t.s)
B.a1l=s([u.iP],t.s)
B.Sa=s(["\uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uadfc\uac70"],t.s)
B.a8G=new A.f("gen_ai_contra_3","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc758 \uc815\ucc45\uc801 \uadfc\uac70\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.LP,0,"\uc57d\uad00\uc740 \uc0ac\uc5c5\uc790\uac00 \uc77c\ubc29\uc801\uc73c\ub85c \ub9c8\ub828\ud558\uc5ec \uace0\uac1d\uc5d0\uac8c \uc81c\uc2dc\ud558\ub294 \uac83\uc774\ubbc0\ub85c, \uadf8 \ubb38\uc5b8\uc774 \ubd88\uba85\ud655\ud558\uac8c \uc791\uc131\ub41c \ub370 \ub530\ub978 \uc704\ud5d8\uacfc \ubd88\uc774\uc775\uc740 \uc774\ub97c \uc791\uc131\ud55c \uc0ac\uc5c5\uc790\uac00 \ubd80\ub2f4\ud558\ub294 \uac83\uc774 \ud615\ud3c9\uc5d0 \ubd80\ud569\ud55c\ub2e4\ub294 \uc815\ucc45\uc801 \uace0\ub824\uac00 \uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uadfc\uac70\uc774\ub2e4.",B.a1l,B.Sa,null)
B.Y2=s([u.fk,"\ubcf4\ud5d8\uc57d\uad00\uc740 \uc560\ucd08\uc5d0 \uc57d\uad00\ubc95\uc758 \uc801\uc6a9\ub300\uc0c1\uc774 \uc544\ub2c8\uae30 \ub54c\ubb38\uc774\ub2e4","\ubcf4\ud5d8\uc57d\uad00\uc740 \ud56d\uc0c1 \uba85\ud655\ud558\uac8c \uc791\uc131\ub418\uc5b4 \uc774 \uc6d0\uce59\uc774 \uc801\uc6a9\ub420 \uc77c\uc774 \uc5c6\uae30 \ub54c\ubb38\uc774\ub2e4","\ubcf4\ud5d8\uacc4\uc57d\uc790\ub294 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc758 \uc9c0\uc704\uc5d0 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4","\ubcf4\ud5d8\uc57d\uad00\uc5d0\ub294 \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \ubc95\ub960\uc0c1 \uba85\uc2dc\uc801\uc73c\ub85c \ubc30\uc81c\ub418\uc5b4 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.a2n=s([u.fk],t.s)
B.RP=s(["\uc791\uc131\uc790\ubd88\uc774\uc775 \uc6d0\uce59\uc758 \uc2e4\ubb34\uc0c1 \uc801\uc6a9\ub840"],t.s)
B.a91=new A.f("gen_ai_contra_4","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\ubcf4\ud5d8\uc57d\uad00\uacfc \uac19\uc774 \uc804\ubb38\uc801\uc774\uace0 \ubcf5\uc7a1\ud55c \uc57d\uad00\uc5d0\uc11c \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \ud2b9\ud788 \uc790\uc8fc \ubb38\uc81c\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Y2,0,"\ubcf4\ud5d8\uc57d\uad00\uc740 \ubcf4\uc7a5\ubc94\uc704\xb7\uba74\ucc45\uc0ac\uc720 \ub4f1\uc744 \uc815\ud558\ub294 \uc804\ubb38\uc801\uc774\uace0 \ubcf5\uc7a1\ud55c \uc870\ud56d\uc774 \ub9ce\uc544, \ubb38\uc5b8\uc758 \ub2e4\uc758\uc801 \ud574\uc11d \uac00\ub2a5\uc131\uc774 \uc0c1\ub300\uc801\uc73c\ub85c \ud06c\uac8c \ub098\ud0c0\ub098\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4. \uc774 \ub54c\ubb38\uc5d0 \uc2e4\ubb34\uc0c1 \ubcf4\ud5d8\uc57d\uad00 \uad00\ub828 \ubd84\uc7c1\uc5d0\uc11c \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc790\uc8fc \ubb38\uc81c\ub418\uace0 \ud65c\uc6a9\ub41c\ub2e4.",B.a2n,B.RP,null)
B.HA=s(['\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\ufffd\uce59\uc740 "\ud574\uc11d"\uc758 \ubb38\uc81c\uc774\uace0, \ubb34\ud6a8 \ubc95\ub9ac\ub294 \ud574\uc11d\uc744 \uac70\uccd0 \ud655\uc815\ub41c \uc870\ud56d "\ub0b4\uc6a9"\uc758 \ud6a8\ub825 \ubb38\uc81c\ub85c \uc11c\ub85c \ub2e8\uacc4\uac00 \ub2e4\ub974\ub2e4',"\ub450 \ubc95\ub9ac\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uc5ec \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\uba74 \uadf8 \uc870\ud56d\uc740 \ud56d\uc0c1 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\ubb34\ud6a8 \ubc95\ub9ac\uac00 \uc801\uc6a9\ub418\uba74 \ud574\uc11d\uc758 \ubb38\uc81c\ub294 \uc544\uc608 \ubc1c\uc0dd\ud558\uc9c0 \uc54a\ub294\ub2e4","\ub450 \ubc95\ub9ac\ub294 \uc11c\ub85c \uc591\ub9bd\ud560 \uc218 \uc5c6\ub294 \ubaa8\uc21c \uad00\uacc4\uc5d0 \uc788\ub2e4"],t.s)
B.W5=s(['\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 "\ud574\uc11d"\uc758 \ubb38\uc81c\uc774\uace0, \ubb34\ud6a8 \ubc95\ub9ac\ub294 \ud574\uc11d\uc744 \uac70\uccd0 \ud655\uc815\ub41c \uc870\ud56d "\ub0b4\uc6a9"\uc758 \ud6a8\ub825 \ubb38\uc81c\ub85c \uc11c\ub85c \ub2e8\uacc4\uac00 \ub2e4\ub974\ub2e4'],t.s)
B.Kp=s(["\ud574\uc11d\uacfc \ubb34\ud6a8\ud310\ub2e8\uc758 \ub2e8\uacc4 \uad6c\ubd84"],t.s)
B.ab1=new A.f("gen_ai_contra_5","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59(\uc81c5\uc870 \uc81c2\ud56d)","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uacfc \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8 \ubc95\ub9ac\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.HA,0,'\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc740 \uc870\ud56d\uc758 \ub73b\uc774 \uba85\ubc31\ud558\uc9c0 \uc54a\uc744 \ub54c "\uc5b4\ub5bb\uac8c \ud574\uc11d\ud560 \uac83\uc778\uac00"\uc758 \ubb38\uc81c\uc778 \ubc18\uba74, \ubb34\ud6a8 \ubc95\ub9ac(\uc81c6\uc870~\uc81c14\uc870)\ub294 \ud574\uc11d\uc744 \ud1b5\ud574 \ud655\uc815\ub41c \uc870\ud56d\uc758 "\ub0b4\uc6a9" \uc790\uccb4\uac00 \ubd88\uacf5\uc815\ud558\uc5ec \ud6a8\ub825\uc744 \uc778\uc815\ud560 \uc218 \uc5c6\ub294\uc9c0\uc758 \ubb38\uc81c\uc774\ub2e4. \ub450 \ubc95\ub9ac\ub294 \uc21c\ucc28\uc801\uc73c\ub85c \uac80\ud1a0\ub420 \uc218 \uc788\ub294 \uc11c\ub85c \ub2e4\ub978 \ub2e8\uacc4\uc758 \uc7c1\uc810\uc774\ub2e4.',B.W5,B.Kp,null)
B.He=s([u.oc,"\uc774\ub7ec\ud55c \uacb0\uacfc\ub294 \ud56d\uc0c1 \ubd80\ub2f9\ud558\ubbc0\ub85c \ubc95\uc6d0\uc774 \ubc18\ub4dc\uc2dc \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \uc7ac\ud574\uc11d\ud574\uc57c \ud55c\ub2e4","\uc774 \uacbd\uc6b0 \uacc4\uc57d \uc790\uccb4\uac00 \ucc98\uc74c\ubd80\ud130 \ubb34\ud6a8\uac00 \ub41c\ub2e4","\uc774 \uacbd\uc6b0 \uace0\uac1d\uc774 \uc624\ud788\ub824 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc744 \uc9c4\ub2e4","\uc774 \uc6d0\uce59\uc774 \uc801\uc6a9\ub41c \uacb0\uacfc\ub294 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \ub2e4\ub8e8\uc5b4\uc9c4\ub2e4"],t.s)
