B.abX=new A.f("gen_ai_case_1","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00 \ud574\uc11d \uc885\ud569\xb7\uc0ac\ub840",'\ubcf4\ud5d8\uc57d\uad00\uc0c1 \uba74\ucc45\uc870\ud56d\uc758 \ubb38\uc5b8\uc774 "\ucc9c\uc7ac\uc9c0\ubcc0\uc73c\ub85c \uc778\ud55c \uc190\ud574"\ub77c\uace0\ub9cc \ub418\uc5b4 \uc788\uc5b4 \ud2b9\uc815 \uc790\uc5f0\uc7ac\ud574\uac00 \uc774\uc5d0 \ud3ec\ud568\ub418\ub294\uc9c0 \ub2e4\ud22c\uc5b4\uc9c0\ub294 \uacbd\uc6b0, \ud574\uc11d \ubc29\ubc95\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.Os,0,"\uc57d\uad00 \uc870\ud56d\uc758 \ud574\uc11d\uc740 \uc6b0\uc120 \ubb38\uc5b8\xb7\ubaa9\uc801\xb7\uccb4\uacc4 \ub4f1\uc744 \uace0\ub824\ud55c \ud1b5\uc0c1\uc758 \ud574\uc11d\ubc29\ubc95\uacfc \uc2e0\uc758\uc131\uc2e4\uc758 \uc6d0\uce59\uc5d0 \ub530\ub77c \uacf5\uc815\ud558\uace0 \ud1b5\uc77c\uc801\uc73c\ub85c \uc774\ub8e8\uc5b4\uc838\uc57c \ud558\uba70, \uadf8\ub7fc\uc5d0\ub3c4 \uc870\ud56d\uc758 \uc758\ubbf8\uac00 \uba85\ubc31\ud788 \ud655\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4\uba74 \ubcf4\ucda9\uc801\uc73c\ub85c \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc5d0 \ub530\ub77c \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ud574\uc11d\ud558\ub294 \uc21c\uc11c\ub85c \uc811\uadfc\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4.",B.Pw,B.JE,null)
B.UQ=s([u.ax,"\uac01 \uace0\uac1d\uc774 \uc6d0\ud558\ub294 \ud574\uc11d\uc744 \uadf8\ub300\ub85c \uc778\uc815\ud574\uc57c \ud55c\ub2e4","\uba3c\uc800 \uc18c\ub97c \uc81c\uae30\ud55c \uace0\uac1d\uc758 \ud574\uc11d\uc774 \ud56d\uc0c1 \uc6b0\uc120\ud55c\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uc81c\uc2dc\ud558\ub294 \ud574\uc11d\uc774 \ud56d\uc0c1 \ucd5c\uc885\uc801\uc73c\ub85c \uc778\uc815\ub41c\ub2e4","\uc774 \uacbd\uc6b0 \uc57d\uad00 \uc790\uccb4\uac00 \uc790\ub3d9\uc73c\ub85c \uc804\ubd80 \ubb34\ud6a8\uac00 \ub41c\ub2e4"],t.s)
