B.a7Y=new A.f("gen_ai_case_2","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00 \ud574\uc11d \uc885\ud569\xb7\uc0ac\ub840","\ub3d9\uc77c\ud55c \uc774\ub3d9\ud1b5\uc2e0 \uc11c\ube44\uc2a4 \uc57d\uad00 \uc870\ud56d\uc5d0 \ub300\ud574 \uc11c\ub85c \ub2e4\ub978 \uace0\uac1d\uc774 \uc0c1\ubc18\ub41c \ud574\uc11d\uc744 \uc8fc\uc7a5\ud558\ub294 \uacbd\uc6b0, \uc57d\uad00 \ud574\uc11d\uc758 \uc811\uadfc \ubc29\ubc95\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.UQ,0,"\uc57d\uad00\uc740 \ub2e4\uc218\uc758 \uace0\uac1d\uc5d0\uac8c \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub418\ub294 \uac83\uc744 \uc804\uc81c\ub85c \ud558\ubbc0\ub85c, \ud2b9\uc815 \uace0\uac1d\uc758 \uc8fc\uad00\uc801 \uc0ac\uc815\uc774\ub098 \uc120\ud638\uac00 \uc544\ub2c8\ub77c \ud3c9\uade0\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 \uace0\uac1d\uc744 \uae30\uc900\uc73c\ub85c \ud55c \uac1d\uad00\uc801\xb7\ud1b5\uc77c\uc801 \ud574\uc11d\uc744 \uc2dc\ub3c4\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774\ub294 \uc57d\uad00 \ud574\uc11d\uc5d0\uc11c \uc77c\uad00\ub418\uac8c \uac15\uc870\ub418\ub294 \uc811\uadfc\ubc29\ubc95\uc774\ub2e4.",B.OC,B.XF,null)
B.JN=s([u.bD,"\ubb38\uc5b8\uc774 \uba85\ud655\ud558\uba74 \uadf8 \uacb0\uacfc\uac00 \uc544\ubb34\ub9ac \uac00\ud639\ud574\ub3c4 \uc5b4\ub5a0\ud55c \ud1b5\uc81c\ub3c4 \ubc1b\uc9c0 \uc54a\ub294\ub2e4","\ubb38\uc5b8\uc774 \uba85\ud655\ud558\uba74 \ud56d\uc0c1 \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc774 \uc801\uc6a9\ub418\uc5b4 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud558\uac8c \ub4a4\uc9d1\ud78c\ub2e4","\uc774 \uacbd\uc6b0 \uacc4\uc57d \uc790\uccb4\uac00 \uc790\ub3d9\uc73c\ub85c \ud574\uc81c\ub41c\ub2e4","\uc774 \uacbd\uc6b0 \uace0\uac1d\uc740 \uc5b4\ub5a0\ud55c \uad6c\uc81c\uc218\ub2e8\ub3c4 \uac00\uc9c8 \uc218 \uc5c6\ub2e4"],t.s)
