B.abB=new A.f("gen_ai_case_4","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00 \ud574\uc11d \uc885\ud569\xb7\uc0ac\ub840","\uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uacfc \ubcc4\ub3c4\ub85c \ud648\ud398\uc774\uc9c0\uc5d0 \uac8c\uc2dc\ud55c \uc548\ub0b4\ubb38\uad6c\uac00 \uc57d\uad00 \ud574\uc11d\uc5d0 \ucc38\uace0\ub420 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Jb,0,"\uc57d\uad00 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \ud655\uc815\ud560 \ub54c\ub294 \uacc4\uc57d \uccb4\uacb0\uc758 \uacbd\uc704, \uac70\ub798\uad00\ud589, \uad00\ub828\ud558\uc5ec \uc0ac\uc5c5\uc790\uac00 \uace0\uac1d\uc5d0\uac8c \uc81c\uacf5\ud55c \uc548\ub0b4\uc790\ub8cc \ub4f1 \uc5ec\ub7ec \uc0ac\uc815\uc774 \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4. \ud648\ud398\uc774\uc9c0 \uc548\ub0b4\ubb38\uad6c\uac00 \uc57d\uad00\uacfc \ub2e4\ub978 \ub0b4\uc6a9\uc774\ub77c\uba74 \uadf8 \uc790\uccb4\ub85c \uac1c\ubcc4\uc57d\uc815\uc5d0 \uc900\ud558\ub294 \uc758\ubbf8\ub97c \uac00\uc9c8 \uc218\ub3c4 \uc788\uc5b4, \uc870\ud56d \ud574\uc11d\uc5d0 \ucc38\uace0\uc790\ub8cc\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4.",B.TF,B.TZ,null)
B.a_Z=s([u.lH,"\ubb34\ud6a8\uc0ac\uc720\ubd80\ud130 \uac80\ud1a0\ud558\uace0 \uadf8 \ub2e4\uc74c\uc5d0 \uc57d\uad00 \ud574\ub2f9\uc131\uc744 \ud655\uc778\ud55c\ub2e4","\uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc744 \uac00\uc7a5 \uba3c\uc800 \uc801\uc6a9\ud558\uace0 \uadf8 \ub2e4\uc74c \uc57d\uad00 \ud574\ub2f9\uc131\uc744 \uac80\ud1a0\ud55c\ub2e4","\uac1c\ubcc4\uc57d\uc815 \uc874\ubd80\ub294 \uc804\ud600 \uac80\ud1a0\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\uc774\ub7ec\ud55c \uac80\ud1a0 \uc21c\uc11c\ub294 \ubc95\ub960\uc0c1 \uc815\ud574\uc9c4 \ubc14\uac00 \uc5c6\uc5b4 \uc0ac\uc5c5\uc790\uac00 \uc784\uc758\ub85c \uc815\ud55c\ub2e4"],t.s)
