B.a7u=new A.f("gen_ai_case_5","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00 \ud574\uc11d \uc885\ud569\xb7\uc0ac\ub840","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59 \uad00\ub828 \uc870\ubb38\ub4e4\uc744 \uc885\ud569\ud560 \ub54c, \uc57d\uad00 \ubd84\uc7c1\uc744 \uac80\ud1a0\ud558\ub294 \uc77c\ubc18\uc801 \uc21c\uc11c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a_Z,0,"\uc57d\uad00 \ubd84\uc7c1\uc740 \ud1b5\uc0c1 \u2460 \ubb38\uc81c\ub41c \uc870\ud56d\uc774 \uc57d\uad00\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0, \u2461 \uac1c\ubcc4\uc57d\uc815\uc73c\ub85c \ubcfc \uc0ac\uc815\uc774 \uc788\ub294\uc9c0, \u2462 \uc2e0\uc758\uc131\uc2e4\xb7\ud1b5\uc77c\uc801 \ud574\uc11d\uc744 \ud1b5\ud574 \uc870\ud56d\uc758 \uc758\ubbf8\ub97c \ud655\uc815\ud558\uace0, \u2463 \uadf8\ub798\ub3c4 \ubd88\uba85\ud655\ud558\uba74 \uc791\uc131\uc790\ubd88\uc774\uc775\uc758 \uc6d0\uce59\uc744 \uc801\uc6a9\ud558\uba70, \u2464 \uc774\ub807\uac8c \ud655\uc815\ub41c \ub0b4\uc6a9\uc774 \uc81c6\uc870~\uc81c14\uc870\uc758 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0\ub97c \uac80\ud1a0\ud558\ub294 \uc21c\uc11c\ub85c \ub17c\ub9ac\ub97c \uc804\uac1c\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4.",B.a0m,B.a2p,null)
B.X8=s([u.li,"\uc0ac\uc5c5\uc790\uc758 \uc774\uc724 \uadf9\ub300\ud654\ub9cc\uc744 \uc720\uc77c\ud55c \ubaa9\ud45c\ub85c \ud55c\ub2e4","\uace0\uac1d\uc774 \ud56d\uc0c1 \ubb34\uc870\uac74 \uc2b9\uc18c\ud558\ub3c4\ub85d \ud558\ub294 \uac83\uc774 \ubaa9\ud45c\uc774\ub2e4","\uc57d\uad00 \uc790\uccb4\uc758 \uc0ac\uc6a9\uc744 \uc804\uba74 \uae08\uc9c0\ud558\ub824\ub294 \uac83\uc774 \ubaa9\ud45c\uc774\ub2e4","\ubc95\uc6d0\uc758 \uc7ac\ud310 \ubd80\ub2f4\uc744 \uc904\uc774\ub294 \uac83\uc774 \uc720\uc77c\ud55c \ubaa9\ud45c\uc774\ub2e4"],t.s)
B.VB=s([u.li],t.s)
B.Oi=s(["\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59 \uaddc\uc815\uc758 \ubaa9\uc801"],t.s)
B.aaY=new A.f("gen_ai_case_6","economic_law","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59","\uc57d\uad00 \ud574\uc11d \uc885\ud569\xb7\uc0ac\ub840","\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59 \uad00\ub828 \uaddc\uc815\ub4e4\uc774 \uad81\uadf9\uc801\uc73c\ub85c \ucd94\uad6c\ud558\ub294 \uac00\uce58\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.X8,0,"\uc57d\uad00 \ud574\uc11d\xb7\ucd1d\uce59 \uaddc\uc815\ub4e4\uc740 \ub2e4\uc218\uc758 \uace0\uac1d\uc5d0\uac8c \ud68d\uc77c\uc801\uc73c\ub85c \uc801\uc6a9\ub418\ub294 \uc57d\uad00 \uac70\ub798\uc758 \ud2b9\uc131\uc744 \uace0\ub824\ud558\uc5ec, \ud574\uc11d\uc758 \uacf5\uc815\uc131\uacfc \uc608\uce21\uac00\ub2a5\uc131\uc744 \ud655\ubcf4\ud558\uace0 \uace0\uac1d\uc774 \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uc9c0\uc704\uc5d0 \ub193\uc774\uc9c0 \uc54a\ub3c4\ub85d \ud558\ub824\ub294 \uacf5\ud1b5\ub41c \uac00\uce58\ub97c \ucd94\uad6c\ud55c\ub2e4. \uc774\ub294 \uc0ac\uc5c5\uc790\uc758 \uc774\uc775\ub9cc\uc744 \uc704\ud55c \uac83\ub3c4, \uace0\uac1d\uc758 \ubb34\uc870\uac74\uc801 \uc2b9\ub9ac\ub97c \ubcf4\uc7a5\ud558\ub824\ub294 \uac83\ub3c4 \uc544\ub2cc \uade0\ud615\uc7a1\ud78c \uc811\uadfc\uc774\ub2e4.",B.VB,B.Oi,null)
B.Wc=s(["\uc0ac\uc5c5\uc790 \ubc0f \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ud45c\uc900\uc774 \ub420 \uc57d\uad00\uc744 \ub9c8\ub828\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uadf8 \uc2ec\uc0ac\ub97c \uccad\uad6c\ud560 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc18c\ube44\uc790\ub2e8\uccb4 \ub4f1\uc758 \uc694\uccad\uc774 \uc788\ub294 \uacbd\uc6b0 \ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc548\uc744 \ub9c8\ub828\ud558\uc5ec \uc2ec\uc0ac\uccad\uad6c\ud560 \uac83\uc744 \uad8c\uace0\ud560 \uc218 \uc788\ub2e4","\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\ub294 \ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub974\uac8c \uc815\ud55c \uc8fc\uc694 \ub0b4\uc6a9\uc774 \uc788\uc73c\uba74 \ud45c\uc900\uc57d\uad00\ubcf4\ub2e4 \uace0\uac1d\uc5d0\uac8c \ub354 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\ub3c4 \uc790\uc720\ub86d\uac8c \uc0ac\uc6a9\ud560 \uc218 \uc788\ub2e4","\ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub974\uac8c \uc815\ud55c \uc8fc\uc694 \ub0b4\uc6a9\uc740 \uace0\uac1d\uc774 \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc5ec\uc57c \ud55c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ud45c\uc900\uc57d\uad00\uc758 \uc0ac\uc6a9\uc744 \ud65c\uc131\ud654\ud558\uae30 \uc704\ud558\uc5ec \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Og=s(["\uadf8\ub7f0 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc740 \ubcc4\ub3c4\ub85c \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc9c0 \uc54a\ub294 \ud55c \ud6a8\ub825\uc774 \uc81c\ud55c\ub41c\ub2e4"],t.s)
B.Mh=s(["\ud45c\uc900\uc57d\uad00","\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0"],t.s)
B.abR=new A.f("gen_al_2","economic_law","\ud45c\uc900\uc57d\uad00",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Wc,2,'\uc57d\uad00\ubc95 \uc81c19\uc870\uc7583\uc740 \uc0ac\uc5c5\uc790 \ubc0f \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub978 \ub0b4\uc6a9\uc758 \uc57d\uad00\uc744 \uc0ac\uc6a9\ud558\uba74\uc11c \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub294 \uacbd\uc6b0, \ud45c\uc900\uc57d\uad00\ubcf4\ub2e4 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc740 \uba85\uc2dc\uc801\uc73c\ub85c \ud45c\uc2dc\ud558\uc9c0 \uc54a\uc73c\uba74 \ud45c\uc900\uc57d\uad00\uacfc \uac19\uc740 \ub0b4\uc6a9\uc73c\ub85c \ud569\uc758\ub41c \uac83\uc73c\ub85c \ubcf8\ub2e4\ub294 \ucde8\uc9c0\uc758 \uaddc\uc815\uc744 \ub450\uc5b4 \uace0\uac1d \ubcf4\ud638\ub97c \uaf80\ud558\uace0 \uc788\ub2e4. \uc989 \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\uba74\uc11c \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc744 "\uc790\uc720\ub86d\uac8c" \uc815\ud560 \uc218 \uc788\ub2e4\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\uc73c\uba70, \uc624\ud788\ub824 \uadf8\ub7f0 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc740 \ubcc4\ub3c4\ub85c \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc9c0 \uc54a\ub294 \ud55c \ud6a8\ub825\uc774 \uc81c\ud55c\ub41c\ub2e4. \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0\ub4e4, \uc989 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc2ec\uc0ac\uccad\uad6c\uad8c, \uacf5\uc815\uc704\uc758 \ud45c\uc900\uc57d\uad00 \uad8c\uace0\uad8c, \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0 \uc81c\uc815\uad8c\uc740 \ubaa8\ub450 \ubc95\uc5d0 \uaddc\uc815\ub41c \uc815\ud655\ud55c \ub0b4\uc6a9\uc774\ub2e4.',B.Og,B.Mh,null)
B.a1C=s([u.m7,"\ubaa8\ub4e0 \uc0ac\uc5c5\uc790\uc5d0\uac8c \ub3d9\uc77c\ud55c \uac00\uaca9\uc744 \uac15\uc81c\ud558\uae30 \uc704\ud55c \uc81c\ub3c4","\uc0ac\uc5c5\uc790 \uac04\uc758 \ub2f4\ud569\uc744 \uacf5\uc2dd\uc801\uc73c\ub85c \ud5c8\uc6a9\ud558\ub294 \uc81c\ub3c4","\uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \uc77c\ubc29\uc801\uc73c\ub85c \ubd88\ub9ac\ud55c \uc57d\uad00\uc744 \ub9cc\ub4dc\ub294 \uc81c\ub3c4","\ud45c\uc900\uc57d\uad00\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\uc744 \uc704\ud55c \ucc38\uace0\uc790\ub8cc\uc5d0 \ubd88\uacfc\ud558\ub2e4"],t.s)
B.K1=s([u.m7],t.s)
B.NC=s(["\ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\uc758 \uc758\uc758"],t.s)
B.a70=new A.f("gen_std_intro_1","economic_law","\ud45c\uc900\uc57d\uad00","\ud45c\uc900\uc57d\uad00\uc758 \uc758\uc758\xb7\uc81c\uc815 \uc808\ucc28","\ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\uc758 \uc758\uc758\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a1C,0,"\ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2ec\uc0ac\ub97c \uac70\uccd0 \ubd88\uacf5\uc815 \uc18c\uc9c0\ub97c \uc904\uc778 \ud45c\uc900\uc801\uc778 \ub0b4\uc6a9\uc758 \uc57d\uad00\uc744 \ub9c8\ub828\ud558\uace0, \uc0ac\uc5c5\uc790\ub4e4\uc774 \uc774\ub97c \uc0ac\uc6a9\ud558\ub3c4\ub85d \uc720\ub3c4\ud568\uc73c\ub85c\uc368 \uc57d\uad00\uc73c\ub85c \uc778\ud55c \ubd84\uc7c1\uc744 \uc608\ubc29\ud558\uace0 \uac70\ub798\uc758 \uacf5\uc815\uc131\uc744 \ub192\uc774\ub824\ub294 \uc81c\ub3c4\uc774\ub2e4.",B.K1,B.NC,null)
B.a_a=s(["\uc0ac\uc5c5\uc790 \ubc0f \uc0ac\uc5c5\uc790\ub2e8\uccb4","\uc624\uc9c1 \uac1c\ubcc4 \uc18c\ube44\uc790 1\uc778\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc7a5 \ubcf8\uc778\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \uad6d\ud68c\uc758\uc6d0\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \ubc95\uc6d0\ub9cc \uac00\ub2a5\ud558\ub2e4"],t.s)
