B.ab5=new A.f("gen_std_intro_2","economic_law","\ud45c\uc900\uc57d\uad00","\ud45c\uc900\uc57d\uad00\uc758 \uc758\uc758\xb7\uc81c\uc815 \uc808\ucc28","\ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\uc744 \uc2ec\uc0ac\uccad\uad6c\ud560 \uc218 \uc788\ub294 \uc790\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a_a,0,"\uc57d\uad00\ubc95\uc0c1 \uc0ac\uc5c5\uc790 \ubc0f \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ud45c\uc900\uc774 \ub420 \uc57d\uad00\uc744 \ub9c8\ub828\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uadf8 \uc2ec\uc0ac\ub97c \uccad\uad6c\ud560 \uc218 \uc788\ub2e4. \uac1c\ubcc4 \uc18c\ube44\uc790 1\uc778\uc774\ub098 \uad6d\ud68c\uc758\uc6d0, \ubc95\uc6d0 \ub4f1\uc740 \ud45c\uc900\uc57d\uad00 \uc81c\uc815 \uc2ec\uc0ac\uccad\uad6c\uc758 \uc8fc\uccb4\uac00 \uc544\ub2c8\ub2e4.",B.Sn,B.L6,null)
B.YC=s(["\ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc548\uc744 \ub9c8\ub828\ud558\uc5ec \uc2ec\uc0ac\uccad\uad6c\ud560 \uac83\uc744 \uc694\uccad\ud560 \uc218 \uc788\ub2e4","\uc18c\ube44\uc790\ub2e8\uccb4\ub294 \ud45c\uc900\uc57d\uad00\uacfc \uad00\ub828\ud558\uc5ec \uc5b4\ub5a0\ud55c \uc694\uccad\ub3c4 \ud560 \uc218 \uc5c6\ub2e4","\uc18c\ube44\uc790\ub2e8\uccb4\ub294 \uc624\uc9c1 \ud615\uc0ac\uace0\ubc1c\ub9cc \ud560 \uc218 \uc788\ub2e4","\uc18c\ube44\uc790\ub2e8\uccb4\ub294 \ud45c\uc900\uc57d\uad00\uc744 \uc9c1\uc811 \uc81c\uc815\ud560 \uc218 \uc788\ub294 \uad8c\ud55c\uc744 \uac16\ub294\ub2e4","\uc18c\ube44\uc790\ub2e8\uccb4\uc758 \uc694\uccad\uc740 \ubc95\ub960\uc0c1 \uc804\ud600 \uadfc\uac70\uac00 \uc5c6\ub2e4"],t.s)
B.Z9=s(["\ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc548\uc744 \ub9c8\ub828\ud558\uc5ec \uc2ec\uc0ac\uccad\uad6c\ud560 \uac83\uc744 \uc694\uccad\ud560 \uc218 \uc788\ub2e4"],t.s)
