B.aai=new A.f("gen_std_intro_3","economic_law","\ud45c\uc900\uc57d\uad00","\ud45c\uc900\uc57d\uad00\uc758 \uc758\uc758\xb7\uc81c\uc815 \uc808\ucc28","\uc18c\ube44\uc790\ub2e8\uccb4 \ub4f1\uc774 \ud45c\uc900\uc57d\uad00\uacfc \uad00\ub828\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc694\uccad\ud560 \uc218 \uc788\ub294 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.YC,0,"\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc5d0 \ub530\ub77c \ub4f1\ub85d\ub41c \uc18c\ube44\uc790\ub2e8\uccb4\ub098 \ud55c\uad6d\uc18c\ube44\uc790\uc6d0 \ub4f1\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc548\uc744 \ub9c8\ub828\ud558\uc5ec \uc2ec\uc0ac\uccad\uad6c\ud560 \uac83\uc744 \uc694\uccad\ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \uc57d\uad00\ubc95\uc0c1 \uc778\uc815\ub418\ub294 \uc808\ucc28\uc774\ub2e4.",B.Z9,B.a2c,null)
B.HE=s([u.eI,"\uc0ac\uc5c5\uc790\uac00 \uc774\uc775\uc744 \ub9ce\uc774 \ub0b8\ub2e4\uace0 \ud310\ub2e8\ub418\ub294 \uacbd\uc6b0","\uc18c\ube44\uc790\uc758 \uc694\uccad\uc774 \uc804\ud600 \uc5c6\uc5b4\ub3c4 \ubb34\uc791\uc704\ub85c \uad8c\uace0\ud55c\ub2e4","\uc624\uc9c1 \ub300\uae30\uc5c5\uc5d0 \ub300\ud574\uc11c\ub9cc \uad8c\uace0\ud560 \uc218 \uc788\ub2e4","\uc624\uc9c1 \uc678\uad6d\uacc4 \uae30\uc5c5\uc5d0 \ub300\ud574\uc11c\ub9cc \uad8c\uace0\ud560 \uc218 \uc788\ub2e4"],t.s)
