B.aae=new A.f("gen_std_case_1","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\uc5ec\ud589\uc5c5, \uc774\uc0ac\ud654\ubb3c\uc6b4\uc1a1\uc5c5 \ub4f1 \uc77c\uc0c1\uc0dd\ud65c\uacfc \ubc00\uc811\ud55c \uc5c5\uc885\uc5d0\uc11c \ud45c\uc900\uc57d\uad00\uc774 \ud65c\uc6a9\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.SE,0,"\uc5ec\ud589\uc5c5, \uc774\uc0ac\ud654\ubb3c\uc6b4\uc1a1\uc5c5 \ub4f1\uacfc \uac19\uc774 \uc18c\ube44\uc790\uc640\uc758 \uac70\ub798\uc5d0\uc11c \ubd84\uc7c1\uc774 \ube48\ubc88\ud558\uac8c \ubc1c\uc0dd\ud558\ub294 \uc5c5\uc885\uc5d0\uc11c\ub294, \ud45c\uc900\uc57d\uad00\uc744 \ub9c8\ub828\ud558\uc5ec \uc0ac\uc5c5\uc790\ub4e4\uc774 \uc0ac\uc6a9\ud558\ub3c4\ub85d \ud568\uc73c\ub85c\uc368 \uc18c\ube44\uc790 \ud53c\ud574\ub97c \uc608\ubc29\ud558\uace0 \uac70\ub798\uc758 \uacf5\uc815\uc131\uacfc \uc608\uce21\uac00\ub2a5\uc131\uc744 \ub192\uc774\ub824\ub294 \ubaa9\uc801\uc73c\ub85c \ud45c\uc900\uc57d\uad00\uc774 \ud65c\ubc1c\ud558\uac8c \ud65c\uc6a9\ub41c\ub2e4.",B.US,B.Hq,null)
B.a1T=s([u.ik,"\ud45c\uc900\uc57d\uad00\uc758 \uc190\ud574\ubc30\uc0c1 \uc870\ud56d\uc740 \ud56d\uc0c1 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \ubd88\ub9ac\ud558\uac8c \uc124\uacc4\ub41c\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \uc190\ud574\ubc30\uc0c1\uc774\ub098 \uc704\uc57d\uae08\uc5d0 \uad00\ud55c \ub0b4\uc6a9\uc744 \uc804\ud600 \ub2e4\ub8e8\uc9c0 \uc54a\ub294\ub2e4","\ud45c\uc900\uc57d\uad00\uc758 \uc704\uc57d\uae08 \uc870\ud56d\uc740 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \ubd88\ub9ac\ud558\ub2e4","\ud45c\uc900\uc57d\uad00\uc758 \uc190\ud574\ubc30\uc0c1 \uc870\ud56d\uc740 \ubc95\ub839\uacfc \ubb34\uad00\ud558\uac8c \uc784\uc758\ub85c \uc815\ud574\uc9c4\ub2e4"],t.s)
