B.Sg=s(["\ud45c\uc900\uc57d\uad00\uc0c1 \uc190\ud574\ubc30\uc0c1\xb7\uc704\uc57d\uae08 \uc870\ud56d\uc758 \ud2b9\uc9d5"],t.s)
B.adW=new A.f("gen_std_case_2","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\ud45c\uc900\uc57d\uad00\uc774 \uc815\ud558\ub294 \uc190\ud574\ubc30\uc0c1\uc561\uc774\ub098 \uc704\uc57d\uae08 \uad00\ub828 \uc870\ud56d\uc758 \uc77c\ubc18\uc801 \ud2b9\uc9d5\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a1T,0,"\ud45c\uc900\uc57d\uad00\uc740 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8 \ubc95\ub9ac(\uacfc\uc911\ud55c \uc190\ud574\ubc30\uc0c1\uc561 \uc608\uc815 \uae08\uc9c0 \ub4f1)\uc5d0 \uc800\ucd09\ub418\uc9c0 \uc54a\ub3c4\ub85d, \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc30d\ubc29\uc758 \uc774\ud574\uad00\uacc4\ub97c \uace0\ub824\ud55c \uade0\ud615 \uc7a1\ud78c \uc190\ud574\ubc30\uc0c1\uc561\xb7\uc704\uc57d\uae08 \uae30\uc900\uc744 \uc81c\uc2dc\ud558\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc544, \uc2e4\uc81c \uc57d\uad00 \uc791\uc131 \uc2dc \ucc38\uace0\uc790\ub8cc\ub85c\uc11c \uac00\uce58\ub97c \uac16\ub294\ub2e4.",B.a2y,B.Sg,null)
B.YR=s([u.mQ,"\uac00\ub9f9\ubcf8\ubd80\uac00 \uac00\ub9f9\uc810\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \ud1b5\uc81c\ud558\ub294 \uc218\ub2e8\uc73c\ub85c\ub9cc \ud65c\uc6a9\ub41c\ub2e4","\uac00\ub9f9\uc810\uc774 \uac00\ub9f9\ubcf8\ubd80\uc5d0\uac8c \uc77c\ubc29\uc801\uc73c\ub85c \uc720\ub9ac\ud55c \uc870\uac74\uc744 \uac15\uc81c\ud558\ub294 \uc218\ub2e8\uc774\ub2e4","\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\ub294 \uac00\ub9f9\uc0ac\uc5c5\uc5d0\uc11c \uc544\ubb34\ub7f0 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\ub294 \uc624\uc9c1 \uc2e0\uaddc \ucc3d\uc5c5\uc790\ub9cc\uc744 \ub300\uc0c1\uc73c\ub85c \ud55c\ub2e4"],t.s)
