B.acW=new A.f("gen_std_case_3","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\ud504\ub79c\ucc28\uc774\uc988(\uac00\ub9f9) \uc5c5\uc885\uc5d0\uc11c \ud45c\uc900\uc57d\uad00\xb7\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\uac00 \uac16\ub294 \uc2e4\ubb34\uc801 \uae30\ub2a5\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.YR,0,"\ud504\ub79c\ucc28\uc774\uc988(\uac00\ub9f9) \uc5c5\uc885\uc5d0\uc11c \ud45c\uc900\uc57d\uad00\xb7\ud45c\uc900\uacc4\uc57d\uc11c \uc131\uaca9\uc758 \uc81c\ub3c4\ub294 \uac00\ub9f9\ubcf8\ubd80\uc640 \uac00\ub9f9\uc810 \uac04 \uacc4\uc57d \uc870\uac74\uc774 \uc5b4\ub290 \ud55c\ucabd\uc5d0 \uc77c\ubc29\uc801\uc73c\ub85c \ubd88\ub9ac\ud558\uc9c0 \uc54a\ub3c4\ub85d, \uacc4\uc57d \uccb4\uacb0 \uc804\uc5d0 \uacf5\uc815\uc131\uc744 \uc810\uac80\ud560 \uc218 \uc788\ub294 \ucc38\uace0 \ud2c0\uc744 \uc81c\uacf5\ud558\ub294 \uc2e4\ubb34\uc801 \uae30\ub2a5\uc744 \ud55c\ub2e4.",B.U3,B.Kg,null)
B.HT=s([u.g,"\ud45c\uc900\uc57d\uad00\uc740 \uc18c\uc1a1\uc5d0\uc11c \uc5b4\ub5a0\ud55c \uc99d\uac70\ub85c\ub3c4 \uc0ac\uc6a9\ub420 \uc218 \uc5c6\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \ubc95\uc6d0\uc744 \ud56d\uc0c1 \uc808\ub300\uc801\uc73c\ub85c \uad6c\uc18d\ud558\ub294 \ud310\uacb0\uacfc \ub3d9\uc77c\ud55c \ud6a8\ub825\uc744 \uac16\ub294\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \ubd84\uc7c1\uacfc \uc804\ud600 \ubb34\uad00\ud55c \ud589\uc815 \ub0b4\ubd80\uc790\ub8cc\uc5d0 \ubd88\uacfc\ud558\ub2e4","\ud45c\uc900\uc57d\uad00\uc740 \uc624\uc9c1 \ud615\uc0ac\uc7ac\ud310\uc5d0\uc11c\ub9cc \uc0ac\uc6a9\ub41c\ub2e4"],t.s)
