B.a8M=new A.f("gen_std_case_4","economic_law","\ud45c\uc900\uc57d\uad00","\uc5c5\uc885\ubcc4 \ud45c\uc900\uc57d\uad00 \ud65c\uc6a9 \uc0ac\ub840","\ud45c\uc900\uc57d\uad00\uc774 \uc2e4\uc81c \uc18c\uc1a1\xb7\ubd84\uc7c1\uc5d0\uc11c \ud65c\uc6a9\ub418\ub294 \ubc29\uc2dd\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.HT,0,"\ud45c\uc900\uc57d\uad00\uc740 \uadf8 \uc790\uccb4\ub85c \ubc95\uc6d0\uc744 \uc808\ub300\uc801\uc73c\ub85c \uad6c\uc18d\ud558\ub294 \uac83\uc740 \uc544\ub2c8\uc9c0\ub9cc, \uc2e4\uc81c \uc18c\uc1a1\uc774\ub098 \ubd84\uc7c1 \uacfc\uc815\uc5d0\uc11c \ubb38\uc81c\ub41c \uac1c\ubcc4 \uc57d\uad00 \uc870\ud56d\uc774 \ud45c\uc900\uc801\uc778 \uc218\uc900\uc5d0 \ube44\ud574 \uc5bc\ub9c8\ub098 \ubd88\ub9ac\ud55c\uc9c0\ub97c \ud310\ub2e8\ud558\ub294 \ub370 \ube44\uad50\xb7\ucc38\uace0 \uc790\ub8cc\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4.",B.GT,B.NM,null)
B.a1m=s([u.nw,"\uc624\uc9c1 \ud45c\uc900\uc57d\uad00\uc744 \uc81c\uc815\ud55c \uacf5\ubb34\uc6d0\uc758 \uac1c\uc778 \uc2e0\uc0c1\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\ud45c\uc900\uc57d\uad00\uacfc \ubb34\uad00\ud55c \uc138\ubc95 \uaddc\uc815\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\ud45c\uc900\uc57d\uad00 \uad00\ub828 \ubb38\uc81c\ub294 \uc804\ud600 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \ud45c\uc900\uc57d\uad00 \ubb38\uc11c\uc758 \ud398\uc774\uc9c0 \uc218\ub9cc \ubb3b\ub294 \ubb38\uc81c\ub9cc \ucd9c\uc81c\ub41c\ub2e4"],t.s)
