B.a9X=new A.f("gen_al_etc_4","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uace0\uac1d\uc758 \uad8c\uc775\ubcf4\ud638\xb7\uae30\ud0c0(\uc81c11~14\uc870)","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c14\uc870(\uc18c\uc1a1\uc81c\uae30\uc758 \uae08\uc9c0 \ub4f1)\uac00 \uaddc\uc728\ud558\ub294 \uc870\ud56d\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Iz,0,"\uc81c14\uc870\ub294 \uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\ub9ac\ud55c \uc7ac\ud310\uad00\ud560 \ud569\uc758 \uc870\ud56d\uc774\ub098, \uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ubc95\ub960\uc0c1 \uc6d0\uce59\uacfc \ub2ec\ub9ac \uace0\uac1d\uc5d0\uac8c \uc785\uc99d\ucc45\uc784\uc744 \uc804\uac00\ud558\ub294 \uc870\ud56d \ub4f1\uc744 \ubb34\ud6a8\uc0ac\uc720\ub85c \uaddc\uc815\ud55c\ub2e4. \uc774\ub294 \uc18c\uc1a1\xb7\ubd84\uc7c1\ud574\uacb0 \uacfc\uc815\uc5d0\uc11c \uace0\uac1d\uc774 \ubd88\ub9ac\ud55c \uc9c0\uc704\uc5d0 \ub193\uc774\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4.",B.Sq,B.Zk,null)
B.V4=s([u.h5,"\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ube44\ubc00 \ubcf4\ud638\ub97c \uc704\ud55c \uac83\uc774\ubbc0\ub85c \ud56d\uc0c1 \uc720\ud6a8\ud558\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc815\ud55c \uacbd\uc6b0\uc5d0\ub9cc \ubb34\ud6a8\uc774\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uc18c\uc1a1\uc744 \ud1b5\ud574\uc11c\ub9cc \ub2e4\ud234 \uc218 \uc788\uace0 \uc57d\uad00\ubc95\uc0c1 \ubb34\ud6a8 \ub300\uc0c1\uc740 \uc544\ub2c8\ub2e4","\uc774\ub7ec\ud55c \uc870\ud56d\uc740 \uace0\uac1d\uc5d0\uac8c \uc720\ub9ac\ud55c \uc870\ud56d\uc73c\ub85c \ubd84\ub958\ub418\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4"],t.s)
