B.a9F=new A.f("gen_al_etc_5","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720","\uace0\uac1d\uc758 \uad8c\uc775\ubcf4\ud638\xb7\uae30\ud0c0(\uc81c11~14\uc870)","\uace0\uac1d\uc774 \uacc4\uc57d\ubaa9\uc801\ubb3c\uc5d0 \uad00\ud558\uc5ec \uc81c3\uc790\uc640 \uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \uac83\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\uac70\ub098, \uc774\ub97c \uc774\uc720\ub85c \uace0\uac1d\uc5d0\uac8c \uacfc\uc911\ud55c \uc704\uc57d\uae08\uc744 \ubb3c\uac8c \ud558\ub294 \uc57d\uad00\uc870\ud56d\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.V4,0,"\uace0\uac1d\uc774 \uacc4\uc57d\ubaa9\uc801\ubb3c\uacfc \uad00\ub828\ud558\uc5ec \uc81c3\uc790\uc640 \uc790\uc720\ub86d\uac8c \uac70\ub798\ud560 \uc218 \uc788\ub294 \uad8c\ub9ac\ub97c \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\uac70\ub098, \uc774\ub97c \uc774\uc720\ub85c \uacfc\uc911\ud55c \uc704\uc57d\uae08\uc744 \ubd80\uacfc\ud558\ub294 \uc870\ud56d\uc740 \uace0\uac1d\uc758 \uc815\ub2f9\ud55c \uad8c\uc775\uc744 \ubd80\ub2f9\ud558\uac8c \uce68\ud574\ud558\ub294 \uac83\uc73c\ub85c \uc81c11\uc870\uac00 \uc815\ud558\ub294 \ubb34\ud6a8\uc0ac\uc720\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4.",B.WR,B.KY,null)
B.NJ=s([u.or,"\uc870\uc0ac\ub294 \uc624\uc9c1 \uac80\ucc30\uc758 \uc694\uccad\uc774 \uc788\uc5b4\uc57c\ub9cc \uac1c\uc2dc\ub420 \uc218 \uc788\ub2e4","\uc870\uc0ac\ub294 \ubc18\ub4dc\uc2dc \ud53c\uc870\uc0ac\uc778\uc758 \uc0ac\uc804 \ub3d9\uc758\ub97c \ubc1b\uc544\uc57c\ub9cc \uac1c\uc2dc\ub420 \uc218 \uc788\ub2e4","\uc2e0\uace0\uc5d0 \uc758\ud55c \uc870\uc0ac\ub294 \uc778\uc815\ub418\uc9c0 \uc54a\uace0 \uc9c1\uad8c\uc870\uc0ac\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc870\uc0ac \uac1c\uc2dc\uc5d0\ub294 \uad6d\ud68c\uc758 \uc0ac\uc804 \uc2b9\uc778\uc774 \ud544\uc694\ud558\ub2e4"],t.s)
