B.a7v=new A.f("gen_iv_start_1","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\uc758 \uac1c\uc2dc(\uc9c1\uad8c\xb7\uc2e0\uace0)","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc704\ubc18\ud589\uc704 \uc870\uc0ac \uac1c\uc2dc\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.NJ,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc95 \uc704\ubc18 \ud610\uc758\uac00 \uc788\ub2e4\uace0 \uc778\uc9c0\ud558\uba74 \uc9c1\uad8c\uc73c\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud560 \uc218 \uc788\uace0, \uc774\ud574\uad00\uacc4\uc778\xb7\uc18c\ube44\uc790\ub2e8\uccb4 \ub4f1\uc758 \uc2e0\uace0\ub97c \uacc4\uae30\ub85c\ub3c4 \uc870\uc0ac\uc5d0 \ucc29\uc218\ud560 \uc218 \uc788\ub2e4. \uc870\uc0ac \uac1c\uc2dc\uc5d0 \ud53c\uc870\uc0ac\uc778\uc758 \uc0ac\uc804 \ub3d9\uc758\ub098 \uad6d\ud68c \uc2b9\uc778, \uac80\ucc30\uc758 \uc694\uccad\uc774 \ud544\uc694\ud55c \uac83\uc740 \uc544\ub2c8\ub2e4.",B.NY,B.Yd,null)
B.R4=s(["\ub204\uad6c\ub4e0\uc9c0 \ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc2e0\uace0\ud560 \uc218 \uc788\ub2e4","\uc2e0\uace0\ub294 \ubc18\ub4dc\uc2dc \ud53c\ud574 \ub2f9\uc0ac\uc790 \ubcf8\uc778\ub9cc \ud560 \uc218 \uc788\ub2e4","\uc2e0\uace0\ub294 \ubc18\ub4dc\uc2dc \ubcc0\ud638\uc0ac\ub97c \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc2e0\uace0\uac00 \uc788\uc73c\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc18\ub4dc\uc2dc \uadf8 \uc2e0\uace0 \ub0b4\uc6a9\ub300\ub85c\ub9cc \ucc98\ubd84\ud574\uc57c \ud55c\ub2e4","\uc2e0\uace0\uc790\ub294 \uc2e0\uace0 \uc774\ud6c4 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc775\uba85\uc744 \uc720\uc9c0\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.JG=s(["\ub204\uad6c\ub4e0\uc9c0 \ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc2e0\uace0\ud560 \uc218 \uc788\ub2e4"],t.s)
