B.a7s=new A.f("gen_iv_start_2","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\uc758 \uac1c\uc2dc(\uc9c1\uad8c\xb7\uc2e0\uace0)","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc54c\uac8c \ub41c \uc790\uc758 \uc2e0\uace0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.R4,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc54c\uac8c \ub41c \uc790\ub294 \ub204\uad6c\ub4e0\uc9c0 \uadf8 \uc0ac\uc2e4\uc744 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc2e0\uace0\ud560 \uc218 \uc788\ub2e4. \uc2e0\uace0\uc790\uac00 \ubc18\ub4dc\uc2dc \ud53c\ud574 \ub2f9\uc0ac\uc790 \ubcf8\uc778\uc77c \ud544\uc694\ub294 \uc5c6\uc73c\uba70, \uc2e0\uace0\uac00 \uc788\ub2e4\uace0 \ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc2e0\uace0 \ub0b4\uc6a9 \uadf8\ub300\ub85c \uad6c\uc18d\ub418\uc5b4 \ucc98\ubd84\ud574\uc57c \ud558\ub294 \uac83\ub3c4 \uc544\ub2c8\uace0 \uc870\uc0ac \uacb0\uacfc\uc5d0 \ub530\ub77c \ubcc4\ub3c4\ub85c \ud310\ub2e8\ud55c\ub2e4.",B.JG,B.QS,null)
