B.adu=new A.f("gen_iv_start_3","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\uc758 \uac1c\uc2dc(\uc9c1\uad8c\xb7\uc2e0\uace0)","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc870\uc0ac \uac1c\uc2dc \uc5ec\ubd80\ub97c \uacb0\uc815\ud560 \ub54c \uace0\ub824\ud558\ub294 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.P4,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc2e0\uace0\ub418\uac70\ub098 \uc778\uc9c0\ub41c \uc0ac\uc2e4\uc774 \ubc95 \uc704\ubc18 \ud610\uc758\ub85c \ubcfc \ub9cc\ud55c \uc0c1\ub2f9\ud55c \uadfc\uac70\ub97c \uac16\ucd94\uace0 \uc788\ub294\uc9c0\ub97c \uc911\uc2ec\uc73c\ub85c \uc870\uc0ac \uac1c\uc2dc \uc5ec\ubd80\ub97c \ud310\ub2e8\ud55c\ub2e4. \uc2e0\uace0\uc790\uc758 \uc7ac\uc0b0\xb7\uad6d\uc801, \ud53c\uc2e0\uace0\uc778\uc758 \uc815\uce58\uc801 \uc131\ud5a5\uc774\ub098 \ub2e8\uc21c \uc784\uc9c1\uc6d0 \uc218\ub294 \uc870\uc0ac \uac1c\uc2dc \uc5ec\ubd80 \ud310\ub2e8\uacfc \ubb34\uad00\ud55c \uc694\uc18c\uc774\ub2e4.",B.M6,B.TW,null)
B.a2r=s([u.o1,"\uc2e0\uace0\uc778\uc774 \uc870\uc0ac\uc758 \ubaa8\ub4e0 \uc9c4\ud589\uc744 \uc9c1\uc811 \uc9c0\ud718\ud55c\ub2e4","\uc2e0\uace0\uc778\uc740 \uc870\uc0ac \uac1c\uc2dc \uc774\ud6c4 \uc544\ubb34\ub7f0 \uc808\ucc28\uc801 \uc9c0\uc704\ub3c4 \uac16\uc9c0 \uc54a\ub294\ub2e4","\uc2e0\uace0\uc778\uc740 \ud53c\uc2e0\uace0\uc778\uc5d0 \ub300\ud55c \ucc98\ubd84 \ub0b4\uc6a9\uc744 \uc2a4\uc2a4\ub85c \uacb0\uc815\ud560 \uc218 \uc788\ub2e4","\uc2e0\uace0\uc778\uc740 \uc870\uc0ac \uac1c\uc2dc\uc640 \ub3d9\uc2dc\uc5d0 \uc790\ub3d9\uc73c\ub85c \uc18c\uc1a1\ub2f9\uc0ac\uc790\uac00 \ub41c\ub2e4"],t.s)
