B.a9V=new A.f("gen_iv_method_2","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\ubc29\ubc95\xb7\uc870\uc0ac\uad8c\ud55c","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac \ubc29\ubc95\uc73c\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub974\uba74?\n\n\u3131. \ub2f9\uc0ac\uc790\xb7\uc774\ud574\uad00\uacc4\uc778 \ub610\ub294 \ucc38\uace0\uc778\uc758 \ucd9c\uc11d\uc694\uad6c \ubc0f \uc9c4\uc220 \uccad\ucde8\n\u3131. \uac10\uc815\uc778\uc758 \uc9c0\uc815 \ubc0f \uac10\uc815 \uc704\ucd09\n\u3137. \uc0ac\uc5c5\uc790 \ub610\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud55c \uc790\ub8cc \uc81c\ucd9c \uc694\uad6c\n\u3139. \ud544\uc694\ud55c \ucd5c\uc18c\ud55c\uc758 \ubc94\uc704\uc5d0\uc11c\uc758 \ud604\uc7a5 \uc870\uc0ac",B.Gs,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc870\uc0ac\ub97c \uc704\ud574 \ub2f9\uc0ac\uc790\xb7\uc774\ud574\uad00\uacc4\uc778\xb7\ucc38\uace0\uc778\uc5d0 \ub300\ud55c \ucd9c\uc11d\uc694\uad6c \ubc0f \uc9c4\uc220 \uccad\ucde8, \uac10\uc815\uc778\uc758 \uc9c0\uc815 \ubc0f \uac10\uc815 \uc704\ucd09, \uc0ac\uc5c5\uc790\xb7\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud55c \uc790\ub8cc \uc81c\ucd9c \uc694\uad6c, \ud544\uc694\ud55c \ucd5c\uc18c\ud55c\uc758 \ubc94\uc704 \ub0b4 \ud604\uc7a5\uc870\uc0ac \ub4f1 \ub2e4\uc591\ud55c \uc870\uc0ac\ubc29\ubc95\uc744 \ud65c\uc6a9\ud560 \uc218 \uc788\ub2e4.",B.YB,B.a2C,null)
B.LJ=s([u.B,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub294 \ud56d\uc0c1 \uac15\uc81c\uc218\uc0ac\uc758 \uc131\uaca9\uc744 \uac00\uc9c0\uba70 \ubc95\uc6d0\uc758 \uc601\uc7a5\uc774 \ud544\uc218\uc801\uc73c\ub85c \uc694\uad6c\ub41c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc870\uc0ac\ub294 \uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \ub3d9\uc758\uac00 \uc5c6\uc73c\uba74 \uc5b4\ub5a0\ud55c \uc870\uce58\ub3c4 \ucde8\ud560 \uc218 \uc5c6\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \ud615\uc0ac\ucc98\ubc8c\uc744 \uc2a4\uc2a4\ub85c \uc989\uc2dc \ud655\uc815\ud560 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub294 \uac80\ucc30\uc758 \uc9c0\ud718\ub97c \ubc1b\uc544\uc57c\ub9cc \uc9c4\ud589\ub420 \uc218 \uc788\ub2e4"],t.s)
