B.aak=new A.f("gen_iv_method_3","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\ubc29\ubc95\xb7\uc870\uc0ac\uad8c\ud55c","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac \uc131\uaca9\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.LJ,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub294 \ud589\uc815\uc870\uc0ac\uc758 \uc131\uaca9\uc744 \uac00\uc9c0\uba70 \uc6d0\uce59\uc801\uc73c\ub85c \uc784\uc758\uc870\uc0ac\uc5d0 \ud574\ub2f9\ud558\uc5ec, \uc601\uc7a5\uc5d0 \uc758\ud55c \uc555\uc218\xb7\uc218\uc0c9\uacfc \uac19\uc740 \ud615\uc0ac\uc808\ucc28\uc0c1 \uac15\uc81c\uc218\uc0ac\uc640\ub294 \uad6c\ubcc4\ub41c\ub2e4. \ub2e4\ub9cc \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \uc870\uc0ac\uac70\ubd80\xb7\ubc29\ud574\uc5d0 \ub300\ud574\uc11c\ub294 \ubcc4\ub3c4\uc758 \uc81c\uc7ac(\uacfc\ud0dc\ub8cc \ub4f1)\uac00 \ub9c8\ub828\ub418\uc5b4 \uc0ac\uc2e4\uc0c1 \uc870\uc0ac\uc5d0 \uc751\ud558\ub3c4\ub85d \ud558\ub294 \uc720\uc778 \uc7a5\uce58\ub97c \ub450\uace0 \uc788\ub2e4.",B.L4,B.IK,null)
B.a0k=s(["\uc870\uc0ac \ubaa9\uc801\uacfc \uad00\ub828\ud558\uc5ec \ud544\uc694\ud55c \ubc94\uc704 \ub0b4\uc5d0\uc11c \uc790\ub8cc \uc81c\ucd9c\uc744 \uc694\uad6c\ud560 \uc218 \uc788\ub2e4","\uc870\uc0ac\uc640 \uc804\ud600 \ubb34\uad00\ud55c \uc0ac\uc5c5\uc790\uc758 \ubaa8\ub4e0 \uc0ac\uc801 \uc790\ub8cc\ub97c \ubb34\uc81c\ud55c\uc73c\ub85c \uc694\uad6c\ud560 \uc218 \uc788\ub2e4","\uc790\ub8cc \uc81c\ucd9c \uc694\uad6c\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubb38\uc11c\ub85c \uc774\ub8e8\uc5b4\uc9c8 \ud544\uc694\uac00 \uc5c6\ub2e4","\uc790\ub8cc \uc81c\ucd9c \uc694\uad6c\uc5d0\ub294 \uc544\ubb34\ub7f0 \ubaa9\uc801 \uc81c\ud55c\uc774 \uc5c6\ub2e4","\uc790\ub8cc \uc81c\ucd9c \uc694\uad6c\ub294 \uc624\uc9c1 \ub300\uae30\uc5c5\uc5d0\uac8c\ub9cc \ud560 \uc218 \uc788\ub2e4"],t.s)
