B.a7E=new A.f("gen_iv_method_6","economic_law","\uc870\uc0ac\uc808\ucc28","\uc870\uc0ac\ubc29\ubc95\xb7\uc870\uc0ac\uad8c\ud55c","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ube44\ubc00\uc744 \uc54c\uac8c \ub41c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Wb,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc18c\uc18d \uacf5\ubb34\uc6d0 \ub4f1\uc740 \uc9c1\ubb34\uc0c1 \uc54c\uac8c \ub41c \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ube44\ubc00 \ub4f1\uc744 \ub204\uc124\ud558\uac70\ub098 \uc870\uc0ac \ubaa9\uc801 \uc678\uc758 \uc6a9\ub3c4\ub85c \uc0ac\uc6a9\ud574\uc11c\ub294 \uc548 \ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774\ub294 \uc870\uc0ac\uc5d0 \ud611\uc870\ud55c \uc0ac\uc5c5\uc790\uc758 \uc815\ub2f9\ud55c \uc774\uc775\uc744 \ubcf4\ud638\ud558\uace0 \uc870\uc0ac\uc5d0 \ub300\ud55c \uc2e0\ub8b0\ub97c \ud655\ubcf4\ud558\uae30 \uc704\ud55c \uc7a5\uce58\uc774\ub2e4.",B.a07,B.VE,null)
B.TL=s(["\uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \ubcc0\ud638\uc778 \ub4f1\uc758 \uc870\ub825\uc744 \ubc1b\uc744 \uc218 \uc788\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc778\uc815\ub41c\ub2e4","\uc870\uc0ac\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubcc0\ud638\uc778\uc774 \ucc38\uc5ec\ud560 \uc218 \uc5c6\ub2e4","\ubcc0\ud638\uc778 \uc870\ub825\uc740 \uc624\uc9c1 \ud615\uc0ac\uc7ac\ud310\uc774 \ud655\uc815\ub41c \uc774\ud6c4\uc5d0\ub9cc \ud5c8\uc6a9\ub41c\ub2e4","\ubcc0\ud638\uc778 \uc870\ub825\uc744 \ubc1b\uc73c\uba74 \uc870\uc0ac \uc790\uccb4\uac00 \ubb34\ud6a8\uac00 \ub41c\ub2e4","\ubcc0\ud638\uc778 \uc870\ub825\uc740 \ub300\uae30\uc5c5\uc5d0\uac8c\ub9cc \ud5c8\uc6a9\ub41c\ub2e4"],t.s)
B.SH=s(["\uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \ubcc0\ud638\uc778 \ub4f1\uc758 \uc870\ub825\uc744 \ubc1b\uc744 \uc218 \uc788\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc778\uc815\ub41c\ub2e4"],t.s)
B.a_J=s(["\ubcc0\ud638\uc778 \uc870\ub825\uad8c"],t.s)
B.aad=new A.f("gen_iv_right_1","economic_law","\uc870\uc0ac\uc808\ucc28","\ud53c\uc870\uc0ac\uc790\uc758 \uad8c\ub9ac\xb7\uc758\ubb34","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc870\uc0ac\ub97c \ubc1b\ub294 \uc0ac\uc5c5\uc790\uac00 \ubcc0\ud638\uc778 \ub4f1\uc758 \uc870\ub825\uc744 \ubc1b\uc744 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.TL,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub97c \ubc1b\ub294 \uc0ac\uc5c5\uc790\ub294 \uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \ubcc0\ud638\uc778 \ub4f1 \ub300\ub9ac\uc778\uc758 \uc870\ub825\uc744 \ubc1b\uc744 \uc218 \uc788\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc73c\ub85c \uc778\uc815\ub418\ub294 \uc808\ucc28\uc801 \uad8c\ub9ac\uc774\ub2e4. \uc774\ub294 \ud53c\uc870\uc0ac\uc778\uc758 \ubc29\uc5b4\uad8c\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \ubcf4\uc7a5\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4.",B.SH,B.a_J,null)
B.VR=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ucd9c\uc11d\uc694\uad6c\uc5d0 \uc751\ud558\uc9c0 \uc54a\uc73c\uba74 \uc81c\uc7ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4","\ucd9c\uc11d\uc694\uad6c\ub294 \uc21c\uc804\ud788 \uc784\uc758\uc801 \uad8c\uc720\uc5d0 \ubd88\uacfc\ud558\uc5ec \ubb34\uc2dc\ud574\ub3c4 \uc5b4\ub5a0\ud55c \ubd88\uc774\uc775\ub3c4 \uc5c6\ub2e4","\ucd9c\uc11d\uc694\uad6c\uc5d0 \uc751\ud558\uba74 \uc790\ub3d9\uc73c\ub85c \uc704\ubc18\uc0ac\uc2e4\uc774 \uc778\uc815\ub41c \uac83\uc73c\ub85c \uac04\uc8fc\ub41c\ub2e4","\ucd9c\uc11d\uc694\uad6c\ub294 \uc624\uc9c1 \uc11c\uba74\uc73c\ub85c\ub9cc \uc751\ud560 \uc218 \uc788\uace0 \ub300\ub9ac\uc778 \ucd9c\uc11d\uc740 \ubd88\uac00\ub2a5\ud558\ub2e4","\ucd9c\uc11d\uc694\uad6c\uc5d0 \uc751\ud558\uc9c0 \uc54a\uc544\ub3c4 \ud56d\uc0c1 \uc870\uc0ac\uac00 \uc790\ub3d9\uc73c\ub85c \uc885\uacb0\ub41c\ub2e4"],t.s)
B.Nv=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ucd9c\uc11d\uc694\uad6c\uc5d0 \uc751\ud558\uc9c0 \uc54a\uc73c\uba74 \uc81c\uc7ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4"],t.s)
