B.adp=new A.f("gen_iv_right_2","economic_law","\uc870\uc0ac\uc808\ucc28","\ud53c\uc870\uc0ac\uc790\uc758 \uad8c\ub9ac\xb7\uc758\ubb34","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucd9c\uc11d\uc694\uad6c\ub97c \ubc1b\uc740 \uc790\uc758 \uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.VR,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub85c\ubd80\ud130 \uc815\ub2f9\ud558\uac8c \ucd9c\uc11d\uc694\uad6c\ub97c \ubc1b\uc740 \uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc774\uc5d0 \uc751\ud558\uc9c0 \uc54a\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc870\uc0ac\ubc29\ud574\uc5d0 \ud574\ub2f9\ud558\uc5ec \uc81c\uc7ac(\uacfc\ud0dc\ub8cc \ub4f1)\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4. \ucd9c\uc11d\uc694\uad6c\uc5d0 \uc751\ud558\ub294 \uac83 \uc790\uccb4\uac00 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc790\uc778\ud558\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uc774\ub294 \uc9c4\uc220\uc744 \uccad\ucde8\ud558\uae30 \uc704\ud55c \uc808\ucc28\uc77c \ubfd0\uc774\ub2e4.",B.Nv,B.Xc,null)
B.Nn=s([u.eO,"\ud53c\uc870\uc0ac\uc778\uc740 \uc5b4\ub5a0\ud55c \uc9c8\ubb38\uc5d0\ub3c4 \ubb34\uc870\uac74 \ub2f5\ubcc0\uc744 \uac70\ubd80\ud560 \uad8c\ub9ac\uac00 \uc804\ud600 \uc5c6\ub2e4","\ud53c\uc870\uc0ac\uc778\uc758 \uc9c4\uc220\uc740 \uc870\uc0ac \uacb0\uacfc\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ubb34\uc2dc\ub41c\ub2e4","\uc9c4\uc220\uc744 \uac70\ubd80\ud558\uba74 \uc790\ub3d9\uc73c\ub85c \ubb34\ud610\uc758 \ucc98\ubd84\uc774 \ub0b4\ub824\uc9c4\ub2e4","\uc9c4\uc220 \uad00\ub828 \uad8c\ub9ac\ub294 \uc870\uc0ac \uc808\ucc28\uc5d0\uc11c \uc804\ud600 \ub17c\uc758\ub418\uc9c0 \uc54a\ub294 \uc0ac\ud56d\uc774\ub2e4"],t.s)
B.YO=s([u.eO],t.s)
