B.ado=new A.f("gen_iv_right_3","economic_law","\uc870\uc0ac\uc808\ucc28","\ud53c\uc870\uc0ac\uc790\uc758 \uad8c\ub9ac\xb7\uc758\ubb34","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc870\uc0ac\uc5d0\uc11c \ud53c\uc870\uc0ac\uc778\uc758 \uc9c4\uc220\uacfc \uad00\ub828\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Nn,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub294 \ud589\uc815\uc870\uc0ac\ub85c\uc11c \ud615\uc0ac\uc808\ucc28\uc0c1 \uc9c4\uc220\uac70\ubd80\uad8c\uacfc \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uac8c \ucde8\uae09\ub418\ub294 \uac83\uc740 \uc544\ub2c8\uc9c0\ub9cc, \uc801\ubc95\uc808\ucc28\uc758 \uad00\uc810\uc5d0\uc11c \uc790\uae30\uc5d0\uac8c \ubd88\ub9ac\ud55c \uc9c4\uc220\uc744 \uac15\uc694\ubc1b\uc9c0 \uc54a\ub3c4\ub85d \ud558\ub294 \uc808\ucc28\uc801 \ubcf4\ud638 \ud544\uc694\uc131\uc774 \ub17c\uc758\ub418\uba70, \uc2e4\ubb34\uc0c1 \ud53c\uc870\uc0ac\uc778\uc758 \ubc29\uc5b4\uad8c \ubcf4\uc7a5 \ucc28\uc6d0\uc5d0\uc11c \uace0\ub824\ub418\ub294 \uc0ac\ud56d\uc774\ub2e4.",B.YO,B.Vu,null)
B.Zm=s([u.M,"\ud53c\uc2ec\uc778\uc740 \uc2ec\uc0ac\ubcf4\uace0\uc11c\uc758 \ub0b4\uc6a9\uc744 \uc804\ud600 \uc5f4\ub78c\ud560 \uc218 \uc5c6\ub2e4","\ud53c\uc2ec\uc778\uc740 \uc2ec\uc758 \uc808\ucc28\uc5d0 \uc5b4\ub5a0\ud55c \ud615\ud0dc\ub85c\ub3c4 \ucc38\uc5ec\ud560 \uc218 \uc5c6\ub2e4","\uc2ec\uc0ac\ubcf4\uace0\uc11c\uac00 \uc791\uc131\ub418\uba74 \uadf8 \uc989\uc2dc \ucc98\ubd84\uc774 \uc790\ub3d9\uc73c\ub85c \ud655\uc815\ub41c\ub2e4","\ud53c\uc2ec\uc778\uc758 \uc758\uacac \uc81c\ucd9c\uc740 \ubc95\ub960\uc0c1 \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
