B.abE=new A.f("gen_iv_right_4","economic_law","\uc870\uc0ac\uc808\ucc28","\ud53c\uc870\uc0ac\uc790\uc758 \uad8c\ub9ac\xb7\uc758\ubb34","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc2ec\uc0ac\uad00\uc774 \uc870\uc0ac \uacb0\uacfc \uc791\uc131\ud558\ub294 \uc2ec\uc0ac\ubcf4\uace0\uc11c\uc5d0 \ub300\ud574 \ud53c\uc2ec\uc778\uc774 \uac16\ub294 \uc808\ucc28\uc801 \uad8c\ub9ac\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Zm,0,"\uc2ec\uc0ac\uad00\uc774 \uc870\uc0ac\ub97c \ub9c8\uce58\uace0 \uc2ec\uc0ac\ubcf4\uace0\uc11c\ub97c \uc791\uc131\ud558\uba74, \ud53c\uc2ec\uc778(\uc870\uc0ac\ub300\uc0c1 \uc0ac\uc5c5\uc790)\uc740 \uadf8 \ub0b4\uc6a9\uc5d0 \ub300\ud574 \uc758\uacac\uc744 \uc81c\ucd9c\ud558\uace0 \uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758 \ub4f1 \uc2ec\uc758 \uacfc\uc815\uc5d0\uc11c \uc758\uacac\uc744 \uc9c4\uc220\ud560 \uae30\ud68c\ub97c \uac00\uc9c8 \uc218 \uc788\ub2e4. \uc774\ub294 \ucc98\ubd84\uc5d0 \uc55e\uc11c \ud53c\uc2ec\uc778\uc758 \ubc29\uc5b4\uad8c\uc744 \ubcf4\uc7a5\ud558\uae30 \uc704\ud55c \ud575\uc2ec\uc801\uc778 \uc808\ucc28\uc774\ub2e4.",B.nK,B.WX,null)
B.UU=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc870\uc0ac\ub97c \uac70\ubd80\xb7\ubc29\ud574\ud558\uac70\ub098 \uc790\ub8cc\ub97c \uc740\ub2c9\xb7\uc778\uba78\ud574\uc11c\ub294 \uc548 \ub41c\ub2e4","\ud53c\uc870\uc0ac\uc778\uc740 \uc870\uc0ac\uc5d0 \uc5b4\ub5a0\ud55c \ud611\uc870\uc758\ubb34\ub3c4 \ubd80\ub2f4\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc790\ub8cc \uc740\ub2c9\xb7\uc778\uba78\uc740 \uc544\ubb34\ub7f0 \ubd88\uc774\uc775 \uc5c6\uc774 \uc790\uc720\ub86d\uac8c \ud560 \uc218 \uc788\ub2e4","\ud611\uc870\uc758\ubb34\ub294 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \ubd80\uacfc\ub41c\ub2e4","\ud611\uc870\uc758\ubb34\ub294 \uc870\uc0ac\uac00 \uac1c\uc2dc\ub418\uae30 \uc804\uc5d0\ub9cc \uc874\uc7ac\ud55c\ub2e4"],t.s)
B.Zh=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc870\uc0ac\ub97c \uac70\ubd80\xb7\ubc29\ud574\ud558\uac70\ub098 \uc790\ub8cc\ub97c \uc740\ub2c9\xb7\uc778\uba78\ud574\uc11c\ub294 \uc548 \ub41c\ub2e4"],t.s)
B.Yl=s(["\ud53c\uc870\uc0ac\uc778\uc758 \ud611\uc870\uc758\ubb34"],t.s)
B.a7X=new A.f("gen_iv_right_5","economic_law","\uc870\uc0ac\uc808\ucc28","\ud53c\uc870\uc0ac\uc790\uc758 \uad8c\ub9ac\xb7\uc758\ubb34","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc870\uc0ac \uacfc\uc815\uc5d0\uc11c \ud53c\uc870\uc0ac\uc778\uc774 \ubd80\ub2f4\ud558\ub294 \ud611\uc870\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.UU,0,"\uc870\uc0ac\ub97c \ubc1b\ub294 \uc0ac\uc5c5\uc790\ub294 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc870\uc0ac\ub97c \uac70\ubd80\xb7\ubc29\ud574\ud558\uac70\ub098 \uad00\ub828 \uc790\ub8cc\ub97c \uc740\ub2c9\xb7\uc778\uba78\ud574\uc11c\ub294 \uc548 \ub418\ub294 \ud611\uc870\uc758\ubb34\ub97c \ubd80\ub2f4\ud55c\ub2e4. \uc774\ub97c \uc704\ubc18\ud558\uba74 \uc870\uc0ac\ubc29\ud574\uc5d0 \ud574\ub2f9\ud558\uc5ec \ubcc4\ub3c4\uc758 \uc81c\uc7ac \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.Zh,B.Yl,null)
B.Od=s([u.lt,"\uc601\uc5c5\ube44\ubc00\uc744 \uc774\uc720\ub85c \ub4e4\uba74 \uc5b4\ub5a0\ud55c \uc790\ub8cc\ub3c4 \uc81c\ucd9c\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4","\uc601\uc5c5\ube44\ubc00 \uc5ec\ubd80\ub294 \uc870\uc0ac\uc640 \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub294 \ubb38\uc81c\uc774\ub2e4","\uc601\uc5c5\ube44\ubc00 \uc790\ub8cc\ub294 \uc808\ub300 \uc870\uc0ac \ub300\uc0c1\uc774 \ub420 \uc218 \uc5c6\ub2e4\ub294 \uac83\uc774 \ubc95\ub960\uc0c1 \uba85\ubb38\uc73c\ub85c \uc815\ud574\uc838 \uc788\ub2e4","\uc601\uc5c5\ube44\ubc00\uc744 \uc774\uc720\ub85c \uac70\ubd80\ud558\uba74 \uc870\uc0ac\ubc29\ud574\uc8c4\uac00 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4\ub294 \uac83\uc774 \ud655\ub9bd\ub41c \uc608\uc678\uc774\ub2e4"],t.s)
