B.VN=s(["\uc870\uc0ac\ubc29\ud574\uc5d0 \ud574\ub2f9\ud558\uc5ec \ud1b5\uc0c1\uc758 \ud611\uc870 \uc704\ubc18\ubcf4\ub2e4 \ub354 \uc911\ud558\uac8c \ucde8\uae09\ub420 \uc218 \uc788\ub2e4","\uc790\ub8cc \uc704\uc870\xb7\ubcc0\uc870\ub294 \uc870\uc0ac\ubc29\ud574\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc790\ub8cc\ub97c \uc704\uc870\ud574\ub3c4 \uc81c\ucd9c\ub9cc \ud558\uba74 \ud56d\uc0c1 \ubb38\uc81c\uc5c6\ub2e4","\uc704\uc870\ub41c \uc790\ub8cc \uc81c\ucd9c\uc740 \uc624\ud788\ub824 \uac10\uacbd\uc0ac\uc720\ub85c \uc778\uc815\ub41c\ub2e4","\uc790\ub8cc \uc704\uc870\xb7\ubcc0\uc870\ub294 \uc870\uc0ac\uc808\ucc28\uc640 \ubb34\uad00\ud55c \ubb38\uc81c\uc774\ub2e4"],t.s)
