B.Vo=s(["\ubc18\ubcf5 \uc704\ubc18\uc73c\ub85c\uc11c \uac00\uc911\ub41c \uc81c\uc7ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9\uc740 \uc5b4\ub5a0\ud55c \ubb38\uc81c\ub3c4 \ub418\uc9c0 \uc54a\ub294\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9\uc740 \uc624\ud788\ub824 \uac10\uacbd\uc0ac\uc720\ub85c \uc791\uc6a9\ud55c\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9 \uc5ec\ubd80\ub294 \uc81c\uc7ac \uc218\uc704\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ubc18\ubcf5 \uc0ac\uc6a9\uc740 \ucd5c\ucd08 \uc704\ubc18\ubcf4\ub2e4 \ud56d\uc0c1 \uac00\ubccd\uac8c \ucde8\uae09\ub41c\ub2e4"],t.s)
