B.Y1=s([u.dK,"\uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c0\uba74 \uad00\ub828\ub41c \ubaa8\ub4e0 \uacc4\uc57d\uc774 \uc790\ub3d9\uc73c\ub85c \ubb34\ud6a8\uac00 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58\ub294 \uac1c\ubcc4 \uacc4\uc57d\uc758 \ud6a8\ub825\uacfc \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uac83\uc774\ub2e4","\uc2dc\uc815\uc870\uce58\uac00 \uc788\uc73c\uba74 \ubbfc\uc0ac\uc18c\uc1a1\uc740 \uc804\ud600 \ud544\uc694\ud558\uc9c0 \uc54a\ub2e4","\uc2dc\uc815\uc870\uce58\ub294 \uc0ac\ubc95\uc0c1 \ud6a8\ub825\uc5d0 \uc5b4\ub5a0\ud55c \uc601\ud5a5\ub3c4 \ubbf8\uce60 \uc218 \uc5c6\ub2e4\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4"],t.s)
