B.ZU=s(["\uc2dc\uc815\uba85\ub839\uc5d0 \ub300\ud55c \ubd88\ubcf5\uc808\ucc28"],t.s)
B.aar=new A.f("gen_clause_review_effect_2","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uc870\uce58\uc758 \ud6a8\ub825\xb7\ubd88\ubcf5\uc808\ucc28","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc57d\uad00 \uc2dc\uc815\uba85\ub839\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc0ac\uc5c5\uc790\uac00 \ucde8\ud560 \uc218 \uc788\ub294 \uc808\ucc28\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.X6,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc57d\uad00 \uc2dc\uc815\uba85\ub839\ub3c4 \ud558\ub098\uc758 \ud589\uc815\ucc98\ubd84\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c, \uc774\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc0ac\uc5c5\uc790\ub294 \uc77c\ubc18\uc801\uc778 \ubd88\ubcf5\uc808\ucc28\uc778 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ud589\uc815\ucc98\ubd84\uc5d0 \ub300\ud55c \uc77c\ubc18 \ubc95\ub9ac\uc5d0 \ubd80\ud569\ud55c\ub2e4.",B.a_r,B.ZU,null)
B.R8=s([u.ke,"\uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c0\uba74 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uad8c\uc774 \uc790\ub3d9\uc73c\ub85c \uc18c\uba78\ud55c\ub2e4","\uc2dc\uc815\uc870\uce58\uc640 \uc190\ud574\ubc30\uc0c1\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc808\ucc28\uc774\ub2e4","\uc2dc\uc815\uc870\uce58\uac00 \uc788\uc73c\uba74 \uace0\uac1d\uc740 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc5c6\ub2e4\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4","\uc190\ud574\ubc30\uc0c1 \uccad\uad6c\ub294 \uc2dc\uc815\uc870\uce58\uac00 \ud655\uc815\ub41c \uc774\ud6c4\uc5d0\ub9cc \uac00\ub2a5\ud558\ub2e4\ub294 \uac83\uc774 \uc808\ub300\uc801 \uc6d0\uce59\uc774\ub2e4"],t.s)
