B.a7l=new A.f("gen_clause_review_effect_3","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uc870\uce58\uc758 \ud6a8\ub825\xb7\ubd88\ubcf5\uc808\ucc28","\uc57d\uad00 \uc2dc\uc815\uc808\ucc28\uc640 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.R8,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\ub294 \ud589\uc815\uc801 \uc81c\uc7ac\ub97c \ubaa9\uc801\uc73c\ub85c \ud558\ub294 \uac83\uc73c\ub85c, \uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc84c\ub294\uc9c0 \uc5ec\ubd80\uc640\ub294 \ubcc4\uac1c\ub85c \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc73c\ub85c \uc778\ud574 \uc2e4\uc81c \ud53c\ud574\ub97c \uc785\uc740 \uace0\uac1d\uc740 \ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\uc73c\uba70, \ub450 \uc808\ucc28\ub294 \ubcd1\uc874\ud560 \uc218 \uc788\ub2e4.",B.a2_,B.UI,null)
B.Zo=s([u.dS,"\uc2dc\uc815\uc870\uce58\ub97c \ubc1b\uc544\ub3c4 \uc5b4\ub5a0\ud55c \ud6c4\uc18d \ubb38\uc81c\ub3c4 \ubc1c\uc0dd\ud558\uc9c0 \uc54a\ub294\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58\ub294 \uac00\ub9f9\uacc4\uc57d\uc11c\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58\ub97c \ubc1b\uc73c\uba74 \uac00\ub9f9\uacc4\uc57d\uc774 \uc790\ub3d9\uc73c\ub85c \uc804\ubd80 \ubb34\ud6a8\uac00 \ub41c\ub2e4\uace0\ub9cc \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc2dc\uc815\uc870\uce58 \uad00\ub828 \ub9ac\uc2a4\ud06c\ub294 \uc790\ubb38\ud560 \ud544\uc694\uac00 \uc5c6\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4"],t.s)
