B.acC=new A.f("gen_clause_review_effect_4","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2dc\uc815\uc870\uce58\uc758 \ud6a8\ub825\xb7\ubd88\ubcf5\uc808\ucc28","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \uc57d\uad00(\uac00\ub9f9\uacc4\uc57d\uc11c) \uc2dc\uc815 \uad00\ub828 \ub9ac\uc2a4\ud06c\ub97c \uc790\ubb38\ud560 \ub54c \uac15\uc870\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Zo,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \uc790\ubb38\ud560 \ub54c, \uac00\ub9f9\uacc4\uc57d\uc11c(\uc57d\uad00) \uc870\ud56d\uc774 \uc2dc\uc815\uc870\uce58\ub97c \ubc1b\uc73c\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815\uc801 \uc81c\uc7ac\uc5d0 \uadf8\uce58\uc9c0 \uc54a\uace0 \uac1c\ubcc4 \uac00\ub9f9\uc810\uacfc\uc758 \ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1 \ubd84\uc7c1 \ub4f1 \ucd94\uac00\uc801\uc778 \ub9ac\uc2a4\ud06c\ub85c \uc774\uc5b4\uc9c8 \uc218 \uc788\ub2e4\ub294 \uc810\uc744 \ud568\uaed8 \uc548\ub0b4\ud558\uc5ec \uc885\ud569\uc801\uc778 \ub9ac\uc2a4\ud06c \uad00\ub9ac\ub97c \ub3d5\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4.",B.RJ,B.ng,null)
B.TM=s([u.fr,"\uc624\uc9c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc704\uc6d0\uc758 \uac1c\uc778 \uc2e0\uc0c1 \uc815\ubcf4\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\uc640 \ubb34\uad00\ud55c \uc138\ubc95 \uaddc\uc815\ub9cc \ucd9c\uc81c\ub41c\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\ub294 \uc804\ud600 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc624\uc9c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccad\uc0ac\uc758 \uc704\uce58\ub9cc \ubb3b\ub294 \ubb38\uc81c\ub9cc \ucd9c\uc81c\ub41c\ub2e4"],t.s)
