B.a9w=new A.f("gen_clause_review_exam_1","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uac00\ub9f9\uac70\ub798\uc0ac \uc2dc\ud5d8\uc5d0\uc11c \uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\uac00 \uc790\uc8fc \ub2e4\ub8e8\ub294 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.TM,0,"\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\ub294 \uc2ec\uc0ac\uccad\uad6c\uad8c\uc790\uc640 \uc9c1\uad8c\uc2ec\uc0ac\uc758 \uc778\uc815, \uc2dc\uc815\uad8c\uace0\uc640 \uc2dc\uc815\uba85\ub839\uc758 \uad6c\ubcc4, \uadf8\ub9ac\uace0 \uc2dc\uc815\uc870\uce58\uac00 \uac1c\ubcc4 \uacc4\uc57d\uc758 \uc0ac\ubc95\uc0c1 \ud6a8\ub825\uc774\ub098 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uacfc \uc5b4\ub5a4 \uad00\uacc4\ub97c \uac16\ub294\uc9c0\ub77c\ub294 \ud575\uc2ec \ucd95\uc744 \uc911\uc2ec\uc73c\ub85c \ucd9c\uc81c\ub418\ub294 \uacbd\ud5a5\uc774 \uc788\ub2e4.",B.U4,B.fB,null)
B.HZ=s([u.m_,"\ub450 \ud30c\ud2b8\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \ub2e4\ub8e8\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \ud30c\ud2b8\ub294 \ubb34\ud6a8\uc0ac\uc720\uc640 \uc804\ud600 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \ubc95\ub960\uc5d0 \uadfc\uac70\ud55c\ub2e4","\ubb34\ud6a8\uc0ac\uc720 \ud30c\ud2b8\ub9cc \uc2dc\ud5d8\uc5d0 \ucd9c\uc81c\ub418\uace0 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\ub294 \ucd9c\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\ub294 \ud615\uc0ac\uc808\ucc28\ub9cc\uc744 \ub2e4\ub8e8\ub294 \ud30c\ud2b8\uc774\ub2e4"],t.s)
