B.ae3=new A.f("gen_clause_review_exam_2","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\uc640 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720 \ud30c\ud2b8\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.HZ,0,'\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720 \ud30c\ud2b8\uac00 "\uc5b4\ub5a4 \ub0b4\uc6a9\uc758 \uc57d\uad00 \uc870\ud56d\uc774 \ubd88\uacf5\uc815\ud558\uc5ec \ubb34\ud6a8\uc778\uac00"\ub77c\ub294 \uc2e4\uccb4\uc801 \ud310\ub2e8\uae30\uc900\uc744 \ub2e4\ub8ec\ub2e4\uba74, \uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \ud30c\ud2b8\ub294 "\uadf8\ub7ec\ud55c \ubd88\uacf5\uc815\uc131\uc744 \ub204\uac00 \ubb38\uc81c \uc81c\uae30\ud558\uace0(\uc2ec\uc0ac\uccad\uad6c\xb7\uc9c1\uad8c\uc2ec\uc0ac), \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc5b4\ub5bb\uac8c \ud655\uc778\xb7\uc2dc\uc815\ud558\ub294\uac00(\uc2dc\uc815\uad8c\uace0\xb7\uc2dc\uc815\uba85\ub839)"\ub77c\ub294 \uc808\ucc28\uc801 \uce21\uba74\uc744 \ub2e4\ub8ec\ub2e4\ub294 \uc810\uc5d0\uc11c \uc11c\ub85c \ubcf4\uc644\uc801\uc778 \uad00\uacc4\uc5d0 \uc788\ub2e4.',B.UT,B.Jr,null)
B.JP=s(["\uc2dc\uc815\uad8c\uace0\uc640 \uc2dc\uc815\uba85\ub839\uc758 \ud6a8\ub825\xb7\uac15\uc81c\uc131 \ucc28\uc774\ub97c \uc11c\ub85c \ub4a4\ubc14\uafb8\uc5b4 \uc81c\uc2dc\ud558\ub294 \uc120\ud0dd\uc9c0","\uac00\ub9f9\uacc4\uc57d\uc11c\uc758 \ud3f0\ud2b8 \ud06c\uae30\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccad\uc0ac\uc758 \uce35\uc218\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc704\uc6d0\uc7a5\uc758 \uac1c\uc778 \ucde8\ubbf8\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0","\uc2ec\uc0ac\uccad\uad6c \uc811\uc218 \ucc3d\uad6c\uc758 \uc8fc\uc18c\ub97c \ubb3b\ub294 \uc120\ud0dd\uc9c0"],t.s)
