B.ad5=new A.f("gen_clause_review_exam_3","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \ubb38\uc81c\uc5d0\uc11c \uc790\uc8fc \ucd9c\uc81c\ub418\ub294 \ud568\uc815 \uc720\ud615\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.JP,0,"\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \ubb38\uc81c\uc5d0\uc11c\ub294 \uc2dc\uc815\uad8c\uace0(\uc644\ud654\ub41c \uc870\uce58)\uc640 \uc2dc\uc815\uba85\ub839(\uac15\uc81c\ub418\ub294 \uc870\uce58)\uc758 \ud6a8\ub825\xb7\uac15\uc81c\uc131 \ucc28\uc774\ub97c \uc11c\ub85c \ub4a4\ubc14\uafb8\uc5b4 \uc81c\uc2dc\ud558\uac70\ub098, \uc9c1\uad8c\uc2ec\uc0ac\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\ub294 \uac83\ucc98\ub7fc \uc11c\uc220\ud558\ub294 \ub4f1\uc758 \uc120\ud0dd\uc9c0\uac00 \ud568\uc815\uc73c\ub85c \uc790\uc8fc \ucd9c\uc81c\ub418\ubbc0\ub85c \uac1c\ub150\uc744 \uc815\ud655\ud788 \uad6c\ubcc4\ud574 \ub450\uc5b4\uc57c \ud55c\ub2e4.",B.Rr,B.a1f,null)
B.a1o=s([u.lO,"\uac00\ub9f9\uacc4\uc57d\uc11c\ub97c \uc804\ud600 \uac80\ud1a0\ud558\uc9c0 \uc54a\uace0 \uc11c\uba85\ub9cc \ub300\ud589\ud558\ub294 \uc7a5\uba74","\uac00\ub9f9\uc810\uc758 \uc138\uae08 \uc2e0\uace0\ub9cc\uc744 \ub300\ud589\ud558\ub294 \uc7a5\uba74","\uac00\ub9f9\ubcf8\ubd80\uc758 \uc778\uc0ac \ubb38\uc81c\ub9cc\uc744 \uc790\ubb38\ud558\ub294 \uc7a5\uba74","\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28\uc640 \uad00\ub828\ud558\uc5ec \uc5b4\ub5a0\ud55c \uc2e4\ubb34\ub3c4 \uc218\ud589\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
