B.K7=s([u.ka,"\uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758\ub294 \uc57d\uad00 \uc0ac\uac74\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uc808\ucc28\uc774\ub2e4","\uc2ec\uc758\ub294 \ud56d\uc0c1 \uc704\uc6d0\uc7a5 1\uc778\uc758 \ub2e8\ub3c5 \uacb0\uc815\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4\ub2e4","\uc804\uc6d0\ud68c\uc758\xb7\uc18c\ud68c\uc758\ub294 \uc624\uc9c1 \ud615\uc0ac\uc0ac\uac74\uc5d0\uc11c\ub9cc \uc5f4\ub9b0\ub2e4","\uc2ec\uc758 \uc808\ucc28\ub294 \uc0ac\uc5c5\uc790\uc758 \ucc38\uc5ec\ub97c \uc644\uc804\ud788 \ubc30\uc81c\ud55c \ucc44 \uc9c4\ud589\ub41c\ub2e4"],t.s)
