B.adt=new A.f("gen_clause_review_exam_8","economic_law","\uc57d\uad00 \uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28","\uc2ec\uc0ac\xb7\uc2dc\uc815\uc808\ucc28 \uad00\ub828 \uc2dc\ud5d8 \ud3ec\uc778\ud2b8","\uc57d\uad00 \uc2dc\uc815\uc808\ucc28\uc640 \ucc98\ubd84\uc2dc\ud6a8\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.OA,0,"\uc57d\uad00 \uc2dc\uc815 \uc0ac\uac74\ub3c4 \ub2e4\ub978 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \ucc98\ubd84\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \ubc95\ub960\uad00\uacc4\uc758 \uc548\uc815\uc744 \uc704\ud574 \uc77c\uc815\ud55c \ucc98\ubd84\uc2dc\ud6a8\uc758 \uc81c\ud55c\uc744 \ubc1b\uc73c\uba70, \uadf8 \uae30\uac04\uc774 \uc9c0\ub098\uba74 \uc6d0\uce59\uc801\uc73c\ub85c \uc2dc\uc815\uba85\ub839 \ub4f1\uc758 \ucc98\ubd84\uc774 \uc81c\ud55c\ub420 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \uc81c\ub3c4\uc758 \uc77c\ubc18 \uc6d0\uce59\uc774\ub2e4.",B.Mr,B.XX,null)
B.II=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub97c \ubc1b\uace0 \uc788\ub294 \uc0ac\uc5c5\uc790\ub294 \uc870\uc0ac \ub300\uc0c1 \ud589\uc704\ub85c \uc778\ud55c \uacbd\uc7c1\uc81c\ud55c\uc0c1\ud0dc\uc758 \uc790\ubc1c\uc801 \ud574\uc18c\ub97c \uc704\ud558\uc5ec \ub3d9\uc758\uc758\uacb0\uc744 \uc2e0\uccad\ud560 \uc218 \uc788\ub2e4","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \ub3d9\uc758\uc758\uacb0\uc744 \ud560 \uc218 \uc5c6\ub2e4","\ub3d9\uc758\uc758\uacb0\uc740 \ud574\ub2f9 \ud589\uc704\uac00 \uc774 \ubc95\uc5d0 \uc704\ubc18\ub41c\ub2e4\uace0 \uc778\uc815\ud55c \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub3d9\uc758\uc758\uacb0\uc744 \uc774\ud589\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \uacbd\uc6b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub3d9\uc758\uc758\uacb0\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \uc788\uae30 \uc804\uc774\ub77c\ub3c4 \uc2e0\uccad\uc778\uc740 \uc2e0\uccad\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Zt=s(["\ub3d9\uc758\uc758\uacb0\uc740 \uc624\ud788\ub824 \uc704\ubc95\uc131 \uc5ec\ubd80\ub97c \ud655\uc815\ud558\uc9c0 \uc54a\uace0 \uc808\ucc28\ub97c \uc870\uae30\uc5d0 \uc885\uacb0\ud558\ub294 \uac83\uc774 \ud575\uc2ec \ucde8\uc9c0"],t.s)
B.Mc=s(["\ub3d9\uc758\uc758\uacb0\uc81c\ub3c4"],t.s)
B.a6T=new A.f("gen_pc_1","economic_law","\ub3d9\uc758\uc758\uacb0",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ub3d9\uc758\uc758\uacb0\uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.II,2,'\ub3d9\uc758\uc758\uacb0 \uc81c\ub3c4(\uacf5\uc815\uac70\ub798\ubc95 \uc81c89\uc870~\uc81c91\uc870)\ub294 \uc870\uc0ac\ub97c \ubc1b\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \uc2dc\uc815\ubc29\uc548\uc744 \ub9c8\ub828\ud574 \uc81c\ucd9c\ud558\uba74, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc704\ubc95 \uc5ec\ubd80\ub97c \ud655\uc815 \uc9d3\uc9c0 \uc54a\uc740 \ucc44 \uadf8 \uc2dc\uc815\ubc29\uc548\uacfc \uac19\uc740 \ucde8\uc9c0\ub85c \uc758\uacb0\ud558\uc5ec \uc0ac\uac74\uc744 \uc2e0\uc18d\ud558\uac8c \uc885\uacb0\ud558\ub294 \uc81c\ub3c4\uc774\ub2e4. \ub530\ub77c\uc11c "\ub3d9\uc758\uc758\uacb0\uc740 \ud574\ub2f9 \ud589\uc704\uac00 \ubc95\uc5d0 \uc704\ubc18\ub41c\ub2e4\uace0 \uc778\uc815\ud55c \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4 \u2014 \ub3d9\uc758\uc758\uacb0\uc740 \uc624\ud788\ub824 \uc704\ubc95\uc131 \uc5ec\ubd80\ub97c \ud655\uc815\ud558\uc9c0 \uc54a\uace0 \uc808\ucc28\ub97c \uc870\uae30\uc5d0 \uc885\uacb0\ud558\ub294 \uac83\uc774 \ud575\uc2ec \ucde8\uc9c0\uc774\uae30 \ub54c\ubb38\uc774\ub2e4. \ub2e4\ub9cc \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\ub2f4\ud569)\ucc98\ub7fc \uc0ac\ud68c\uc801 \ud3d0\ud574\uac00 \ud070 \ud589\uc704\ub294 \ub3d9\uc758\uc758\uacb0 \ub300\uc0c1\uc5d0\uc11c \uc6d0\uce59\uc801\uc73c\ub85c \uc81c\uc678\ub418\uba70, \uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc774\ud589\ud558\uc9c0 \uc54a\uc73c\uba74 \uacf5\uc815\uc704\uac00 \ub3d9\uc758\uc758\uacb0\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4\ub294 \uc810\ub3c4 \ud568\uaed8 \uae30\uc5b5\ud574\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.Zt,B.Mc,null)
B.Sf=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc95 \uc704\ubc18 \uc0ac\uc5c5\uc790\uac00 \ud569\ubcd1\uc73c\ub85c \uc18c\uba78\ud55c \uacbd\uc6b0 \uc874\uc18d\ud558\ub294 \ud68c\uc0ac\uc5d0 \ub300\ud558\uc5ec \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\xb7\uc9d5\uc218\ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ubc1b\uc740 \ud68c\uc0ac\uac00 \ubd84\ud560\ub418\ub294 \uacbd\uc6b0 \ubd84\ud560\ub418\ub294 \ud68c\uc0ac\uc640 \uc2e0\uc124\ud68c\uc0ac\ub294 \uadf8 \uacfc\uc9d5\uae08\uc744 \uc5f0\ub300\ud558\uc5ec \ub0a9\ubd80\ud560 \ucc45\uc784\uc744 \uc9c4\ub2e4","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uc758\ubb34\uc790\uac00 \ubb34\uc790\ub825\uc774 \ub418\uc5b4 \uc9d5\uc218\uac00 \ubd88\uac00\ub2a5\ud574\uc9c4 \uacbd\uc6b0 \uacb0\uc190\ucc98\ubd84\uc744 \ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uae30\ud55c\uc758 \uc5f0\uae30\ub97c \uc2e0\uccad\ud558\ub824\ub294 \uc790\ub294 \ub0a9\ubd80\ud1b5\uc9c0\ub97c \ubc1b\uc740 \ub0a0\ubd80\ud130 60\uc77c \uc774\ub0b4\uc5d0 \uc2e0\uccad\ud558\uc5ec\uc57c \ud55c\ub2e4","\uacfc\uc9d5\uae08\uc740 \ud615\ubc8c\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c \ub3d9\uc77c\ud55c \ud589\uc704\uc5d0 \ub300\ud558\uc5ec \ubc8c\uae08\uacfc \uacfc\uc9d5\uae08\uc744 \ud568\uaed8 \ubd80\uacfc\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.HQ=s(["\uacfc\uc9d5\uae08\uc740 \ud615\uc0ac\ucc98\ubc8c\uc774 \uc544\ub2c8\ub77c \ubc95 \uc704\ubc18\uc73c\ub85c \uc5bb\uc740 \ubd80\ub2f9\uc774\ub4dd\uc744 \ud658\uc218\ud558\uace0 \uc704\ubc18\ud589\uc704\ub97c \uc5b5\uc9c0\ud558\uae30 \uc704\ud55c \ud589\uc815\uc81c\uc7ac"],t.s)
B.VZ=s(["\uacfc\uc9d5\uae08\uc758 \ubc95\uc801 \uc131\uc9c8"],t.s)
B.aaO=new A.f("gen_pc_2","economic_law","\uacfc\uc9d5\uae08",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacfc\uc9d5\uae08\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Sf,4,"\uacfc\uc9d5\uae08\uc740 \ud615\uc0ac\ucc98\ubc8c\uc774 \uc544\ub2c8\ub77c \ubc95 \uc704\ubc18\uc73c\ub85c \uc5bb\uc740 \ubd80\ub2f9\uc774\ub4dd\uc744 \ud658\uc218\ud558\uace0 \uc704\ubc18\ud589\uc704\ub97c \uc5b5\uc9c0\ud558\uae30 \uc704\ud55c \ud589\uc815\uc81c\uc7ac(\ud589\uc815\uc0c1 \uc81c\uc7ac\uae08)\uc758 \uc131\uaca9\uc744 \uac16\ub294\ub2e4\ub294 \uac83\uc774 \ub300\ubc95\uc6d0 \ubc0f \ud5cc\ubc95\uc7ac\ud310\uc18c\uc758 \uc77c\uad00\ub41c \uc785\uc7a5\uc774\ub2e4. \ub530\ub77c\uc11c \ub3d9\uc77c\ud55c \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud574 \ud615\uc0ac\ucc98\ubc8c(\ubc8c\uae08)\uacfc \uacfc\uc9d5\uae08\uc774 \ud568\uaed8 \ubd80\uacfc\ub418\ub354\ub77c\ub3c4, \uc774\ub294 \uc131\uc9c8\uc774 \ub2e4\ub978 \ubcc4\uac1c\uc758 \uc81c\uc7ac\ub97c \ubcd1\uacfc\ud558\ub294 \uac83\uc774\ubbc0\ub85c \uc774\uc911\ucc98\ubc8c\uae08\uc9c0\uc6d0\uce59\uc5d0 \uc704\ubc18\ub418\uc9c0 \uc54a\ub294\ub2e4. \ubc18\uba74 \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0\ub4e4 \u2014 \ud569\ubcd1\xb7\ubd84\ud560 \uc2dc \uacfc\uc9d5\uae08 \uc2b9\uacc4, \ubb34\uc790\ub825\uc5d0 \ub530\ub978 \uacb0\uc190\ucc98\ubd84, 60\uc77c \uc774\ub0b4 \ub0a9\ubd80\uae30\ud55c \uc5f0\uae30 \uc2e0\uccad \u2014 \uc740 \ubaa8\ub450 \uacf5\uc815\uac70\ub798\ubc95\ub839\uc0c1 \uc2e4\uc81c\ub85c \uc778\uc815\ub418\ub294 \uc81c\ub3c4\uc774\ubbc0\ub85c \uc633\uc740 \uc124\uba85\uc774\ub2e4.",B.HQ,B.VZ,null)
B.IL=s([u.n0,"\uacfc\uc9d5\uae08\uc740 \uc624\ub85c\uc9c0 \uad6d\uac00 \uc7ac\uc815 \ud655\ucda9\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4","\uacfc\uc9d5\uae08\uc740 \ud53c\ud574\uc790\uc5d0 \ub300\ud55c \uc190\ud574\ubc30\uc0c1\uc744 \ub300\uc2e0\ud558\ub294 \uc81c\ub3c4\uc774\ub2e4","\uacfc\uc9d5\uae08\uc740 \ud615\uc0ac\ucc98\ubc8c\uc744 \uc644\uc804\ud788 \ub300\uccb4\ud558\uae30 \uc704\ud55c \uc81c\ub3c4\uc774\ub2e4","\uacfc\uc9d5\uae08\uc740 \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\ud65c\ub3d9\uc744 \uc804\uba74 \uae08\uc9c0\ud558\uae30 \uc704\ud55c \uc218\ub2e8\uc774\ub2e4"],t.s)
B.a0B=s([u.n0],t.s)
B.T6=s(["\uacfc\uc9d5\uae08 \uc81c\ub3c4\uc758 \ubaa9\uc801"],t.s)
B.abj=new A.f("gen_pc_nature_1","economic_law","\uacfc\uc9d5\uae08","\uacfc\uc9d5\uae08\uc758 \ubc95\uc801 \uc131\uc9c8","\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uacfc\uc9d5\uae08 \uc81c\ub3c4\uc758 \ubaa9\uc801\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.IL,0,"\uacfc\uc9d5\uae08 \uc81c\ub3c4\ub294 \ubc95 \uc704\ubc18\ud589\uc704\ub85c \uc0ac\uc5c5\uc790\uac00 \uc5bb\uc740 \ubd80\ub2f9\ud55c \uacbd\uc81c\uc801 \uc774\uc775\uc744 \ud658\uc218\ud558\uace0, \uc7a5\ub798\uc5d0 \uc720\uc0ac\ud55c \uc704\ubc18\ud589\uc704\uac00 \uc7ac\ubc1c\ud558\uc9c0 \uc54a\ub3c4\ub85d \uc5b5\uc9c0\ud558\ub294 \ub370 \uc8fc\ub41c \ubaa9\uc801\uc774 \uc788\ub294 \ud589\uc815\uc81c\uc7ac \uc218\ub2e8\uc774\ub2e4. \ud53c\ud574\uc790\uc5d0 \ub300\ud55c \uc190\ud574\ubc30\uc0c1\uc740 \ubcc4\ub3c4\uc758 \ubbfc\uc0ac\uc808\ucc28\ub97c \ud1b5\ud574 \uc774\ub8e8\uc5b4\uc9c0\uba70, \uacfc\uc9d5\uae08\uc774 \ud615\uc0ac\ucc98\ubc8c\uc744 \ub300\uccb4\ud558\uac70\ub098 \uc601\uc5c5 \uc790\uccb4\ub97c \uae08\uc9c0\ud558\ub294 \uc81c\ub3c4\ub294 \uc544\ub2c8\ub2e4.",B.a0B,B.T6,null)
B.a_x=s([u.a9,"\uacfc\uc9d5\uae08\uacfc \ubc8c\uae08\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc131\uc9c8\uc774\ubbc0\ub85c \ud568\uaed8 \ubd80\uacfc\ud558\uba74 \uc774\uc911\ucc98\ubc8c\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uacfc\uc9d5\uae08\uc774 \ubd80\uacfc\ub418\uba74 \ubc8c\uae08\uc740 \ud56d\uc0c1 \uc790\ub3d9\uc73c\ub85c \uba74\uc81c\ub41c\ub2e4","\ubc8c\uae08\uc774 \ud655\uc815\ub418\uba74 \uacfc\uc9d5\uae08\uc740 \uc790\ub3d9\uc73c\ub85c \ucde8\uc18c\ub418\uc5b4\uc57c \ud55c\ub2e4","\uacfc\uc9d5\uae08\uacfc \ubc8c\uae08\uc758 \ubcd1\uacfc\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.GH=s([u.a9],t.s)
B.Y9=s(["\uacfc\uc9d5\uae08\uacfc \ubc8c\uae08\uc758 \ubcd1\uacfc"],t.s)
B.a9B=new A.f("gen_pc_nature_2","economic_law","\uacfc\uc9d5\uae08","\uacfc\uc9d5\uae08\uc758 \ubc95\uc801 \uc131\uc9c8","\uacfc\uc9d5\uae08\uacfc \ud615\uc0ac\ucc98\ubc8c(\ubc8c\uae08)\uc758 \ubcd1\uacfc\uc5d0 \uad00\ud55c \ud310\ub840\xb7\ud1b5\uc124\uc758 \uc785\uc7a5\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_x,0,"\ud310\ub840\uc640 \ud1b5\uc124\uc740 \uacfc\uc9d5\uae08\uc744 \ud589\uc815\uc0c1 \uc81c\uc7ac\uae08\uc73c\ub85c, \ubc8c\uae08\uc744 \ud615\uc0ac\ucc98\ubc8c\ub85c \uac01\uac01 \uc131\uc9c8\uc774 \ub2e4\ub978 \uc81c\uc7ac\ub85c \ud30c\uc545\ud558\uc5ec, \ub3d9\uc77c\ud55c \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud574 \uacfc\uc9d5\uae08\uacfc \ubc8c\uae08\uc774 \ud568\uaed8 \ubd80\uacfc\ub418\ub354\ub77c\ub3c4 \uc774\uc911\ucc98\ubc8c\uae08\uc9c0\uc6d0\uce59\uc5d0 \uc704\ubc18\ub418\uc9c0 \uc54a\ub294\ub2e4\uace0 \ubcf8\ub2e4. \ub450 \uc81c\uc7ac\ub294 \uac01\uac01 \ub3c5\ub9bd\uc801\uc778 \uc694\uac74\uacfc \uc808\ucc28\uc5d0 \ub530\ub77c \ubd80\uacfc\ub418\uba70 \uc11c\ub85c \uc790\ub3d9\uc73c\ub85c \ub300\uccb4\ub418\uac70\ub098 \uba74\uc81c\ub418\ub294 \uad00\uacc4\uac00 \uc544\ub2c8\ub2e4.",B.GH,B.Y9,null)
B.Kw=s([u.c2,"\uc704\ubc18\ud589\uc704\uac00 \uc778\uc815\ub418\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc18\ub4dc\uc2dc \uc0c1\ud55c\uc561 \uc804\ubd80\ub97c \ubd80\uacfc\ud574\uc57c \ud55c\ub2e4","\uacfc\uc9d5\uae08 \ubd80\uacfc\ub294 \ubc95\uc6d0\uc774 \uc804\uc801\uc73c\ub85c \uacb0\uc815\ud558\ub294 \uc0ac\ud56d\uc774\ub2e4","\uacfc\uc9d5\uae08 \ubd80\uacfc \uc5ec\ubd80\ub294 \uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \ud76c\ub9dd\uc5d0 \ub530\ub77c \uacb0\uc815\ub41c\ub2e4","\uacfc\uc9d5\uae08\uc740 \uc704\ubc18\ud589\uc704\uc640 \ubb34\uad00\ud558\uac8c \ub9e4\ub144 \uc815\uae30\uc801\uc73c\ub85c \ubd80\uacfc\ub41c\ub2e4"],t.s)
B.Y0=s([u.c2],t.s)
