B.adH=new A.f("gen_pc_nature_3","economic_law","\uacfc\uc9d5\uae08","\uacfc\uc9d5\uae08\uc758 \ubc95\uc801 \uc131\uc9c8","\uacfc\uc9d5\uae08 \ubd80\uacfc\uac00 \uc7ac\ub7c9\ud589\uc704\uc778\uc9c0 \uae30\uc18d\ud589\uc704\uc778\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Kw,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc704\ubc18\ud589\uc704\uc758 \ub0b4\uc6a9\xb7\uc815\ub3c4\xb7\uae30\uac04\xb7\uc774\uc775\uaddc\ubaa8 \ub4f1 \uc5ec\ub7ec \uc694\uc18c\ub97c \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\uc5ec \uacfc\uc9d5\uae08 \ubd80\uacfc \uc5ec\ubd80\uc640 \uad6c\uccb4\uc801 \uae08\uc561\uc744 \uc815\ud558\ub294 \uc7ac\ub7c9\uc744 \uac16\ub294\ub2e4. \ub2e4\ub9cc \uc774\ub7ec\ud55c \uc7ac\ub7c9\uc740 \ubb34\uc81c\ud55c\uc774 \uc544\ub2c8\ub77c \ubc95\ub839\uc774 \uc815\ud55c \uc0b0\uc815\uae30\uc900\uacfc \ud55c\ub3c4 \ub0b4\uc5d0\uc11c \ud589\uc0ac\ub418\uc5b4\uc57c \ud558\uba70, \uadf8 \uc7ac\ub7c9\uad8c \ud589\uc0ac\uac00 \ud604\uc800\ud788 \ubd80\ub2f9\ud558\uba74 \uc0ac\ubc95\uc2ec\uc0ac\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.Y0,B.WB,null)
