B.U0=s(["\uc77c\uc815\ud55c \uc0ac\uc720\uac00 \uc788\ub294 \uacbd\uc6b0 \ub0a9\ubd80\uae30\ud55c\uc758 \uc5f0\uc7a5\uc774\ub098 \ubd84\ud560\ub0a9\ubd80\ub97c \uc2e0\uccad\ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubd84\ud560\ub0a9\ubd80\uac00 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ub0a9\ubd80\uae30\ud55c \uc5f0\uc7a5 \uc2e0\uccad\uc5d0\ub294 \uc544\ubb34\ub7f0 \uae30\ud55c \uc81c\ud55c\uc774 \uc5c6\ub2e4","\ubd84\ud560\ub0a9\ubd80\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \ud5c8\uc6a9\ub41c\ub2e4","\ub0a9\ubd80\uae30\ud55c \uc5f0\uc7a5\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2b9\uc778 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uac00 \uc784\uc758\ub85c \uacb0\uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
