B.a73=new A.f("gen_pc_transfer_1","economic_law","\uacfc\uc9d5\uae08","\uc2b9\uacc4\xb7\uc9d5\uc218\xb7\uacb0\uc190\ucc98\ubd84","\ubc95 \uc704\ubc18 \uc0ac\uc5c5\uc790\uac00 \ud569\ubcd1\uc73c\ub85c \uc18c\uba78\ud55c \uacbd\uc6b0 \uacfc\uc9d5\uae08 \ubd80\uacfc\xb7\uc9d5\uc218\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.W2,0,"\uc704\ubc18\uc0ac\uc5c5\uc790\uac00 \ud569\ubcd1\uc73c\ub85c \uc18c\uba78\ud55c \uacbd\uc6b0, \uadf8 \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08 \ucc45\uc784\uc774 \ud569\ubcd1\uc73c\ub85c \uc778\ud574 \uc18c\uba78\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \ud569\ubcd1 \ud6c4 \uc874\uc18d\ud558\ub294 \ud68c\uc0ac\ub098 \uc0c8\ub85c \uc124\ub9bd\ub41c \ud68c\uc0ac\uac00 \uc774\ub97c \uc2b9\uacc4\ud558\uc5ec \ubd80\uacfc\xb7\uc9d5\uc218\uc758 \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4. \uc774\ub294 \ud569\ubcd1\uc744 \ud1b5\ud55c \ucc45\uc784\ud68c\ud53c\ub97c \ubc29\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4.",B.OD,B.a0I,null)
B.a1y=s(["\ubd84\ud560\ub418\ub294 \ud68c\uc0ac\uc640 \uc2e0\uc124\ud68c\uc0ac\uac00 \uadf8 \uacfc\uc9d5\uae08\uc744 \uc5f0\ub300\ud558\uc5ec \ub0a9\ubd80\ud560 \ucc45\uc784\uc744 \uc9c4\ub2e4","\ubd84\ud560\ub418\uba74 \uacfc\uc9d5\uae08 \ucc45\uc784\uc740 \uc790\ub3d9\uc73c\ub85c \uc18c\uba78\ud55c\ub2e4","\ubd84\ud560 \ud6c4\uc5d0\ub294 \uc624\uc9c1 \uc2e0\uc124\ud68c\uc0ac\ub9cc \ub2e8\ub3c5\uc73c\ub85c \ucc45\uc784\uc744 \uc9c4\ub2e4","\ubd84\ud560 \ud6c4\uc5d0\ub294 \uc624\uc9c1 \ubd84\ud560\ub418\ub294 \ud68c\uc0ac\ub9cc \ub2e8\ub3c5\uc73c\ub85c \ucc45\uc784\uc744 \uc9c4\ub2e4","\ubd84\ud560 \uc2dc \uacfc\uc9d5\uae08 \ucc45\uc784\uc740 \uc8fc\uc8fc \uac1c\uc778\uc5d0\uac8c \uc774\uc804\ub41c\ub2e4"],t.s)
B.PW=s(["\ubd84\ud560\ub418\ub294 \ud68c\uc0ac\uc640 \uc2e0\uc124\ud68c\uc0ac\uac00 \uadf8 \uacfc\uc9d5\uae08\uc744 \uc5f0\ub300\ud558\uc5ec \ub0a9\ubd80\ud560 \ucc45\uc784\uc744 \uc9c4\ub2e4"],t.s)
B.Ju=s(["\ubd84\ud560 \uc2dc \uacfc\uc9d5\uae08 \uc5f0\ub300\ucc45\uc784"],t.s)
B.acQ=new A.f("gen_pc_transfer_2","economic_law","\uacfc\uc9d5\uae08","\uc2b9\uacc4\xb7\uc9d5\uc218\xb7\uacb0\uc190\ucc98\ubd84","\uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ubc1b\uc740 \ud68c\uc0ac\uac00 \ubd84\ud560\ub418\ub294 \uacbd\uc6b0 \uacfc\uc9d5\uae08 \ub0a9\ubd80\ucc45\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a1y,0,"\uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ubc1b\uc740 \ud68c\uc0ac\uac00 \ubd84\ud560\ub418\ub294 \uacbd\uc6b0, \ubd84\ud560\ub418\ub294 \ud68c\uc0ac\uc640 \uadf8\ub85c\ubd80\ud130 \uc2e0\uc124\ub41c \ud68c\uc0ac\uac00 \ud574\ub2f9 \uacfc\uc9d5\uae08\uc744 \uc5f0\ub300\ud558\uc5ec \ub0a9\ubd80\ud560 \ucc45\uc784\uc744 \uc9c0\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774 \uc5ed\uc2dc \ud68c\uc0ac\ubd84\ud560\uc774\ub77c\ub294 \uc870\uc9c1 \uc7ac\ud3b8\uc744 \ud1b5\ud574 \uacfc\uc9d5\uae08 \ucc45\uc784\uc744 \ud68c\ud53c\ud558\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud55c \uc7a5\uce58\uc774\ub2e4.",B.PW,B.Ju,null)
B.a_D=s(["\uc774\ub7ec\ud55c \uacbd\uc6b0 \uacb0\uc190\ucc98\ubd84\uc744 \ud560 \uc218 \uc788\ub2e4","\ubb34\uc790\ub825\uc774 \ub418\ub354\ub77c\ub3c4 \uacfc\uc9d5\uae08\uc740 \uc808\ub300 \uacb0\uc190\ucc98\ubd84\ub420 \uc218 \uc5c6\ub2e4","\ubb34\uc790\ub825\uc774 \ub418\uba74 \uacfc\uc9d5\uae08 \ucc44\uad8c\uc740 \uad6d\uac00\uac00 \uc544\ub2c8\ub77c \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc790\ub3d9 \uc774\uc804\ub41c\ub2e4","\ubb34\uc790\ub825 \uc5ec\ubd80\uc640 \uad00\uacc4\uc5c6\uc774 \ud56d\uc0c1 \uac15\uc81c\uc9d1\ud589\uc774 \uc6b0\uc120\ub41c\ub2e4","\ubb34\uc790\ub825\uc774 \ub418\uba74 \ud615\uc0ac\ucc98\ubc8c\ub85c \uc790\ub3d9 \uc804\ud658\ub41c\ub2e4"],t.s)
B.Rx=s(["\uc774\ub7ec\ud55c \uacbd\uc6b0 \uacb0\uc190\ucc98\ubd84\uc744 \ud560 \uc218 \uc788\ub2e4"],t.s)
B.Hp=s(["\ubb34\uc790\ub825\uacfc \uacb0\uc190\ucc98\ubd84"],t.s)
B.a8s=new A.f("gen_pc_transfer_3","economic_law","\uacfc\uc9d5\uae08","\uc2b9\uacc4\xb7\uc9d5\uc218\xb7\uacb0\uc190\ucc98\ubd84","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uc758\ubb34\uc790\uac00 \ubb34\uc790\ub825\uc774 \ub418\uc5b4 \uc9d5\uc218\uac00 \uc0ac\uc2e4\uc0c1 \ubd88\uac00\ub2a5\ud574\uc9c4 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_D,0,"\uacfc\uc9d5\uae08 \ub0a9\ubd80\uc758\ubb34\uc790\uac00 \ubb34\uc790\ub825\uc774 \ub418\uc5b4 \uc0ac\uc2e4\uc0c1 \uc9d5\uc218\uac00 \ubd88\uac00\ub2a5\ud574\uc9c4 \uacbd\uc6b0\uc5d0\ub294, \ub2e4\ub978 \uc870\uc138\ucc44\uad8c \ub4f1\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc77c\uc815\ud55c \uc808\ucc28\ub97c \uac70\uccd0 \uacb0\uc190\ucc98\ubd84\uc744 \ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \uc9d5\uc218 \uc2e4\uc775\uc774 \uc5c6\ub294 \ucc44\uad8c\uc744 \ud589\uc815\uc801\uc73c\ub85c \uc815\ub9ac\ud558\uae30 \uc704\ud55c \uc81c\ub3c4\uc774\ub2e4.",B.Rx,B.Hp,null)
B.U2=s(["\uccb4\ub0a9\ub41c \uacfc\uc9d5\uae08\uc740 \uad6d\uc138 \uccb4\ub0a9\ucc98\ubd84\uc758 \uc608\uc5d0 \ub530\ub77c \uac15\uc81c\uc9d5\uc218\ub420 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08\uc740 \uccb4\ub0a9\ub418\uc5b4\ub3c4 \uc5b4\ub5a0\ud55c \uac15\uc81c\uc9d1\ud589 \uc218\ub2e8\ub3c4 \uc0ac\uc6a9\ud560 \uc218 \uc5c6\ub2e4","\uacfc\uc9d5\uae08 \uccb4\ub0a9\uc740 \ud56d\uc0c1 \ubbfc\uc0ac\uc18c\uc1a1\uc744 \ud1b5\ud574\uc11c\ub9cc \ud68c\uc218\ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08 \uccb4\ub0a9 \uc2dc\uc5d0\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\ub9cc \uac00\ub2a5\ud558\uace0 \uac15\uc81c\uc9d5\uc218\ub294 \ubd88\uac00\ub2a5\ud558\ub2e4","\uacfc\uc9d5\uae08 \uccb4\ub0a9\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub97c \ud1b5\ud574\uc11c\ub9cc \ud574\uacb0\ub41c\ub2e4"],t.s)
B.Zq=s(["\uccb4\ub0a9\ub41c \uacfc\uc9d5\uae08\uc740 \uad6d\uc138 \uccb4\ub0a9\ucc98\ubd84\uc758 \uc608\uc5d0 \ub530\ub77c \uac15\uc81c\uc9d5\uc218\ub420 \uc218 \uc788\ub2e4"],t.s)
B.PX=s(["\uacfc\uc9d5\uae08 \uccb4\ub0a9\uacfc \uac15\uc81c\uc9d5\uc218"],t.s)
B.a9x=new A.f("gen_pc_transfer_4","economic_law","\uacfc\uc9d5\uae08","\uc2b9\uacc4\xb7\uc9d5\uc218\xb7\uacb0\uc190\ucc98\ubd84","\uacfc\uc9d5\uae08 \ubbf8\ub0a9 \uc2dc \uac15\uc81c\uc9d5\uc218 \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.U2,0,"\uacfc\uc9d5\uae08\uc744 \uae30\ud55c \ub0b4\uc5d0 \ub0a9\ubd80\ud558\uc9c0 \uc54a\ub294 \uacbd\uc6b0, \uad6d\uc138 \uccb4\ub0a9\ucc98\ubd84\uc758 \uc608\uc5d0 \ub530\ub77c \uac15\uc81c\uc9d5\uc218 \uc808\ucc28\uac00 \uc9c4\ud589\ub420 \uc218 \uc788\ub2e4. \uc774\ub294 \uacfc\uc9d5\uae08\uc774 \uc870\uc138\uc640 \uc720\uc0ac\ud558\uac8c \uac15\uc81c\uc801\uc73c\ub85c \uc9d5\uc218\ub420 \uc218 \uc788\ub294 \uacf5\ubc95\uc0c1 \uae08\uc804\ucc44\uad8c\uc73c\ub85c\uc11c\uc758 \uc131\uaca9\uc744 \uac00\uc9c0\uae30 \ub54c\ubb38\uc774\ub2e4.",B.Zq,B.PX,null)
B.Hj=s([u.jq,"\ub0a9\ubd80\uae30\ud55c \uc5f0\uae30 \uc2e0\uccad\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uae30\uac04 \uc81c\ud55c\ub3c4 \uc5c6\ub2e4","\ub0a9\ubd80\uae30\ud55c \uc5f0\uae30\ub294 \uc2e0\uccad \uc989\uc2dc \uc790\ub3d9\uc73c\ub85c \uc778\uc815\ub41c\ub2e4","\ub0a9\ubd80\uae30\ud55c \uc5f0\uae30 \uc2e0\uccad\uc740 \uacfc\uc9d5\uae08 \ubd80\uacfc \uc774\uc804\uc5d0\ub9cc \uac00\ub2a5\ud558\ub2e4","\ub0a9\ubd80\uae30\ud55c \uc5f0\uae30\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc778\uc815\ub418\ub294 \uc81c\ub3c4\uc774\ub2e4"],t.s)
B.ID=s([u.jq],t.s)
B.MJ=s(["\ub0a9\ubd80\uae30\ud55c \uc5f0\uae30 \uc2e0\uccad"],t.s)
B.a7r=new A.f("gen_pc_transfer_5","economic_law","\uacfc\uc9d5\uae08","\uc2b9\uacc4\xb7\uc9d5\uc218\xb7\uacb0\uc190\ucc98\ubd84","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uae30\ud55c \uc5f0\uae30 \uc2e0\uccad\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Hj,0,"\uacfc\uc9d5\uae08 \ub0a9\ubd80\uae30\ud55c\uc758 \uc5f0\uae30\ub97c \uc2e0\uccad\ud558\ub824\ub294 \uc790\ub294 \ub0a9\ubd80\ud1b5\uc9c0\ub97c \ubc1b\uc740 \ub0a0\ub85c\ubd80\ud130 \ubc95\ub839\uc774 \uc815\ud55c \uc77c\uc815\ud55c \uae30\uac04(\uc608: 60\uc77c) \uc774\ub0b4\uc5d0 \uc2e0\uccad\ud558\uc5ec\uc57c \ud558\uba70, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uadf8 \uc0ac\uc720\uc758 \ud0c0\ub2f9\uc131\uc744 \uc2ec\uc0ac\ud558\uc5ec \uc2b9\uc778 \uc5ec\ubd80\ub97c \uacb0\uc815\ud55c\ub2e4. \uc2e0\uccad\ub9cc\uc73c\ub85c \uc790\ub3d9\uc73c\ub85c \uc5f0\uae30\uac00 \uc778\uc815\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.ID,B.MJ,null)
B.Ts=s(["\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uae08\uc9c0 \uaddc\uc815\uc744 \uc704\ubc18\ud558\uc5ec \uc190\ud574\ub97c \uc785\uc740 \uc790\uac00 \uc788\ub294 \uacbd\uc6b0, \uc0ac\uc5c5\uc790\ub294 \uc790\uc2e0\uc5d0\uac8c \uace0\uc758 \ub610\ub294 \uacfc\uc2e4\uc774 \uc5c6\uc5c8\uc74c\uc744 \ub4e4\uc5b4 \ucc45\uc784\uc744 \uba74\ud560 \uc218 \uc5c6\ub2e4","\uc790\uc9c4\uc2e0\uace0 \ub4f1\uc73c\ub85c \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc744 \uac10\uba74\ubc1b\uc740 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc740 \ubc1c\uc0dd\ud55c \uc190\ud574\ub97c \ucd08\uacfc\ud558\uc9c0 \uc54a\ub294 \ubc94\uc704\ub85c \ud55c\uc815\ub420 \uc218 \uc788\ub2e4","\ubc95\uc6d0\uc740 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc758 \uc18c\uac00 \uc81c\uae30\ub41c \ub54c \ud544\uc694\ud558\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \ud574\ub2f9 \uc0ac\uac74\uae30\ub85d\uc758 \uc1a1\ubd80\ub97c \uc694\uad6c\ud560 \uc218 \uc788\ub2e4","\uc190\ud574\uac00 \ubc1c\uc0dd\ud55c \uc0ac\uc2e4\uc740 \uc778\uc815\ub418\ub098 \uc190\ud574\uc561\uc744 \uc99d\uba85\ud558\uae30 \uc704\ud574 \ud544\uc694\ud55c \uc0ac\uc2e4\uc744 \uc99d\uba85\ud558\ub294 \uac83\uc774 \uc0ac\uc548\uc758 \uc131\uc9c8\uc0c1 \uace4\ub780\ud55c \uacbd\uc6b0, \ubc95\uc6d0\uc740 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\ub97c \uae30\uac01\ud558\uc5ec\uc57c \ud55c\ub2e4","\ubc95\uc6d0\uc740 \ub2f9\uc0ac\uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc790\ub8cc\uc81c\ucd9c\uba85\ub839\uc5d0 \ub530\ub974\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0 \uc790\ub8cc\uc758 \uae30\uc7ac\uc5d0 \uad00\ud55c \uc0c1\ub300\ubc29\uc758 \uc8fc\uc7a5\uc744 \uc9c4\uc2e4\ud55c \uac83\uc73c\ub85c \uc778\uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
B.S6=s(['\ubcc0\ub860 \uc804\uccb4\uc758 \ucde8\uc9c0\uc640 \uc99d\uac70\uc870\uc0ac\uc758 \uacb0\uacfc\uc5d0 \uae30\ucd08\ud558\uc5ec "\uc0c1\ub2f9\ud55c \uc190\ud574\uc561"\uc744 \uc778\uc815\ud560 \uc218 \uc788\ub3c4\ub85d'],t.s)
B.Ur=s(["\uc190\ud574\ubc30\uc0c1\ucc45\uc784","\uc190\ud574\uc561 \uc778\uc815"],t.s)
B.a7N=new A.f("gen_pc_3","economic_law","\uc190\ud574\ubc30\uc0c1\ucc45\uc784",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc190\ud574\ubc30\uc0c1 \ucc45\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Ts,3,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c115\uc870\ub294 \ubc95 \uc704\ubc18\ud589\uc704\ub85c \uc190\ud574\uac00 \ubc1c\uc0dd\ud55c \uc0ac\uc2e4\uc740 \uc778\uc815\ub418\uc9c0\ub9cc \uadf8 \uc190\ud574\uc561\uc744 \uc99d\uba85\ud558\ub294 \uac83\uc774 \uc0ac\uc548\uc758 \uc131\uc9c8\uc0c1 \uadf9\ud788 \uace4\ub780\ud55c \uacbd\uc6b0, \ubc95\uc6d0\uc774 \uccad\uad6c\ub97c \uae30\uac01\ud558\uc9c0 \uc54a\uace0 \ubcc0\ub860 \uc804\uccb4\uc758 \ucde8\uc9c0\uc640 \uc99d\uac70\uc870\uc0ac\uc758 \uacb0\uacfc\uc5d0 \uae30\ucd08\ud558\uc5ec "\uc0c1\ub2f9\ud55c \uc190\ud574\uc561"\uc744 \uc778\uc815\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc190\ud574\uc561 \uc778\uc815 \uc81c\ub3c4\ub97c \ub450\uace0 \uc788\ub2e4. \uc774\ub294 \uc190\ud574\uc758 \ubc1c\uc0dd\uc740 \uba85\ubc31\ud558\uc9c0\ub9cc \uc815\ud655\ud55c \uc561\uc218 \uc0b0\uc815\uc774 \uc5b4\ub824\uc6b4 \ud53c\ud574\uc790\ub97c \ub450\ud141\uac8c \ubcf4\ud638\ud558\uae30 \uc704\ud55c \ud2b9\uce59\uc73c\ub85c, \ubbfc\uc0ac\uc18c\uc1a1\uc758 \uc77c\ubc18 \uc99d\uba85\ucc45\uc784 \uc6d0\uce59\uc5d0 \ub300\ud55c \uc911\uc694\ud55c \uc608\uc678\ub2e4. \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0(\uace0\uc758\xb7\uacfc\uc2e4 \uc785\uc99d\ucc45\uc784 \uc804\ud658, \uae30\ub85d\uc1a1\ubd80 \uc694\uad6c\uad8c, \uc790\ub8cc\uc81c\ucd9c\uba85\ub839 \uc704\ubc18 \uc2dc \uc0c1\ub300\ubc29 \uc8fc\uc7a5 \uc778\uc815)\ub294 \ubaa8\ub450 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2e4\uc81c\ub85c \uc778\uc815\ub418\ub294 \uc190\ud574\ubc30\uc0c1 \ud2b9\uce59\ub4e4\uc774\ub2e4.',B.S6,B.Ur,null)
B.Rt=s(["\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1 \uacf5\uc815\uac70\ub798\ubc95 \uad00\ub828 \ubd84\uc7c1 \uc804\ubc18\uc5d0 \ub300\ud55c \uc870\uc815","\uc624\uc9c1 \ud615\uc0ac\uc0ac\uac74\ub9cc\uc744 \uc804\ub2f4\ud55c\ub2e4","\uc624\uc9c1 \ub178\ub3d9\uc7c1\uc758\ub9cc\uc744 \uc804\ub2f4\ud55c\ub2e4","\uc624\uc9c1 \ud2b9\ud5c8\ubd84\uc7c1\ub9cc\uc744 \uc804\ub2f4\ud55c\ub2e4","\uc624\uc9c1 \uc138\ubb34\uc870\uc0ac \uc774\uc758\uc2e0\uccad\ub9cc\uc744 \uc804\ub2f4\ud55c\ub2e4"],t.s)
