B.Ns=s([u.jL,"\uc870\uc815 \uc131\ub9bd\uc740 \ud56d\uc0c1 \ud615\uc0ac\ud310\uacb0\uacfc \ub3d9\uc77c\ud55c \ud6a8\ub825\uc744 \uac00\uc9c4\ub2e4","\uc870\uc815 \uc131\ub9bd\uc740 \uc5b4\ub5a0\ud55c \ubc95\uc801 \ud6a8\ub825\ub3c4 \uac16\uc9c0 \uc54a\ub294 \ub2e8\uc21c \ucc38\uace0\uc0ac\ud56d\uc774\ub2e4","\uc870\uc815 \uc131\ub9bd\uc740 \uad6d\uc81c\uc870\uc57d\uacfc \ub3d9\uc77c\ud55c \ud6a8\ub825\uc744 \uac00\uc9c4\ub2e4","\uc870\uc815 \uc131\ub9bd \uc5ec\ubd80\ub294 \ud6a8\ub825\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uac1c\ub150\uc774\ub2e4"],t.s)
