B.a6M=new A.f("gen_ftc_adr_effect_2","economic_law","\ubd84\uc7c1\uc870\uc815\ud611\uc758\ud68c(\uacf5\uc815\uac70\ub798)","\uc870\uc815\uc758 \uc131\ub9bd\xb7\ud6a8\ub825","\uacf5\uc815\uac70\ub798\ubd84\uc7c1\uc870\uc815\uc5d0\uc11c \uc870\uc815\uc774 \uc131\ub9bd\ud55c \uacbd\uc6b0\uc640 \uc7ac\ud310\uc0c1 \ud654\ud574\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ns,0,"\uc870\uc815\uc774 \uc131\ub9bd\ud55c \uacbd\uc6b0 \uadf8 \ud6a8\ub825\uc744 \uc7ac\ud310\uc0c1 \ud654\ud574\uc640 \uac19\uc740 \uc218\uc900\uc73c\ub85c \uc778\uc815\ud560 \uac83\uc778\uc9c0 \uc5ec\ubd80\ub294 \uad00\ub828 \ubc95\ub839\uc758 \uc81c\ub3c4 \uc124\uacc4\uc5d0 \ub530\ub77c \uc815\ud574\uc9c0\ub294 \uc0ac\ud56d\uc73c\ub85c, \uc870\uc815 \uc81c\ub3c4\uc758 \uc2e4\ud6a8\uc131\uc744 \ub192\uc774\uae30 \uc704\ud574 \uc774\ub7ec\ud55c \ud6a8\ub825 \ubd80\uc5ec\uac00 \ub17c\uc758\ub418\ub294 \uc9c0\uc810\uc774\ub2e4.",B.Xa,B.L7,null)
