B.a6X=new A.f("gen_ftc_adr_effect_4","economic_law","\ubd84\uc7c1\uc870\uc815\ud611\uc758\ud68c(\uacf5\uc815\uac70\ub798)","\uc870\uc815\uc758 \uc131\ub9bd\xb7\ud6a8\ub825","\uacf5\uc815\uac70\ub798\ubd84\uc7c1\uc870\uc815 \uc808\ucc28\uc640 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58 \uad8c\ud55c\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.nJ,0,"\uacf5\uc815\uac70\ub798\ubd84\uc7c1\uc870\uc815 \uc808\ucc28\ub294 \ub2f9\uc0ac\uc790 \uac04\uc758 \uac1c\ubcc4 \ubd84\uc7c1\uc744 \uc870\uc815\uc744 \ud1b5\ud574 \ud574\uacb0\ud558\ub294 \ub370 \ucd08\uc810\uc744 \ub450\ub294 \ubc18\uba74, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\ub294 \ubc95 \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud574 \ud589\uc815\uc801\uc73c\ub85c \uc81c\uc7ac\ud558\ub294 \uac83\uc744 \ubaa9\uc801\uc73c\ub85c \ud558\ub294 \ubcc4\uac1c\uc758 \uc81c\ub3c4\ub85c\uc11c, \uc11c\ub85c \ubcd1\uc874\ud560 \uc218 \uc788\ub294 \uad00\uacc4\uc5d0 \uc788\ub2e4.",B.nC,B.nq,null)
B.a7T=new A.f("gen_ftc_adr_effect_5","economic_law","\ubd84\uc7c1\uc870\uc815\ud611\uc758\ud68c(\uacf5\uc815\uac70\ub798)","\uc870\uc815\uc758 \uc131\ub9bd\xb7\ud6a8\ub825",u.oI,B.nk,0,"\uc870\uc815\uc774 \uc131\ub9bd\ub418\uc5c8\uc74c\uc5d0\ub3c4 \ub2f9\uc0ac\uc790\uac00 \uadf8 \ub0b4\uc6a9\uc744 \uc774\ud589\ud558\uc9c0 \uc54a\ub294 \uacbd\uc6b0, \uc870\uc815 \ud569\uc758\uc758 \ubc95\uc801 \uc131\uaca9\uc5d0 \ub530\ub77c \uc774\ud589\uc744 \uad6c\ud558\uae30 \uc704\ud55c \ubcc4\ub3c4\uc758 \uc808\ucc28(\ubbfc\uc0ac\uc0c1 \uccad\uad6c \ub4f1)\uac00 \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4.",B.ny,B.nd,null)
B.Ka=s([u.eB,"\uc870\uc815\uc744 \uc2e0\uccad\ud558\uba74 \ubb34\uc870\uac74 \uac00\ub9f9\uc810\uc8fc\uc5d0\uac8c \uc720\ub9ac\ud55c \uacb0\uacfc\uac00 \ub098\uc628\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc870\uc815 \uc808\ucc28\ub294 \uc548\ub0b4\ud560 \ud544\uc694\uac00 \uc804\ud600 \uc5c6\ub294 \uc0ac\ud56d\uc774\ub2e4","\uc870\uc815\uc740 \ubc18\ub4dc\uc2dc \uc18c\uc1a1\ubcf4\ub2e4 \ub098\uc05c \uacb0\uacfc\ub97c \uac00\uc838\uc628\ub2e4\uace0 \uc548\ub0b4\ud574\uc57c \ud55c\ub2e4","\uc870\uc815 \uc2e0\uccad \uc790\uaca9\uc740 \uac00\ub9f9\ubcf8\ubd80\uc5d0\uac8c\ub9cc \uc788\ub2e4\uace0 \uc548\ub0b4\ud574\uc57c \ud55c\ub2e4"],t.s)
