B.aa4=new A.f("gen_ftc_adr_effect_6","economic_law","\ubd84\uc7c1\uc870\uc815\ud611\uc758\ud68c(\uacf5\uc815\uac70\ub798)","\uc870\uc815\uc758 \uc131\ub9bd\xb7\ud6a8\ub825","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uac00\ub9f9\uc810\uc8fc\uc5d0\uac8c \uacf5\uc815\uac70\ub798\ubd84\uc7c1\uc870\uc815\ud611\uc758\ud68c \ud65c\uc6a9\uc744 \uc548\ub0b4\ud560 \ub54c \uc720\uc758\ud560 \uc810\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ka,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \uac00\ub9f9\uc810\uc8fc\uc5d0\uac8c \uacf5\uc815\uac70\ub798\ubd84\uc7c1\uc870\uc815\ud611\uc758\ud68c \uc81c\ub3c4\ub97c \uc548\ub0b4\ud560 \ub54c, \uc870\uc815\uc774 \uc2e0\uc18d\ud55c \ud574\uacb0\uc5d0 \uc720\uc6a9\ud560 \uc218 \uc788\ub2e4\ub294 \uc7a5\uc810\uacfc \ud568\uaed8 \uc870\uc815 \uc131\ub9bd\uc758 \ubc95\uc801 \ud6a8\ub825 \ubc94\uc704, \uc870\uc815\uc774 \uc131\ub9bd\ud558\uc9c0 \uc54a\uc744 \uacbd\uc6b0\uc758 \ub300\uc548(\uc18c\uc1a1 \ub4f1)\uc744 \uade0\ud615 \uc788\uac8c \uc124\uba85\ud574\uc57c \uc815\ud655\ud55c \uc815\ubcf4 \uc81c\uacf5\uc774 \ub41c\ub2e4.",B.Qn,B.ns,null)
