B.a8O=new A.f("gen_ub_1","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc720\ud615 \uc911 \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uad6c\uc785\uac15\uc81c  \u3134. \ubd80\ub2f9\uc5fc\ub9e4  \u3137. \uc774\uc775\uc81c\uacf5\uac15\uc694  \u3139. \ud310\ub9e4\ubaa9\ud45c\uac15\uc81c  \u3141. \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c",B.Ri,1,'\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 "\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9"\uc740 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1 \uc6b0\uc6d4\uc801 \uc9c0\uc704\ub97c \uc774\uc6a9\ud574 \uc0c1\ub300\ubc29\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\uc774\uc775\uc744 \uc8fc\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc73c\ub85c, \uadf8 \ud558\uc704 \uc720\ud615\uc740 \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\xb7\ubd88\uc774\uc775\uc81c\uacf5\xb7\uacbd\uc601\uac04\uc12d 5\uac00\uc9c0\ub85c \uc2dc\ud589\ub839\uc5d0 \uc5f4\uac70\ub418\uc5b4 \uc788\ub2e4. \ubc18\uba74 \ubd80\ub2f9\uc5fc\ub9e4(\u3134)\ub294 "\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c" \uc720\ud615\uc5d0 \uc18d\ud558\uace0, \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c(\u3141) \uc790\uccb4\ub3c4 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uacfc\ub294 \ubcc4\uac1c\uc758 \ub300\ubd84\ub958\uc774\ubbc0\ub85c \ud63c\ub3d9\ud558\uc9c0 \uc54a\uc544\uc57c \ud55c\ub2e4. \ub530\ub77c\uc11c \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c(\u3131, \u3137, \u3139)\ub9cc \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud558\uba70, \uc774\ub294 \uc2e4\ubb34\uc0c1\uc73c\ub85c\ub3c4 \uac00\ub9f9\ubcf8\ubd80\xb7\ub300\ud615\uc720\ud1b5\uc5c5\uccb4\uac00 \uac00\ub9f9\uc810\xb7\ub0a9\ud488\uc5c5\uccb4\uc5d0 \ud589\ud558\ub294 \uac11\uc9c8 \uaddc\uc81c\uc758 \ud575\uc2ec \uadfc\uac70\uc870\ud56d\uc73c\ub85c \uc790\uc8fc \ucd9c\uc81c\ub41c\ub2e4.',B.R6,B.Vt,null)
B.Na=s(["\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \uac00\uc9c0\uae09\uae08\xb7\ub300\uc5ec\uae08 \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \ubd80\ub3d9\uc0b0\xb7\uc720\uac00\uc99d\uad8c\xb7\uc0c1\ud488 \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \ub9e4\ub9e4\ud558\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \uc778\ub825\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\uc9c1\uc811 \uac70\ub798\ud558\uba74 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud568\uc5d0\ub3c4 \uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\ub97c \ub9e4\uac1c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1 \uc9c0\uae09\ub418\ub294 \ub300\uac00\ubcf4\ub2e4 \ub0ae\uc740 \ub300\uac00\ub85c \uc790\uae30\uc758 \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uacf5\uae09\ud558\ub294 \ud589\uc704"],t.s)
B.a0Y=s(["\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778\xb7\uacc4\uc5f4\uc0ac\uc5d0 \ub300\ud55c \uc774\uc775 \ubab0\uc544\uc8fc\uae30\uac00 \ud575\uc2ec\uc774\uace0 \ubd80\ub2f9\uc5fc\ub9e4\ub294 \uc2dc\uc7a5\uc5d0\uc11c \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ucd95\ucd9c\ud558\ub824\ub294 \uac00\uaca9\uc815\ucc45"],t.s)
B.Qp=s(["\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704","\ubd80\ub2f9\uc5fc\ub9e4\uc640 \uad6c\ubd84"],t.s)
B.a6V=new A.f("gen_ub_2","economic_law","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uc9c0\uc6d0\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.Na,4,'\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \ub300\ud574 \uc790\uae08\xb7\uc790\uc0b0\xb7\uc778\ub825\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\uac70\ub098, \ud544\uc694 \uc774\uc0c1\uc758 \uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud574 \uc774\uc775\uc744 \ubab0\uc544\uc8fc\ub294 \ubc29\uc2dd\uc73c\ub85c \ubd80\ub2f9\ud558\uac8c \uc9c0\uc6d0\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4. \ubc18\uba74 \ub9c8\uc9c0\ub9c9 \uc120\ud0dd\uc9c0\ucc98\ub7fc \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1 \uc9c0\uae09\ub418\ub294 \ub300\uac00\ubcf4\ub2e4 \ub0ae\uc740 \uac00\uaca9\uc5d0 \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uacf5\uae09\ud558\ub294 \ud589\uc704\ub294 "\ubd80\ub2f9\uc5fc\ub9e4"\ub85c\uc11c, \uc774\ub294 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824\ub294 \ubaa9\uc801\uc758 "\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c" \uc720\ud615\uc5d0 \ud574\ub2f9\ud55c\ub2e4. \ub450 \uc720\ud615 \ubaa8\ub450 "\ubd80\ub2f9\ud558\uac8c \ub0ae\uc740/\uc720\ub9ac\ud55c \uc870\uac74"\uc774\ub77c\ub294 \uacf5\ud1b5\uc810 \ub54c\ubb38\uc5d0 \ud5f7\uac08\ub9ac\uae30 \uc27d\uc9c0\ub9cc, \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778\xb7\uacc4\uc5f4\uc0ac\uc5d0 \ub300\ud55c \uc774\uc775 \ubab0\uc544\uc8fc\uae30\uac00 \ud575\uc2ec\uc774\uace0 \ubd80\ub2f9\uc5fc\ub9e4\ub294 \uc2dc\uc7a5\uc5d0\uc11c \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ucd95\ucd9c\ud558\ub824\ub294 \uac00\uaca9\uc815\ucc45\uc774\ub77c\ub294 \uc810\uc5d0\uc11c \uaddc\uc81c \ubaa9\uc801\uc774 \ub2e4\ub974\ub2e4.',B.a0Y,B.Qp,null)
B.W_=s(["\ubd80\ub2f9\ud558\uac8c \uac70\ub798\uc0c1\ub300\ubc29\uc774 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc758 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \uc54a\ub294 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\ub294 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc758 \uac70\ub798\uc9c0\uc5ed\uc744 \ubd80\ub2f9\ud558\uac8c \uad6c\uc18d\ud558\ub294 \ud589\uc704\ub294 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc744 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc640\ub9cc \uac70\ub798\ud558\ub3c4\ub85d \uad6c\uc18d\ud558\ub294 \uac83\uc740 \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \ud558\uc704 \uc720\ud615\uc774\ub2e4","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.XL=s(["\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \ubd09\uc1c4\ud574 \uc2dc\uc7a5\uc758 \uacbd\uc7c1\uad6c\uc870 \uc790\uccb4\ub97c \uc65c\uace1"],t.s)
B.a1K=s(["\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798"],t.s)
B.abv=new A.f("gen_ub_3","economic_law","\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.W_,0,'\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc758 \uac70\ub798\ucc98 \uc120\ud0dd\uc774\ub098 \ud310\ub9e4 \uc9c0\uc5ed\xb7\ub300\uc0c1\uc744 \ubd80\ub2f9\ud558\uac8c \uad6c\uc18d\ud558\ub294 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud558\uba70, \uadf8 \ub300\ud45c\uc801 \ud558\uc704 \uc720\ud615\uc774 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798(\uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uad6c\uc18d)\uc640 \uac70\ub798\uc9c0\uc5ed\xb7\uac70\ub798\uc0c1\ub300\ubc29 \uc81c\ud55c\uc774\ub2e4. \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \ubd09\uc1c4\ud574 \uc2dc\uc7a5\uc758 \uacbd\uc7c1\uad6c\uc870 \uc790\uccb4\ub97c \uc65c\uace1\ud560 \uc218 \uc788\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub418\uba70, "\ud56d\uc0c1 \uc801\ubc95"\ud558\ub2e4\ub294 \uc124\uba85(\uc120\ud0dd\uc9c0 \u2462)\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ub610\ud55c \uac70\ub798\uc9c0\uc5ed \uc81c\ud55c\uc740 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc774 \uc544\ub2c8\ub77c \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798 \uc790\uccb4\uc758 \ud558\uc704\uc720\ud615\uc774\uace0(\uc120\ud0dd\uc9c0 \u2461\ub294 \uc624\ub2f5), \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640\ub294 \ubcc4\uac1c\uc758 \ub3c5\ub9bd\ub41c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc720\ud615\uc774\ub77c\ub294 \uc810(\uc120\ud0dd\uc9c0 \u2463\ub3c4 \uc624\ub2f5)\uc744 \ud568\uaed8 \uc815\ub9ac\ud574\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.XL,B.a1K,null)
B.a_y=s(["\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc0ac\uc2e4\uc744 \uc790\uc9c4\uc2e0\uace0\ud558\uac70\ub098 \uc870\uc0ac\uc5d0 \ud611\uc870\ud55c \uc790\uc5d0 \ub300\ud574\uc11c\ub294 \uc2dc\uc815\uc870\uce58 \ub610\ub294 \uacfc\uc9d5\uae08\uc744 \uac10\uacbd\ud558\uac70\ub098 \uba74\uc81c\ud560 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74 \ud61c\ud0dd\uc740 \ud615\uc0ac\uace0\ubc1c\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc5b4 \uace0\ubc1c\uc744 \uba74\uc81c\ud560 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uac10\uba74\uc81c\ub3c4\ub294 \ub3d9\uc77c\ud55c \uc0ac\uc5c5\uc790\uac00 \ubc18\ubcf5\uc801\uc73c\ub85c \uc790\uc9c4\uc2e0\uace0\ud558\ub294 \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc99d\uac70\uc81c\uacf5 \ub4f1\uc758 \ubc29\ubc95\uc73c\ub85c \uc870\uc0ac\uc5d0 \ud611\uc870\ud55c \uc790\uc5d0 \ub300\ud558\uc5ec \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc758 \uac10\uacbd \ub610\ub294 \uba74\uc81c\uac00 \uac00\ub2a5\ud558\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc790\uc9c4\uc2e0\uace0\uc790 \ub4f1\uc758 \ub3d9\uc758 \uc5c6\uc774 \uadf8 \uc2e0\uc6d0 \ub4f1 \uad00\ub828 \uc790\ub8cc\ub97c \ub2e4\ub978 \ubaa9\uc801\uc73c\ub85c \uc0ac\uc6a9\ud574\uc11c\ub294 \uc548 \ub41c\ub2e4"],t.s)
B.ZM=s(["\ubc18\ubcf5 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74\uc744 \ubc30\uc81c\ud560 \uc218 \uc788\ub3c4\ub85d \uaddc\uc815"],t.s)
B.Lu=s(["\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74(\ub9ac\ub2c8\uc5b8\uc2dc)"],t.s)
B.aac=new A.f("gen_ca_1","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc790\uc9c4\uc2e0\uace0\uc790 \ub4f1\uc5d0 \ub300\ud55c \uac10\uba74\uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a_y,2,'\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4(\ub9ac\ub2c8\uc5b8\uc2dc)\ub294 \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \uadf8 \uc0ac\uc2e4\uc744 \uc2e0\uace0\ud558\uac70\ub098 \uc870\uc0ac\uc5d0 \ud611\uc870\ud558\uba74 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08\uc744 \uac10\uacbd \ub610\ub294 \uba74\uc81c\ud574\uc8fc\ub294 \uc81c\ub3c4\ub85c, \ub2f4\ud569\uc758 \uc740\ubc00\uc131\uc744 \uae68\ub728\ub824 \uc801\ubc1c\ub960\uc744 \ub192\uc774\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\ub2e4. \uadf8\ub7f0\ub370 \ub3d9\uc77c\ud55c \uc0ac\uc5c5\uc790\uac00 \uc5ec\ub7ec \ucc28\ub840 \ubc18\ubcf5\uc801\uc73c\ub85c \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \ud6c4 \ub9e4\ubc88 \uc790\uc9c4\uc2e0\uace0\ub85c \uac10\uba74\ubc1b\ub294 \uacbd\uc6b0\uae4c\uc9c0 \ubb34\uc870\uac74 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud55c\ub2e4\uba74 \uc624\ud788\ub824 \ub2f4\ud569\uc744 \uc870\uc7a5\ud558\ub294 \uc5ed\ud6a8\uacfc\uac00 \uc0dd\uae38 \uc218 \uc788\uc73c\ubbc0\ub85c, \uc2dc\ud589\ub839\uc740 \uc77c\uc815 \uc694\uac74 \ud558\uc5d0 \ubc18\ubcf5 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74\uc744 \ubc30\uc81c\ud560 \uc218 \uc788\ub3c4\ub85d \uaddc\uc815\ud558\uace0 \uc788\ub2e4. \ub530\ub77c\uc11c "\ud56d\uc0c1 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\uc5ec\uc57c \ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.ZM,B.Lu,null)
B.Zs=s([u.fF,"\uc790\uc9c4\uc2e0\uace0\uc790\uc5d0\uac8c \uc624\ud788\ub824 \ub354 \ubb34\uac70\uc6b4 \ucc98\ubc8c\uc744 \uac00\ud558\uae30 \uc704\ud568\uc774\ub2e4","\ub2f4\ud569\uc744 \uc870\uc7a5\ud558\uace0 \uc0ac\uc5c5\uc790 \uac04 \ud611\uc870\ub97c \uac15\ud654\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \ubaa8\ub4e0 \uc0ac\uc5c5\uc790\ub97c \ub3d9\uc77c\ud558\uac8c \ucc98\ubc8c\ud558\uae30 \uc704\ud568\uc774\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4\ub294 \uc2e4\uc81c\ub85c \uc544\ubb34\ub7f0 \uc815\ucc45\uc801 \ud6a8\uacfc\uac00 \uc5c6\ub2e4"],t.s)
B.Kd=s([u.fF],t.s)
