B.a8F=new A.f("gen_leniency_intro_1","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uac10\uba74 \uc694\uac74","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4(\ub9ac\ub2c8\uc5b8\uc2dc)\uc758 \ub3c4\uc785 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Zs,0,"\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4\ub294 \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\uac00 \uc790\uc9c4\uc2e0\uace0\ub97c \ud1b5\ud574 \uac10\uba74 \ud61c\ud0dd\uc744 \ubc1b\uc744 \uc218 \uc788\ub3c4\ub85d \ud568\uc73c\ub85c\uc368, \ub2f4\ud569 \ucc38\uc5ec \uc0ac\uc5c5\uc790\ub4e4 \uc0ac\uc774\uc5d0 \ubc30\uc2e0\uc5d0 \ub300\ud55c \ubd88\uc548\uc744 \uc870\uc131\ud558\uc5ec \ub2f4\ud569\uc758 \uc740\ubc00\uc131\uc744 \uae68\ub728\ub9ac\uace0 \uc801\ubc1c\ub960\uc744 \ub192\uc5ec \ub2f4\ud569\uc744 \uc0ac\uc804\uc5d0 \uc5b5\uc9c0\ud558\ub824\ub294 \uc815\ucc45\uc801 \ucde8\uc9c0\ub97c \uac16\ub294\ub2e4.",B.Kd,B.Mf,null)
B.V3=s([u.dI,"\ub2e8\uc21c\ud788 \ub2f4\ud569\uc5d0 \ucc38\uc5ec\ud588\ub2e4\ub294 \uc0ac\uc2e4\ub9cc\uc73c\ub85c \uc790\ub3d9\uc73c\ub85c \uc804\ubd80 \uba74\uc81c\ub41c\ub2e4","\uac00\uc7a5 \ub9c8\uc9c0\ub9c9\uc73c\ub85c \uc2e0\uace0\ud55c \uc0ac\uc5c5\uc790\uac00 \ud56d\uc0c1 \uc804\ubd80 \uba74\uc81c\ub97c \ubc1b\ub294\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\ub294 \uc5b4\ub5a0\ud55c \uc694\uac74\ub3c4 \uc5c6\uc774 \uc804\ubd80 \uba74\uc81c\ub97c \ubc1b\ub294\ub2e4","\uc804\ubd80 \uba74\uc81c\ub294 \uc624\uc9c1 \ub300\uae30\uc5c5\uc5d0\uac8c\ub9cc \uc778\uc815\ub41c\ub2e4"],t.s)
B.SQ=s([u.dI],t.s)
B.Rl=s(["\uc804\ubd80 \uba74\uc81c \uc694\uac74"],t.s)
B.acN=new A.f("gen_leniency_intro_2","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uac10\uba74 \uc694\uac74","\uc790\uc9c4\uc2e0\uace0\uc790\ub85c\uc11c \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08\uc744 \uc804\ubd80 \uba74\uc81c\ubc1b\uae30 \uc704\ud55c \uc77c\ubc18\uc801 \uc694\uac74\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.V3,0,"\uc790\uc9c4\uc2e0\uace0\uc790\uac00 \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc744 \uc804\ubd80 \uba74\uc81c\ubc1b\uae30 \uc704\ud574\uc11c\ub294 \ud1b5\uc0c1 \ud574\ub2f9 \uacf5\ub3d9\ud589\uc704 \uc0ac\uc2e4\uc744 \uc785\uc99d\ud558\ub294 \ucd5c\ucd08\uc758 \uc99d\uac70\ub97c \uc81c\uacf5\ud558\uace0, \uc870\uc0ac\uac00 \ub05d\ub0a0 \ub54c\uae4c\uc9c0 \uc131\uc2e4\ud558\uac8c \ud611\uc870\ud558\uba70, \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc790\uc9c4\uc2e0\uace0 \uc0ac\uc2e4\uc744 \ub204\uc124\ud558\uc9c0 \uc54a\ub294 \ub4f1\uc758 \uc694\uac74\uc744 \ucda9\uc871\ud558\uc5ec\uc57c \ud55c\ub2e4.",B.SQ,B.Rl,null)
B.a0O=s([u.J,"2\uc21c\uc704 \uc790\uc9c4\uc2e0\uace0\uc790\ub294 \uc5b4\ub5a0\ud55c \ud61c\ud0dd\ub3c4 \ubc1b\uc744 \uc218 \uc5c6\ub2e4","2\uc21c\uc704 \uc790\uc9c4\uc2e0\uace0\uc790\ub294 1\uc21c\uc704\uc640 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc804\ubd80 \uba74\uc81c\ub97c \ubc1b\ub294\ub2e4","2\uc21c\uc704 \uc790\uc9c4\uc2e0\uace0\uc790\ub294 \uc624\ud788\ub824 \uac00\uc911\ucc98\ubc8c\uc744 \ubc1b\ub294\ub2e4","2\uc21c\uc704 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74\uc740 \ubc95\ub960\uc0c1 \uc804\ud600 \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4"],t.s)
