B.aat=new A.f("gen_leniency_intro_3","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uc81c\ub3c4\uc758 \ucde8\uc9c0\xb7\uac10\uba74 \uc694\uac74","2\uc21c\uc704 \uc790\uc9c4\uc2e0\uace0\uc790(\uc870\uc0ac \ud611\uc870\uc790)\uc5d0\uac8c \uc778\uc815\ub418\ub294 \uac10\uba74 \ud61c\ud0dd\uc758 \uc77c\ubc18\uc801 \uc218\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a0O,0,"\ud574\ub2f9 \uacf5\ub3d9\ud589\uc704\ub97c \uc785\uc99d\ud558\ub294 \ub370 \ud544\uc694\ud55c \uc99d\uac70\ub97c 2\ubc88\uc9f8\ub85c \uc81c\uacf5\ud558\uace0 \uc870\uc0ac\uc5d0 \ud611\uc870\ud558\ub294 \ub4f1 \uc694\uac74\uc744 \uac16\ucd98 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294, 1\uc21c\uc704 \uc790\uc9c4\uc2e0\uace0\uc790(\uc804\ubd80 \uba74\uc81c)\ubcf4\ub2e4\ub294 \ub0ae\uc740 \uc218\uc900\uc774\uc9c0\ub9cc \uc77c\uc815 \ube44\uc728(\uc608: \uacfc\uc9d5\uae08 \uc77c\ubd80 \uac10\uacbd)\uc758 \uac10\uba74 \ud61c\ud0dd\uc774 \uc778\uc815\ub420 \uc218 \uc788\ub2e4.",B.a1i,B.Se,null)
B.a_8=s([u.nb,"\uc870\uc0ac \ucd08\uae30\uc5d0\ub9cc \ud611\uc870\ud558\uace0 \uc774\ud6c4\uc5d0\ub294 \ud611\uc870\ud558\uc9c0 \uc54a\uc544\ub3c4 \ub418\ub294 \uac83","\uc870\uc0ac\uad00\uacfc \uac1c\uc778\uc801\uc778 \uce5c\ubd84\uc744 \uc313\ub294 \uac83","\uc870\uc0ac\uc640 \ubb34\uad00\ud55c \uc790\ub8cc\ub97c \ub300\ub7c9\uc73c\ub85c \uc81c\ucd9c\ud558\ub294 \uac83","\uc870\uc0ac\uc5d0 \ud611\uc870\ud55c\ub2e4\ub294 \ub9d0\ub9cc \ud558\uace0 \uc2e4\uc81c \ud589\ub3d9\uc740 \ud558\uc9c0 \uc54a\ub294 \uac83"],t.s)
