B.O9=s([u.oq,"\ubaa8\ub4e0 \uc2e0\uace0\uc790\uc5d0\uac8c \uc21c\uc11c\uc640 \ubb34\uad00\ud558\uac8c \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\ub294 \uad6c\uc870","\uc2e0\uace0 \uc21c\uc11c\uc640 \uad00\uacc4\uc5c6\uc774 \ubb34\uc791\uc704\ub85c \ud61c\ud0dd\uc744 \ubc30\ubd84\ud558\ub294 \uad6c\uc870","\uc2e0\uace0\ub97c \uac00\uc7a5 \ub2a6\uac8c \ud55c \uc0ac\uc5c5\uc790\uc5d0\uac8c \uac00\uc7a5 \ud070 \ud61c\ud0dd\uc744 \uc8fc\ub294 \uad6c\uc870","\uc2e0\uace0 \uc790\uccb4\ub97c \uc6d0\ucc9c\uc801\uc73c\ub85c \ucc28\ub2e8\ud558\ub294 \uad6c\uc870"],t.s)
