B.K4=s([u.oR,"\uc790\uc9c4\uc2e0\uace0\uc790\uc5d0\uac8c \uc624\ud788\ub824 \ubd88\uc774\uc775\uc744 \uc8fc\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc2e0\uc6d0 \ubcf4\ud638\ub294 \uc790\uc9c4\uc2e0\uace0 \uc5ec\ubd80\uc640 \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub2e4","\uc2e0\uc6d0 \ubcf4\ud638\ub294 \uc624\uc9c1 \ud615\uc2dd\uc801 \uc808\ucc28\ub85c\uc11c \uc2e4\uc9c8\uc801 \uc758\ubbf8\uac00 \uc5c6\ub2e4","\uc2e0\uc6d0 \ubcf4\ud638\ub294 \ub2e4\ub978 \uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \uc2e0\uace0\uc790\ub97c \uc54c\ub9ac\uae30 \uc704\ud55c \uac83\uc774\ub2e4"],t.s)
