B.a08=s([u.h6,"\uc790\uc9c4\uc2e0\uace0 \uc790\ub8cc\ub294 \ubbfc\uc0ac\uc18c\uc1a1\uc5d0\uc11c \uc808\ub300\ub85c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uc790\ub8cc\ub294 \ud56d\uc0c1 \uc804\uba74 \uacf5\uac1c\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uc790\ub8cc\ub294 \ud53c\ud574\uc790\uc758 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uc790\ub8cc\uc758 \ud65c\uc6a9\uc740 \ubc95\ub960\uc0c1 \uc804\ud600 \ub17c\uc758\ub41c \ubc14 \uc5c6\ub2e4"],t.s)
