B.a9d=new A.f("gen_leniency_secret_3","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74","\uc2e0\uc6d0\xb7\uc790\ub8cc\uc758 \ube44\ubc00\ubcf4\ud638","\uc790\uc9c4\uc2e0\uace0 \uad00\ub828 \uc790\ub8cc\uac00 \ubbfc\uc0ac\uc18c\uc1a1\uc758 \uc190\ud574\ubc30\uc0c1\uccad\uad6c \uc808\ucc28\uc5d0\uc11c \ud65c\uc6a9\ub418\ub294 \ubb38\uc81c\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a08,0,"\uc790\uc9c4\uc2e0\uace0\ub97c \ud1b5\ud574 \ud655\ubcf4\ub41c \uc790\ub8cc\uac00 \uc774\ud6c4 \ud53c\ud574\uc790\uc758 \ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1\uccad\uad6c \uc808\ucc28\uc5d0\uc11c \uc99d\uac70\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub294\uc9c0\ub294, \uc790\uc9c4\uc2e0\uace0 \uc720\uc778\uc744 \uc800\ud574\ud558\uc9c0 \uc54a\uc73c\uba74\uc11c\ub3c4 \ud53c\ud574\uc790\uc758 \uc2e4\ud6a8\uc801 \uad8c\ub9ac\uad6c\uc81c\ub97c \ub3c4\ubaa8\ud574\uc57c \ud55c\ub2e4\ub294 \ub450 \uac00\uc9c0 \uc815\ucc45 \ubaa9\ud45c \uc0ac\uc774\uc758 \uade0\ud615\uc744 \ucc3e\ub294 \ubb38\uc81c\ub85c \ub17c\uc758\ub41c\ub2e4.",B.N_,B.ML,null)
B.Md=s([u.kU,"\uc774\ub7ec\ud55c \uc790\ub8cc\ub294 \ub204\uad6c\ub098 \uc790\uc720\ub86d\uac8c \uc5f4\ub78c\xb7\ubcf5\uc81c\ud560 \uc218 \uc788\ub294 \uacf5\uac1c \uc790\ub8cc\uc774\ub2e4","\uc774\ub7ec\ud55c \uc790\ub8cc\ub294 \uc870\uc0ac \uc885\ub8cc \uc989\uc2dc \uc544\ubb34\ub7f0 \uc81c\ud55c \uc5c6\uc774 \ud3d0\uae30\ub418\uc5b4\uc57c \ud55c\ub2e4","\uc774\ub7ec\ud55c \uc790\ub8cc\ub294 \uc624\uc9c1 \uc2e0\uace0\uc790 \ubcf8\uc778\ub9cc \uc5f4\ub78c\ud560 \uc218 \uc5c6\ub2e4","\uc774\ub7ec\ud55c \uc790\ub8cc\ub294 \ubc95\uc801\uc73c\ub85c \uc5b4\ub5a0\ud55c \ubcf4\ud638\ub3c4 \ubc1b\uc9c0 \ubabb\ud55c\ub2e4"],t.s)
