B.abk=new A.f("gen_md_criteria_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc911 \ucc29\ucde8\ub0a8\uc6a9(\uac00\uaca9\ub0a8\uc6a9\xb7\uc18c\ube44\uc790\uc774\uc775\uc800\ud574\ud589\uc704 \ub4f1)\uacfc \ubc30\uc81c\ub0a8\uc6a9(\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\xb7\uc2dc\uc7a5\ucc38\uac00\ubc29\ud574 \ub4f1)\uc758 \uad6c\ubd84\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.OG,4,"\ucc29\ucde8\ub0a8\uc6a9\uacfc \ubc30\uc81c\ub0a8\uc6a9\uc740 \ub0a8\uc6a9\ud589\uc704\uc758 \uc131\uaca9\uc744 \uc124\uba85\ud558\uae30 \uc704\ud574 \uac15\ud559\uc0c1 \uc0ac\uc6a9\ub418\ub294 \ubd84\ub958\ub85c, \uacf5\uc815\uac70\ub798\ubc95 \uc870\ubb38\uc774 \uc9c1\uc811 \uadf8 \uba85\uce6d\uc744 \uaddc\uc815\ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub2e4. \ucc29\ucde8\ub0a8\uc6a9\uc740 \uac70\ub798\uc0c1\ub300\ubc29\xb7\uc18c\ube44\uc790\ub85c\ubd80\ud130 \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \ucde8\ud558\ub294 \uc720\ud615(\uac00\uaca9\ub0a8\uc6a9 \ub4f1), \ubc30\uc81c\ub0a8\uc6a9\uc740 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c\ud558\uac70\ub098 \uc2e0\uaddc\uc9c4\uc785\uc744 \ub9c9\ub294 \uc720\ud615\uc744 \uac00\ub9ac\ud0a4\uc9c0\ub9cc, \uc2e4\uc81c \uc0ac\uc548\uc5d0\uc11c\ub294 \ud558\ub098\uc758 \ud589\uc704\uac00 \ub450 \uc131\uaca9\uc744 \ud568\uaed8 \uac00\uc9c8 \uc218\ub3c4 \uc788\uc5b4 \uc644\uc804\ud788 \ubc30\ud0c0\uc801\uc774\ub77c\uace0 \ub2e8\uc815\ud560 \uc218 \uc5c6\ub2e4.",B.Rh,B.PO,null)
B.OU=s(["\uc6d0\uac00 \uc0c1\uc2b9 \ub4f1 \uac1d\uad00\uc801 \uc694\uc778\uc5d0 \ub530\ub978 \ud569\ub9ac\uc801\uc778 \uac00\uaca9 \uc870\uc815","\uae30\uc220\ud601\uc2e0\uc774\ub098 \ud6a8\uc728\uc131 \uc99d\ub300\ub97c \uc704\ud55c \ubd88\uac00\ud53c\ud55c \uc870\uce58","\uc18c\ube44\uc790 \ud6c4\uc0dd \uc99d\ub300\uc5d0 \uc2e4\uc9c8\uc801\uc73c\ub85c \uae30\uc5ec\ud558\ub294 \uac70\ub798\uc870\uac74 \ubcc0\uacbd","\uc624\ub85c\uc9c0 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud560 \ubaa9\uc801\uc73c\ub85c \uc124\uacc4\ub41c \uc870\uce58","\uc548\uc804\uc774\ub098 \ud488\uc9c8\uad00\ub9ac\ub97c \uc704\ud574 \ud569\ub9ac\uc801\uc73c\ub85c \ud544\uc694\ud55c \ubc94\uc704\uc758 \uac70\ub798\uc870\uac74 \uc124\uc815"],t.s)
B.Pi=s(["\uc624\ub85c\uc9c0 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud560 \ubaa9\uc801\uc73c\ub85c \uc124\uacc4\ub41c \uc870\uce58"],t.s)
B.M5=s(["\uc815\ub2f9\ud55c \uc774\uc720","\uc704\ubc95\uc131 \uc870\uac01"],t.s)
B.aa2=new A.f("gen_md_criteria_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900",'\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uac00 "\uc815\ub2f9\ud55c \uc774\uc720"\uac00 \uc788\uc5b4 \uc704\ubc95\uc131\uc774 \uc870\uac01\ub420 \uc218 \uc788\ub294 \uc0ac\uc815\uc73c\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6b4 \uac83\uc740?',B.OU,3,"\uc815\ub2f9\ud55c \uc774\uc720\ub294 \uc6d0\uac00 \uc694\uc778, \ud6a8\uc728\uc131\xb7\uae30\uc220\ud601\uc2e0, \uc18c\ube44\uc790 \ud6c4\uc0dd, \ud569\ub9ac\uc801\uc778 \ud488\uc9c8\xb7\uc548\uc804\uad00\ub9ac \ud544\uc694\uc131 \ub4f1 \uac1d\uad00\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 \uc0ac\uc720\ub97c \uac00\ub9ac\ud0a8\ub2e4. \ubc18\uba74 \uc624\ub85c\uc9c0 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \uc124\uacc4\ub41c \uc870\uce58\ub294 \uc815\ub2f9\ud55c \uc774\uc720\ub85c \uc778\uc815\ub418\uae30 \uc5b4\ub835\uace0 \uc624\ud788\ub824 \ubc30\uc81c\ub0a8\uc6a9\uc758 \uc804\ud615\uc801\uc778 \uc9d5\ud45c\ub85c \ud3c9\uac00\ub41c\ub2e4.",B.Pi,B.M5,null)
B.GU=s(["\ud589\uc704 \uc8fc\uccb4\uac00 \ud574\ub2f9 \uac70\ub798\ubd84\uc57c\uc758 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5ec\uc57c \ud55c\ub2e4","\ubb38\uc81c\ub41c \ud589\uc704\uac00 \ubc95\uc774 \uc815\ud55c \ub0a8\uc6a9\ud589\uc704 \uc720\ud615 \uc911 \ud558\ub098\uc5d0 \ud574\ub2f9\ud574\uc57c \ud55c\ub2e4","\uadf8 \ud589\uc704\uc5d0 \ubd80\ub2f9\uc131(\uc704\ubc95\uc131)\uc774 \uc778\uc815\ub418\uc5b4\uc57c \ud55c\ub2e4","\ud589\uc704\ub85c \uc778\ud55c \uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824\uac00 \uc804\ud600 \uc5c6\uc5b4\ub3c4 \ud56d\uc0c1 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud55c\ub2e4","\uac1c\ubcc4 \uc0ac\uc548\uc758 \uc2dc\uc7a5\uad6c\uc870, \uac70\ub798\uad00\ud589 \ub4f1 \uad6c\uccb4\uc801 \uc0ac\uc815\uc774 \ud568\uaed8 \uace0\ub824\ub41c\ub2e4"],t.s)
B.LI=s(["\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824\uac00 \uc804\ud600 \uc5c6\uc5b4\ub3c4 \ud56d\uc0c1 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud55c\ub2e4"],t.s)
B.UA=s(["\ub0a8\uc6a9\ud589\uc704 \uc131\ub9bd\uc694\uac74"],t.s)
B.aaN=new A.f("gen_md_criteria_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc758 \uc131\ub9bd\uc694\uac74\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.GU,3,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud558\ub824\uba74 \u2460 \ud589\uc704\uc790\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc77c \uac83, \u2461 \ubc95\uc815 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc5d0 \ud574\ub2f9\ud560 \uac83, \u2462 \ubd80\ub2f9\uc131(\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824 \ub4f1)\uc774 \uc778\uc815\ub420 \uac83\uc774\ub77c\ub294 \uc694\uac74\uc774 \ubaa8\ub450 \ucda9\uc871\ub418\uc5b4\uc57c \ud55c\ub2e4. \uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\ub098 \uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824\uac00 \uc804\ud600 \uc5c6\ub2e4\uba74 \ubd80\ub2f9\uc131 \uc694\uac74\uc774 \ud760\uacb0\ub418\uc5b4 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.LI,B.UA,null)
B.ST=s(["\ub3d9\uc77c\ud558\uac70\ub098 \uc720\uc0ac\ud55c \uc678\ud615\uc758 \ud589\uc704\ub77c\ub3c4 \ud589\uc704 \uc8fc\uccb4\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc778\uc9c0\uc5d0 \ub530\ub77c \ub0a8\uc6a9\ud589\uc704 \ub610\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub85c \uac01\uac01 \uaddc\uc728\ub420 \uc218 \uc788\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc640 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uac1c\ub150\uc774\ub77c \uc911\ubcf5 \uaddc\uc815\uc5d0 \ubd88\uacfc\ud558\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uaddc\uc815\uc73c\ub85c\ub294 \uc804\ud600 \uaddc\uc728\ub420 \uc218 \uc5c6\ub2e4","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uaddc\uc815\uc774\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\ub294 \uc0ac\uc5c5\uc790 \uaddc\ubaa8\uc640 \ubb34\uad00\ud558\uac8c \ubaa8\ub4e0 \uc0ac\uc5c5\uc790\uc5d0\uac8c \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.WM=s(["\ud589\uc704 \uc8fc\uccb4\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc778\uc9c0\uc5d0 \ub530\ub77c \ub0a8\uc6a9\ud589\uc704 \ub610\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub85c \uac01\uac01 \uaddc\uc728\ub420 \uc218 \uc788\ub2e4"],t.s)
B.KK=s(["\ub0a8\uc6a9\ud589\uc704\uc640 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uc758 \uad00\uacc4"],t.s)
B.a9i=new A.f("gen_md_criteria_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\uae30\uc900","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc640 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704(\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \ubcc4\ub3c4\uc758 \ub300\ubd84\ub958)\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.ST,0,"\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\xb7\uac70\ub798\uac70\uc808\ucc98\ub7fc \uc678\ud615\uc774 \ube44\uc2b7\ud55c \ud589\uc704\ub77c\ub3c4, \ud589\uc704\uc790\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud558\uba74 \ub0a8\uc6a9\ud589\uc704\ub85c, \uadf8\ub807\uc9c0 \uc54a\uc73c\uba74 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1 \ub2e4\ub978 \uaddc\uc815\uc73c\ub85c \uaddc\uc728\ub420 \uc218 \uc788\ub2e4. \ub450 \uc81c\ub3c4\ub294 \uaddc\uc81c \ucde8\uc9c0\uc640 \uc694\uac74\uc774 \ub2e4\ub974\uba70 \uc0c1\ud638 \ubc30\ud0c0\uc801\uc73c\ub85c \ub300\uccb4\ub418\ub294 \uad00\uacc4\uac00 \uc544\ub2c8\ub77c, \uc0ac\uc548\uc5d0 \ub530\ub77c \ud568\uaed8 \uac80\ud1a0\ub420 \uc218\ub3c4 \uc788\ub2e4. \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\ub294 \uadf8 \uc815\uc758\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \uaddc\uc81c\ub77c\ub294 \uc810\uc774 \ud575\uc2ec\uc774\ub2e4.",B.WM,B.KK,null)
B.PM=s(["\ud574\ub2f9 \ud589\uc704\uc758 \uc911\uc9c0\ub97c \uba85\ud558\ub294 \uc2dc\uc815\uc870\uce58","\uc704\ubc18\ud589\uc704 \uc0ac\uc2e4\uc758 \uacf5\ud45c \ub4f1 \ud544\uc694\ud55c \uc2dc\uc815\uc870\uce58","\uad00\ub828\ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \ud55c \uacfc\uc9d5\uae08 \ubd80\uacfc","\ud53c\ud574\ub97c \uc785\uc740 \uc18c\ube44\uc790\uc5d0 \ub300\ud55c \ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c","\uac00\uaca9 \uc778\ud558 \ub4f1 \uc704\ubc18\uc0c1\ud0dc\ub97c \uc2dc\uc815\ud558\uae30 \uc704\ud55c \uc870\uce58"],t.s)
B.Om=s(["\ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c"],t.s)
B.Wk=s(["\uc2dc\uc815\uc870\uce58 \uc885\ub958"],t.s)
B.aca=new A.f("gen_md_sanction_1","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud574 \ucde8\ud560 \uc218 \uc788\ub294 \uc870\uce58\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6b4 \uac83\uc740?",B.PM,3,'\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud574 \ud589\uc704 \uc911\uc9c0\uba85\ub839, \uc2dc\uc815\uc870\uce58, \uc704\ubc18\uc0ac\uc2e4 \uacf5\ud45c, \uad00\ub828\ub9e4\ucd9c\uc561 \uae30\uc900 \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1 \ud589\uc815\uc801 \uc81c\uc7ac\ub97c \ud560 \uc218 \uc788\ub2e4. \ub2e4\ub9cc "\ud615\uc0ac \uad6c\uc18d\uc601\uc7a5 \uccad\uad6c"\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815 \uc81c\uc7ac \uc218\ub2e8\uc774 \uc544\ub2c8\ub77c \ud615\uc0ac\uc18c\uc1a1\uc808\ucc28\uc5d0\uc11c \uac80\uc0ac\xb7\ubc95\uc6d0\uc774 \uad00\uc5ec\ud558\ub294 \uc601\uc5ed\uc73c\ub85c, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc9c1\uc811 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c \ud589\ud558\ub294 \uc870\uce58\uac00 \uc544\ub2c8\ub2e4.',B.Om,B.Wk,null)
B.MX=s(["\uad00\ub828\ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \uc77c\uc815 \ube44\uc728 \uc774\ub0b4\uc5d0\uc11c \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08\uc740 \uc704\ubc18\ud589\uc704\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \ub3d9\uc77c\ud55c \uc815\uc561\uc73c\ub85c \ubd80\uacfc\ub41c\ub2e4","\ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uacfc\uc9d5\uae08 \uc0c1\ud55c\uc740 \uc815\uc561\uc73c\ub85c \uace0\uc815\ub418\uc9c0 \uc54a\uace0 \ubcc4\ub3c4 \uae30\uc900\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08 \ubd80\uacfc\ub294 \ubc18\ub4dc\uc2dc \ubc95\uc6d0\uc758 \uc7ac\ud310\uc744 \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0\ub294 \uacfc\uc9d5\uae08 \uc81c\ub3c4\uac00 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Lc=s(["\uad00\ub828\ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \uc77c\uc815 \ube44\uc728 \uc774\ub0b4\uc5d0\uc11c \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc"],t.s)
B.n7=s(["\uacfc\uc9d5\uae08 \uc0b0\uc815\uae30\uc900"],t.s)
B.abd=new A.f("gen_md_sanction_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.MX,0,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08\uc740 \uc704\ubc18\ud589\uc704 \uad00\ub828 \ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \ubc95\ub839\uc774 \uc815\ud55c \ube44\uc728 \uc774\ub0b4\uc5d0\uc11c \ubd80\uacfc\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\uba70, \ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\ub97c \ub300\ube44\ud55c \ubcc4\ub3c4\uc758 \uc815\uc561 \uae30\uc900(\uacfc\uc9d5\uae08 \uc0c1\ud55c\uc561)\ub3c4 \ud568\uaed8 \ub9c8\ub828\ub418\uc5b4 \uc788\ub2e4. \uacfc\uc9d5\uae08 \ubd80\uacfc\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815\ucc98\ubd84\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c0\uba70 \ubc95\uc6d0\uc758 \uc7ac\ud310\uc744 \uac70\uccd0\uc57c\ub9cc \uac00\ub2a5\ud55c \uac83\uc740 \uc544\ub2c8\uace0(\ubd88\ubcf5 \uc2dc \uc0ac\ud6c4\uc801\uc73c\ub85c \ud589\uc815\uc18c\uc1a1\uc774 \uac00\ub2a5\ud560 \ubfd0), \uc704\ubc18\ud589\uc704\uc758 \ub0b4\uc6a9\xb7\uc815\ub3c4\uc5d0 \ub530\ub77c \uae08\uc561\uc774 \ub2ec\ub77c\uc9c4\ub2e4.",B.Lc,B.n7,null)
B.a0N=s(["\ucc98\ubd84\uc5d0 \uc774\uc758\uac00 \uc788\ub294 \uc0ac\uc5c5\uc790\ub294 \uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucc98\ubd84\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ubd88\ubcf5\uc774 \ubd88\uac00\ub2a5\ud558\ub2e4","\ubd88\ubcf5\uc740 \uc624\uc9c1 \ud5cc\ubc95\uc18c\uc6d0\uc744 \ud1b5\ud574\uc11c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc774\uc758\uc2e0\uccad \uc808\ucc28 \uc5c6\uc774 \ud615\uc0ac\uc7ac\ud310\uc73c\ub85c\ub9cc \ub2e4\ud234 \uc218 \uc788\ub2e4","\ucc98\ubd84\uc5d0 \ub300\ud55c \ubd88\ubcf5\uc740 \uc18c\ube44\uc790\ub9cc \uc81c\uae30\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Sb=s(["\uc774\uc758\uc2e0\uccad\uc774\ub098 \ud589\uc815\uc18c\uc1a1 \ub4f1\uc744 \ud1b5\ud574 \ub2e4\ud234 \uc218 \uc788\ub2e4"],t.s)
B.nO=s(["\ubd88\ubcf5\uc808\ucc28"],t.s)
B.adX=new A.f("gen_md_sanction_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ucc98\ubd84\uc5d0 \ubd88\ubcf5\ud558\ub294 \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.a0N,0,"\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \ucc98\ubd84\uc5d0 \uc774\uc758\uac00 \uc788\ub294 \uc0ac\uc5c5\uc790\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \ub300\ud55c \uc774\uc758\uc2e0\uccad\uc774\ub098 \ubc95\uc6d0\uc5d0 \ub300\ud55c \ud589\uc815\uc18c\uc1a1\uc744 \ud1b5\ud574 \ucc98\ubd84\uc758 \ucde8\uc18c\xb7\ubcc0\uacbd\uc744 \uad6c\ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \ub2e4\ub978 \ud589\uc815\ucc98\ubd84\uc5d0 \ub300\ud55c \ubd88\ubcf5 \uad6c\uc870\uc640 \uc720\uc0ac\ud558\uba70, \ud615\uc0ac\uc7ac\ud310\uc774\ub098 \ud5cc\ubc95\uc18c\uc6d0\ub9cc\uc774 \uc720\uc77c\ud55c \ubd88\ubcf5 \uc218\ub2e8\uc740 \uc544\ub2c8\ub2e4.",B.Sb,B.nO,null)
B.RO=s(["\uc704\ubc18\ud589\uc704\ub97c \uc911\uc9c0\uc2dc\ucf1c \uacbd\uc7c1\uc9c8\uc11c\ub97c \ud68c\ubcf5\ud558\ub294 \uac83","\uc704\ubc18\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc7a5\ub798\uc758 \uc720\uc0ac\ud589\uc704 \uc7ac\ubc1c\uc744 \ubc29\uc9c0\ud558\ub3c4\ub85d \ud558\ub294 \uac83","\ud53c\ud574\ub97c \uc785\uc740 \uacbd\uc7c1\uc0ac\uc5c5\uc790\xb7\uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ubcf4\ud638\ud558\ub294 \ub370 \uae30\uc5ec\ud558\ub294 \uac83","\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \ud1f4\ucd9c \uc790\uccb4\ub97c \ubaa9\ud45c\ub85c \ud558\ub294 \uac83","\uacbd\uc7c1\uc9c8\uc11c\ub97c \uc800\ud574\ud55c \uc0c1\ud0dc\ub97c \uc2dc\uc815\ud558\uc5ec \uc815\uc0c1\uc801\uc778 \uc2dc\uc7a5\uae30\ub2a5\uc744 \ud68c\ubcf5\ud558\ub294 \uac83"],t.s)
B.Hi=s(["\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \ud1f4\ucd9c \uc790\uccb4\ub97c \ubaa9\ud45c\ub85c \ud558\ub294 \uac83"],t.s)
B.T2=s(["\uc2dc\uc815\uc870\uce58\uc758 \ubaa9\uc801"],t.s)
B.a7W=new A.f("gen_md_sanction_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58\uc758 \ubaa9\uc801\uc73c\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.RO,3,"\uc2dc\uc815\uc870\uce58\ub294 \uc704\ubc18\ud589\uc704\ub97c \uc911\uc9c0\uc2dc\ud0a4\uace0 \uacbd\uc7c1\uc9c8\uc11c\uc640 \uc2dc\uc7a5\uae30\ub2a5\uc744 \uc815\uc0c1\uc801\uc73c\ub85c \ud68c\ubcf5\uc2dc\ud0a4\uba70, \uc7ac\ubc1c\uc744 \ubc29\uc9c0\ud558\uace0 \uad00\ub828 \uc0ac\uc5c5\uc790\xb7\uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ubcf4\ud638\ud558\ub294 \ub370 \ubaa9\uc801\uc774 \uc788\ub2e4. \uc704\ubc18\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\uc2dc\ud0a4\ub294 \uac83 \uc790\uccb4\uac00 \uc2dc\uc815\uc870\uce58\uc758 \ubaa9\uc801\uc740 \uc544\ub2c8\uba70, \uc5b4\ub514\uae4c\uc9c0\ub098 \uc704\ubc18\uc0c1\ud0dc\ub97c \uc2dc\uc815\ud558\ub294 \ub370 \ucd08\uc810\uc774 \uc788\ub2e4.",B.Hi,B.T2,null)
B.a2x=s(["\uc77c\uc815\ud55c \uacbd\uc6b0 \ud615\uc0ac\ucc98\ubc8c \uaddc\uc815\uc774 \ud568\uaed8 \uc801\uc6a9\ub420 \uc218 \uc788\uc5b4 \ud589\uc815\uc81c\uc7ac\uc640 \ud615\uc0ac\uc81c\uc7ac\uac00 \ubcd1\uc874\ud560 \uc218 \uc788\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \ub418\uc9c0 \uc54a\ub294\ub2e4","\ud615\uc0ac\ucc98\ubc8c\uc774 \ud655\uc815\ub418\uba74 \uacfc\uc9d5\uae08 \ub4f1 \ud589\uc815\uc81c\uc7ac\ub294 \uc790\ub3d9\uc73c\ub85c \uc804\ubd80 \ucde8\uc18c\ub41c\ub2e4","\ud615\uc0ac\ucc98\ubc8c\uc740 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\ud615\uc0ac\ucc98\ubc8c \uc5ec\ubd80\ub294 \uc18c\ube44\uc790\uc758 \uac1c\ubcc4 \ub3d9\uc758\uc5d0 \ub530\ub77c \uacb0\uc815\ub41c\ub2e4"],t.s)
B.Uz=s(["\ud589\uc815\uc81c\uc7ac\uc640 \ud615\uc0ac\uc81c\uc7ac\uac00 \ubcd1\uc874\ud560 \uc218 \uc788\ub2e4"],t.s)
B.OI=s(["\ud615\uc0ac\ucc98\ubc8c \ubcd1\uacfc \uac00\ub2a5\uc131"],t.s)
B.abe=new A.f("gen_md_sanction_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uac00 \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a2x,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \ub4f1 \uc8fc\uc694 \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud574 \ud589\uc815\uc81c\uc7ac(\uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08)\uc640 \ubcc4\ub3c4\ub85c \ud615\uc0ac\ucc98\ubc8c \uaddc\uc815\uc744 \ub450\uace0 \uc788\uc5b4, \uc0ac\uc548\uc5d0 \ub530\ub77c \ud589\uc815\uc81c\uc7ac\uc640 \ud615\uc0ac\uc81c\uc7ac\uac00 \ud568\uaed8 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4. \ud615\uc0ac\ucc98\ubc8c \uc5ec\ubd80\uc640 \uacfc\uc9d5\uae08 \ub4f1 \ud589\uc815\uc81c\uc7ac\ub294 \ubcc4\uac1c\uc758 \uc808\ucc28\uc640 \uc694\uac74\uc5d0 \ub530\ub77c \ud310\ub2e8\ub418\ubbc0\ub85c, \ud558\ub098\uac00 \ud655\uc815\ub418\uc5c8\ub2e4\uace0 \ub2e4\ub978 \ud558\ub098\uac00 \uc790\ub3d9\uc73c\ub85c \uc18c\uba78\ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Uz,B.OI,null)
B.a1W=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc9c1\uad8c\uc73c\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud560 \uc218 \uc788\ub2e4","\uc774\ud574\uad00\uacc4\uc778\uc758 \uc2e0\uace0\ub97c \uacc4\uae30\ub85c \uc870\uc0ac\uac00 \uc2dc\uc791\ub420 \uc218\ub3c4 \uc788\ub2e4","\uc870\uc0ac \uacb0\uacfc\uc5d0 \ub530\ub77c \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08 \ub4f1 \ucc98\ubd84\uc774 \ub0b4\ub824\uc9c8 \uc218 \uc788\ub2e4","\uc870\uc0ac\uc640 \ucc98\ubd84 \uacfc\uc815\uc5d0\uc11c \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc758\uacac\uc9c4\uc220 \uae30\ud68c\uac00 \uc804\ud600 \ubd80\uc5ec\ub418\uc9c0 \uc54a\ub294\ub2e4","\ucc98\ubd84 \uc804 \uc2ec\uc758 \ub4f1 \uc808\ucc28\uc801 \ub2e8\uacc4\ub97c \uac70\uce58\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4"],t.s)
