B.a7U=new A.f("gen_md_sanction_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc870\uc0ac \ubc0f \ucc98\ubd84 \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.a1W,3,'\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc9c1\uad8c \ub610\ub294 \uc2e0\uace0\ub97c \uacc4\uae30\ub85c \uc870\uc0ac\ub97c \uac1c\uc2dc\ud560 \uc218 \uc788\uace0, \uc870\uc0ac \uacb0\uacfc\uc5d0 \ub530\ub77c \uc2ec\uc758 \ub4f1 \uc808\ucc28\ub97c \uac70\uccd0 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \ucc98\ubd84\uc744 \ub0b4\ub9b0\ub2e4. \uc774 \uacfc\uc815\uc5d0\uc11c \ud53c\uc2ec\uc778(\uc0ac\uc5c5\uc790)\uc5d0\uac8c\ub294 \uc758\uacac\uc9c4\uc220 \uae30\ud68c \ub4f1 \ubc29\uc5b4\uad8c\uc774 \ubcf4\uc7a5\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ubbc0\ub85c, "\uc758\uacac\uc9c4\uc220 \uae30\ud68c\uac00 \uc804\ud600 \ubd80\uc5ec\ub418\uc9c0 \uc54a\ub294\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.RE,B.MB,null)
B.Uy=s(["\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704 \ub610\ub294 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\ud589\uc704"],t.s)
B.a2e=s(["\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704 \ub610\ub294 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"],t.s)
