B.aaS=new A.f("gen_md_case_1","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc778 A\uc0ac\uac00 \uacbd\uc7c1\uc0ac\uc5c5\uc790 B\uc0ac\uc758 \uc2e0\uc81c\ud488 \ucd9c\uc2dc\ub97c \ubc29\ud574\ud560 \ubaa9\uc801\uc73c\ub85c, \uc790\uc0ac \uc720\ud1b5\ub9dd\uc5d0\ub9cc \uacf5\uae09\ud558\ub294 \ud544\uc218\ubd80\ud488\uc758 \ud310\ub9e4\ub97c B\uc0ac\uc5d0\uac8c \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac70\uc808\ud55c \uacbd\uc6b0 \ud574\ub2f9\ud558\ub294 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Uy,0,'\ud544\uc218\uc801\uc778 \uc694\uc18c(\ubd80\ud488\xb7\uc124\ube44 \ub4f1)\uc758 \uc0ac\uc6a9\uc744 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac70\uc808\ud574 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \uc9c4\uc785\uc774\ub098 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub294 \uc0ac\uc548\uc5d0 \ub530\ub77c "\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704" \ub610\ub294 "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\ub85c \ud3ec\uc12d\ub420 \uc218 \uc788\ub294 \ub300\ud45c\uc801\uc778 \ubc30\uc81c\ub0a8\uc6a9 \uc0ac\ub840\uc774\ub2e4. \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\xb7\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\xb7\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc740 \ubaa8\ub450 \uc774 \uc0ac\ub840\uc758 \uc0ac\uc2e4\uad00\uacc4\uc640 \ubb34\uad00\ud55c \ubcc4\uac1c\uc758 \uaddc\uc81c \uc720\ud615\uc774\ub2e4.',B.a2e,B.JY,null)
B.Sc=s([u.bG,"\uc2dc\uc7a5\uc810\uc720\uc728\uc774 \uc5bc\ub9c8\uc774\ub4e0 \uac00\uaca9\uc744 \uc62c\ub9ac\ub294 \ud589\uc704\ub294 \ud56d\uc0c1 \ud569\ubc95\uc774\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac00\uaca9 \uc778\uc0c1\uc740 \ud56d\uc0c1 \uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\uc640 \ubb34\uad00\ud558\uac8c \ud310\ub2e8\ub41c\ub2e4"],t.s)
