B.a8T=new A.f("gen_md_case_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc810\uc720\uc728 70%\uc778 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \uc6d0\uac00 \uc0c1\uc2b9 \uc694\uc778\uc774 \uc804\ud600 \uc5c6\uc74c\uc5d0\ub3c4 \ud2b9\ubcc4\ud55c \uc774\uc720 \uc5c6\uc774 \uc790\uc0ac \uc81c\ud488 \uac00\uaca9\uc744 \ud070 \ud3ed\uc73c\ub85c \uc778\uc0c1\ud55c \uacbd\uc6b0, \uc774\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Sc,0,"\uc6d0\uac00 \uc0c1\uc2b9 \ub4f1 \uac1d\uad00\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 \uadfc\uac70 \uc5c6\uc774 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uac00\uaca9\uc744 \ubd80\ub2f9\ud558\uac8c \uc778\uc0c1\ud558\ub294 \uac83\uc740 \uac00\uaca9\ub0a8\uc6a9\uc758 \uc804\ud615\uc801\uc778 \uc0ac\ub840\ub85c \ud3c9\uac00\ub420 \uc218 \uc788\ub2e4. \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc790\uc0ac \uc0c1\ud488\uc744 \uac70\ub798\ud558\ub294 \uc720\ud1b5\uc5c5\uc790\uc5d0\uac8c \ud310\ub9e4\uac00\uaca9\uc744 \uac15\uc81c\ud558\ub294 \ud589\uc704\ub85c \uc774 \uc0ac\ub840\uc640 \ub2e4\ub974\uace0, \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc8fc\uccb4\uac00 \ub418\uc5b4\uc57c \ud558\ubbc0\ub85c \uc5ed\uc2dc \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.LU,B.Lg,null)
B.H5=s(["\ucd9c\uace0\uc870\uc808","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5"],t.s)
B.ZE=s(["\uc0dd\uc0b0\xb7\ucd9c\uace0\ub7c9\uc744 \ucd5c\uadfc \ucd94\uc138\ubcf4\ub2e4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ucf1c \uc218\uae09\uc5d0 \uc778\uc704\uc801 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \ud589\uc704\ub294 \ucd9c\uace0\uc870\uc808"],t.s)
