B.a6N=new A.f("gen_md_case_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \ubc18\ub3c4\uccb4 \uc218\uc694 \uae09\uc99d \uc0c1\ud669\uc5d0\uc11c \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0dd\uc0b0\ub7c9\uc744 \uc885\uc804 \ub300\ube44 \ud604\uc800\ud788 \uc904\uc5ec \uc2dc\uc7a5\uc5d0 \uc778\uc704\uc801\uc778 \ud488\uadc0 \ud604\uc0c1\uc744 \uc77c\uc73c\ud0a8 \uacbd\uc6b0 \ud574\ub2f9\ud560 \uc218 \uc788\ub294 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc740?",B.H5,0,"\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0dd\uc0b0\xb7\ucd9c\uace0\ub7c9\uc744 \ucd5c\uadfc \ucd94\uc138\ubcf4\ub2e4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ucf1c \uc218\uae09\uc5d0 \uc778\uc704\uc801 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \ud589\uc704\ub294 \ucd9c\uace0\uc870\uc808\uc758 \uc804\ud615\uc801 \uc0ac\ub840\uc774\ub2e4. \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\xb7\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc740 \uac01\uac01 \ub2e4\ub978 \uc694\uac74\uacfc \uc8fc\uccb4\ub97c \uc804\uc81c\ub85c \ud558\ub294 \ubcc4\uac1c\uc758 \uaddc\uc81c \uc720\ud615\uc73c\ub85c, \uc774 \uc0ac\ub840\uc640\ub294 \uc131\uaca9\uc774 \ub2e4\ub974\ub2e4.",B.ZE,B.XE,null)
B.Vj=s([u.cx,"\uc2e0\uaddc \uc9c4\uc785\uc744 \ub9c9\ub294 \ud589\uc704\ub294 \uc774\uc720\ub97c \ubd88\ubb38\ud558\uace0 \ud56d\uc0c1 \uc704\ubc95\ud558\ub2e4","\uc548\uc804\uae30\uc900\uc744 \uc774\uc720\ub85c \ub4e0 \uacbd\uc6b0\ub294 \ud56d\uc0c1 \ud615\uc2dd\uc801 \ud56d\ubcc0\uc73c\ub85c \ucde8\uae09\ub418\uc5b4 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uacbd\uc6b0 \ubc18\ub4dc\uc2dc \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub85c \uc758\uc728\ud574\uc57c \ud55c\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c\ub9cc \uaddc\uc728\ub420 \uc218 \uc788\ub2e4"],t.s)
