B.a9b=new A.f("gen_md_case_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \uc2e0\uaddc \uc9c4\uc785\uc744 \uc2dc\ub3c4\ud558\ub294 B\uc0ac\uc5d0\uac8c \ud544\uc218\uc801\uc778 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \uac70\uc808\ud558\uba74\uc11c, \ub3d9\uc2dc\uc5d0 \uadf8 \uac70\uc808\uc774 \uc548\uc804\uae30\uc900 \ubbf8\ub2ec\uc744 \uc774\uc720\ub85c \ud55c \ud569\ub9ac\uc801 \uc870\uce58\uc600\uc74c\uc774 \uac1d\uad00\uc801\uc73c\ub85c \uc785\uc99d\ub41c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Vj,0,'\ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\ucc98\ub7fc \ubcf4\uc774\ub294 \ud589\uc704\ub77c\ub3c4, \uc548\uc804\xb7\ud488\uc9c8\uad00\ub9ac \ub4f1 \uac1d\uad00\uc801\uc774\uace0 \ud569\ub9ac\uc801\uc778 "\uc815\ub2f9\ud55c \uc774\uc720"\uac00 \uc2e4\uc81c\ub85c \uc785\uc99d\ub41c\ub2e4\uba74 \uc704\ubc95\uc131\uc774 \uc870\uac01\ub418\uc5b4 \ub0a8\uc6a9\ud589\uc704\uac00 \uc131\ub9bd\ud558\uc9c0 \uc54a\uc744 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \uc774\ub7ec\ud55c \ud56d\ubcc0\uc740 \ud615\uc2dd\uc801 \uc8fc\uc7a5\ub9cc\uc73c\ub85c\ub294 \uc778\uc815\ub418\uc9c0 \uc54a\uace0 \uac1d\uad00\uc801 \uadfc\uac70\uac00 \ub4b7\ubc1b\uce68\ub418\uc5b4\uc57c \ud558\uba70, \uc774 \uc0ac\ub840\ub294 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\ub098 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc640\ub294 \ubb34\uad00\ud55c \ub2e8\ub3c5\ud589\uc704 \uc0ac\uc548\uc774\ub2e4.',B.Yb,B.XP,null)
B.NS=s(["\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704","\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c \uc704\ubc18","\ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\ud589\uc704"],t.s)
B.UO=s(["\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"],t.s)
B.a2q=s(["\uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704 \uc0ac\ub840"],t.s)
B.a7R=new A.f("gen_md_case_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 A\uc0ac\uac00 \uc790\uc0ac\uc640 \uacbd\uc7c1 \uad00\uacc4\uc5d0 \uc788\ub294 B\uc0ac\uc5d0 \ub300\ud574\uc11c\ub9cc \ub9e4\uc6b0 \ubd88\ub9ac\ud55c \uac70\ub798\uc870\uac74\uc744 \uc81c\uc2dc\ud558\uc5ec B\uc0ac\uc758 \uc815\uc0c1\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud604\uc800\ud788 \uc5b4\ub835\uac8c \ub9cc\ub4e4\uc5c8\ub2e4\uba74, \uc774\ub294 \ub2e4\uc74c \uc911 \uc5b4\ub290 \uc720\ud615\uc73c\ub85c \ud3ec\uc12d\ub420 \uac00\ub2a5\uc131\uc774 \uac00\uc7a5 \ud070\uac00?",B.NS,0,'\uacbd\uc7c1\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \ubd88\ub9ac\ud55c \uac70\ub798\uc870\uac74\uc744 \uc81c\uc2dc\ud558\uc5ec \uc815\uc0c1\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud604\uc800\ud788 \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub294 "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub294 \uc804\ud615\uc801 \uc0ac\ub840\uc774\ub2e4. \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\xb7\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\xb7\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5\uc740 \uac01\uac01 \ubcc4\ub3c4\uc758 \uc694\uac74(\uc720\ud1b5\uc5c5\uc790\uc5d0 \ub300\ud55c \uac00\uaca9 \uac15\uc81c, \uc0ac\uc5c5\uc790 \uac04 \ud569\uc758, \uae30\uc5c5\uc9d1\ub2e8 \uaddc\uc81c, \ud2b9\uc218\uad00\uacc4\uc778 \uac70\ub798 \ub4f1)\uc744 \uc804\uc81c\ub85c \ud558\ubbc0\ub85c \uc774 \uc0ac\ub840\uc640\ub294 \ubd80\ud569\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.UO,B.a2q,null)
B.a16=s(["\ud589\uc704\uc790\uac00 \ud574\ub2f9 \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0","\ubb38\uc81c\ub41c \ud589\uc704\uac00 \ubc95\uc815 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615 \uc911 \uc5b4\ub514\uc5d0 \ud574\ub2f9\ud558\ub294\uc9c0","\ud589\uc704\uc758 \ubd80\ub2f9\uc131(\uacbd\uc7c1\uc81c\ud55c\ud6a8\uacfc\xb7\uc18c\ube44\uc790\uc774\uc775 \uce68\ud574 \uc6b0\ub824 \ub4f1)\uc774 \uc778\uc815\ub418\ub294\uc9c0","\ud589\uc704\uc790\uc758 \uac1c\uc778\uc801 \uce5c\ubd84\uad00\uacc4\ub098 \uc0ac\uc801\uc778 \ud3c9\ud310\uc774 \uc5b4\ub5a0\ud55c\uc9c0","\uc815\ub2f9\ud55c \uc774\uc720 \ub4f1 \uc704\ubc95\uc131 \uc870\uac01\uc0ac\uc720\uac00 \uc874\uc7ac\ud558\ub294\uc9c0"],t.s)
B.SU=s(["\ud589\uc704\uc790\uc758 \uac1c\uc778\uc801 \uce5c\ubd84\uad00\uacc4\ub098 \uc0ac\uc801\uc778 \ud3c9\ud310\uc774 \uc5b4\ub5a0\ud55c\uc9c0"],t.s)
B.a1d=s(["\uc0ac\ub840\ubd84\uc11d \uccb4\ud06c\ub9ac\uc2a4\ud2b8"],t.s)
B.aaI=new A.f("gen_md_case_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud310\ub840\xb7\uc0ac\ub840","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc0ac\ub840\ub97c \ubd84\uc11d\ud560 \ub54c \uac80\ud1a0\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uac70\ub9ac\uac00 \uba3c \uac83\uc740?",B.a16,3,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc0ac\ub840 \ubd84\uc11d\uc740 \ud589\uc704\uc790\uc758 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud574\ub2f9 \uc5ec\ubd80, \ubc95\uc815 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615 \ud574\ub2f9\uc131, \ubd80\ub2f9\uc131 \uc778\uc815 \uc5ec\ubd80, \uc815\ub2f9\ud55c \uc774\uc720 \ub4f1 \uc704\ubc95\uc131 \uc870\uac01\uc0ac\uc720 \uc874\ubd80\ub97c \uc911\uc2ec\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4\ub2e4. \ud589\uc704\uc790\uc758 \uac1c\uc778\uc801 \uce5c\ubd84\uad00\uacc4\ub098 \uc0ac\uc801 \ud3c9\ud310\uc740 \ubc95\uc801 \ud310\ub2e8 \uc694\uc18c\uac00 \uc544\ub2c8\ubbc0\ub85c \uac80\ud1a0 \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4.",B.SU,B.a1d,null)
B.VU=s(["\uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud589\uc704\ub85c \uc778\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0 \uc774 \ubc95\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294\uc9c0 \uc5ec\ubd80\ub294 \uc9c1\uc811\uc801\uc774\uace0 \uc0c1\ub2f9\ud558\uba70 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc744 \uae30\uc900\uc73c\ub85c \uc81c\ud55c \ud574\uc11d\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc678\ud589\uc704\uac00 \uc678\uad6d \ubc95\ub960\uc0c1 \uc801\ubc95\ud558\ub2e4\uba74 \uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc774 \ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub41c\ub2e4","\uc815\ubd80\ub294 \ub300\ud55c\ubbfc\uad6d\uc758 \ubc95\ub960 \ubc0f \uc774\uc775\uc5d0 \ubc18\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uc678\uad6d\uc815\ubd80\uc640 \uc774 \ubc95 \uc9d1\ud589\uc744 \uc704\ud55c \ud611\uc815\uc744 \uccb4\uacb0\ud560 \uc218 \uc788\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uadfc\uac70 \uc870\ubb38\uc740 \uc774 \ubc95 \uc81c\uc815 \ub2f9\uc2dc\ubd80\ud130 \uc874\uc7ac\ud55c \uac83\uc740 \uc544\ub2c8\ub2e4"],t.s)
B.Sx=s(["\uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc6b0\ub9ac\ub098\ub77c \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\uace0 \ud310\uc2dc"],t.s)
B.UF=s(["\uc5ed\uc678\uc801\uc6a9"],t.s)
B.a84=new A.f("gen_gn_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc758 \uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.VU,2,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c3\uc870\ub294 \uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud6a8\uacfc\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud55c\ub2e4\ub294 \uc5ed\uc678\uc801\uc6a9 \uc6d0\uce59\uc744 \uba85\uc2dc\ud558\uace0 \uc788\ub2e4. \ub300\ubc95\uc6d0 \ud310\ub840(\ud751\uc5f0\uc804\uadf9\ubd09 \uc0ac\uac74 \ub4f1)\ub294 \uc774\ub54c "\uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0"\ub97c \ubb38\uc81c\ub41c \uad6d\uc678\ud589\uc704\ub85c \uc778\ud574 \uc9c1\uc811\uc801\xb7\uc0c1\ub2f9\ud558\uace0 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0\ub85c \uc81c\ud55c \ud574\uc11d\ud558\ub418, \uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc678\ud589\uc704\uac00 \uadf8 \uc678\uad6d \ubc95\ub960\uc0c1\uc73c\ub85c\ub294 \uc801\ubc95\ud55c \ud589\uc704\uc600\ub2e4 \ud558\ub354\ub77c\ub3c4 \uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc6b0\ub9ac\ub098\ub77c \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\uace0 \ud310\uc2dc\ud558\uc600\ub2e4. \uc989 "\uc678\uad6d\uc5d0\uc11c \uc801\ubc95 = \uad6d\ub0b4\ubc95 \uc801\uc6a9 \ubc30\uc81c"\ub77c\ub294 \ub4f1\uc2dd\uc740 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec\uc774\uba70, \uad6d\uac00 \uac04 \ud611\uc815 \uccb4\uacb0 \uadfc\uac70(\uc81c56\uc870)\ub098 \uc5ed\uc678\uc801\uc6a9 \uc870\ubb38\uc758 \uc2e0\uc124 \uc5f0\ud601\ub3c4 \ud568\uaed8 \uc54c\uc544\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.Sx,B.UF,null)
B.YT=s(["\uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1\uc744 \ucd09\uc9c4\ud558\ub294 \uac83","\ucc3d\uc758\uc801\uc778 \uae30\uc5c5\ud65c\ub3d9\uc744 \uc870\uc7a5\ud558\ub294 \uac83","\uc18c\ube44\uc790\ub97c \ubcf4\ud638\ud558\ub294 \uac83","\uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804\uc744 \ub3c4\ubaa8\ud558\ub294 \uac83","\ud2b9\uc815 \uc0b0\uc5c5 \ubd84\uc57c\uc758 \uad6d\ub0b4 \uae30\uc5c5\uc744 \uc678\uad6d \uae30\uc5c5\uacfc\uc758 \uacbd\uc7c1\uc73c\ub85c\ubd80\ud130 \ubcf4\ud638\ud558\ub294 \uac83"],t.s)
B.TK=s(["\ud2b9\uc815 \uc0b0\uc5c5 \ubd84\uc57c\uc758 \uad6d\ub0b4 \uae30\uc5c5\uc744 \uc678\uad6d \uae30\uc5c5\uacfc\uc758 \uacbd\uc7c1\uc73c\ub85c\ubd80\ud130 \ubcf4\ud638\ud558\ub294 \uac83"],t.s)
B.Rp=s(["\ubc95\uc758 \ubaa9\uc801"],t.s)
B.aaR=new A.f("gen_gn_purpose_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c1\uc870\uac00 \uba85\uc2dc\ud558\ub294 \ubaa9\uc801\uc73c\ub85c \ubcfc \uc218 \uc5c6\ub294 \uac83\uc740?",B.YT,4,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c1\uc870\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704\uc758 \ub0a8\uc6a9\uacfc \uacfc\ub3c4\ud55c \uacbd\uc81c\ub825 \uc9d1\uc911\uc744 \ubc29\uc9c0\ud558\uace0 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \ubc0f \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub97c \uaddc\uc81c\ud558\uc5ec \uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1\uc744 \ucd09\uc9c4\ud568\uc73c\ub85c\uc368 \ucc3d\uc758\uc801\uc778 \uae30\uc5c5\ud65c\ub3d9\uc744 \uc870\uc7a5\ud558\uace0 \uc18c\ube44\uc790\ub97c \ubcf4\ud638\ud568\uacfc \uc544\uc6b8\ub7ec \uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804\uc744 \ub3c4\ubaa8\ud568\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \ud2b9\uc815 \uc0b0\uc5c5\uc758 \uad6d\ub0b4 \uae30\uc5c5\uc744 \uc678\uad6d \uacbd\uc7c1\uc73c\ub85c\ubd80\ud130 \ubcf4\ud638\ud558\ub294 \uac83\uc740 \uc774 \ubc95\uc758 \ubaa9\uc801\uc774 \uc544\ub2c8\uba70, \uc624\ud788\ub824 \uacbd\uc7c1 \ucd09\uc9c4\uc774 \ud575\uc2ec \ubaa9\uc801\uc774\ub2e4.",B.TK,B.Rp,null)
B.a0R=s(["\uc790\uc720\ub85c\uc6b4 \uc2dc\uc7a5 \uc9c4\uc785\xb7\uacbd\uc7c1\uc758 \ubcf4\uc7a5(\uc790\uc720\uacbd\uc7c1)\uacfc \ubd80\ub2f9\ud55c \ubc29\ubc95\uc5d0 \uc758\ud55c \uacbd\uc7c1 \ubc30\uc81c \uae08\uc9c0(\uacf5\uc815\uacbd\uc7c1)\ub97c \ud568\uaed8 \ucd94\uad6c\ud558\ub294 \uac1c\ub150\uc774\ub2e4","\uc790\uc720\uacbd\uc7c1\ub9cc\uc744 \ucd94\uad6c\ud560 \ubfd0 \uacf5\uc815\uc131\uc740 \uace0\ub824\ud558\uc9c0 \uc54a\ub294\ub2e4","\uacf5\uc815\uacbd\uc7c1\ub9cc\uc744 \ucd94\uad6c\ud560 \ubfd0 \uc9c4\uc785\uc758 \uc790\uc720\ub294 \ubcf4\uc7a5\ud558\uc9c0 \uc54a\ub294\ub2e4","\uacbd\uc7c1\uc758 \uc790\uc720\uc640 \uacf5\uc815\uc131\uc740 \uc11c\ub85c \uc591\ub9bd\ud560 \uc218 \uc5c6\ub294 \uac1c\ub150\uc774\ub2e4","\uc774 \uac1c\ub150\uc740 \uc624\uc9c1 \ub300\uae30\uc5c5\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.Qr=s(["\uc790\uc720\ub85c\uc6b4 \uc2dc\uc7a5 \uc9c4\uc785\xb7\uacbd\uc7c1\uc758 \ubcf4\uc7a5(\uc790\uc720\uacbd\uc7c1)\uacfc \ubd80\ub2f9\ud55c \ubc29\ubc95\uc5d0 \uc758\ud55c \uacbd\uc7c1 \ubc30\uc81c \uae08\uc9c0(\uacf5\uc815\uacbd\uc7c1)\ub97c \ud568\uaed8 \ucd94\uad6c"],t.s)
B.IB=s(["\uc790\uc720\uacbd\uc7c1\uacfc \uacf5\uc815\uacbd\uc7c1"],t.s)
B.acl=new A.f("gen_gn_purpose_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc774 \ucd94\uad6c\ud558\ub294 "\uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a0R,0,'"\uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1"\uc740 \ub204\uad6c\ub098 \uc2dc\uc7a5\uc5d0 \uc790\uc720\ub86d\uac8c \uc9c4\uc785\ud558\uc5ec \uacbd\uc7c1\ud560 \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4\ub294 \uc790\uc720\uacbd\uc7c1\uc758 \uce21\uba74\uacfc, \ubd80\ub2f9\ud55c \ubc29\ubc95\uc73c\ub85c \uacbd\uc7c1\uc790\ub97c \ubc30\uc81c\ud558\uac70\ub098 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ubd88\uc774\uc775\uc744 \uc8fc\ub294 \ud589\uc704\ub294 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4\ub294 \uacf5\uc815\uacbd\uc7c1\uc758 \uce21\uba74\uc744 \ud568\uaed8 \ud3ec\ud568\ud558\ub294 \uac1c\ub150\uc774\ub2e4. \ub450 \uce21\uba74\uc740 \ub300\ub9bd\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uc791\ub3d9\ud558\uba70, \uc0ac\uc5c5\uc790 \uaddc\ubaa8\uc640 \ubb34\uad00\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4.',B.Qr,B.IB,null)
B.V0=s(["\uacf5\uc815\ud55c \uacbd\uc7c1\ud658\uacbd\uc744 \uc870\uc131\ud568\uc73c\ub85c\uc368 \uc0ac\uc5c5\uc790\ub4e4\uc774 \ud601\uc2e0\uacfc \ud6a8\uc728\uc131 \ud5a5\uc0c1\uc744 \ud1b5\ud574 \uacbd\uc7c1\ud558\ub3c4\ub85d \uc720\uc778\ud558\ub824\ub294 \uac83\uc774\ub2e4","\ud2b9\uc815 \uae30\uc5c5\uc5d0\uac8c \ub3c5\uc810\uc801 \uc9c0\uc704\ub97c \ubcf4\uc7a5\ud574 \uc548\uc815\uc801\uc778 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ub3d5\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\ubaa8\ub4e0 \uae30\uc5c5\uc758 \uc2e0\uc81c\ud488 \uac1c\ubc1c\uc744 \uc815\ubd80\uac00 \uc9c1\uc811 \uc9c0\uc6d0\ud558\uaca0\ub2e4\ub294 \uc758\ubbf8\uc774\ub2e4","\ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9\uc740 \ubc95\uc758 \ubaa9\uc801\uacfc \ubb34\uad00\ud55c \ubd80\uc218\uc801 \ubb38\uad6c\uc5d0 \ubd88\uacfc\ud558\ub2e4","\ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9 \uc870\uc7a5\uc740 \ub300\uae30\uc5c5\uc5d0\ub9cc \ud574\ub2f9\ub418\ub294 \ubaa9\uc801\uc774\ub2e4"],t.s)
B.Jl=s(["\uacf5\uc815\ud55c \uacbd\uc7c1\ud658\uacbd\uc744 \uc870\uc131\ud568\uc73c\ub85c\uc368 \uc0ac\uc5c5\uc790\ub4e4\uc774 \ud601\uc2e0\uacfc \ud6a8\uc728\uc131 \ud5a5\uc0c1\uc744 \ud1b5\ud574 \uacbd\uc7c1\ud558\ub3c4\ub85d \uc720\uc778"],t.s)
B.Vk=s(["\ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9 \uc870\uc7a5"],t.s)
B.a8H=new A.f("gen_gn_purpose_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc774 "\ucc3d\uc758\uc801\uc778 \uae30\uc5c5\ud65c\ub3d9\uc744 \uc870\uc7a5"\ud55c\ub2e4\uace0 \uaddc\uc815\ud55c \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.V0,0,"\uacbd\uc7c1\uc774 \ud65c\ubc1c\ud55c \uc2dc\uc7a5\uc5d0\uc11c\ub294 \uc0ac\uc5c5\uc790\ub4e4\uc774 \uc0b4\uc544\ub0a8\uae30 \uc704\ud574 \ube44\uc6a9\uc808\uac10\xb7\ud488\uc9c8\uac1c\uc120\xb7\uae30\uc220\ud601\uc2e0 \ub4f1 \ucc3d\uc758\uc801\uc778 \ub178\ub825\uc744 \uae30\uc6b8\uc774\uac8c \ub41c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uc740 \uc2dc\uc7a5\uc9c0\ubc30\ub825 \ub0a8\uc6a9\uc774\ub098 \ubd80\ub2f9\ud55c \ub2f4\ud569\xb7\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1 \uacbd\uc7c1\uc744 \uc65c\uace1\ud558\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud568\uc73c\ub85c\uc368 \uc774\ub7ec\ud55c \ucc3d\uc758\uc801 \uae30\uc5c5\ud65c\ub3d9\uc774 \uc774\ub8e8\uc5b4\uc9c8 \uc218 \uc788\ub294 \ud658\uacbd\uc744 \uc870\uc131\ud558\ub824\ub294 \ucde8\uc9c0\ub97c \uac16\ub294\ub2e4.",B.Jl,B.Vk,null)
B.a_7=s(["\uac1c\ubcc4 \uc18c\ube44\uc790\ud53c\ud574\uc758 \uc0ac\ud6c4\uc801 \uad6c\uc81c\ubcf4\ub2e4\ub294 \uacbd\uc7c1 \ucd09\uc9c4\uc744 \ud1b5\ud574 \uc18c\ube44\uc790\ud6c4\uc0dd\uc744 \uc99d\uc9c4\ud558\ub294 \uac04\uc811\uc801\xb7\uad6c\uc870\uc801 \ubcf4\ud638\uc5d0 \uac00\uae5d\ub2e4","\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc744 \uc644\uc804\ud788 \ub300\uccb4\ud558\ub294 \uc18c\ube44\uc790\ud53c\ud574 \uad6c\uc81c \uc804\ub2f4 \ubc95\ub960\uc774\ub2e4","\uc18c\ube44\uc790 \ubcf4\ud638\ub294 \uc774 \ubc95\uc758 \ubaa9\uc801\uc5d0 \uc804\ud600 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc18c\ube44\uc790 \ubcf4\ud638\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\ub294 \ubaa9\uc801\uc774\ub2e4","\uc18c\ube44\uc790 \ubcf4\ud638\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\uc744 \ud1b5\ud574\uc11c\ub9cc \ub2ec\uc131\ub41c\ub2e4"],t.s)
B.WV=s(["\uacbd\uc7c1 \ucd09\uc9c4\uc744 \ud1b5\ud574 \uc18c\ube44\uc790\ud6c4\uc0dd\uc744 \uc99d\uc9c4\ud558\ub294 \uac04\uc811\uc801\xb7\uad6c\uc870\uc801 \ubcf4\ud638\uc5d0 \uac00\uae5d\ub2e4"],t.s)
B.OO=s(["\uc18c\ube44\uc790\ubcf4\ud638\uc758 \uc131\uaca9"],t.s)
B.adw=new A.f("gen_gn_purpose_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc5d0 \uc758\ud55c "\uc18c\ube44\uc790 \ubcf4\ud638"\uc758 \uc131\uaca9\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a_7,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uac1c\ubcc4 \uc18c\ube44\uc790\uc758 \ud53c\ud574\ub97c \uc9c1\uc811 \uad6c\uc81c\ud558\ub294 \uc808\ucc28(\uc608: \uc18c\ube44\uc790\ubd84\uc7c1\uc870\uc815)\ub97c \uc8fc\ub41c \uc218\ub2e8\uc73c\ub85c \ud558\uae30\ubcf4\ub2e4\ub294, \uacbd\uc7c1\uc744 \ucd09\uc9c4\ud558\uc5ec \uac00\uaca9 \uc778\ud558\xb7\ud488\uc9c8 \ud5a5\uc0c1 \ub4f1 \uc18c\ube44\uc790\ud6c4\uc0dd \uc99d\uc9c4 \ud6a8\uacfc\uac00 \uc2dc\uc7a5 \uc804\ubc18\uc5d0 \ubbf8\uce58\ub3c4\ub85d \ud558\ub294 \uad6c\uc870\uc801\xb7\uac04\uc811\uc801 \ubc29\uc2dd\uc73c\ub85c \uc18c\ube44\uc790\ub97c \ubcf4\ud638\ud558\ub294 \uc131\uaca9\uc774 \uac15\ud558\ub2e4. \uac1c\ubcc4 \ud53c\ud574\uad6c\uc81c\ub294 \uc18c\ube44\uc790\uae30\ubcf8\ubc95 \ub4f1 \ub2e4\ub978 \ubc95\ub960\uc758 \uc601\uc5ed\uacfc \ud568\uaed8 \uc791\ub3d9\ud55c\ub2e4.",B.WV,B.OO,null)
B.P5=s(["\uacfc\ub3c4\ud55c \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\ub97c \uc704\ud55c \uae30\uc5c5\uc9d1\ub2e8 \uad00\ub828 \uaddc\uc81c","\uac1c\ubcc4 \uc18c\ube44\uc790\uc5d0 \ub300\ud55c \uc190\ud574\ubc30\uc0c1 \uc18c\uc1a1 \uc808\ucc28","\ud615\uc0ac\uc18c\uc1a1\ubc95\uc0c1 \uc99d\uac70\uc7ac\ud310\uc8fc\uc758","\ubbfc\ubc95\uc0c1 \uacc4\uc57d\uc790\uc720\uc758 \uc6d0\uce59","\ub178\ub3d9\ubc95\uc0c1 \uadfc\ub85c\uc2dc\uac04 \uaddc\uc81c"],t.s)
B.Z0=s(["\uacfc\ub3c4\ud55c \uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c\ub97c \uc704\ud55c \uae30\uc5c5\uc9d1\ub2e8 \uad00\ub828 \uaddc\uc81c"],t.s)
B.Xz=s(["\uad6d\ubbfc\uacbd\uc81c \uade0\ud615\ubc1c\uc804","\uacbd\uc81c\ub825\uc9d1\uc911 \uc5b5\uc81c"],t.s)
B.aay=new A.f("gen_gn_purpose_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150",'\uacf5\uc815\uac70\ub798\ubc95\uc774 "\uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804"\uc744 \ubaa9\uc801\uc73c\ub85c \uaddc\uc815\ud55c \uac83\uacfc \uac00\uc7a5 \ubc00\uc811\ud558\uac8c \uad00\ub828\ub41c \uc81c\ub3c4\ub294?',B.P5,0,"\uad6d\ubbfc\uacbd\uc81c\uc758 \uade0\ud615\uc788\ub294 \ubc1c\uc804\uc774\ub77c\ub294 \ubaa9\uc801\uc740 \ud2b9\uc815 \uae30\uc5c5\uc9d1\ub2e8\uc73c\ub85c \uacbd\uc81c\ub825\uc774 \uacfc\ub3c4\ud558\uac8c \uc9d1\uc911\ub418\ub294 \uac83\uc744 \uc5b5\uc81c\ud558\uae30 \uc704\ud55c \uc9c0\uc8fc\ud68c\uc0ac \uaddc\uc81c, \uc0c1\ud638\ucd9c\uc790\xb7\uc21c\ud658\ucd9c\uc790 \uc81c\ud55c, \ucc44\ubb34\ubcf4\uc99d \uc81c\ud55c \ub4f1 \uae30\uc5c5\uc9d1\ub2e8 \uad00\ub828 \uaddc\uc81c\uc640 \uac00\uc7a5 \ubc00\uc811\ud558\uac8c \uad00\ub828\ub41c\ub2e4. \uc774\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\uc774\ub098 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uaddc\uc81c\uc640\ub294 \ubcc4\ub3c4\ub85c \uad6d\ubbfc\uacbd\uc81c \uc804\uccb4\uc758 \uade0\ud615\uc744 \uace0\ub824\ud558\ub294 \ucde8\uc9c0\uc758 \uaddc\uc815\uc774\ub2e4.",B.Z0,B.Xz,null)
B.UZ=s([u.b9,"\uacbd\uc7c1\ubc95\uc758 \uc720\uc77c\ud55c \ubaa9\uc801\uc740 \ud2b9\uc815 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \uac1c\uc778\uc758 \ub9e4\ucd9c\uc744 \ubcf4\uc7a5\ud558\ub294 \uac83\uc774\ub2e4","\uacbd\uc7c1\ubc95\uc740 \uacbd\uc7c1\uc790\uc758 \uc2dc\uc7a5 \ud1f4\ucd9c\uc744 \ubc29\uc9c0\ud558\ub294 \uac83\uc744 \ucd5c\uc6b0\uc120 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4","\uacbd\uc7c1\ubc95\uc740 \uc18c\ube44\uc790\ubcf4\ub2e4 \uc0ac\uc5c5\uc790\uc758 \uc774\uc775\uc744 \uc6b0\uc120\ud55c\ub2e4","\uacbd\uc7c1\ubc95\uc758 \ubcf4\ud638\ubc95\uc775\uc740 \uc2dc\ub300\uc640 \ubb34\uad00\ud558\uac8c \uace0\uc815\ub418\uc5b4 \uc788\uc73c\uba70 \ud559\uc124\uc0c1 \ub2e4\ud23c\uc774 \uc5c6\ub2e4"],t.s)
B.a19=s([u.b9],t.s)
B.UR=s(["\uacbd\uc7c1\uc758 \ubcf4\ud638 vs \uacbd\uc7c1\uc790\uc758 \ubcf4\ud638"],t.s)
B.adg=new A.f("gen_gn_purpose_6","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubaa9\uc801\xb7\uae30\ubcf8\uc774\ub150","\uacbd\uc7c1\ubc95\uc758 \ubcf4\ud638\ubc95\uc775\uc5d0 \uad00\ud55c \uc77c\ubc18\uc801 \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.UZ,0,'\uacbd\uc7c1\ubc95 \uc774\ub860\uc0c1 \ub110\ub9ac \ubc1b\uc544\ub4e4\uc5ec\uc9c0\ub294 \uad00\uc810\uc740 "\uacbd\uc7c1\uc758 \ubcf4\ud638\uc774\uc9c0 \uacbd\uc7c1\uc790\uc758 \ubcf4\ud638\uac00 \uc544\ub2c8\ub2e4"\ub77c\ub294 \uba85\uc81c\ub85c \uc694\uc57d\ub41c\ub2e4. \uc989 \ud2b9\uc815 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \uac1c\uc778\uc758 \uc874\uc18d\uc774\ub098 \uc774\uc775 \uc790\uccb4\ub97c \ubcf4\uc7a5\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \uc5ec\ub7ec \uc0ac\uc5c5\uc790\uac00 \uc790\uc720\ub86d\uace0 \uacf5\uc815\ud558\uac8c \uacbd\uc7c1\ud560 \uc218 \uc788\ub294 \uc2dc\uc7a5\uc758 \uad6c\uc870\uc640 \uacfc\uc815\uc744 \ubcf4\ud638\ud558\ub294 \uac83\uc774 \ud575\uc2ec \ubcf4\ud638\ubc95\uc775\uc774\ub77c\ub294 \uac83\uc774\ub2e4. \uc774 \uad00\uc810\uc5d0\uc11c\ub294 \uacbd\uc7c1\uc758 \uacb0\uacfc\ub85c \ube44\ud6a8\uc728\uc801\uc778 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\ub294 \uac83 \uc790\uccb4\ub294 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.a19,B.UR,null)
B.UP=s(["\uc81c\uc870\uc5c5\xb7\uc11c\ube44\uc2a4\uc5c5 \ub610\ub294 \uadf8 \ubc16\uc758 \uc0ac\uc5c5\uc744 \ud558\ub294 \uc790\ub85c\uc11c, \ubc95\uc778\xb7\uac1c\uc778\uc744 \ubd88\ubb38\ud55c\ub2e4","\uc790\ubcf8\uae08 \uc77c\uc815 \uaddc\ubaa8 \uc774\uc0c1\uc778 \ubc95\uc778\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc0c1\uc7a5\uae30\uc5c5\ub9cc\uc744 \uc0ac\uc5c5\uc790\ub85c \ubcf8\ub2e4","\uc624\uc9c1 \uc601\ub9ac\ub97c \ubaa9\uc801\uc73c\ub85c \uc124\ub9bd\ub41c \ubc95\uc778\ub9cc \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uacf5\uacf5\uae30\uad00\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
