B.St=s(["\uc0ac\uc5c5\uc790\uc758 \uc815\uc758"],t.s)
B.a8d=new A.f("gen_gn_def_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc0ac\uc5c5\uc790"\uc758 \uc815\uc758\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.UP,0,'\uacf5\uc815\uac70\ub798\ubc95\uc0c1 "\uc0ac\uc5c5\uc790"\ub294 \uc81c\uc870\uc5c5\xb7\uc11c\ube44\uc2a4\uc5c5 \ub610\ub294 \uadf8 \ubc16\uc758 \uc0ac\uc5c5\uc744 \ud558\ub294 \uc790\ub97c \ub9d0\ud558\uba70, \ubc95\uc778\uc778\uc9c0 \uac1c\uc778\uc778\uc9c0, \uc601\ub9ac\xb7\ube44\uc601\ub9ac\ub97c \ubd88\ubb38\ud558\uace0 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uc774\uc0c1 \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4. \uc790\ubcf8\uae08 \uaddc\ubaa8\ub098 \uc0c1\uc7a5 \uc5ec\ubd80\ub294 \uc0ac\uc5c5\uc790\uc131 \ud310\ub2e8\uc758 \uae30\uc900\uc774 \uc544\ub2c8\uba70, \uacf5\uacf5\uae30\uad00\ub3c4 \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc0ac\uc5c5\uc790\ub85c \ucde8\uae09\ub420 \uc218 \uc788\ub2e4.',B.SM,B.St,null)
B.YX=s(["\uadf8 \ud615\ud0dc\ub97c \ubd88\ubb38\ud558\uace0 2 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc758 \uc774\uc775\uc744 \uc99d\uc9c4\ud560 \ubaa9\uc801\uc73c\ub85c \uc870\uc9c1\ud55c \uacb0\ud569\uccb4 \ub610\ub294 \uc5f0\ud569\uccb4","\ub3d9\uc77c\ud55c \uc9c0\uc5ed\uc5d0 \uc18c\uc7ac\ud55c \uc0ac\uc5c5\uc790\ub4e4\uc758 \uce5c\ubaa9 \ubaa8\uc784","\ub2e8 1\uac1c\uc758 \uc0ac\uc5c5\uc790\ub85c \uad6c\uc131\ub41c \ub2e8\uccb4","\uc815\ubd80\uac00 \uc124\ub9bd\uc744 \uac15\uc81c\ud55c \ubc95\uc815\ub2e8\uccb4\ub9cc\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\ub85c\ub9cc \uad6c\uc131\ub41c \ub2e8\uccb4\ub97c \uc758\ubbf8\ud55c\ub2e4"],t.s)
B.SL=s(["2 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc758 \uc774\uc775\uc744 \uc99d\uc9c4\ud560 \ubaa9\uc801\uc73c\ub85c \uc870\uc9c1\ud55c \uacb0\ud569\uccb4 \ub610\ub294 \uc5f0\ud569\uccb4"],t.s)
