B.a6Z=new A.f("gen_gn_def_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc0ac\uc5c5\uc790\ub2e8\uccb4"\uc758 \uc815\uc758\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.YX,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc870\ud569\xb7\ud611\ud68c \ub4f1 \uba85\uce6d\uc774\ub098 \ubc95\uc801 \ud615\ud0dc\uc640 \uad00\uacc4\uc5c6\uc774, 2 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790\uac00 \uacf5\ub3d9\uc758 \uc774\uc775\uc744 \uc99d\uc9c4\ud560 \ubaa9\uc801\uc73c\ub85c \uc870\uc9c1\ud55c \uacb0\ud569\uccb4 \ub610\ub294 \uc5f0\ud569\uccb4\ub97c \uc758\ubbf8\ud55c\ub2e4. \ub2e8\uc21c \uce5c\ubaa9 \ubaa8\uc784\uc774\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc0ac\uc5c5\uc790 \uacf5\ub3d9\uc758 \uc774\uc775 \uc99d\uc9c4\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub85c \uc778\uc815\ub420 \uc218 \uc788\uc73c\uba70, \ubc18\ub4dc\uc2dc \ubc95\uc815\ub2e8\uccb4\uc774\uac70\ub098 \uc815\ubd80\uac00 \uc124\ub9bd\uc744 \uac15\uc81c\ud55c \ub2e8\uccb4\uc77c \ud544\uc694\ub294 \uc5c6\ub2e4.",B.SL,B.a_q,null)
B.NW=s(["2 \uc774\uc0c1\uc758 \ud68c\uc0ac\uac00 \ub3d9\uc77c\ud55c \uae30\uc5c5\uc9d1\ub2e8\uc5d0 \uc18d\ud558\ub294 \uacbd\uc6b0 \uc11c\ub85c\ub97c \uacc4\uc5f4\ud68c\uc0ac\ub77c \ud55c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\ub294 \ubc18\ub4dc\uc2dc \ub3d9\uc77c \uc5c5\uc885\uc744 \uc601\uc704\ud558\ub294 \ud68c\uc0ac\ub9cc\uc744 \uac00\ub9ac\ud0a8\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\ub294 \uc678\uad6d\uc5d0 \ubcf8\uc0ac\ub97c \ub454 \ud68c\uc0ac\uc5d0\ub9cc \uc801\uc6a9\ub418\ub294 \uac1c\ub150\uc774\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \uc5ec\ubd80\ub294 \ub9e4\ucd9c\uc561 \uaddc\ubaa8\ub85c\ub9cc \ud310\ub2e8\ud55c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\ub294 \uc0c1\uc7a5 \uc5ec\ubd80\uc5d0 \ub530\ub77c \uacb0\uc815\ub41c\ub2e4"],t.s)
