B.a7w=new A.f("gen_gn_def_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uacc4\uc5f4\ud68c\uc0ac"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.NW,0,"\uacc4\uc5f4\ud68c\uc0ac\ub294 2 \uc774\uc0c1\uc758 \ud68c\uc0ac\uac00 \ub3d9\uc77c\ud55c \uae30\uc5c5\uc9d1\ub2e8\uc5d0 \uc18d\ud558\ub294 \uacbd\uc6b0 \uadf8 \uc0c1\ud638\uac04\uc758 \uad00\uacc4\ub97c \uac00\ub9ac\ud0a4\ub294 \uac1c\ub150\uc774\ub2e4. \ub3d9\uc77c \uc5c5\uc885 \uc5ec\ubd80, \uc0c1\uc7a5 \uc5ec\ubd80, \ub9e4\ucd9c\uc561 \uaddc\ubaa8\uc640\ub294 \ubb34\uad00\ud558\uba70, \ub3d9\uc77c\ud55c \uc9c0\ubc30\ub825 \uc544\ub798 \uc788\ub294 \uae30\uc5c5\uc9d1\ub2e8 \uc18c\uc18d \uc5ec\ubd80\uac00 \ud575\uc2ec \ud310\ub2e8\uae30\uc900\uc774\ub2e4. \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud310\ub2e8\uc774\ub098 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704 \ub4f1 \uc5ec\ub7ec \uaddc\uc815\uc5d0\uc11c \uacc4\uc5f4\ud68c\uc0ac \uad00\uacc4\uac00 \uc911\uc694\ud55c \uace0\ub824\uc694\uc18c\ub85c \uc791\uc6a9\ud55c\ub2e4.",B.TP,B.a_Y,null)
B.OS=s(["\uc8fc\uc2dd(\uc9c0\ubd84)\uc758 \uc18c\uc720\ub97c \ud1b5\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc9c0\ubc30\ud558\ub294 \uac83\uc744 \uc8fc\ub41c \uc0ac\uc5c5\uc73c\ub85c \ud558\ub294 \ud68c\uc0ac\ub97c \ub9d0\ud55c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac\ub294 \ubc18\ub4dc\uc2dc \uc81c\uc870\uc5c5\uc744 \uc9c1\uc811 \uc601\uc704\ud574\uc57c \ud55c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc8fc\uc2dd\uc744 \uc804\ud600 \ubcf4\uc720\ud558\uc9c0 \uc54a\ub294 \ud68c\uc0ac\ub97c \uc758\ubbf8\ud55c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac \uc81c\ub3c4\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc804\uba74\uc801\uc73c\ub85c \uae08\uc9c0\ub41c\ub2e4","\uc9c0\uc8fc\ud68c\uc0ac\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \ud55c \uc720\ud615\uc73c\ub85c \ubd84\ub958\ub41c\ub2e4"],t.s)
B.WF=s(["\uc8fc\uc2dd(\uc9c0\ubd84)\uc758 \uc18c\uc720\ub97c \ud1b5\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc9c0\ubc30\ud558\ub294 \uac83\uc744 \uc8fc\ub41c \uc0ac\uc5c5\uc73c\ub85c \ud558\ub294 \ud68c\uc0ac"],t.s)
