B.a89=new A.f("gen_gn_def_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc9c0\uc8fc\ud68c\uc0ac"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.OS,0,"\uc9c0\uc8fc\ud68c\uc0ac\ub294 \uc8fc\uc2dd(\uc9c0\ubd84) \uc18c\uc720\ub97c \ud1b5\ud574 \ub2e4\ub978 \ud68c\uc0ac\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc9c0\ubc30\ud558\ub294 \uac83\uc744 \uc8fc\ub41c \uc0ac\uc5c5\uc73c\ub85c \ud558\ub294 \ud68c\uc0ac\ub97c \ub9d0\ud55c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uc740 \uc9c0\uc8fc\ud68c\uc0ac \uc790\uccb4\ub97c \uc804\uba74 \uae08\uc9c0\ud558\uc9c0 \uc54a\uace0, \ubd80\ucc44\ube44\uc728 \uc81c\ud55c\uc774\ub098 \uc790\ud68c\uc0ac \uc9c0\ubd84\uc728 \uc694\uac74 \ub4f1 \uc77c\uc815\ud55c \ud589\uc704\uaddc\uc81c\ub97c \ud1b5\ud574 \uad00\ub9ac\ud558\ub294 \ubc29\uc2dd\uc744 \ucde8\ud55c\ub2e4. \uc9c0\uc8fc\ud68c\uc0ac\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \ud68c\uc0ac(\uc0ac\uc5c5\uc790)\uc758 \ud55c \ud615\ud0dc\uc774\ub2e4.",B.WF,B.GN,null)
B.a_U=s(['\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uacbd\uc7c1\uc81c\ud55c\uc801 \ud589\uc704\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uc640 \ubcc4\ub3c4\ub85c "\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704"\ub77c\ub294 \ub3c5\uc790\uc801\uc778 \uaddc\uc815\uc73c\ub85c \uaddc\uc728\ub41c\ub2e4',"\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub294 \ubc95\ub960\uc0c1 \uc644\uc804\ud788 \ub3d9\uc77c\ud558\uac8c \ucde8\uae09\ub418\uc5b4 \uad6c\ubcc4\ud560 \uc2e4\uc775\uc774 \uc5c6\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\ub294 \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc774 \ubd80\uacfc\ub420 \uc218 \uc5c6\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\ub9cc \ubc1b\uc744 \uc218 \uc788\ub2e4"],t.s)
B.Zn=s(['\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704"\ub77c\ub294 \ub3c5\uc790\uc801\uc778 \uaddc\uc815\uc73c\ub85c \uaddc\uc728\ub41c\ub2e4'],t.s)
B.a0P=s(["\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uaddc\uc728\uc758 \ub3c5\uc790\uc131"],t.s)
B.a8b=new A.f("gen_gn_def_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub97c \uad6c\ubcc4\ud558\ub294 \uc2e4\uc775\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_U,0,'\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \uc81c\ud55c\ud558\uac70\ub098 \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704 \ub4f1\uc744 "\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704"\ub77c\ub294 \ubcc4\ub3c4\uc758 \uc7a5(\u7ae0)\uc5d0\uc11c \uaddc\uc728\ud558\uace0 \uc788\uc5b4, \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704\xb7\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub4f1\uacfc\ub294 \uad6c\ubd84\ub418\ub294 \ub3c5\uc790\uc801\uc778 \uaddc\uc81c \uccb4\uacc4\ub97c \uac16\ub294\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\ub3c4 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08 \ub4f1 \uc81c\uc7ac\uac00 \ubd80\uacfc\ub420 \uc218 \uc788\ub2e4.',B.Zn,B.a0P,null)
B.LY=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9, \uae30\uc5c5\uacb0\ud569, \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \ub4f1 \uc5ec\ub7ec \uaddc\uc815\uc5d0\uc11c \uacf5\ud1b5\uc801\uc73c\ub85c \uc0ac\uc6a9\ub418\ub294 \uae30\ucd08 \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \uc624\uc9c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0\ub9cc \uc801\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \ud615\uc0ac\ucc98\ubc8c \uaddc\uc815\uc5d0\uc11c\ub9cc \uc0ac\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \ubc95 \uc2dc\ud589 \uc774\ud6c4 \uc0ad\uc81c\ub420 \uc608\uc815\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\ud574\ub2f9 \uc815\uc758\ub294 \uc678\uad6d\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.X1=s(["\uc5ec\ub7ec \uaddc\uc815\uc5d0\uc11c \uacf5\ud1b5\uc801\uc73c\ub85c \uc0ac\uc6a9\ub418\ub294 \uae30\ucd08 \uac1c\ub150\uc774\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
