B.acP=new A.f("gen_gn_def_6","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc8fc\uc694 \uc6a9\uc5b4\uc758 \uc815\uc758",'"\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c"(\uad00\ub828\uc2dc\uc7a5) \uc815\uc758\uaddc\uc815\uc774 \ubc95\ub960 \ucd1d\uce59\uc5d0 \uc704\uce58\ud558\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.LY,0,'"\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c"(\uad00\ub828\uc2dc\uc7a5)\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9 \uc5ec\ubd80, \uae30\uc5c5\uacb0\ud569\uc758 \uacbd\uc7c1\uc81c\ud55c\uc131, \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc131\ub9bd \ub4f1 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc5ec\ub7ec \ud575\uc2ec \uaddc\uc815\uc5d0\uc11c \uacf5\ud1b5\uc801\uc73c\ub85c \uc804\uc81c\ub418\ub294 \uae30\ucd08 \uac1c\ub150\uc774\ub2e4. \uc774 \ub54c\ubb38\uc5d0 \uac1c\ubcc4 \uc7a5(\u7ae0)\uc774 \uc544\ub2c8\ub77c \ubc95\ub960 \ucd1d\uce59(\uc815\uc758\uaddc\uc815)\uc5d0\uc11c \ud1b5\uc77c\uc801\uc73c\ub85c \uaddc\uc815\ud558\uc5ec \uc5ec\ub7ec \uaddc\uc815\uc5d0 \uc77c\uad00\ub418\uac8c \uc801\uc6a9\ub420 \uc218 \uc788\ub3c4\ub85d \ud558\uace0 \uc788\ub2e4.',B.X1,B.KV,null)
B.Oo=s(["\ud2b9\ud5c8\uad8c\xb7\uc2e4\uc6a9\uc2e0\uc548\uad8c\xb7\ub514\uc790\uc778\uad8c\xb7\uc0c1\ud45c\uad8c\xb7\uc800\uc791\uad8c\uc758 \uc815\ub2f9\ud55c \ud589\uc0ac\ub77c\uace0 \uc778\uc815\ub418\ub294 \ud589\uc704\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud558\uc9c0 \uc544\ub2c8\ud55c\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c\uc740 \uc774 \ubc95\uc758 \uc801\uc6a9\ub300\uc0c1\uc5d0\uc11c \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc644\uc804\ud788 \ubc30\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c \ud589\uc0ac\ub294 \uadf8 \ubaa9\uc801\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc801\uc6a9\uc81c\uc678\ub41c\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678\ub294 \uc0c1\ud45c\uad8c\uc5d0\ub9cc \ud55c\uc815\ub41c\ub2e4","\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678\ub294 \uc678\uad6d\uc5d0 \ub4f1\ub85d\ub41c \uad8c\ub9ac\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.R5=s(["\uc815\ub2f9\ud55c \ud589\uc0ac\ub77c\uace0 \uc778\uc815\ub418\ub294 \ud589\uc704\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud558\uc9c0 \uc544\ub2c8\ud55c\ub2e4"],t.s)
B.Yz=s(["\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678"],t.s)
B.a9c=new A.f("gen_gn_scope_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubb34\uccb4\uc7ac\uc0b0\uad8c\uc758 \ud589\uc0ac\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Oo,0,'\uacf5\uc815\uac70\ub798\ubc95\uc740 \ud2b9\ud5c8\uad8c\xb7\uc2e4\uc6a9\uc2e0\uc548\uad8c\xb7\ub514\uc790\uc778\uad8c\xb7\uc0c1\ud45c\uad8c\xb7\uc800\uc791\uad8c \ub4f1 \ubb34\uccb4\uc7ac\uc0b0\uad8c\uc758 "\uc815\ub2f9\ud55c" \ud589\uc0ac\ub77c\uace0 \uc778\uc815\ub418\ub294 \ud589\uc704\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud558\uc9c0 \uc54a\ub294\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \ub2e4\ub9cc \uc774\ub294 \uc815\ub2f9\ud55c \uad8c\ub9ac\ud589\uc0ac\uc758 \ubc94\uc704 \ub0b4\uc5d0\uc11c\ub9cc \uc778\uc815\ub418\ub294 \uc81c\ud55c\uc801 \uc801\uc6a9\uc81c\uc678\uc774\uba70, \uad8c\ub9ac\ub97c \ube59\uc790\ud558\uc5ec \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704\uae4c\uc9c0 \ubcf4\ud638\ud558\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.',B.R5,B.Yz,null)
B.Rq=s([u.l6,"\ud2b9\ud5c8\uad8c \ud589\uc0ac\ub77c\ub294 \uc774\uc720\ub9cc\uc73c\ub85c \ud56d\uc0c1 \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub41c\ub2e4","\uc774 \uacbd\uc6b0\ub294 \ubc18\ub4dc\uc2dc \ud615\uc0ac\ucc98\ubc8c\ub9cc \uac00\ub2a5\ud558\uace0 \ud589\uc815\uc81c\uc7ac\ub294 \ubd88\uac00\ub2a5\ud558\ub2e4","\ud2b9\ud5c8\uad8c\uc744 \uc774\uc720\ub85c \ud55c \ud589\uc704\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2ec\uc0ac \ub300\uc0c1 \uc790\uccb4\uac00 \ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c\ub9cc \ub2e4\ub8e8\uc5b4\uc9c4\ub2e4"],t.s)
