B.adc=new A.f("gen_gn_scope_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ud2b9\ud5c8\uad8c\uc790\uc778 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \ud2b9\ud5c8\uad8c\uc744 \ube59\uc790\ud558\uc5ec \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640\uc758 \uac70\ub798\ub97c \uac70\uc808\ud558\uace0 \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824 \ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Rq,0,'\ubb34\uccb4\uc7ac\uc0b0\uad8c \uc801\uc6a9\uc81c\uc678\ub294 "\uc815\ub2f9\ud55c" \uad8c\ub9ac\ud589\uc0ac\uc5d0 \ud55c\uc815\ub41c\ub2e4. \ud2b9\ud5c8\uad8c\uc744 \uba85\ubaa9\uc73c\ub85c \ub0b4\uc138\uc6b0\ub354\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uacbd\uc7c1\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub824\ub294 \ubaa9\uc801\uc758 \ud589\uc704(\uc608: \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \uac70\ub798\uac70\uc808\uc744 \ud1b5\ud55c \ubc30\uc81c)\ub294 \uc815\ub2f9\ud55c \uad8c\ub9ac\ud589\uc0ac\ub85c \ubcf4\uae30 \uc5b4\ub824\uc6cc \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\uace0, \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9 \ub4f1 \ud1b5\uc0c1\uc801\uc778 \uc2ec\uc0ac \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.',B.RK,B.L8,null)
B.a_h=s(["\uc18c\uaddc\ubaa8 \uc0ac\uc5c5\uc790 \ub610\ub294 \uc18c\ube44\uc790\uc758 \uc0c1\ud638\ubd80\uc870\ub97c \ubaa9\uc801\uc73c\ub85c \ud558\uace0 \uc784\uc758\uc124\ub9bd\xb7\ud0c8\ud1f4\uc758 \uc790\uc720\xb7\uc758\uacb0\uad8c \ud3c9\ub4f1 \ub4f1 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\ub294 \uc801\uc6a9\uc774 \uc81c\uc678\ub420 \uc218 \uc788\ub2e4","\uc870\ud569\uc774\ub77c\ub294 \uba85\uce6d\uc744 \uc0ac\uc6a9\ud558\uae30\ub9cc \ud558\uba74 \uc694\uac74\uacfc \uad00\uacc4\uc5c6\uc774 \ud56d\uc0c1 \uc801\uc6a9\uc81c\uc678\ub41c\ub2e4","\uc870\ud569\uc758 \ud589\uc704\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\uc6a9\uc81c\uc678 \ub300\uc0c1\uc774 \ub420 \uc218 \uc5c6\ub2e4","\uc870\ud569\uc758 \uc801\uc6a9\uc81c\uc678\ub294 \ub300\uae30\uc5c5\uc73c\ub85c \uad6c\uc131\ub41c \uc870\ud569\uc5d0\ub3c4 \ub3d9\uc77c\ud558\uac8c \uc778\uc815\ub41c\ub2e4","\uc870\ud569\uc758 \uc801\uc6a9\uc81c\uc678 \uc5ec\ubd80\ub294 \uc870\ud569\uc758 \uc124\ub9bd\uc5f0\ub3c4\ub9cc\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4"],t.s)
B.RA=s(["\uc784\uc758\uc124\ub9bd\xb7\ud0c8\ud1f4\uc758 \uc790\uc720\xb7\uc758\uacb0\uad8c \ud3c9\ub4f1 \ub4f1 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\ub294 \uc801\uc6a9\uc774 \uc81c\uc678\ub420 \uc218 \uc788\ub2e4"],t.s)
B.YQ=s(["\uc870\ud569\uc758 \uc801\uc6a9\uc81c\uc678 \uc694\uac74"],t.s)
B.adG=new A.f("gen_gn_scope_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc77c\uc815\ud55c \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\uc5d0 \ub300\ud55c \uc801\uc6a9\uc81c\uc678\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_h,0,'\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc18c\uaddc\ubaa8 \uc0ac\uc5c5\uc790 \ub610\ub294 \uc18c\ube44\uc790\uc758 \uc0c1\ud638\ubd80\uc870\ub97c \ubaa9\uc801\uc73c\ub85c \ud558\uba70 \uc784\uc758\ub85c \uc124\ub9bd\ub418\uace0 \uc870\ud569\uc6d0\uc758 \uac00\uc785\xb7\ud0c8\ud1f4\uac00 \uc790\uc720\ub86d\uace0 \uc758\uacb0\uad8c\uc774 \ud3c9\ub4f1\ud55c \ub4f1 \uc77c\uc815\ud55c \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc758 \ud589\uc704\uc5d0 \ub300\ud574 \uc801\uc6a9\uc744 \uc81c\uc678\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uace0 \uc788\ub2e4. \ub2e4\ub9cc \uc774\ub294 \uc694\uac74 \ucda9\uc871 \uc5ec\ubd80\uc5d0 \ub530\ub77c \ud310\ub2e8\ub418\ub294 \uac83\uc774\uc9c0, \ub2e8\uc21c\ud788 "\uc870\ud569"\uc774\ub77c\ub294 \uba85\uce6d \uc0ac\uc6a9\ub9cc\uc73c\ub85c \uc778\uc815\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.',B.RA,B.YQ,null)
B.I2=s(["\uc870\ud569\uc774 \ubd88\uacf5\uc815\ud55c \uac70\ub798\ubc29\ubc95\uc744 \uc0ac\uc6a9\ud558\uac70\ub098 \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uc5ec \uac00\uaca9\uc744 \uc778\uc0c1\ud558\ub294 \uacbd\uc6b0","\uc870\ud569\uc6d0\uc758 \uc218\uac00 5\uc778\uc744 \ucd08\uacfc\ud558\ub294 \uacbd\uc6b0","\uc870\ud569\uc758 \uc124\ub9bd \ubaa9\uc801\uc774 \uc0c1\ud638\ubd80\uc870\uc778 \uacbd\uc6b0","\uc870\ud569\uc6d0\uc758 \uac00\uc785\uacfc \ud0c8\ud1f4\uac00 \uc790\uc720\ub85c\uc6b4 \uacbd\uc6b0","\uc870\ud569\uc758 \uc758\uacb0\uad8c\uc774 \ud3c9\ub4f1\ud558\uac8c \ubcf4\uc7a5\ub418\ub294 \uacbd\uc6b0"],t.s)
B.IR=s(["\ubd88\uacf5\uc815\ud55c \uac70\ub798\ubc29\ubc95\uc744 \uc0ac\uc6a9\ud558\uac70\ub098 \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uc5ec \uac00\uaca9\uc744 \uc778\uc0c1\ud558\ub294 \uacbd\uc6b0"],t.s)
B.Zv=s(["\uc870\ud569 \uc801\uc6a9\uc81c\uc678\uc758 \ud55c\uacc4"],t.s)
B.aaT=new A.f("gen_gn_scope_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\uc801\uc6a9\uc81c\uc678 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc774\ub77c \ud558\ub354\ub77c\ub3c4 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uaddc\uc728\uc744 \ubc1b\uc744 \uc218 \uc788\ub294 \uacbd\uc6b0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.I2,0,"\uc801\uc6a9\uc81c\uc678 \uc694\uac74\uc744 \uac16\ucd98 \uc870\ud569\uc774\ub77c\ub3c4 \uadf8 \uc870\ud569\uc774 \ubd88\uacf5\uc815\ud55c \uac70\ub798\ubc29\ubc95\uc744 \uc0ac\uc6a9\ud558\uac70\ub098 \ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\uc5ec \uac00\uaca9\uc744 \uc778\uc0c1\ud558\ub294 \ub4f1\uc758 \ud589\uc704\ub97c \ud558\ub294 \uacbd\uc6b0\uc5d0\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\uace0 \uaddc\uc728\uc744 \ubc1b\uc744 \uc218 \uc788\ub2e4. \uc870\ud569\uc6d0 \uc218, \uc124\ub9bd\ubaa9\uc801, \uac00\uc785\xb7\ud0c8\ud1f4\uc758 \uc790\uc720, \uc758\uacb0\uad8c \ud3c9\ub4f1 \ub4f1\uc740 \uc624\ud788\ub824 \uc801\uc6a9\uc81c\uc678\uac00 \uc778\uc815\ub418\uae30 \uc704\ud55c \uc694\uac74\uc5d0 \ud574\ub2f9\ud558\ub294 \uc0ac\ud56d\ub4e4\uc774\ub2e4.",B.IR,B.Zv,null)
B.a2E=s(["\uad6d\ub0b4\uc5d0\uc11c \uc0ac\uc5c5\uc744 \uc601\uc704\ud558\ub294 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc6d0\uce59\uc801\uc73c\ub85c \uc801\uc6a9\ub418\uba70, \uad6d\uac00\xb7\uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\ub3c4 \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0 \uc0ac\uc5c5\uc790\uc5d0 \ud3ec\ud568\ub420 \uc218 \uc788\ub2e4","\uc774 \ubc95\uc740 \ubbfc\uac04 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uad6d\uac00\xb7\uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \ubc95\uc740 \uc678\uad6d\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774 \ubc95\uc740 \uac1c\uc778\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\uace0 \ubc95\uc778\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc774 \ubc95\uc758 \uc778\uc801 \uc801\uc6a9\ubc94\uc704\ub294 \ub9e4\ucd9c\uc561 \uaddc\ubaa8\ub85c\ub9cc \uacb0\uc815\ub41c\ub2e4"],t.s)
B.a1O=s(["\uad6d\uac00\xb7\uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\ub3c4 \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0 \uc0ac\uc5c5\uc790\uc5d0 \ud3ec\ud568\ub420 \uc218 \uc788\ub2e4"],t.s)
