B.ade=new A.f("gen_gn_scope_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\uacf5\uc815\uac70\ub798\ubc95\uc758 \uc778\uc801 \uc801\uc6a9\ubc94\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a2E,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uad6d\ub0b4\uc5d0\uc11c \uc0ac\uc5c5\uc744 \uc601\uc704\ud558\ub294 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uc6d0\uce59\uc801\uc73c\ub85c \uc801\uc6a9\ub418\uba70, \ubc95\uc778\xb7\uac1c\uc778\uc744 \ubd88\ubb38\ud55c\ub2e4. \uad6d\uac00\ub098 \uc9c0\ubc29\uc790\uce58\ub2e8\uccb4\ub3c4 \uacf5\uad8c\ub825 \ud589\uc0ac \uc8fc\uccb4\uac00 \uc544\ub2c8\ub77c \uc0ac\uacbd\uc81c \uc8fc\uccb4\ub85c\uc11c \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ud558\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\uace0, \uc5ed\uc678\uc801\uc6a9 \ubc95\ub9ac\uc5d0 \ub530\ub77c \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uc5d0\ub3c4 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4.",B.a1O,B.RM,null)
B.Hz=s([u._,"\ub2e4\ub978 \ubc95\ub839\uc758 \uc874\uc7ac\ub9cc\uc73c\ub85c \ud56d\uc0c1 \uc790\ub3d9\uc73c\ub85c \uacf5\uc815\uac70\ub798\ubc95 \uc801\uc6a9\uc774 \uc804\uba74 \ubc30\uc81c\ub41c\ub2e4","\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub978 \ud589\uc704\ub294 \uadf8 \ub0b4\uc6a9\uc744 \ubd88\ubb38\ud558\uace0 \ubaa8\ub450 \uc801\uc6a9\uc81c\uc678 \ub300\uc0c1\uc774\ub2e4","\ub2e4\ub978 \ubc95\ub839\uacfc\uc758 \uad00\uacc4\ub294 \uc774 \ubc95\uc5d0\uc11c \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub978 \ud589\uc704\ub294 \ubc18\ub4dc\uc2dc \ud615\uc0ac\ucc98\ubc8c \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4\ub294 \uc758\ubbf8\uc774\ub2e4"],t.s)
