B.abG=new A.f("gen_gn_scope_6","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc801\uc6a9\ubc94\uc704\xb7\uc801\uc6a9\uc81c\uc678","\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub978 \uc815\ub2f9\ud55c \ud589\uc704\uc640 \uacf5\uc815\uac70\ub798\ubc95 \uc801\uc6a9\uc81c\uc678\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Hz,0,"\ub2e4\ub978 \ubc95\ub839\uc5d0 \ub530\ub77c \ud589\ud558\ub294 \uc815\ub2f9\ud55c \ud589\uc704\uc5d0 \ub300\ud55c \uc801\uc6a9\uc81c\uc678\ub294 \uadf8 \ubc95\ub839\uc5d0 \uba85\uc2dc\uc801\uc774\uace0 \uad6c\uccb4\uc801\uc778 \uadfc\uac70\uac00 \uc788\ub294 \uacbd\uc6b0\uc5d0 \ud55c\ud574 \uc81c\ud55c\uc801\uc73c\ub85c \uc778\uc815\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \ub2e8\uc21c\ud788 \ub2e4\ub978 \ubc95\ub839\uc774 \uc874\uc7ac\ud55c\ub2e4\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uacf5\uc815\uac70\ub798\ubc95 \uc801\uc6a9\uc774 \uc790\ub3d9\uc73c\ub85c \uc804\uba74 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uadf8 \ud589\uc704\uac00 \uc2e4\uc9c8\uc801\uc73c\ub85c \uacbd\uc7c1\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294\uc9c0 \uc5ec\ubd80\uac00 \ud568\uaed8 \uac80\ud1a0\ub41c\ub2e4.",B.Ph,B.Tt,null)
B.NP=s(["\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc77c\ubc18\ubc95\uc801 \uc9c0\uc704\ub97c \uac00\uc9c0\uba70, \uac1c\ubcc4 \ubc95\ub960\uc740 \ud2b9\uc815 \uac70\ub798\ubd84\uc57c\uc5d0 \ud2b9\ud654\ub41c \ud2b9\ubcc4\ubc95\uc73c\ub85c\uc11c \uc6b0\uc120 \uc801\uc6a9\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uc740 \uacf5\uc815\uac70\ub798\ubc95\uacfc \uc544\ubb34\ub7f0 \uad00\ub828\uc774 \uc5c6\ub294 \ubcc4\uac1c\uc758 \ub3c5\ub9bd\ub41c \ubc95\uccb4\uacc4\uc774\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uc774 \uc788\uc73c\uba74 \uacf5\uc815\uac70\ub798\ubc95\uc740 \ud574\ub2f9 \ubd84\uc57c\uc5d0\uc11c \uc644\uc804\ud788 \ud6a8\ub825\uc744 \uc0c1\uc2e4\ud55c\ub2e4","\uacf5\uc815\uac70\ub798\ubc95\uc774 \ud56d\uc0c1 \uac1c\ubcc4 \ubc95\ub960\uc5d0 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\uac1c\ubcc4 \ubc95\ub960\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc740 \ub3d9\uc2dc\uc5d0 \uc801\uc6a9\ub420 \uc218 \uc5c6\ub2e4"],t.s)
