B.acU=new A.f("gen_gn_system_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4","\uac00\ub9f9\uc0ac\uc5c5\uac70\ub798\uc758 \uacf5\uc815\ud654\uc5d0 \uad00\ud55c \ubc95\ub960, \ud558\ub3c4\uae09\uac70\ub798 \uacf5\uc815\ud654\uc5d0 \uad00\ud55c \ubc95\ub960 \ub4f1 \uac1c\ubcc4 \ubc95\ub960\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.NP,0,"\uac00\ub9f9\uc0ac\uc5c5\ubc95\xb7\ud558\ub3c4\uae09\ubc95 \ub4f1\uc740 \ud2b9\uc815 \uac70\ub798\ubd84\uc57c(\uac00\ub9f9, \ud558\ub3c4\uae09 \ub4f1)\uc758 \ud2b9\uc131\uc744 \ubc18\uc601\ud574 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uae30\ubcf8 \uc774\ub150 \uc544\ub798 \ub9c8\ub828\ub41c \ud2b9\ubcc4\ubc95\uc73c\ub85c, \ud574\ub2f9 \ubd84\uc57c\uc5d0\uc11c\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \ud2b9\ubcc4\ubc95\uc774 \uc6b0\uc120 \uc801\uc6a9\ub41c\ub2e4. \ub2e4\ub9cc \uc774\ub4e4 \ubc95\ub960\ub3c4 \uad81\uadf9\uc801\uc73c\ub85c\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc774 \ucd94\uad6c\ud558\ub294 \uacf5\uc815\ud558\uace0 \uc790\uc720\ub85c\uc6b4 \uacbd\uc7c1 \ucd09\uc9c4\uc774\ub77c\ub294 \uc774\ub150\uc744 \uacf5\uc720\ud558\uba70, \ub450 \ubc95\ub960\uc774 \uc0c1\ud638 \ubc30\ud0c0\uc801\uc73c\ub85c \ub2e8\uc808\ub41c \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Kj,B.Za,null)
B.XG=s(["\uc57d\uad00\ubc95\uc740 \ubd88\uacf5\uc815\uc57d\uad00 \uc2ec\uc0ac\ub97c \ubcc4\ub3c4\ub85c \uaddc\uc728\ud558\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uc18c\uad00\uc758 \uac1c\ubcc4 \ubc95\ub960\ub85c\uc11c \uacf5\uc815\uac70\ub798\ubc95\uacfc \ud568\uaed8 \uc791\ub3d9\ud55c\ub2e4","\uc57d\uad00\ubc95\uc740 \uacf5\uc815\uac70\ub798\ubc95\uacfc \uc804\ud600 \uad00\ub828 \uc5c6\ub294 \ub2e4\ub978 \uc815\ubd80\ubd80\ucc98 \uc18c\uad00 \ubc95\ub960\uc774\ub2e4","\uc57d\uad00\ubc95\uc774 \uc2dc\ud589\ub418\uba74 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uaddc\uc815\uc740 \uc804\ubd80 \ud3d0\uc9c0\ub41c\ub2e4","\uc57d\uad00\ubc95\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc57d\uad00\uc5d0 \uad00\ud55c \uc0ac\ud56d\uc740 \uc624\uc9c1 \ubbfc\ubc95\uc73c\ub85c\ub9cc \uaddc\uc728\ub418\uace0 \uc57d\uad00\ubc95\uc740 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
