B.a8n=new A.f("gen_gn_system_2","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.XG,0,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc18c\uad00\ud558\ub294 \uac1c\ubcc4 \ubc95\ub960\ub85c\uc11c, \uc0ac\uc5c5\uc790\uac00 \ubbf8\ub9ac \ub9c8\ub828\ud55c \uc57d\uad00 \uc870\ud56d\uc758 \ubd88\uacf5\uc815\uc131\uc744 \uc2ec\uc0ac\xb7\uaddc\uc81c\ud558\ub294 \uac83\uc744 \ubaa9\uc801\uc73c\ub85c \ud55c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uacfc\ub294 \uaddc\uc728 \ub300\uc0c1\uacfc \uc694\uac74\uc774 \ub2e4\ub974\uc9c0\ub9cc, \uac19\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c \uccb4\uacc4 \uc548\uc5d0\uc11c \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uc791\ub3d9\ud558\ub294 \uad00\uacc4\uc5d0 \uc788\ub2e4.",B.PL,B.KM,null)
B.XY=s(["\ub450 \ubc95\ub960\uc740 \ubaa9\uc801\uacfc \ubcf4\ud638\ubc95\uc775\uc758 \uac15\uc870\uc810\uc774 \ub2e4\ub974\uc9c0\ub9cc \uc18c\ube44\uc790 \ud6c4\uc0dd \uc99d\uc9c4\uc774\ub77c\ub294 \uce21\uba74\uc5d0\uc11c \uc0c1\ud638 \ubcf4\uc644\uc801\uc73c\ub85c \uae30\ub2a5\ud55c\ub2e4","\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc774 \uc2dc\ud589\ub41c \uc774\ud6c4 \uacf5\uc815\uac70\ub798\ubc95\uc740 \ud3d0\uc9c0\ub418\uc5c8\ub2e4","\ub450 \ubc95\ub960\uc740 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \ub0b4\uc6a9\uc744 \uaddc\uc815\ud558\uace0 \uc788\uc5b4 \ud558\ub098\ub9cc \uc874\uc7ac\ud574\ub3c4 \ubb34\ubc29\ud558\ub2e4","\uc18c\ube44\uc790\uae30\ubcf8\ubc95\uc740 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uc18c\ube44\uc790\uc5d0\uac8c\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc18c\ube44\uc790 \uad00\ub828 \uc0ac\ud56d\uc744 \uc804\ud600 \ub2e4\ub8e8\uc9c0 \uc54a\ub294\ub2e4"],t.s)
