B.a1U=s(["\ub3d9\uc77c\ud55c \uc0ac\uc548\uc5d0 \ub300\ud574 \ud2b9\ubcc4\ubc95\uc5d0 \ubcc4\ub3c4\uc758 \uaddc\uc815\uc774 \uc788\uc73c\uba74 \uadf8 \ud2b9\ubcc4\ubc95 \uaddc\uc815\uc774 \uc77c\ubc18\ubc95\ubcf4\ub2e4 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4","\ud2b9\ubcc4\ubc95\uacfc \uc77c\ubc18\ubc95\uc774 \ucda9\ub3cc\ud558\uba74 \ud56d\uc0c1 \uc77c\ubc18\ubc95\uc774 \uc6b0\uc120\ud55c\ub2e4","\ud2b9\ubcc4\ubc95 \uc6b0\uc120\uc758 \uc6d0\uce59\uc740 \uacf5\uc815\uac70\ub798\ubc95 \uccb4\uacc4\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ud2b9\ubcc4\ubc95\uc774 \uc788\uc73c\uba74 \uc77c\ubc18\ubc95\uc740 \uadf8 \uc989\uc2dc \uc804\uccb4\uac00 \ud3d0\uc9c0\ub41c \uac83\uc73c\ub85c \ubcf8\ub2e4","\ud2b9\ubcc4\ubc95 \uc6b0\uc120\uc758 \uc6d0\uce59\uc740 \ud615\ubc95\uc5d0\ub9cc \uc801\uc6a9\ub418\uace0 \ud589\uc815\ubc95 \ubd84\uc57c\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
