B.a8P=new A.f("gen_gn_system_4","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4",'"\ud2b9\ubcc4\ubc95 \uc6b0\uc120\uc758 \uc6d0\uce59"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a1U,0,'"\ud2b9\ubcc4\ubc95\uc740 \uc77c\ubc18\ubc95\uc5d0 \uc6b0\uc120\ud55c\ub2e4"\ub294 \ubc95 \uc801\uc6a9\uc758 \uc77c\ubc18\uc6d0\uce59\uc73c\ub85c, \ub3d9\uc77c\ud55c \uc0ac\ud56d\uc5d0 \ub300\ud574 \ud2b9\ubcc4\ubc95\uc5d0 \ubcc4\ub3c4\uc758 \uaddc\uc815\uc774 \uc788\ub294 \uacbd\uc6b0\uc5d0\ub294 \uadf8 \ud2b9\ubcc4\ubc95\uc774 \uc77c\ubc18\ubc95\ubcf4\ub2e4 \uc6b0\uc120\ud558\uc5ec \uc801\uc6a9\ub41c\ub2e4. \uacf5\uc815\uac70\ub798\ubc95\uacfc \uac00\ub9f9\uc0ac\uc5c5\ubc95\xb7\ud558\ub3c4\uae09\ubc95 \ub4f1\uc758 \uad00\uacc4\uc5d0\uc11c\ub3c4 \uc774 \uc6d0\ufffd\ub9ac\uc774 \uc801\uc6a9\ub418\uc5b4, \ud574\ub2f9 \ud2b9\ubcc4\ubc95\uc774 \uaddc\uc728\ud558\ub294 \uc0ac\ud56d\uc5d0\ub294 \ud2b9\ubcc4\ubc95\uc774 \uba3c\uc800 \uc801\uc6a9\ub41c\ub2e4.',B.a_O,B.To,null)
B.a_o=s(["\ud53c\ud574\uc790\ub294 \uacf5\uc815\uac70\ub798\ubc95 \ubc0f \ubbfc\ubc95\uc0c1 \uc190\ud574\ubc30\uc0c1 \uad00\ub828 \uaddc\uc815 \ub4f1\uc744 \ud1b5\ud574 \uac00\ud574 \uc0ac\uc5c5\uc790\ub97c \uc0c1\ub300\ub85c \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\uc5d0 \ub300\ud574\uc11c\ub294 \uc5b4\ub5a0\ud55c \ubbfc\uc0ac\uc801 \uad6c\uc81c\uc218\ub2e8\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4","\ubbfc\uc0ac\uc801 \uad6c\uc81c\ub294 \ubc18\ub4dc\uc2dc \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc0ac\uc804 \ucc98\ubd84\uc774 \uc788\uc5b4\uc57c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc190\ud574\ubc30\uc0c1\uccad\uad6c\uad8c\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc778\uc815\ub41c\ub2e4","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18 \ud53c\ud574\uc790\ub294 \ud615\uc0ac\uace0\uc18c\ub9cc \uac00\ub2a5\ud558\uace0 \ubbfc\uc0ac\uc18c\uc1a1\uc740 \uc81c\uae30\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.P2=s(["\uacf5\uc815\uac70\ub798\ubc95 \ubc0f \ubbfc\ubc95\uc0c1 \uc190\ud574\ubc30\uc0c1 \uad00\ub828 \uaddc\uc815 \ub4f1\uc744 \ud1b5\ud574 \uac00\ud574 \uc0ac\uc5c5\uc790\ub97c \uc0c1\ub300\ub85c \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\ub2e4"],t.s)
