B.adl=new A.f("gen_gn_system_5","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ubc95 \uccb4\uacc4\xb7\ub2e4\ub978 \ubc95\ub960\uacfc\uc758 \uad00\uacc4","\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\ud589\uc704\ub85c \ud53c\ud574\ub97c \uc785\uc740 \uc790\uc758 \ubbfc\uc0ac\uc801 \uad6c\uc81c\uc218\ub2e8\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_o,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc704\ubc18\ud589\uc704\ub85c \uc190\ud574\ub97c \uc785\uc740 \uc790\ub294 \uacf5\uc815\uac70\ub798\ubc95 \ubc0f \ubbfc\ubc95\uc758 \ubd88\ubc95\ud589\uc704 \uad00\ub828 \uaddc\uc815 \ub4f1\uc5d0 \uadfc\uac70\ud558\uc5ec \uac00\ud574 \uc0ac\uc5c5\uc790\ub97c \uc0c1\ub300\ub85c \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\ub2e4. \uc774\ub7ec\ud55c \ubbfc\uc0ac\uc801 \uad6c\uc81c\uc218\ub2e8\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \ud589\uc815\ucc98\ubd84\uacfc\ub294 \ubcc4\uac1c\ub85c \uc778\uc815\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\uba70, \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \ud53c\ud574\ub97c \uc785\uc740 \uc790\ub77c\uba74 \uccad\uad6c\ud560 \uc218 \uc788\ub2e4.",B.P2,B.a2B,null)
B.M1=s(["\uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud6a8\uacfc\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub824\ub294 \uac83\uc774\ub2e4","\uc678\uad6d\uc5d0\uc11c \ubc1c\uc0dd\ud55c \ud589\uc704\ub294 \uadf8 \uc5b4\ub5a4 \uacbd\uc6b0\uc5d0\ub3c4 \uc774 \ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \ub420 \uc218 \uc5c6\ub3c4\ub85d \ud558\ub824\ub294 \uac83\uc774\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc740 \uad6d\ub0b4\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uc678\uad6d\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \ud615\uc0ac\ucc98\ubc8c\ub9cc\uc744 \ubaa9\uc801\uc73c\ub85c \ub9c8\ub828\ub41c \uac83\uc774\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc740 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uc601\ud5a5\uacfc \ubb34\uad00\ud558\uac8c \ubaa8\ub4e0 \uad6d\uc678\ud589\uc704\uc5d0 \uc801\uc6a9\ub41c\ub2e4"],t.s)
