B.ac9=new A.f("gen_gn_extra_3","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc5ed\uc678\uc801\uc6a9\xb7\uad6d\uc81c\ud611\ub825","\uacf5\uc815\uac70\ub798\ubc95 \uc9d1\ud589\uc744 \uc704\ud55c \uad6d\uc81c\ud611\ub825\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.JZ,0,"\uacf5\uc815\uac70\ub798\ubc95\uc740 \uc815\ubd80\uac00 \ub300\ud55c\ubbfc\uad6d\uc758 \ubc95\ub960 \ubc0f \uc774\uc775\uc5d0 \ubc18\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uc678\uad6d\uc815\ubd80\uc640 \uc774 \ubc95\uc758 \uc9d1\ud589\uc744 \uc704\ud55c \ud611\uc815\uc744 \uccb4\uacb0\ud560 \uc218 \uc788\ub2e4\ub294 \uadfc\uac70\ub97c \ub450\uc5b4, \uad6d\uacbd\uc744 \ub118\ub294 \uacbd\uc7c1\uc81c\ud55c\ud589\uc704\uc5d0 \ub300\uc751\ud558\uae30 \uc704\ud55c \uad6d\uc81c\ud611\ub825\uc758 \uadfc\uac70\ub97c \ub9c8\ub828\ud558\uace0 \uc788\ub2e4. \uc774\ub294 \uac1c\ubcc4 \uc0ac\uac74\ub9c8\ub2e4 \uad6d\ud68c \ub3d9\uc758\ub97c \uc694\ud558\ub294 \uc808\ucc28\uac00 \uc544\ub2c8\ub77c \uc815\ubd80 \uac04 \ud611\ub825\uccb4\uacc4 \uad6c\ucd95\uc744 \uc704\ud55c \uc77c\ubc18\uc801 \uadfc\uac70 \uaddc\uc815\uc774\ub2e4.",B.OY,B.U9,null)
B.T_=s([u.h8,"\uad6d\ub0b4\uc5d0\uc11c\ub9cc \uc601\uc5c5\ud558\ub294 \uc18c\uaddc\ubaa8 \uac1c\uc778\uc0ac\uc5c5\uc790 \uac04\uc758 \uc21c\uc218\ud55c \uad6d\ub0b4 \uac70\ub798\ubd84\uc7c1","\uad6d\ub0b4 \uc18c\ube44\uc790 \uac1c\uc778 \uac04\uc758 \uc911\uace0\ubb3c\ud488 \uac70\ub798","\uc21c\uc218\ud558\uac8c \uad6d\ub0b4 \uacf5\uacf5\uae30\uad00 \ub0b4\ubd80\uc758 \uc778\uc0ac \ubb38\uc81c","\uad6d\ub0b4 \ud559\uad50\uc758 \uad50\uc721\uacfc\uc815 \ud3b8\uc131 \ubb38\uc81c"],t.s)
