B.a1R=s([u.fA,"\uc5ed\uc678\uc801\uc6a9\uc740 \uc5b4\ub5a0\ud55c \uad6d\uc81c\ubc95\uc801 \uace0\ub824\ub3c4 \ud544\uc694\ud558\uc9c0 \uc54a\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc740 \uc624\uc9c1 \uad6d\ub0b4 \uc0ac\uc5c5\uc790\uc758 \uc774\uc775\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uc778\uc815 \uc5ec\ubd80\ub294 \uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ub3d9\uc758\uac00 \uc788\uc5b4\uc57c\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc740 \uad6d\uc81c\ud611\uc57d\uacfc \ubb34\uad00\ud558\uac8c \uc77c\ubc29\uc801\uc73c\ub85c\ub9cc \uacb0\uc815\ub41c\ub2e4"],t.s)
