B.WL=s([u.al,"\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uad6d\ub0b4 \uc0ac\uc5c5\uc790\ub97c \ud574\uc678 \uc9c4\ucd9c \uc2dc \uaddc\uc81c\ud558\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uad6d\ub0b4\uc2dc\uc7a5\uacfc \ubb34\uad00\ud55c \uc21c\uc218 \uc678\uad6d \ub0b4 \uac70\ub798\uae4c\uc9c0 \uaddc\uc728\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uad6d\ub0b4 \uc18c\ube44\uc790\uc758 \ud574\uc678\uc9c1\uad6c\ub97c \uae08\uc9c0\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uc678\uad6d \uc815\ubd80\uc758 \uc694\uccad\uc774 \uc788\uc5b4\uc57c\ub9cc \ubc1c\ub3d9\ub420 \uc218 \uc788\ub2e4\ub294 \uc758\ubbf8\uc774\ub2e4"],t.s)
