B.a88=new A.f("gen_gn_extra_6","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\uc5ed\uc678\uc801\uc6a9\xb7\uad6d\uc81c\ud611\ub825","\uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc774 \uc774 \ubc95\uc5d0 \ub3c4\uc785\ub41c \ucde8\uc9c0\uc640 \uad00\ub828\ud558\uc5ec \uac00\uc7a5 \uc633\uc740 \uc124\uba85\uc740?",B.WL,0,"\uae30\uc5c5\ud65c\ub3d9\uc774 \uad6d\uacbd\uc744 \ub118\uc5b4 \uc774\ub8e8\uc5b4\uc9c0\ub294 \uc624\ub298\ub0a0\uc758 \uc2dc\uc7a5 \ud658\uacbd\uc5d0\uc11c, \uad6d\uc678\ud589\uc704\ub77c\ub294 \uc774\uc720\ub9cc\uc73c\ub85c \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \ubd80\uc815\uc801 \uc601\ud5a5\uc744 \ubc29\uce58\ud55c\ub2e4\uba74 \uacbd\uc7c1\ubc95\uc758 \uc2e4\ud6a8\uc131\uc774 \ud06c\uac8c \uc800\ud558\ub420 \uc218 \uc788\ub2e4. \uc5ed\uc678\uc801\uc6a9 \uaddc\uc815\uc740 \uc774\ub7ec\ud55c \uacf5\ubc31\uc744 \ubc29\uc9c0\ud558\uace0 \uad6d\ub0b4 \uacbd\uc7c1\uc9c8\uc11c\ub97c \uc2e4\uc9c8\uc801\uc73c\ub85c \ubcf4\ud638\ud558\uae30 \uc704\ud574 \ub3c4\uc785\ub41c \uac83\uc73c\ub85c \uc774\ud574\ub41c\ub2e4.",B.GQ,B.a_B,null)
B.Qi=s(["\ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \uacf5\ub3d9\ud589\uc704\ub85c \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc758 \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \ud604\uc7ac \ub610\ub294 \uc7a5\ub798\uc758 \uc0ac\uc5c5\uc790 \uc218\ub97c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9 \ub610\ub294 \ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\ub3c4\ub85d \ubc29\uc870\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc0c1\ud488 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"],t.s)
