B.add=new A.f("gen_ta_1","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Qi,4,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c51\uc870\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uae08\uc9c0\ud589\uc704\ub85c \u2460 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub97c \ud1b5\ud55c \uacbd\uc7c1\uc81c\ud55c, \u2461 \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \ud604\uc7ac \ub610\ub294 \uc7a5\ub798\uc758 \uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c, \u2462 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9\xb7\ud65c\ub3d9\uc758 \ubd80\ub2f9\ud55c \uc81c\ud55c, \u2463 \uc0ac\uc5c5\uc790\uc5d0\uac8c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\uac8c \ud558\uac70\ub098 \ubc29\uc870\ud558\ub294 \ud589\uc704\ub97c \uc5f4\uac70\ud558\uace0 \uc788\ub2e4. \ubc18\uba74 "\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc0c1\ud488 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ud589\ud558\ub294 "\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c"\ub85c\uc11c, \uc774\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc758 \ud558\uc704 \uc720\ud615\uc5d0 \ud574\ub2f9\ud560 \ubfd0 \ubc95 \uc81c51\uc870\uac00 \uc5f4\uac70\ud558\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uace0\uc720\uc758 \uae08\uc9c0\ud589\uc704 \uc720\ud615\uc5d0\ub294 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.Hk,B.V9,null)
B.P1=s([u.i8,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uacb0\uc758\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ud569\uc758\uac00 \uc544\ub2c8\ubbc0\ub85c \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uac00\uaca9\uc5d0 \uad00\ud55c \uacb0\uc758\ub294 \ud56d\uc0c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc815\ub2f9\ud55c \uc790\uc728\uaddc\uc81c\ub85c \uc778\uc815\ub41c\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc624\uc9c1 \uac1c\ubcc4 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \ucc45\uc784\uc774 \uc788\uace0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\ub294 \ucc45\uc784\uc774 \uc5c6\ub2e4","\uc774\ub7ec\ud55c \uacb0\uc758\ub294 \ubc18\ub4dc\uc2dc \uad6d\uac00\uc758 \uc2b9\uc778\uc744 \ubc1b\uc544\uc57c \uc704\ubc95\ud558\uac8c \ub41c\ub2e4"],t.s)
