B.abK=new A.f("gen_ta_compete_2","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uacbd\uc7c1\uc81c\ud55c \uacf5\ub3d9\ud589\uc704 \uc720\ud615",'\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uc911 "\ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \uacf5\ub3d9\ud589\uc704"\uc758 \ud310\ub2e8\uae30\uc900\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?',B.a2k,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uacbd\uc7c1\uc81c\ud55c\uc801 \uacf5\ub3d9\ud589\uc704 \uc5ec\ubd80\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790 \uac04 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \ud310\ub2e8\uae30\uc900\uacfc \uc720\uc0ac\ud558\uac8c, \ud574\ub2f9 \ud589\uc704\uac00 \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud558\ub294\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub77c\ub294 \ud615\uc2dd\uc774 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ub2f4\ud569\uacfc \uc2e4\uc9c8\uc801\uc73c\ub85c \ub2e4\ub974\uc9c0 \uc54a\ub2e4\ub294 \uc810\uc5d0\uc11c \uc720\uc0ac\ud55c \uc2ec\uc0ac \ud2c0\uc774 \uc801\uc6a9\ub418\ub294 \uac83\uc774\ub2e4.",B.a_F,B.Su,null)
B.Wi=s(["\uc0dd\uc0b0\ub7c9 \uc81c\ud55c\uc744 \ud1b5\ud574 \uacbd\ufffd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud55c\ub2e4\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4","\ucd1d\ud68c \uc758\uacb0\uc744 \uac70\ucce4\ub2e4\ub294 \uc808\ucc28\uc801 \uc815\ub2f9\uc131\ub9cc\uc73c\ub85c \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uc0dd\uc0b0\ub7c9\uc5d0 \uad00\ud55c \uacb0\uc758\ub294 \uac00\uaca9\uc5d0 \uad00\ud55c \uacb0\uc758\uc640 \ub2ec\ub9ac \uaddc\uc81c \ub300\uc0c1\uc774 \ub420 \uc218 \uc5c6\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uac1c\ubcc4 \uc18c\ube44\uc790\uc5d0 \ub300\ud55c \ubb38\uc81c\uc77c \ubfd0\uc774\ub2e4","\uc0dd\uc0b0\ub7c9 \uc81c\ud55c \uacb0\uc758\ub294 \uacf5\uc815\uac70\ub798\ubc95\uacfc \ubb34\uad00\ud55c \uc0b0\uc5c5\uc815\ucc45 \uc0ac\ud56d\uc774\ub2e4"],t.s)
