B.a6Y=new A.f("gen_ta_compete_3","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uacbd\uc7c1\uc81c\ud55c \uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ucd1d\ud68c\uc758 \uc758\uacb0\uc744 \uac70\uccd0 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \uc0dd\uc0b0\ub7c9\uc744 \uc81c\ud55c\ud558\uae30\ub85c \uacb0\uc758\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Wi,0,"\uc0dd\uc0b0\ub7c9 \uc81c\ud55c\uc740 \uac00\uaca9 \ub2f4\ud569\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc2dc\uc7a5\uc758 \uc218\uae09\uc5d0 \uc778\uc704\uc801 \uc601\ud5a5\uc744 \ubbf8\uccd0 \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud560 \uc218 \uc788\ub294 \ub300\ud45c\uc801\uc778 \uacbd\uc7c1\uc81c\ud55c \ud589\uc704 \uc720\ud615\uc774\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \ucd1d\ud68c \uc758\uacb0\uc774\ub77c\ub294 \ub0b4\ubd80 \uc808\ucc28\ub97c \uac70\ucce4\ub2e4\ub294 \uc0ac\uc815\ub9cc\uc73c\ub85c \uadf8 \uc2e4\uc9c8\uc801 \uc704\ubc95\uc131\uc774 \uce58\uc720\ub418\ub294 \uac83\uc740 \uc544\ub2c8\uba70, \uacbd\uc7c1\uc81c\ud55c \ud6a8\uacfc\uac00 \uc778\uc815\ub418\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc728\ub420 \uc218 \uc788\ub2e4.",B.UN,B.N9,null)
B.Tj=s([u.lc,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ub2f4\ud569\uc758 \uc9c1\uc811 \ub2f9\uc0ac\uc790\uac00 \uc544\ub2c8\ubbc0\ub85c \uc5b4\ub5a0\ud55c \ucc45\uc784\ub3c4 \uc9c0\uc9c0 \uc54a\ub294\ub2e4","\ubc29\uc870\ud589\uc704\ub294 \uc5b8\uc81c\ub098 \ucc98\ubc8c \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4","\uc774 \uacbd\uc6b0 \ucc45\uc784\uc740 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uadc0\uc18d\ub418\uace0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc644\uc804\ud788 \uba74\ucc45\ub41c\ub2e4","\uc720\ub3c4\xb7\ubc29\uc870\ud589\uc704\ub294 \ud615\uc0ac\ubc95\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub420 \ubfd0 \uacf5\uc815\uac70\ub798\ubc95\uacfc\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
