B.a8V=new A.f("gen_ta_compete_4","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uacbd\uc7c1\uc81c\ud55c \uacf5\ub3d9\ud589\uc704 \uc720\ud615","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790 \uac04 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\ub2f4\ud569)\ub97c \ud558\ub3c4\ub85d \uc720\ub3c4\ud558\uac70\ub098 \uc774\ub97c \ubc29\uc870\ud558\ub294 \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Tj,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4 \uc0ac\uc774\uc758 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\ub2f4\ud569)\ub97c \uc9c1\uc811 \uc8fc\ub3c4\ud558\uc9c0 \uc54a\ub354\ub77c\ub3c4, \uc774\ub97c \uc720\ub3c4\ud558\uac70\ub098 \ubc29\uc870\ud558\ub294 \ud589\uc704 \uc5ed\uc2dc \uacbd\ufffd\uc7c1\uc81c\ud55c\uc801 \uacb0\uacfc\ub97c \ub0b3\ub294\ub2e4\ub294 \uc810\uc5d0\uc11c \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc728\ub420 \uc218 \uc788\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640 \uac1c\ubcc4 \uad6c\uc131\uc0ac\uc5c5\uc790 \ubaa8\ub450 \uac01\uc790\uc758 \uad00\uc5ec \uc815\ub3c4\uc5d0 \ub530\ub77c \ucc45\uc784\uc744 \uc9c8 \uc218 \uc788\ub2e4.",B.GC,B.VT,null)
B.Jk=s([u.F,"\uacf5\uac1c\ub41c \ud1b5\uacc4\uc790\ub8cc\ub97c \ub2e8\uc21c\ud788 \uc885\ud569\ud558\uc5ec \ubc30\ud3ec\ud558\ub294 \uacbd\uc6b0","\uc77c\ubc18\uc801\uc778 \uc0b0\uc5c5 \ub3d9\ud5a5\uc5d0 \uad00\ud55c \uacf5\uac1c \uc138\ubbf8\ub098\ub97c \uac1c\ucd5c\ud558\ub294 \uacbd\uc6b0","\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc548\uc804\uc0ac\uace0 \uc608\ubc29\uc744 \uc704\ud55c \uc77c\ubc18\uc801 \uc815\ubcf4\ub97c \uacf5\uc720\ud558\ub294 \uacbd\uc6b0","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uacf5\ud45c\ud55c \uc815\ucc45\uc790\ub8cc\ub97c \uadf8\ub300\ub85c \uc804\ub2ec\ud558\ub294 \uacbd\uc6b0"],t.s)
