B.ad6=new A.f("gen_ta_restrict_1","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \ud604\uc7ac \ub610\ub294 \uc7a5\ub798\uc758 \uc0ac\uc5c5\uc790 \uc218\ub97c \uc81c\ud55c\ud558\ub294 \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Sw,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \ud604\uc7ac \ub610\ub294 \uc7a5\ub798 \ud65c\ub3d9\ud560 \uc0ac\uc5c5\uc790\uc758 \uc218\ub97c \uc778\uc704\uc801\uc73c\ub85c \uc81c\ud55c\ud558\ub294 \ud589\uc704\ub294, \uc2e0\uaddc \uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \uc9c4\uc785\uc744 \ubd09\uc1c4\ud574 \uae30\uc874 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \uacbd\uc7c1 \uc555\ub825\uc744 \ub0ae\ucd94\ub294 \ud6a8\uacfc\ub97c \ub0b3\uc73c\ubbc0\ub85c \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc728\ub41c\ub2e4. \ub2e4\ub9cc \uc774\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ud569\ub9ac\uc801 \uae30\uc900\uc5d0 \ub530\ub77c \ucd5c\uc18c\ud55c\uc758 \ud68c\uc6d0\uc790\uaca9\uc694\uac74\uc744 \uc815\ud558\ub294 \uac83 \uc790\uccb4\ub97c \uc804\uba74 \uae08\uc9c0\ud558\ub294 \uac83\uc740 \uc544\ub2c8\uace0, \ubd80\ub2f9\ud558\uac8c \uc9c4\uc785\uc744 \ubd09\uc1c4\ud558\ub294 \uacbd\uc6b0\uac00 \ubb38\uc81c\ub41c\ub2e4.",B.Ru,B.K0,null)
B.NG=s([u.a2,"\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc548\uc804\uc0ac\uace0\ub97c \uc608\ubc29\ud558\uae30 \uc704\ud55c \ucd5c\uc18c\ud55c\uc758 \ud569\ub9ac\uc801 \uc9c0\uce68\uc744 \uc81c\uacf5\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \uad00\ub828 \ubc95\ub839 \uc900\uc218\ub97c \uc548\ub0b4\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc790\uc728\uc801 \ucc38\uc5ec\ub97c \uc804\uc81c\ub85c \ud55c \uacf5\ub3d9 \ub9c8\ucf00\ud305 \ucea0\ud398\uc778\uc744 \uc81c\uc548\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc694\uccad\uc5d0 \ub530\ub77c \uc5c5\uacc4 \ud1b5\uacc4\uc790\ub8cc\ub97c \uc81c\uacf5\ud558\ub294 \ud589\uc704"],t.s)
