B.a9U=new A.f("gen_ta_restrict_2","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9 \ub610\ub294 \ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704\uc758 \uc0ac\ub840\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.NG,0,'\uad6c\uc131\uc0ac\uc5c5\uc790\uac00 \ubcf8\ub798 \uc790\uc720\ub86d\uac8c \ud560 \uc218 \uc788\ub294 \uad11\uace0\xb7\ud310\ucd09 \ub4f1 \uc815\ub2f9\ud55c \uc601\uc5c5\ud65c\ub3d9\uc744 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc81c\ud55c\ud558\ub294 \ud589\uc704\ub294 "\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9 \ub610\ub294 \ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704"\uc758 \uc804\ud615\uc801 \uc0ac\ub840\uc774\ub2e4. \ubc18\uba74 \uc548\uc804 \uad00\ub828 \ucd5c\uc18c\ud55c\uc758 \ud569\ub9ac\uc801 \uc9c0\uce68 \uc81c\uacf5, \ubc95\ub839\uc900\uc218 \uc548\ub0b4, \uc790\uc728\ucc38\uc5ec \uc804\uc81c\uc758 \uacf5\ub3d9\ub9c8\ucf00\ud305 \uc81c\uc548, \ud1b5\uacc4\uc790\ub8cc \uc81c\uacf5 \ub4f1\uc740 \ud1b5\uc0c1 \uc815\ub2f9\ud55c \ud65c\ub3d9\uc73c\ub85c \ud3c9\uac00\ub41c\ub2e4.',B.WE,B.OW,null)
B.LZ=s(["\uc774\ub294 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704\uc774\uc790 \uc2e4\uc9c8\uc801\uc73c\ub85c \uac00\uaca9 \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704\ub85c \ud3c9\uac00\ub420 \uc218 \uc788\ub2e4","\uc815\uad00\uc5d0 \uaddc\uc815\ub418\uc5b4 \uc788\uc73c\uba74 \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uac00\uaca9 \ud560\uc778 \uae08\uc9c0\ub294 \uc18c\ube44\uc790 \ubcf4\ud638\ub97c \uc704\ud55c \uc870\uce58\uc774\ubbc0\ub85c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc774\ub7ec\ud55c \uaddc\uc815\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \ub0b4\ubd80 \ubb38\uc81c\uc77c \ubfd0 \uacf5\uc815\uac70\ub798\ubc95\uacfc \ubb34\uad00\ud558\ub2e4","\uac00\uaca9 \ud560\uc778 \uae08\uc9c0\ub294 \uc624\uc9c1 \ub300\uae30\uc5c5\uc5d0\ub9cc \uc801\uc6a9\ub418\ub294 \uaddc\uc81c\uc774\ub2e4"],t.s)
B.Ow=s(["\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704\uc774\uc790 \uc2e4\uc9c8\uc801\uc73c\ub85c \uac00\uaca9 \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud589\uc704\ub85c \ud3c9\uac00\ub420 \uc218 \uc788\ub2e4"],t.s)
