B.ae6=new A.f("gen_ta_restrict_3","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uac00\uaca9 \ud560\uc778\xb7\ud310\ucd09\uc744 \uc815\uad00\uc774\ub098 \ub0b4\ubd80\uaddc\uc815\uc73c\ub85c \uae08\uc9c0\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.LZ,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc815\uad00\uc774\ub098 \ub0b4\ubd80\uaddc\uc815\uc744 \ud1b5\ud574 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uac00\uaca9 \ud560\uc778\uc774\ub098 \ud310\ucd09\ud65c\ub3d9\uc744 \uae08\uc9c0\ud558\ub294 \uac83\uc740, \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc815\ub2f9\ud55c \uc601\uc5c5\ud65c\ub3d9(\uc0ac\uc5c5\ub0b4\uc6a9)\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704\uc774\uc790 \uc2e4\uc9c8\uc801\uc73c\ub85c \uac00\uaca9 \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \ud6a8\uacfc\ub97c \ub0b3\ub294 \ud589\uc704\ub85c \ud3c9\uac00\ub420 \uc218 \uc788\ub2e4. \uc815\uad00\uc5d0 \uaddc\uc815\ub418\uc5b4 \uc788\ub2e4\ub294 \ud615\uc2dd\uc801 \uc0ac\uc815\ub9cc\uc73c\ub85c \uadf8 \uc704\ubc95\uc131\uc774 \ubd80\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4.",B.Ow,B.Ha,null)
B.a_t=s([u.nT,"\uae30\uc874 \uc0ac\uc5c5\uc790\uc758 \ub3d9\uc758 \uc694\uac74\uc740 \ud56d\uc0c1 \ud569\ub9ac\uc801 \uc790\uc728\uaddc\uc81c\ub85c \uc778\uc815\ub41c\ub2e4","\uc774\ub7ec\ud55c \uc694\uac74\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc7ac\uc0b0\uad8c \ud589\uc0ac\uc5d0 \ud574\ub2f9\ud558\uc5ec \uc804\ud600 \uaddc\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc2e0\uaddc \ud68c\uc6d0 \uac00\uc785 \uc694\uac74\uc740 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uaddc\uc728 \ub300\uc0c1\uc774 \ub420 \uc218 \uc5c6\ub2e4","\uc774 \uacbd\uc6b0\ub294 \uc624\uc9c1 \ubbfc\ubc95\uc0c1 \uacc4\uc57d\uc790\uc720\uc758 \ubb38\uc81c\uc77c \ubfd0\uc774\ub2e4"],t.s)
B.a1u=s([u.nT],t.s)
B.Gv=s(["\uc790\uc758\uc801 \uac00\uc785 \uc694\uac74\uc758 \ubb38\uc81c"],t.s)
B.a80=new A.f("gen_ta_restrict_4","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc2e0\uaddc \ud68c\uc6d0 \uac00\uc785 \uc694\uac74\uc73c\ub85c \uae30\uc874 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \ub3d9\uc758\ub97c \ubc18\ub4dc\uc2dc \ubc1b\ub3c4\ub85d \ud558\uace0, \uae30\uc874 \uc0ac\uc5c5\uc790\uac00 \uc784\uc758\ub85c \ub3d9\uc758\ub97c \uac70\ubd80\ud560 \uc218 \uc788\uac8c \uc815\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a_t,0,"\uc2e0\uaddc \uac00\uc785 \uc694\uac74\uc73c\ub85c \uae30\uc874 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc784\uc758\uc801 \ub3d9\uc758\ub97c \uc694\uad6c\ud558\uace0 \uadf8 \ub3d9\uc758\ub97c \uc790\uc758\uc801\uc73c\ub85c \uac70\ubd80\ud560 \uc218 \uc788\uac8c \ud558\ub294 \uac83\uc740, \uc0ac\uc2e4\uc0c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc2e0\uaddc \uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5 \uc9c4\uc785 \uc5ec\ubd80\ub97c \uc88c\uc6b0\ud558\ub294 \uacb0\uacfc\ub97c \ub0b3\uc544 \uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c \ud589\uc704\ub85c \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4. \ud569\ub9ac\uc801\uc774\uace0 \uac1d\uad00\uc801\uc778 \uc790\uaca9\uae30\uc900\uc5d0 \ub530\ub978 \uc2ec\uc0ac\uc640\ub294 \ub2ec\ub9ac, \uae30\uc874 \ud68c\uc6d0\uc758 \uc790\uc758\uc801 \ub3d9\uc758\uc5d0 \uc88c\uc6b0\ub418\ub294 \uad6c\uc870\ub294 \uacbd\uc7c1\uc81c\ud55c \uc6b0\ub824\uac00 \ud06c\ub2e4.",B.a1u,B.Gv,null)
B.XQ=s([u.lK,"\uc5b4\ub5a0\ud55c \ud68c\uc6d0\uc790\uaca9 \uc694\uac74\ub3c4 \uc608\uc678 \uc5c6\uc774 \uc804\ubd80 \uc704\ubc95\ud558\ub2e4","\uc804\ubb38\uc131 \uae30\uc900\uc740 \ud56d\uc0c1 \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud558\ub294 \uac83\uc73c\ub85c \uac04\uc8fc\ub41c\ub2e4","\uc774\ub7ec\ud55c \uae30\uc900\uc740 \ubc18\ub4dc\uc2dc \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc0ac\uc804 \uc2b9\uc778\uc744 \ubc1b\uc544\uc57c\ub9cc \uc815\ud560 \uc218 \uc788\ub2e4","\uc804\ubb38\uc131 \uae30\uc900\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uc815\ubd80\ub9cc \uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
