B.abJ=new A.f("gen_ta_restrict_5","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ud68c\uc6d0\uc790\uaca9 \uc694\uac74\uc73c\ub85c \ud569\ub9ac\uc801\uc774\uace0 \uac1d\uad00\uc801\uc778 \ucd5c\uc18c\ud55c\uc758 \uc804\ubb38\uc131 \uae30\uc900(\uc608: \uad00\ub828 \uc790\uaca9\uc99d \ubcf4\uc720)\uc744 \uc694\uad6c\ud558\ub294 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.XQ,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc5c5\ubb34\uc758 \uc804\ubb38\uc131\uc774\ub098 \uc548\uc804 \ud655\ubcf4 \ub4f1\uc744 \uc704\ud574 \ud569\ub9ac\uc801\uc774\uace0 \uac1d\uad00\uc801\uc778 \ucd5c\uc18c\ud55c\uc758 \uc790\uaca9\uc694\uac74(\uad00\ub828 \uc790\uaca9\uc99d \ubcf4\uc720 \ub4f1)\uc744 \uc815\ud558\ub294 \uac83\uc740, \uadf8 \uc790\uccb4\ub85c \ubd80\ub2f9\ud55c \uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c\uc774\ub77c\uace0 \ub2e8\uc815\ud558\uae30 \uc5b4\ub835\ub2e4. \ubb38\uc81c\ub294 \uadf8\ub7ec\ud55c \uae30\uc900\uc774 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc2e0\uaddc \uc9c4\uc785\uc744 \uc790\uc758\uc801\xb7\uacfc\ub3c4\ud558\uac8c \ubd09\uc1c4\ud558\ub294 \uc218\ub2e8\uc73c\ub85c \ub0a8\uc6a9\ub418\ub294\uc9c0 \uc5ec\ubd80\uc774\ub2e4.",B.P3,B.a0J,null)
B.Mx=s([u.is,"\uc601\uc5c5\uc9c0\uc5ed \ubd84\ud560\uc740 \ud56d\uc0c1 \ud6a8\uc728\uc801\uc778 \uacbd\uc601\uae30\ubc95\uc73c\ub85c\uc11c \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc601\uc5c5\uc9c0\uc5ed \ubd84\ud560 \uacb0\uc758\ub294 \uc18c\ube44\uc790\uc5d0\uac8c \uc804\ud600 \uc601\ud5a5\uc744 \ubbf8\uce58\uc9c0 \uc54a\ub294\ub2e4","\uc774\ub7ec\ud55c \uacb0\uc758\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uc815\ubd80\ub9cc \ud560 \uc218 \uc788\ub294 \uc870\uce58\uc774\ub2e4","\uc601\uc5c5\uc9c0\uc5ed \ubd84\ud560\uc740 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uac1c\ubcc4 \uacc4\uc57d\uc73c\ub85c\ub9cc \ub2e4\ub8e8\uc5b4\uc9c8 \ubfd0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
