B.a9h=new A.f("gen_ta_restrict_6","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc0ac\uc5c5\uc790\uc218 \uc81c\ud55c\xb7\uc0ac\uc5c5\ub0b4\uc6a9 \uc81c\ud55c","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\uc9c0\uc5ed\uc744 \uc784\uc758\ub85c \ub098\ub204\uc5b4 \uc11c\ub85c\uc758 \uc9c0\uc5ed\uc744 \uce68\ubc94\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uacb0\uc758\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Mx,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \uc601\uc5c5\uc9c0\uc5ed\uc744 \uc784\uc758\ub85c \ubd84\ud560\ud558\uc5ec \uc11c\ub85c \uce68\ubc94\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uacb0\uc758\ud558\ub294 \uac83\uc740, \uc9c0\uc5ed\ubcc4 \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\uac70\ud558\ub294 \ud589\uc704\ub85c\uc11c \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9\xb7\ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub2e4. \uc774\ub294 \uc18c\ube44\uc790\uc758 \uc120\ud0dd\uad8c \ucd95\uc18c\uc640 \uac00\uaca9 \uc0c1\uc2b9\uc73c\ub85c \uc774\uc5b4\uc9c8 \uc218 \uc788\uc5b4 \uacbd\uc7c1\uc81c\ud55c \uc6b0\ub824\uac00 \ud06c\ub2e4.",B.RB,B.a1E,null)
B.M2=s(["\uc774\ub7ec\ud55c \ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc728\ub41c\ub2e4","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub9cc \ud560 \uc218 \uc788\uc73c\ubbc0\ub85c \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640\ub294 \ubb34\uad00\ud558\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ubc29\uc870\ud589\uc704\uc5d0 \ub300\ud574 \uc5b4\ub5a0\ud55c \ucc45\uc784\ub3c4 \uc9c0\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uc720\ud615\uc740 \uc624\uc9c1 \ud615\uc0ac\ucc98\ubc8c\ub9cc \uac00\ub2a5\ud558\uace0 \ud589\uc815\uc81c\uc7ac\ub294 \ubd88\uac00\ub2a5\ud558\ub2e4","\uc774 \uc720\ud615\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc815\uad00\uc5d0 \uba85\uc2dc\ub418\uc9c0 \uc54a\uc73c\uba74 \uaddc\uc81c\ud560 \uc218 \uc5c6\ub2e4"],t.s)
