B.a7I=new A.f("gen_ta_aid_1","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0 \ubc29\uc870","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub85c \ud558\uc5ec\uae08 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub97c \ud558\uac8c \ud558\uac70\ub098 \uc774\ub97c \ubc29\uc870\ud558\ub294 \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.M2,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c51\uc870 \uc81c1\ud56d \uc81c4\ud638\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \ub610\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\uac8c \ud558\uac70\ub098 \uc774\ub97c \ubc29\uc870\ud558\ub294 \ud589\uc704\ub97c \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc815\ud55c\ub2e4. \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc9c1\uc811 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uc758 \uc8fc\uccb4\uac00 \uc544\ub2c8\ub354\ub77c\ub3c4, \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \uadf8\ub7ec\ud55c \ud589\uc704\ub97c \uc720\ub3c4\xb7\ubc29\uc870\ud55c\ub2e4\uba74 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc790\uccb4\uac00 \ucc45\uc784\uc744 \uc9c8 \uc218 \uc788\ub2e4.",B.Rn,B.JR,null)
B.Hl=s([u.a,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc9c0\uce68\uc740 \uad8c\uace0\uc5d0 \ubd88\uacfc\ud558\ubbc0\ub85c \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4","\uac70\ub798\uac70\uc808\uc740 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \uc790\uc720\uc774\ubbc0\ub85c \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uc9c0\uce68\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uc774 \uacbd\uc6b0 \ud2b9\uc815 \uc720\ud1b5\uc5c5\uc790\uc5d0\uac8c\ub294 \uc5b4\ub5a0\ud55c \ubc95\uc801 \ubcf4\ud638\ub3c4 \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc9c0\uce68\uc740 \uc624\uc9c1 \ub3c4\ub355\uc801 \ubb38\uc81c\uc77c \ubfd0 \ubc95\uc801 \ubb38\uc81c\uac00 \uc544\ub2c8\ub2e4"],t.s)
