B.adZ=new A.f("gen_ta_aid_2","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0 \ubc29\uc870","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \ud2b9\uc815 \uc720\ud1b5\uc5c5\uc790\uc640\uc758 \uac70\ub798\ub97c \ubd80\ub2f9\ud558\uac8c \uac70\uc808\ud558\ub3c4\ub85d \uc9c0\uce68\uc744 \ub0b4\ub9b0 \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.Hl,0,'\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \ud2b9\uc815 \uac70\ub798\uc0c1\ub300\ubc29\uacfc\uc758 \uac70\ub798\ub97c \ubd80\ub2f9\ud558\uac8c \uac70\uc808\ud558\ub3c4\ub85d \uc9c0\uce68\uc744 \ub0b4\ub9ac\ub294 \uac83\uc740, \uac1c\ubcc4 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704(\uac70\ub798\uac70\uc808)\ub97c \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc870\uc9c1\uc801\uc73c\ub85c \uc720\ub3c4\ud55c \uac83\uc73c\ub85c \ud3c9\uac00\ub418\uc5b4 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc728\ub420 \uc218 \uc788\ub2e4. "\uad8c\uace0"\ub77c\ub294 \ud615\uc2dd\uc744 \ucde8\ud558\ub354\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\ub97c \uc88c\uc6b0\ud55c\ub2e4\uba74 \ucc45\uc784\uc744 \ud53c\ud558\uae30 \uc5b4\ub835\ub2e4.',B.Op,B.SF,null)
B.OE=s([u.P,"\ucd5c\uc885 \ud310\ub9e4\uac00\uaca9\uc5d0 \uad00\ud55c \uc9c0\uc2dc\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc815\ub2f9\ud55c \uad8c\ud55c \ubc94\uc704\uc5d0 \uc18d\ud55c\ub2e4","\uc774\ub7ec\ud55c \uc9c0\uc2dc\ub294 \uc18c\ube44\uc790 \ubcf4\ud638\ub97c \uc704\ud55c \uac83\uc774\ubbc0\ub85c \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\ub9cc \uaddc\uc81c \ub300\uc0c1\uc774 \ub418\uace0 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc640\ub294 \ubb34\uad00\ud558\ub2e4","\uc774 \uc9c0\uc2dc\ub294 \uc624\uc9c1 \ub3c4\ub9e4\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \uc18c\ub9e4\uc5c5\uc790\uc5d0\uac8c\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
