B.adn=new A.f("gen_ta_aid_3","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0 \ubc29\uc870","\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc5d0\uac8c \ucd5c\uc885 \ud310\ub9e4\uac00\uaca9\uc744 \uc77c\uc815 \uc218\uc900 \uc774\ud558\ub85c \ub0b4\ub9ac\uc9c0 \ubabb\ud558\ub3c4\ub85d \uc9c0\uc2dc\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.OE,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uad6c\uc131\uc0ac\uc5c5\uc790\ub4e4\uc758 \ucd5c\uc885 \ud310\ub9e4\uac00\uaca9\uc744 \uc77c\uc815 \uc218\uc900 \uc774\ud558\ub85c \ub0b4\ub9ac\uc9c0 \ubabb\ud558\ub3c4\ub85d \uc9c0\uc2dc\ud558\ub294 \uac83\uc740, \uc2e4\uc9c8\uc801\uc73c\ub85c \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc870\uc9c1\uc801\uc73c\ub85c \ud558\uac8c \ud558\uac70\ub098 \ubc29\uc870\ud558\ub294 \uac83\uc73c\ub85c \ud3c9\uac00\ub418\uc5b4 \uc81c51\uc870 \uc81c1\ud56d \uc81c4\ud638\uc5d0 \ub530\ub978 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\ub85c \ubb38\uc81c\ub420 \uc218 \uc788\ub2e4.",B.M8,B.QF,null)
B.Kk=s([u.jW,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc560\ucd08\uc5d0 \uc544\ubb34\ub7f0 \uc601\ud5a5\ub825\uc774 \uc5c6\uae30 \ub54c\ubb38\uc5d0 \ud615\uc2dd\uc801\uc73c\ub85c\ub9cc \uaddc\uc815\ub41c \uac83\uc774\ub2e4","\uc774 \uaddc\uc815\uc740 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ucc45\uc784\uc744 \uc644\uc804\ud788 \ub300\uccb4\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\uc774 \uaddc\uc815\uc740 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc7ac\uc815 \ud655\ubcf4\ub97c \uc704\ud55c \uac83\uc774\ub2e4","\uc774 \uaddc\uc815\uc740 \uc624\uc9c1 \uad6d\ub0b4 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub418\uace0 \ub2e4\ub978 \uacbd\uc6b0\ub294 \ubb34\uad00\ud558\ub2e4"],t.s)
