B.a9T=new A.f("gen_ta_aid_4","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0 \ubc29\uc870",'\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uc911 "\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\uac8c \ud558\uac70\ub098 \ubc29\uc870\ud558\ub294 \ud589\uc704"\uac00 \uaddc\uc81c\ub418\ub294 \uc774\uc720\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.Kk,0,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ub2e4\uc218\uc758 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \ub3d9\uc2dc\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce60 \uc218 \uc788\ub294 \uc870\uc9c1\uc774\uae30 \ub54c\ubb38\uc5d0, \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub97c \ub9e4\uac1c\ub85c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub098 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \uc774\ub8e8\uc5b4\uc9c0\uba74 \uadf8 \ud30c\uae09\ud6a8\uacfc\uac00 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \ub2e8\ub3c5 \uc704\ubc18\ubcf4\ub2e4 \ud6e8\uc52c \uad11\ubc94\uc704\ud558\uac8c \ud655\uc0b0\ub420 \uc218 \uc788\ub2e4. \uc774 \uaddc\uc815\uc740 \uc774\ub7ec\ud55c \uc870\uc9c1\uc801\xb7\uc9d1\ub2e8\uc801 \uc704\ubc95\ud589\uc704 \ud655\uc0b0\uc744 \ubc29\uc9c0\ud558\ub824\ub294 \ucde8\uc9c0\uc5d0\uc11c \ub9c8\ub828\ub41c \uac83\uc774\ub2e4.",B.KA,B.HL,null)
B.IE=s([u.a1,"\uad8c\uace0\ub77c\ub294 \ud615\uc2dd\uc744 \ucde8\ud558\uba74 \uadf8 \ub0b4\uc6a9\uacfc \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uc774\ub7ec\ud55c \uad8c\uace0\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \ud45c\ud604\uc758 \uc790\uc720\ub85c\uc11c \uc5b4\ub5a0\ud55c \uc81c\ud55c\ub3c4 \ubc1b\uc9c0 \uc54a\ub294\ub2e4","\uc774 \uacbd\uc6b0 \ud2b9\uc815 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub294 \uc544\ubb34\ub7f0 \ubc95\uc801 \ubcf4\ud638\ub97c \ubc1b\uc744 \uc218 \uc5c6\ub2e4","\uad8c\uace0 \ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uac1c\ubcc4 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \ucc45\uc784\uc774 \uadc0\uc18d\ub41c\ub2e4"],t.s)
