B.YZ=s(["\ud574\ub2f9 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud55c \uc2dc\uc815\uc870\uce58 \ubc0f \uacfc\uc9d5\uae08 \ubd80\uacfc","\uc704\ubc18\ud589\uc704\uc5d0 \uad00\uc5ec\ud55c \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ubcc4\ub3c4\uc758 \uc2dc\uc815\uc870\uce58","\uc704\ubc18\uc0ac\uc2e4\uc758 \uacf5\ud45c \uba85\ub839","\ud574\ub2f9 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uac15\uc81c \ud574\uc0b0 \uba85\ub839\uc744 \ud56d\uc0c1 \uc6b0\uc120\uc801\uc73c\ub85c \ubc1c\ub3d9","\uc704\ubc18\ud589\uc704\uc758 \uc911\uc9c0 \uba85\ub839"],t.s)
