B.Nd=s([u.O,"\uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0 \ub300\ud574\uc11c\ub294 \uc5b4\ub5a0\ud55c \uc870\uc0ac\ub3c4 \uc9c4\ud589\ud560 \uc218 \uc5c6\ub2e4","\uc870\uc0ac\ub294 \ubc18\ub4dc\uc2dc \uad6c\uc131\uc0ac\uc5c5\uc790 \uc804\uc6d0\uc758 \ub3d9\uc758\uac00 \uc788\uc5b4\uc57c\ub9cc \uac1c\uc2dc\ub420 \uc218 \uc788\ub2e4","\uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \uc870\uc0ac\uc5d0 \uc804\ud600 \ud611\uc870\ud560 \uc758\ubb34\uac00 \uc5c6\ub2e4","\uc870\uc0ac \uacb0\uacfc\uc640 \ubb34\uad00\ud558\uac8c \ud56d\uc0c1 \uc2dc\uc815\uc870\uce58\uac00 \ub0b4\ub824\uc9c4\ub2e4"],t.s)
