B.a7G=new A.f("gen_ta_sanction_6","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc2dc\uc815\uc870\uce58(\uc0ac\uc5c5\uc790\ub2e8\uccb4)","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uaddc\uc81c\uc758 \uc2e4\ud6a8\uc131\uc744 \ub192\uc774\uae30 \uc704\ud574 \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \ucc45\uc784\uc744 \ubb3c\uc744 \uc218 \uc788\ub3c4\ub85d \ud55c \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Ys,0,"\uc704\ubc18\ud589\uc704\uc5d0 \uc2e4\uc9c8\uc801\uc73c\ub85c \uad00\uc5ec\ud55c \uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c\ub3c4 \ucc45\uc784\uc744 \ubb3c\uc744 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uac83\uc740, \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub77c\ub294 \uc870\uc9c1\uc758 \ud615\uc2dd \ub4a4\uc5d0 \uc228\uc5b4 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \uc790\uc2e0\uc758 \ucc45\uc784\uc744 \ud68c\ud53c\ud558\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uace0, \uc2e4\uc9c8\uc801\uc778 \uc704\ubc18\ud589\uc704\uc790\uc5d0\uac8c \uc0c1\uc751\ud558\ub294 \ucc45\uc784\uc744 \ubd80\uacfc\ud568\uc73c\ub85c\uc368 \uaddc\uc81c\uc758 \uc2e4\ud6a8\uc131\uc744 \ub192\uc774\uae30 \uc704\ud55c \ucde8\uc9c0\ub85c \uc774\ud574\ub41c\ub2e4.",B.Tz,B.a_k,null)
B.Un=s(["\uc0ac\uc5c5\uc790\uac00 \uc0c1\ud488\uc744 \uac70\ub798\ud558\uba70 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uac70\ub798\uac00\uaca9\uc744 \uc815\ud558\uc5ec \uadf8 \uac00\uaca9\ub300\ub85c \ud310\ub9e4\ud558\ub3c4\ub85d \uac15\uc81c\ud558\ub294 \ud589\uc704\ub294 \uad6c\uc18d\ub825 \uc5ec\ubd80\uc640 \uc0c1\uad00\uc5c6\uc774 \ud56d\uc0c1 \uae08\uc9c0\ub41c\ub2e4","\uc800\uc791\uad8c\ubc95\uc0c1 \uc800\uc791\ubb3c\ub85c\uc11c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc0c1\ud488\uc758 \uacbd\uc6b0 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub420 \uc218 \uc788\ub2e4","\ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\uc5b4\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uae08\uc9c0\ub294 \uc6a9\uc5ed\uc758 \uc81c\uacf5\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uac15\uc81c\ub825 \uc5c6\ub294 \ud76c\ub9dd\uac00\uaca9\uc744 \uc81c\uc2dc\ud558\ub294 \ud589\uc704\ub3c4 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c \uae08\uc9c0\ub41c\ub2e4"],t.s)
