B.ada=new A.f("gen_rpm_type_6","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ucd5c\uace0\xb7\ucd5c\uc800 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\uc758 \uad6c\ubcc4","\uac00\ub9f9\ubcf8\ubd80\uac00 \uac00\ub9f9\uc810\uc5d0 \ub300\ud574 \ucd5c\uc800\ud310\ub9e4\uac00\uaca9\uc744 \uc9c0\uc815\ud558\uace0 \uc774\ub97c \ub530\ub974\uc9c0 \uc54a\uc73c\uba74 \uacf5\uae09\uc744 \uc911\ub2e8\ud558\uaca0\ub2e4\uace0 \ud1b5\ubcf4\ud55c \uacbd\uc6b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Xv,0,"\uac00\ub9f9\ubcf8\ubd80\uac00 \uac00\ub9f9\uc810\uc5d0 \ub300\ud574 \ucd5c\uc800\ud310\ub9e4\uac00\uaca9\uc744 \uc9c0\uc815\ud558\uace0 \uc774\ub97c \ub530\ub974\uc9c0 \uc54a\uc744 \uacbd\uc6b0 \uacf5\uae09\uc744 \uc911\ub2e8\ud558\uaca0\ub2e4\uace0 \ud1b5\ubcf4\ud558\ub294 \ud589\uc704\ub294 \uad6c\uc18d\ub825\uc744 \uac16\ucd98 \ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud560 \uc18c\uc9c0\uac00 \uc788\uc73c\uba70, \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc778\uc815\ub418\uc9c0 \uc54a\ub294 \ud55c \uc704\ubc95\ud55c \ud589\uc704\ub85c \ud3c9\uac00\ub420 \uc218 \uc788\ub2e4.",B.Ks,B.KT,null)
B.a1S=s(["\ud574\ub2f9 \ud589\uc704\uc5d0 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\ub2e4\uace0 \uc778\uc815\ub418\ub294 \uacbd\uc6b0","\uc0ac\uc5c5\uc790\uac00 \uc6d0\ud55c\ub2e4\uace0 \ub9d0\ud558\uae30\ub9cc \ud558\uba74 \ud56d\uc0c1 \ud5c8\uc6a9\ub41c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc774 \ub300\uae30\uc5c5\uc778 \uacbd\uc6b0\uc5d0\ub9cc \ud5c8\uc6a9\ub41c\ub2e4","\uac00\uaca9\uc774 \ub9e4\uc6b0 \uc800\ub834\ud55c \uacbd\uc6b0\uc5d0\ub9cc \ud5c8\uc6a9\ub41c\ub2e4","\uc628\ub77c\uc778 \uac70\ub798\uc778 \uacbd\uc6b0\uc5d0\ub9cc \ud56d\uc0c1 \ud5c8\uc6a9\ub41c\ub2e4"],t.s)
