B.a9e=new A.f("gen_rpm_exception_1","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720\xb7\uc608\uc678","\ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \uc608\uc678\uc801\uc73c\ub85c \ud5c8\uc6a9\ub420 \uc218 \uc788\ub294 \uacbd\uc6b0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a1S,0,"\ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uae08\uc9c0\ub418\uc9c0\ub9cc, \ud574\ub2f9 \ud589\uc704\uc5d0 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\ub2e4\uace0 \uc778\uc815\ub418\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \ud5c8\uc6a9\ub420 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ubc95\ub9ac\ub85c \uc778\uc815\ub41c\ub2e4. \uc815\ub2f9\ud55c \uc774\uc720\ub294 \uac1c\ubcc4 \uc0ac\uc548\uc758 \uad6c\uccb4\uc801 \uc0ac\uc815\uc744 \uc885\ud569\ud558\uc5ec \ud310\ub2e8\ub41c\ub2e4.",B.HW,B.ND,null)
B.OP=s([u.a4,"\uc800\uc791\ubb3c\uc740 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uaddc\uc81c\uc640 \uc804\ud600 \ubb34\uad00\ud558\uae30 \ub54c\ubb38\uc774\ub2e4","\uc800\uc791\ubb3c\uc740 \ud56d\uc0c1 \uac00\uaca9\uc744 \ubb34\ub8cc\ub85c \ud574\uc57c \ud558\uae30 \ub54c\ubb38\uc774\ub2e4","\uc800\uc791\uad8c\uc790\ub97c \ucc98\ubc8c\ud558\uae30 \uc704\ud55c \uaddc\uc815\uc774\ub2e4","\uc800\uc791\ubb3c \uc720\ud1b5\uc5c5\uc790\ub97c \ud56d\uc0c1 \ubd88\ub9ac\ud558\uac8c \ud558\uae30 \uc704\ud55c \uaddc\uc815\uc774\ub2e4"],t.s)
