B.acj=new A.f("gen_rpm_exception_2","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720\xb7\uc608\uc678","\uc800\uc791\uad8c\ubc95\uc0c1 \uc800\uc791\ubb3c\uc5d0 \ub300\ud55c \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uc608\uc678 \uaddc\uc815\uc758 \ucde8\uc9c0\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.OP,0,"\u300c\uc800\uc791\uad8c\ubc95\u300d\uc0c1 \uc800\uc791\ubb3c(\uc608: \ucd9c\ud310\ubb3c) \uc911 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uac83\uc5d0 \ub300\ud574 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \uc608\uc678\uc801\uc73c\ub85c \ud5c8\uc6a9\ud558\ub294 \uac83\uc740, \ucd9c\ud310\ubb3c\uacfc \uac19\uc740 \ubb38\ud654\uc0c1\ud488\uc758 \uc720\ud1b5 \ud2b9\uc131\uc774\ub098 \ub2e4\uc591\uc131 \ubcf4\ud638 \ub4f1 \uc815\ucc45\uc801 \uace0\ub824\ub97c \ubc18\uc601\ud55c \ud2b9\ubcc4 \uc608\uc678 \uaddc\uc815\uc73c\ub85c \uc774\ud574\ub41c\ub2e4.",B.MA,B.IH,null)
B.Q1=s([u.h,"\uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \ub9e4\ucd9c \uaddc\ubaa8\ub9cc \uace0\ub824\ud55c\ub2e4","\uc624\uc9c1 \uc0ac\uc5c5\uc790 \ub300\ud45c\uc758 \uac1c\uc778\uc801 \uc758\uacac\ub9cc \uace0\ub824\ud55c\ub2e4","\uc624\uc9c1 \uac70\ub798\uc0c1\ub300\ubc29\uc758 \uad6d\uc801\ub9cc \uace0\ub824\ud55c\ub2e4","\uc815\ub2f9\ud55c \uc774\uc720 \ud310\ub2e8\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uae30\uc900\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
