B.Pd=s(["\uc815\ub2f9\ud55c \uc774\uc720\uc758 \uc99d\uba85\ucc45\uc784"],t.s)
B.ad9=new A.f("gen_rpm_exception_4","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720\xb7\uc608\uc678","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \uad00\ud55c \uc815\ub2f9\ud55c \uc774\uc720\uc758 \uc99d\uba85\ucc45\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.O6,0,"\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\ub2e4\ub294 \uc0ac\uc815\uc740 \uadf8 \ud589\uc704\uc758 \uc704\ubc95\uc131\uc744 \uc870\uac01\ud558\uae30 \uc704\ud55c \ud56d\ubcc0\uc0ac\uc720\uc758 \uc131\uaca9\uc744 \uac00\uc9c0\ubbc0\ub85c, \uc774\ub97c \uc8fc\uc7a5\ud558\ub294 \uc0ac\uc5c5\uc790 \uce21\uc774 \uc99d\uba85\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc778 \uc99d\uba85\ucc45\uc784 \ubc30\ubd84 \uc6d0\uce59\uc5d0 \ubd80\ud569\ud55c\ub2e4.",B.MV,B.Pd,null)
B.T5=s([u.gn,"\ubb34\uc784\uc2b9\ucc28 \ubb38\uc81c\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ubb34\uc784\uc2b9\ucc28 \ubc29\uc9c0\ub294 \uc624\uc9c1 \ucd5c\uace0\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0\uc11c\ub9cc \ub17c\uc758\ub41c\ub2e4","\ubb34\uc784\uc2b9\ucc28 \ubc29\uc9c0\ub294 \uc5b8\uc81c\ub098 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \uc815\ub2f9\ud654\ud558\ub294 \uc808\ub300\uc801 \uc0ac\uc720\uc774\ub2e4","\ubb34\uc784\uc2b9\ucc28\ub294 \uc18c\ube44\uc790\uc5d0\uac8c\ub9cc \ucc45\uc784\uc774 \uc788\ub294 \ubb38\uc81c\uc774\ub2e4"],t.s)
