B.acz=new A.f("gen_rpm_exception_6","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720\xb7\uc608\uc678","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640 \uad00\ub828\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc608\uc678 \ub300\uc0c1 \uc800\uc791\ubb3c\uc758 \uc9c0\uc815 \uc808\ucc28\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.S8,0,"\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uc608\uc678\uac00 \uc778\uc815\ub418\ub294 \uc800\uc791\ubb3c\uc758 \ubc94\uc704\ub294 \uad00\uacc4 \uc911\uc559\ud589\uc815\uae30\uad00\uc758 \uc7a5\uacfc\uc758 \ud611\uc758\ub97c \uac70\uccd0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc808\ucc28\ub97c \ud1b5\ud574 \uc815\ud574\uc9c0\uba70, \uc774\ub294 \uc800\uc791\uad8c\uc790\ub098 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \uc784\uc758\ub85c \uc815\ud560 \uc218 \uc788\ub294 \uc0ac\ud56d\uc774 \uc544\ub2c8\ub2e4.",B.Z3,B.Ug,null)
B.Tu=s(["\uc2dc\uc815\uc870\uce58 \ubc0f \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1\uc758 \uc870\uce58\ub97c \ucde8\ud560 \uc218 \uc788\ub2e4","\uc5b4\ub5a0\ud55c \uc81c\uc7ac\ub3c4 \ud560 \uc218 \uc5c6\uace0 \uad8c\uace0\ub9cc \uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \ud615\uc0ac\uace0\ubc1c\ub9cc \uac00\ub2a5\ud558\uace0 \ud589\uc815\ucc98\ubd84\uc740 \ubd88\uac00\ub2a5\ud558\ub2e4","\uc624\uc9c1 \uc190\ud574\ubc30\uc0c1 \uc18c\uc1a1\uc744 \ub300\uc2e0 \uc81c\uae30\ud574\uc904 \uc218 \uc788\ub2e4","\uc704\ubc18 \uc0ac\uc5c5\uc790\uc758 \uc601\uc5c5\uc744 \uc989\uc2dc \ud3d0\uc1c4\ud574\uc57c \ud55c\ub2e4"],t.s)
B.a_0=s(["\uc2dc\uc815\uc870\uce58 \ubc0f \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1\uc758 \uc870\uce58\ub97c \ucde8\ud560 \uc218 \uc788\ub2e4"],t.s)
