B.aaz=new A.f("gen_rpm_sanction_1","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc190\ud574\ubc30\uc0c1","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uc704\ubc18\uc5d0 \ub300\ud574 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \ucde8\ud560 \uc218 \uc788\ub294 \uc870\uce58\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Tu,0,"\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uc704\ubc18\uc774 \uc778\uc815\ub418\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub2e4\ub978 \ubc95 \uc704\ubc18\ud589\uc704\uc640 \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc2dc\uc815\uc870\uce58(\uc911\uc9c0\uba85\ub839 \ub4f1) \ubc0f \uc704\ubc18 \uc815\ub3c4\uc5d0 \ub530\ub978 \uacfc\uc9d5\uae08 \ubd80\uacfc \ub4f1\uc758 \ud589\uc815\uc801 \uc870\uce58\ub97c \ucde8\ud560 \uc218 \uc788\ub2e4.",B.a_0,B.XB,null)
B.nD=s(["\ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud558\ub294 \ub4f1 \ubcc4\ub3c4\uc758 \uad6c\uc81c\uc218\ub2e8\uc744 \ud65c\uc6a9\ud560 \uc218 \uc788\ub2e4","\ud53c\ud574\ub97c \uc785\uc5b4\ub3c4 \uc5b4\ub5a0\ud55c \uad6c\uc81c\uc218\ub2e8\ub3c4 \uac00\uc9c8 \uc218 \uc5c6\ub2e4","\uc624\uc9c1 \ud615\uc0ac\uace0\uc18c\ub9cc \uac00\ub2a5\ud558\ub2e4","\ud53c\ud574 \uad6c\uc81c\ub294 \uc624\uc9c1 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc7ac\ub7c9\uc5d0 \uc804\uc801\uc73c\ub85c \ub9e1\uaca8\uc9c4\ub2e4","\uad6c\uc81c\uc218\ub2e8\uc740 \ubc95\ub960\uc0c1 \uc804\ud600 \ub9c8\ub828\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4"],t.s)
B.n8=s(["\ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud558\ub294 \ub4f1 \ubcc4\ub3c4\uc758 \uad6c\uc81c\uc218\ub2e8\uc744 \ud65c\uc6a9\ud560 \uc218 \uc788\ub2e4"],t.s)
