B.adS=new A.f("gen_rpm_sanction_2","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc190\ud574\ubc30\uc0c1","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c \ud53c\ud574\ub97c \uc785\uc740 \uac70\ub798\uc0c1\ub300\ubc29\uc758 \uad6c\uc81c\uc218\ub2e8\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.nD,0,"\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c \uc778\ud574 \ud53c\ud574\ub97c \uc785\uc740 \uac70\ub798\uc0c1\ub300\ubc29\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uc870\uce58\uc640\ub294 \ubcc4\ub3c4\ub85c \ubbfc\uc0ac\uc0c1 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud558\ub294 \ub4f1 \uc790\uc2e0\uc758 \uad8c\ub9ac\ub97c \uad6c\uc81c\ubc1b\uae30 \uc704\ud55c \uc218\ub2e8\uc744 \ud65c\uc6a9\ud560 \uc218 \uc788\ub2e4.",B.n8,B.nz,null)
B.a0r=s([u.dp,"\uc624\uc9c1 \uc0ac\uc5c5\uc790\uc758 \uc124\ub9bd\uc5f0\ub3c4\ub9cc \uace0\ub824\ub41c\ub2e4","\uc624\uc9c1 \uc0ac\uc5c5\uc790 \ub300\ud45c\uc758 \ub098\uc774\ub9cc \uace0\ub824\ub41c\ub2e4","\uacfc\uc9d5\uae08\uc740 \ud56d\uc0c1 \uc815\uc561\uc73c\ub85c \uc77c\ub960\uc801\uc73c\ub85c \ubd80\uacfc\ub41c\ub2e4","\uacfc\uc9d5\uae08 \uc0b0\uc815\uc5d0\ub294 \uc5b4\ub5a0\ud55c \uae30\uc900\ub3c4 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
