B.a76=new A.f("gen_rpm_sanction_3","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc190\ud574\ubc30\uc0c1","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08 \uc0b0\uc815 \uc2dc \uace0\ub824\ub418\ub294 \uc694\uc18c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a0r,0,"\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ub300\ud55c \uacfc\uc9d5\uae08\uc740 \ub2e4\ub978 \ubc95 \uc704\ubc18\ud589\uc704\uc640 \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc704\ubc18\ud589\uc704\uc640 \uad00\ub828\ub41c \ub9e4\ucd9c\uc561, \uc704\ubc18\uae30\uac04, \uc704\ubc18\uc758 \uc815\ub3c4 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\uc5ec \uc0b0\uc815\ub418\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4.",B.Jc,B.OJ,null)
B.Zp=s(["\ubc18\ubcf5\uc131\uc774 \uc778\uc815\ub418\uba74 \uac00\uc911\uc0ac\uc720\ub85c \uace0\ub824\ub418\uc5b4 \uc81c\uc7ac \uc218\uc704\uac00 \ub192\uc544\uc9c8 \uc218 \uc788\ub2e4","\ubc18\ubcf5 \uc5ec\ubd80\ub294 \uc81c\uc7ac \uc218\uc704\uc640 \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\ubc18\ubcf5\ud558\uba74 \uc624\ud788\ub824 \uc81c\uc7ac\uac00 \uac10\uacbd\ub41c\ub2e4","\ubc18\ubcf5 \ud589\uc704\ub294 \ud56d\uc0c1 \ucc98\ubc8c \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4","\ubc18\ubcf5 \ud589\uc704\ub294 \uc624\uc9c1 \uc190\ud574\ubc30\uc0c1\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub41c\ub2e4"],t.s)
B.Zy=s(["\ubc18\ubcf5\uc131\uc774 \uc778\uc815\ub418\uba74 \uac00\uc911\uc0ac\uc720\ub85c \uace0\ub824\ub418\uc5b4 \uc81c\uc7ac \uc218\uc704\uac00 \ub192\uc544\uc9c8 \uc218 \uc788\ub2e4"],t.s)
