B.adr=new A.f("gen_rpm_sanction_4","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc190\ud574\ubc30\uc0c1","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ubc18\ubcf5\uc801\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9c4 \uacbd\uc6b0\uc758 \uc81c\uc7ac \uc218\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Zp,0,"\ub3d9\uc77c\ud558\uac70\ub098 \uc720\uc0ac\ud55c \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ubc18\ubcf5\uc801\uc73c\ub85c \ud589\ud55c \uc0ac\uc2e4\uc774 \uc778\uc815\ub418\uba74, \uc774\ub294 \uac00\uc911\uc0ac\uc720\ub85c \uace0\ub824\ub418\uc5b4 \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08 \ub4f1\uc758 \uc81c\uc7ac \uc218\uc704\uac00 \ub192\uc544\uc9c8 \uc218 \uc788\ub2e4.",B.Zy,B.GB,null)
B.a_g=s([u.ok,"\uac00\ub9f9\ubcf8\ubd80\ub294 \uac00\ub9f9\uc810 \ud310\ub9e4\uac00\uaca9\uc744 \uc790\uc720\ub86d\uac8c \uac15\uc81c\ud560 \uc218 \uc788\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uac00\ub9f9\uacc4\uc57d\uc5d0\uc11c \uc804\ud600 \ubb38\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4","\uac00\ub9f9\uc810\uc774 \uac00\uaca9\uc744 \uc9c0\ud0a4\uc9c0 \uc54a\uc73c\uba74 \ubb34\uc870\uac74 \uacf5\uae09\uc744 \uc911\ub2e8\ud558\ub77c\uace0 \uc870\uc5b8\ud574\uc57c \ud55c\ub2e4","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uaddc\uc81c\ub294 \uac00\ub9f9\uac70\ub798\uc0ac \uc5c5\ubb34\uc640 \ubb34\uad00\ud558\ub2e4\uace0 \uc548\ub0b4\ud558\uba74 \ub41c\ub2e4"],t.s)
B.ZL=s([u.ok],t.s)
B.acm=new A.f("gen_rpm_sanction_5","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\uc81c\uc7ac\xb7\uc190\ud574\ubc30\uc0c1","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uad00\ub828 \ub9ac\uc2a4\ud06c\ub97c \uc790\ubb38\ud560 \ub54c \uac15\uc870\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.a_g,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \uc790\ubb38\ud560 \ub54c, \uac00\ub9f9\uc810\uc5d0 \ub300\ud55c \ucd5c\uc800\ud310\ub9e4\uac00\uaca9 \uc9c0\uc815\uacfc \uadf8 \uc900\uc218\ub97c \uac15\uc81c\ud558\ub294 \uc870\uce58\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc774\ub8e8\uc5b4\uc9c0\uba74 \ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c\uc11c \uc704\ubc95\ud560 \uc218 \uc788\ub2e4\ub294 \uc810\uc744 \uba85\ud655\ud788 \uc548\ub0b4\ud558\uc5ec \ubc95\uc801 \ub9ac\uc2a4\ud06c\ub97c \uc0ac\uc804\uc5d0 \uad00\ub9ac\ud558\ub3c4\ub85d \ub3c4\uc640\uc57c \ud55c\ub2e4.",B.ZL,B.ng,null)
B.I1=s(["\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc790\uae08\uc744 \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc790\uc0b0\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc0ac\uc5c5\uae30\ud68c\ub97c \uc81c\uacf5\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\ud569\ub9ac\uc801 \uace0\ub824\ub098 \ube44\uad50 \uc5c6\uc774 \uc0c1\ub2f9\ud55c \uaddc\ubaa8\ub85c \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc2dc\uc7a5\uac00\uaca9\ubcf4\ub2e4 \ub0ae\uc740 \uac00\uaca9\uc73c\ub85c \uc77c\ubc18 \uc18c\ube44\uc790\uc5d0\uac8c \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\uc744 \uc81c\uacf5\ud558\ub294 \ud589\uc704"],t.s)
B.Ov=s(["\uc77c\ubc18 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c \ud55c \ud1b5\uc0c1\uc801\uc778 \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\ucc98\ub7fc \ud2b9\uc218\uad00\uacc4\uc778\uacfc \ubb34\uad00\ud55c \uac70\ub798\ub294 \uc560\ucd08\uc5d0 \uaddc\uc81c \ub300\uc0c1 \ubc94\uc704\uc5d0 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Pk=s(["\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc77c\uac10\ubab0\uc544\uc8fc\uae30"],t.s)
B.ab9=new A.f("gen_sp_1","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\ud55c \uc774\uc775\uc81c\uacf5\ud589\uc704(\uc0ac\uc775\ud3b8\ucde8)\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.I1,4,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c47\uc870(\ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\ud55c \uc774\uc775\uc81c\uacf5 \ub4f1 \uae08\uc9c0, \uc774\ub978\ubc14 "\uc77c\uac10\ubab0\uc544\uc8fc\uae30" \uaddc\uc81c)\ub294 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc758 \uc790\uae08\xb7\uc790\uc0b0\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed\xb7\uc778\ub825 \uac70\ub798, \uc0ac\uc5c5\uae30\ud68c \uc81c\uacf5, \ud569\ub9ac\uc801 \uace0\ub824 \uc5c6\ub294 \uc0c1\ub2f9\ud55c \uaddc\ubaa8\uc758 \uac70\ub798\ub97c \ud1b5\ud574 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704\ub97c \uae08\uc9c0 \ub300\uc0c1\uc73c\ub85c \uaddc\uc815\ud55c\ub2e4. \uc774 \uaddc\uc81c\uc758 \ubaa9\uc801\uc740 \ub300\uae30\uc5c5\uc9d1\ub2e8 \ucd1d\uc218 \uc77c\uac00\ub098 \uacc4\uc5f4\ud68c\uc0ac \ub4f1 "\ud2b9\uc218\uad00\uacc4\uc778"\uc5d0\uac8c \ubd80\ub97c \ubd80\ub2f9\ud558\uac8c \uc774\uc804\uc2dc\ud0a4\ub294 \uac83\uc744 \ub9c9\ub294 \ub370 \uc788\uc73c\ubbc0\ub85c, \uc77c\ubc18 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c \ud55c \ud1b5\uc0c1\uc801\uc778 \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\ucc98\ub7fc \ud2b9\uc218\uad00\uacc4\uc778\uacfc \ubb34\uad00\ud55c \uac70\ub798\ub294 \uc560\ucd08\uc5d0 \uaddc\uc81c \ub300\uc0c1 \ubc94\uc704\uc5d0 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.Ov,B.Pk,null)
B.a05=s(["\ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub418\uba74 \ud574\ub2f9 \uc0ac\uac74\uc5d0 \ub300\ud55c \uc2ec\uc758\uc808\ucc28\ub294 \uc885\ub8cc\ub41c\ub2e4","\uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub3d9\uc758\uc758\uacb0\uc744 \uc774\ud589\ud558\uc9c0 \uc54a\uc73c\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc774\ud589\uac15\uc81c\uae08\uc744 \ubd80\uacfc\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub418\uba74 \ud5a5\ud6c4 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc18c\uc1a1\uc5d0\uc11c \uc2e0\uccad\uc778\uc740 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc790\ubc31\ud55c \uac83\uc73c\ub85c \uac04\uc8fc\ub418\uc5b4 \uc6d0\uace0\uc758 \uc785\uc99d\ucc45\uc784\uc774 \uba74\uc81c\ub41c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub3d9\uc758\uc758\uacb0\uc758 \uc774\ud589\uc2e4\ud0dc\ub97c \uc810\uac80\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \ucde8\uc18c\ub41c \uacbd\uc6b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc911\ub2e8\ub418\uc5c8\ub358 \uc6d0\ub798\uc758 \uc2ec\uc758\uc808\ucc28\ub97c \uacc4\uc18d\ud560 \uc218 \uc788\ub2e4"],t.s)
