B.ads=new A.f("gen_consent_relation_4","economic_law","\ub3d9\uc758\uc758\uacb0","\ub3d9\uc758\uc758\uacb0\uacfc \ub2e4\ub978 \uc808\ucc28\uc758 \uad00\uacc4","\uac00\ub9f9\uac70\ub798\uc0ac\uac00 \uac00\ub9f9\ubcf8\ubd80\uc5d0 \ub3d9\uc758\uc758\uacb0 \uc81c\ub3c4\ub97c \uc790\ubb38\ud560 \ub54c \uac15\uc870\ud574\uc57c \ud560 \uc0ac\ud56d\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Hu,0,"\uac00\ub9f9\uac70\ub798\uc0ac\ub294 \ub3d9\uc758\uc758\uacb0 \uc81c\ub3c4\ub97c \uc790\ubb38\ud560 \ub54c, \uc704\ubc95\uc131\uc744 \ub2e4\ud22c\uc9c0 \uc54a\uace0 \uc2dc\uc815\ubc29\uc548 \uc774\ud589\uc744 \ud1b5\ud574 \uc2e0\uc18d\ud558\uac8c \uc0ac\uac74\uc744 \uc885\uacb0\ud560 \uc218 \uc788\ub2e4\ub294 \uc7a5\uc810\uacfc \ud568\uaed8, \ud655\uc815\ub41c \ub3d9\uc758\uc758\uacb0\uc744 \uc774\ud589\ud558\uc9c0 \uc54a\uc73c\uba74 \uc774\ud589\uac15\uc81c\uae08 \ub4f1\uc758 \uc81c\uc7ac\ub97c \ubc1b\uc744 \uc218 \uc788\ub2e4\ub294 \uc774\ud589\uc758\ubb34\uc758 \ubb34\uac8c\ub97c \ud568\uaed8 \uade0\ud615 \uc788\uac8c \uc548\ub0b4\ud574\uc57c \ud55c\ub2e4.",B.YD,B.Or,null)
