B.ZD=s(['\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc784\uc9c1\uc6d0 \uc218"\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815\uc758 \ubc95\uc815 \uace0\ub824\uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4'],t.s)
B.a7P=new A.f("gen_pc_5","economic_law","\uacfc\uc9d5\uae08",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacfc\uc9d5\uae08 \uc0b0\uc815 \uc2dc \uace0\ub824\ud558\ub294 \uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Ho,4,'\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ud560 \ub54c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\ub824\ud558\ub294 \uc694\uc18c\ub294 \uc704\ubc18\ud589\uc704\uc758 \ub0b4\uc6a9\xb7\uc815\ub3c4, \uae30\uac04\xb7\ud69f\uc218, \uc704\ubc18\ud589\uc704\ub85c \ucde8\ub4dd\ud55c \uc774\uc775\uc758 \uaddc\ubaa8 \ub4f1\uc774\uba70, \uc774\ub294 \uc704\ubc18\ud589\uc704\uc758 \uc911\ub300\uc131\uacfc \ubd80\ub2f9\uc774\ub4dd\uc758 \uaddc\ubaa8\uc5d0 \ube44\ub840\ud558\uc5ec \uc81c\uc7ac \uc218\uc900\uc744 \uc815\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4. \ubc18\uba74 "\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc784\uc9c1\uc6d0 \uc218"\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815\uc758 \ubc95\uc815 \uace0\ub824\uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4 \u2014 \uacfc\uc9d5\uae08\uc740 \uc5b4\ub514\uae4c\uc9c0\ub098 \uc704\ubc18\ud589\uc704 \uc790\uccb4\uc758 \uacbd\uc911\uacfc \uadf8\ub85c \uc778\ud55c \uc774\ub4dd \uaddc\ubaa8\ub97c \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ub418\ub294 \uac83\uc774\uc9c0, \uae30\uc5c5\uc758 \uc870\uc9c1 \uaddc\ubaa8(\uc784\uc9c1\uc6d0 \uc218)\ub97c \uc9c1\uc811\uc801\uc778 \uc0b0\uc815 \uae30\uc900\uc73c\ub85c \uc0bc\uc9c0 \uc54a\ub294\ub2e4.',B.ZD,B.n7,null)
B.K_=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\uc5d0\uc11c \uc815\ud55c \uac83\ubcf4\ub2e4 \ub0ae\uc740 \ub300\uae08\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uc9c0\uae09\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc790\uae30 \uc0c1\ud488\uacfc \ud568\uaed8 \ub2e4\ub978 \uc0c1\ud488\uc758 \uad6c\uc785\uc744 \uac15\uc81c\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uac00 \uc9c0\uc815\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488\uc744 \uad6c\uc785\ud558\ub3c4\ub85d \uac15\uc694\ud558\ub294 \ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \ubc30\ud0c0\uc870\uac74\uc744 \ubd99\uc774\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ud2b9\uc815 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"],t.s)
B.Oh=s(['"\ubd88\uc774\uc775\uc81c\uacf5"\uc740 \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\ucc98\ub7fc \ubcc4\ub3c4\ub85c \uc720\ud615\ud654\ub41c \ud589\uc704 \uc678\uc758 \ubc29\ubc95\uc73c\ub85c'],t.s)
B.Yo=s(["\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\ubd88\uc774\uc775\uc81c\uacf5"],t.s)
B.ad2=new A.f("gen_ub_4","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9",null,'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704 \uc911 "\ubd88\uc774\uc775\uc81c\uacf5"\uc5d0 \ud574\ub2f9\ud558\ub294 \uc0ac\ub840\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.K_,0,'"\ubd88\uc774\uc775\uc81c\uacf5"\uc740 \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\ucc98\ub7fc \ubcc4\ub3c4\ub85c \uc720\ud615\ud654\ub41c \ud589\uc704 \uc678\uc758 \ubc29\ubc95\uc73c\ub85c, \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc77c\ubc29\uc801\uc73c\ub85c \ubd88\uc774\uc775\uc774 \ub418\ub294 \uae09\ubd80\xb7\ub300\uac00\ub97c \uc815\ud558\uac70\ub098 \uacc4\uc57d \ub0b4\uc6a9\uc744 \ubd88\ub9ac\ud558\uac8c \ubcc0\uacbd\ud558\ub294 \ud589\uc704\ub97c \ud3ec\uad04\uc801\uc73c\ub85c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc774\ub2e4. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\uc5d0\uc11c \uc815\ud55c \ub300\uae08\ubcf4\ub2e4 \ub0ae\uc740 \uae08\uc561\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uc9c0\uae09\ud558\ub294 \ud589\uc704\ub294 \ub300\ud45c\uc801\uc778 \ubd88\uc774\uc775\uc81c\uacf5 \uc0ac\ub840\uc5d0 \ud574\ub2f9\ud55c\ub2e4. \ubc18\uba74 \u2461\ub294 \ub07c\uc6cc\ud314\uae30(\uac70\ub798\uac15\uc81c), \u2462\uc740 \uad6c\uc785\uac15\uc81c, \u2463\ub294 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798(\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798), \u2464\ub294 \ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\ub85c\uc11c \uac01\uac01 \ubcc4\ub3c4\uc758 \ud558\uc704\uc720\ud615\uc774\ubbc0\ub85c \uc11c\ub85c \ud63c\ub3d9\ud558\uc9c0 \uc54a\uc544\uc57c \ud55c\ub2e4.',B.Oh,B.Yo,null)
B.a21=s([u.cw,"\ubc18\ub4dc\uc2dc \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc0ac\uc5c5\uc790\uc5d0 \ud574\ub2f9\ud574\uc57c\ub9cc \uac70\ub798\uc0c1 \uc9c0\uc704\uac00 \uc778\uc815\ub41c\ub2e4","\uac70\ub798 \uaddc\ubaa8\uac00 \uc77c\uc815 \uae08\uc561 \uc774\uc0c1\uc774\uc5b4\uc57c\ub9cc \uac70\ub798\uc0c1 \uc9c0\uc704\uac00 \uc778\uc815\ub41c\ub2e4","\uac70\ub798 \ub2f9\uc0ac\uc790\uac00 \ubaa8\ub450 \ub300\uae30\uc5c5\uc774\uc5b4\uc57c\ub9cc \uac70\ub798\uc0c1 \uc9c0\uc704\uac00 \uc778\uc815\ub41c\ub2e4","\uac70\ub798\uc0c1 \uc9c0\uc704\ub294 \uacc4\uc57d\uc11c\uc5d0 \uba85\uc2dc\uc801\uc73c\ub85c \uae30\uc7ac\ub418\uc5b4\uc57c\ub9cc \uc778\uc815\ub41c\ub2e4"],t.s)
B.Qw=s([u.cw],t.s)
B.Nu=s(["\uac70\ub798\uc0c1 \uc9c0\uc704\uc758 \ud310\ub2e8\uae30\uc900"],t.s)
B.adV=new A.f("gen_super_status_1","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uac70\ub798\uc0c1\uc9c0\uc704 \uc874\ubd80\uc758 \ud310\ub2e8",'\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc5d0\uc11c "\uac70\ub798\uc0c1 \uc9c0\uc704"\uac00 \uc778\uc815\ub418\ub294 \uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.a21,0,'\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc5d0\uc11c "\uac70\ub798\uc0c1 \uc9c0\uc704"\ub294 \ubc18\ub4dc\uc2dc \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc0ac\uc5c5\uc790\uc77c \uac83\uc744 \uc694\ud558\uc9c0 \uc54a\uc73c\uba70, \uac70\ub798\uc0c1\ub300\ubc29\uc774 \uc0ac\uc2e4\uc0c1 \uac70\ub798\ucc98\ub97c \uc804\ud658\ud558\uae30 \uc5b4\ub824\uc6b4 \uc815\ub3c4\ub85c \ud2b9\uc815 \uc0ac\uc5c5\uc790\uc5d0\uac8c \uac70\ub798\uc0c1 \uc758\uc874\ud558\uace0 \uc788\uc5b4 \uadf8 \uc0ac\uc5c5\uc790\uac00 \uc0c1\ub300\uc801\uc73c\ub85c \uc6b0\uc6d4\ud55c \uc9c0\uc704\uc5d0 \uc788\ub294 \uad00\uacc4\uc778\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4.',B.Qw,B.Nu,null)
B.Jx=s([u.l9,"\uac00\ub9f9\ubcf8\ubd80\uac00 \ud56d\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc0ac\uc5c5\uc790\uc774\uae30 \ub54c\ubb38\uc774\ub2e4","\uac00\ub9f9\uacc4\uc57d\uc11c\uc5d0 \uac70\ub798\uc0c1 \uc9c0\uc704\ub77c\ub294 \ubb38\uad6c\uac00 \uba85\uc2dc\ub418\uc5b4 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4","\uac00\ub9f9\uc810\uc758 \ub9e4\ucd9c \uaddc\ubaa8\uac00 \ud06c\uae30 \ub54c\ubb38\uc774\ub2e4","\uac00\ub9f9\ubcf8\ubd80\uc640 \uac00\ub9f9\uc810\uc758 \uc9c0\uc5ed\uc774 \ub3d9\uc77c\ud558\uae30 \ub54c\ubb38\uc774\ub2e4"],t.s)
B.a0i=s([u.l9],t.s)
B.a0M=s(["\uac00\ub9f9\uad00\uacc4\uc5d0\uc11c\uc758 \uac70\ub798\uc0c1 \uc9c0\uc704"],t.s)
B.a8z=new A.f("gen_super_status_2","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uac70\ub798\uc0c1\uc9c0\uc704 \uc874\ubd80\uc758 \ud310\ub2e8","\uac00\ub9f9\ubcf8\ubd80\uc640 \uac00\ub9f9\uc810 \uc0ac\uc774\uc758 \uad00\uacc4\uc5d0\uc11c \uac70\ub798\uc0c1 \uc9c0\uc704\uac00 \uc778\uc815\ub418\ub294 \uadfc\uac70\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Jx,0,"\uac00\ub9f9\ubcf8\ubd80\uc640 \uac00\ub9f9\uc810 \uc0ac\uc774\uc5d0\uc11c\ub294, \uac00\ub9f9\uc810\uc774 \ud2b9\uc815 \uac00\ub9f9\ubcf8\ubd80\uc758 \uc0c1\ud45c\xb7\uc601\uc5c5\ubc29\uc2dd\uc5d0 \ub530\ub77c \uacc4\uc18d\uc801\uc778 \uac70\ub798\uad00\uacc4\ub97c \ub9fa\uc73c\uba70 \uc0c1\ub2f9\ud55c \uc815\ub3c4\ub85c \uc758\uc874\ud558\uace0 \uac70\ub798\ucc98 \uc804\ud658\uc774 \uc27d\uc9c0 \uc54a\uc740 \uc0ac\uc815 \ub4f1\uc744 \uadfc\uac70\ub85c \uac00\ub9f9\ubcf8\ubd80\uc758 \uac70\ub798\uc0c1 \uc9c0\uc704\uac00 \uc778\uc815\ub418\ub294 \uacbd\uc6b0\uac00 \ub9ce\ub2e4.",B.a0i,B.a0M,null)
B.a1q=s([u.N,"\ub450 \uaddc\uc81c\ub294 \uc644\uc804\ud788 \ub3d9\uc77c\ud55c \uc694\uac74\uacfc \ub300\uc0c1\uc744 \uac16\ub294\ub2e4","\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\uc758 \ud558\uc704 \uac1c\ub150\uc5d0 \ubd88\uacfc\ud558\ub2e4","\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4","\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9 \uaddc\uc81c\ub294 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Pf=s([u.N],t.s)
B.YH=s(["\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uacfc \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\uc758 \uad6c\ubcc4"],t.s)
B.a8j=new A.f("gen_super_status_3","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\uac70\ub798\uc0c1\uc9c0\uc704 \uc874\ubd80\uc758 \ud310\ub2e8","\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9 \uaddc\uc81c\uc640 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9 \uaddc\uc81c\uc758 \uad00\uacc4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.a1q,0,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\uc740 \uad00\ub828\uc2dc\uc7a5 \uc804\uccb4\uc5d0\uc11c\uc758 \uc9c0\ubc30\uc801 \uc9c0\uc704\ub97c \uc804\uc81c\ub85c \ud558\ub294 \ubc18\uba74, \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc740 \uac1c\ubcc4 \uac70\ub798\uad00\uacc4\uc5d0\uc11c \uc0c1\ub300\ubc29\uc774 \uc0c1\ub300\uc801\uc73c\ub85c \uc5f4\ub4f1\ud55c \uc9c0\uc704\uc5d0 \uc788\uc5b4 \ubc1c\uc0dd\ud558\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\uc758 \ud55c \uc720\ud615\uc73c\ub85c, \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc0ac\uc5c5\uc790\uac00 \uc544\ub2c8\ub354\ub77c\ub3c4 \uc131\ub9bd\ud560 \uc218 \uc788\ub294 \ubcc4\uac1c\uc758 \uaddc\uc81c \uc720\ud615\uc774\ub2e4.",B.Pf,B.YH,null)
B.a1A=s(["\ub0a9\ud488\uc5c5\uccb4\uac00 \ub9e4\ucd9c\uc758 \uc0c1\ub2f9 \ubd80\ubd84\uc744 \uc18c\uc218\uc758 \ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\uc5d0 \uc758\uc874\ud558\ub294 \uac70\ub798 \uad6c\uc870","\ub0a9\ud488\uc5c5\uccb4\uac00 \ub2e4\uc591\ud55c \ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\uc5d0 \uade0\ub4f1\ud558\uac8c \ubd84\uc0b0\ud558\uc5ec \uac70\ub798\ud558\ub294 \uad6c\uc870","\ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\uac00 \uc18c\uaddc\ubaa8\ub85c \uc6b4\uc601\ub418\ub294 \uacbd\uc6b0\uc5d0\ub9cc \ubb38\uc81c\ub41c\ub2e4","\ub0a9\ud488\uc5c5\uccb4\uac00 \ud56d\uc0c1 \ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uccb4\ubcf4\ub2e4 \ub9e4\ucd9c \uaddc\ubaa8\uac00 \ud070 \uacbd\uc6b0\uc5d0\ub9cc \ubb38\uc81c\ub41c\ub2e4","\uac70\ub798\uc0c1 \uc9c0\uc704\ub294 \ub300\uaddc\ubaa8\uc720\ud1b5\uc5c5\uacfc \uc804\ud600 \ubb34\uad00\ud55c \uac1c\ub150\uc774\ub2e4"],t.s)
