B.a9s=new A.f("gen_super_sanction_4","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9","\ubd80\ub2f9\uc131 \ud310\ub2e8\xb7\uc81c\uc7ac","\uac00\ub9f9\uc0ac\uc5c5\ubc95\uacfc \uacf5\uc815\uac70\ub798\ubc95\uc774 \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc744 \ud568\uaed8 \uaddc\uc81c\ud558\ub294 \uac83\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.X5,0,"\uac00\ub9f9\uc0ac\uc5c5\ubc95\uc740 \uac00\ub9f9\ubcf8\ubd80\uc640 \uac00\ub9f9\uc810 \uac04\uc758 \ud2b9\uc218\ud55c \uac70\ub798\uad00\uacc4 \ud2b9\uc131\uc744 \ubc18\uc601\ud558\uc5ec \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud560 \uc218 \uc788\ub294 \ud589\uc704 \uc720\ud615(\ubd80\ub2f9\ud55c \uc601\uc5c5\uc9c0\uc5ed \uce68\ud574, \ubd80\ub2f9\ud55c \uacc4\uc57d\ud574\uc9c0 \ub4f1)\uc744 \ubcf4\ub2e4 \uad6c\uccb4\ud654\ud558\uc5ec \uaddc\uc815\ud558\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc73c\uba70, \uc774\ub294 \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc77c\ubc18\uc801\uc778 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \uaddc\uc81c\uc640 \ud568\uaed8 \uac00\ub9f9\ubd84\uc57c\uc758 \ud2b9\uc218\uc131\uc744 \ubcf4\uc644\ud558\ub294 \uc5ed\ud560\uc744 \ud55c\ub2e4.",B.Lz,B.QM,null)
B.Q9=s(["\ub458 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790 \uac04\uc758 \ud569\uc758\uac00 \uc788\uc5b4\uc57c \ud55c\ub2e4","\ud569\uc758\ub294 \uba85\uc2dc\uc801 \ud569\uc758\ubfd0\ub9cc \uc544\ub2c8\ub77c \ubb35\uc2dc\uc801 \uc758\uc0ac\uc5f0\ub77d\uc73c\ub85c\ub3c4 \uc778\uc815\ub420 \uc218 \uc788\ub2e4","\ud569\uc758\uc758 \uc874\uc7ac\ub294 \uc774\ub97c \uc8fc\uc7a5\ud558\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc99d\uba85\ud558\uc5ec\uc57c \ud55c\ub2e4","\ud569\uc758\uac00 \uc788\uc5c8\ub354\ub77c\ub3c4 \uc2e4\ud589\ud589\uc704\ub85c \ub098\uc544\uac00\uc9c0 \uc54a\uc558\ub2e4\uba74 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud558\uc5ec\uc57c \ud55c\ub2e4"],t.s)
