B.a8q=new A.f("gen_ca_3","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc131\ub9bd\uc694\uac74\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.Q9,3,'\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc0ac\uc5c5\uc790 \uac04 "\ud569\uc758" \uc790\uccb4\ub85c \uc131\ub9bd\ud558\uba70, \uadf8 \ud569\uc758\ub97c \uc2e4\uc81c\ub85c \uc2e4\ud589\uc5d0 \uc62e\uacbc\ub294\uc9c0 \uc5ec\ubd80\ub294 \uc131\ub9bd\uc694\uac74\uc774 \uc544\ub2c8\ub77c\ub294 \uac83\uc774 \ud310\ub840\uc758 \uc77c\uad00\ub41c \uc785\uc7a5\uc774\ub2e4. \uc989 \ud569\uc758\ub9cc \uc788\uc73c\uba74 \uc2e4\ud589\ud589\uc704\uac00 \uc5c6\uc5c8\ub354\ub77c\ub3c4 \uc774\ubbf8 \uacbd\uc7c1\uc81c\ud55c\uc758 \uc704\ud5d8\uc774 \ubc1c\uc0dd\ud55c \uac83\uc73c\ub85c \ubcf4\uc544 \uacf5\ub3d9\ud589\uc704\uac00 \uc131\ub9bd\ud558\uace0, \uc2e4\ud589 \uc5ec\ubd80\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815 \ub4f1 \uc81c\uc7ac \uc218\uc704\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce60 \ubfd0\uc774\ub2e4. \ub530\ub77c\uc11c "\uc2e4\ud589\ud589\uc704\ub85c \ub098\uc544\uac00\uc9c0 \uc54a\uc558\ub2e4\uba74 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ud569\uc758\uc5d0\ub294 \ubb35\uc2dc\uc801 \uc758\uc0ac\uc5f0\ub77d\ub3c4 \ud3ec\ud568\ub418\uace0, \uadf8 \uc99d\uba85\ucc45\uc784\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uc788\uc73c\uba70, \uacbd\uc7c1\uc81c\ud55c\uc131 \uc694\uac74\uc774 \ud544\uc694\ud558\ub2e4\ub294 \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0\ub294 \ubaa8\ub450 \uc633\uc740 \uc124\uba85\uc774\ub2e4.',B.a1D,B.XM,null)
