B.acs=new A.f("gen_collusion_presume_4","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\ud569\uc758 \ucd94\uc815\xb7\uc99d\uba85\ucc45\uc784","\uc815\ud669\uc99d\uac70\ub9cc\uc73c\ub85c \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \ud569\uc758\ub97c \uc778\uc815\ud560 \uc218 \uc788\ub294\uc9c0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.SN,0,"\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc740\ubc00\ud558\uac8c \uc774\ub8e8\uc5b4\uc9c0\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc544 \uc9c1\uc811\uc99d\uac70\ub97c \ud655\ubcf4\ud558\uae30 \uc5b4\ub824\uc6b4 \uacbd\uc6b0\uac00 \ub9ce\uc73c\ubbc0\ub85c, \uc9c1\uc811\uc99d\uac70\uac00 \uc5c6\ub354\ub77c\ub3c4 \uac00\uaca9 \uc778\uc0c1\uc758 \uc2dc\uae30\xb7\ud3ed \uc77c\uce58, \ud68c\ud569 \uc815\ud669, \uc815\ubcf4\uad50\ud658 \ub0b4\uc5ed \ub4f1 \uc5ec\ub7ec \uc815\ud669\uc99d\uac70\ub97c \uc885\ud569\ud558\uc5ec \ud569\uc758\uc758 \uc874\uc7ac\ub97c \uc778\uc815\ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ud310\ub840\uc758 \ud0dc\ub3c4\uc774\ub2e4.",B.KJ,B.It,null)
B.Rb=s(["\ub2e4\ub978 \uc815\ud669\uc99d\uac70\uc640 \ud568\uaed8 \ud569\uc758\ub97c \uc778\uc815\ud558\ub294 \uc720\ub825\ud55c \uc99d\uac70\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\uc740 \uc5b4\ub5a0\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc99d\uac70\ub85c \uc0ac\uc6a9\ub420 \uc218 \uc5c6\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\ub9cc \uc788\uc73c\uba74 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \ubc18\ubc15 \uae30\ud68c \uc5c6\uc774 \uace7\ubc14\ub85c \ucc98\ubd84\uc774 \ud655\uc815\ub41c\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\uc740 \uc624\uc9c1 \uc790\uc9c4\uc2e0\uace0\uc790 \ubcf8\uc778\uc758 \uc0ac\uac74\uc5d0\ub9cc \uc0ac\uc6a9\ub41c\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc758 \uc9c4\uc220\uc740 \ud56d\uc0c1 \uc2e0\ube59\uc131\uc774 \uc5c6\ub294 \uac83\uc73c\ub85c \ucde8\uae09\ub41c\ub2e4"],t.s)
B.Qf=s(["\ub2e4\ub978 \uc815\ud669\uc99d\uac70\uc640 \ud568\uaed8 \ud569\uc758\ub97c \uc778\uc815\ud558\ub294 \uc720\ub825\ud55c \uc99d\uac70\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4"],t.s)
