B.a9K=new A.f("gen_collusion_presume_5","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\ud569\uc758 \ucd94\uc815\xb7\uc99d\uba85\ucc45\uc784","\uc790\uc9c4\uc2e0\uace0(\ub9ac\ub2c8\uc5b8\uc2dc)\ub97c \ud1b5\ud574 \ud655\ubcf4\ub41c \uc9c4\uc220\uc774 \ub2e4\ub978 \ucc38\uc5ec \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ud569\uc758 \uc99d\uba85\uc5d0 \ubbf8\uce58\ub294 \uc601\ud5a5\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.Rb,0,"\uc790\uc9c4\uc2e0\uace0(\ub9ac\ub2c8\uc5b8\uc2dc)\ub97c \ud1b5\ud574 \ud655\ubcf4\ub41c \uc0ac\uc5c5\uc790\uc758 \uc9c4\uc220\uc740 \ub2e4\ub978 \ucc38\uc5ec \uc0ac\uc5c5\uc790\uc5d0 \ub300\ud55c \ud569\uc758\ub97c \uc99d\uba85\ud558\ub294 \ub370 \uc788\uc5b4 \ub2e4\ub978 \uc815\ud669\uc99d\uac70\uc640 \ud568\uaed8 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ub418\ub294 \uc720\ub825\ud55c \uc99d\uac70\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \uadf8 \uc9c4\uc220\ub9cc\uc73c\ub85c \uace7\ubc14\ub85c \ubc18\ubc15 \uae30\ud68c \uc5c6\uc774 \ucc98\ubd84\uc774 \ud655\uc815\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.Qf,B.Sp,null)
B.L3=s(["\ud569\uc758 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\ub294 \ub370 \ucc38\uace0\ub418\ub294 \uc5ec\ub7ec \uc815\ud669 \uc911 \ud558\ub098\ub85c \uace0\ub824\ub420 \uc218 \uc788\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\ub9cc\uc73c\ub85c \ud56d\uc0c1 \ud569\uc758\uac00 \ud655\uc815\uc801\uc73c\ub85c \uc778\uc815\ub41c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uc740 \ud569\uc758 \ud310\ub2e8\uacfc \uc804\ud600 \ubb34\uad00\ud558\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uc740 \uc624\uc9c1 \uae30\uc5c5\uacb0\ud569 \uc2ec\uc0ac\uc5d0\uc11c\ub9cc \ubb38\uc81c\ub41c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 \ubcc0\ub3d9\uc740 \ud569\uc758\ub97c \ubd80\uc815\ud558\ub294 \uc808\ub300\uc801 \uc99d\uac70\uc774\ub2e4"],t.s)
B.SO=s(["\ud569\uc758 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud558\ub294 \ub370 \ucc38\uace0\ub418\ub294 \uc5ec\ub7ec \uc815\ud669 \uc911 \ud558\ub098\ub85c \uace0\ub824\ub420 \uc218 \uc788\ub2e4"],t.s)
