B.GJ=s([u.d8,"\ud569\uc758\uac00 \uc788\uc5c8\ub358 \ucd5c\ucd08 \uc2dc\uc810\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud558\uace0 \uc774\ud6c4 \uc0ac\uc815\uc740 \uc804\ud600 \uace0\ub824\ud558\uc9c0 \uc54a\ub294\ub2e4","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \ud56d\uc0c1 \uc815\ubd80\uc758 \uc870\uc0ac \uac1c\uc2dc\uc77c\ub85c \uace0\uc815\ub41c\ub2e4","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \ud310\ub2e8\ud560 \ud544\uc694\uac00 \uc5c6\ub294 \uac1c\ub150\uc774\ub2e4","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \uc5b8\ub860\ubcf4\ub3c4\uc77c\uc744 \uae30\uc900\uc73c\ub85c \ud55c\ub2e4"],t.s)
