B.J7=s(["\uacf5\ub3d9\ud589\uc704 \uc885\uae30\uc758 \ud310\ub2e8\uae30\uc900"],t.s)
B.a98=new A.f("gen_collusion_end_1","economic_law","\ub2f4\ud569\uc758 \uc131\ub9bd\uc694\uac74","\uacf5\ub3d9\ud589\uc704\uc758 \uc885\ub8cc\xb7\uac1c\ubcc4 \uc0ac\uc5c5\uc790 \ucc45\uc784","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30(\u7d42\u671f)\ub97c \ud310\ub2e8\ud558\ub294 \uae30\uc900\uc73c\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?",B.GJ,0,"\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc758 \uc885\uae30\ub294 \ub2e8\uc21c\ud788 \ud569\uc758\uac00 \uc131\ub9bd\ud55c \uc2dc\uc810\uc774 \uc544\ub2c8\ub77c, \ud569\uc758\uc5d0 \ub530\ub978 \uc2e4\ud589\ud589\uc704\uac00 \ucd5c\uc885\uc801\uc73c\ub85c \uc885\ub8cc\ub41c \uc2dc\uc810\uc744 \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud558\ub294 \uac83\uc774 \uc77c\ubc18\uc801\uc774\ub2e4. \uc774\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815, \ucc98\ubd84\uc2dc\ud6a8 \uae30\uc0b0 \ub4f1\uc5d0 \uc911\uc694\ud55c \uc758\ubbf8\ub97c \uac16\ub294\ub2e4.",B.MQ,B.J7,null)
